# Provider configuration
provider "aws" {
  region = "us-east-1"
}

# Data source to look up the existing hosted zone named "primary"
# Note: In a real-world scenario, zone names are typically fully qualified domain names (e.g., "example.com").
# This data source looks for a zone with the exact name provided in the request.
data "aws_route53_zone" "primary" {
  name = "primary"
}

# Resource: CloudWatch Logs Log Group
# This creates the log group where query logs will be stored.
resource "aws_cloudwatch_log_group" "route53_logs" {
  name              = "aws_route53_example_com"
  retention_in_days = 7
}

# Resource: CloudWatch Logs Resource Policy
# This policy grants Route 53 permissions to create log streams and put log events into the specific log group.
resource "aws_cloudwatch_log_resource_policy" "route53_query_logging_policy" {
  policy_name = "route53-query-logging-policy"

  policy_document = <<POLICY
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "route53.amazonaws.com"
      },
      "Action": [
        "logs:CreateLogStream",
        "logs:PutLogEvents"
      ],
      "Resource": "${aws_cloudwatch_log_group.route53_logs.arn}:*"
    }
  ]
}
POLICY
}

# Resource: Route 53 Query Log
# This associates the hosted zone with the CloudWatch Logs log group to start logging queries.
resource "aws_route53_query_log" "example" {
  cloudwatch_log_group_arn = aws_cloudwatch_log_group.route53_logs.arn
  hosted_zone_id           = data.aws_route53_zone.primary.id
}

