# 1. Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 2. Create the Primary VPC (used for the initial Zone setup)
resource "aws_vpc" "primary_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "primary-vpc"
  }
}

# 3. Create a Secondary VPC (to be associated via the association resource)
resource "aws_vpc" "secondary_vpc" {
  cidr_block           = "10.1.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "secondary-vpc"
  }
}

# 4. Create a Private Route 53 Hosted Zone
# A private zone must be associated with at least one VPC upon creation.
resource "aws_route53_zone" "private_zone" {
  name = "example.internal"

  vpc {
    vpc_id = aws_vpc.primary_vpc.id
  }

  tags = {
    Name = "example-internal-zone"
  }
}

# 5. Route 53 Hosted Zone Association
# This resource specifically associates the Private Zone with the Secondary VPC.
# This allows resources in 'secondary_vpc' to resolve records in 'example.internal'.
resource "aws_route53_zone_association" "secondary_assoc" {
  zone_id = aws_route53_zone.private_zone.id
  vpc_id  = aws_vpc.secondary_vpc.id

  # It is best practice to explicitly set the VPC region, 
  # especially if the provider region might differ or for clarity.
  vpc_region = "us-east-1"
}

