# This configuration sets up the infrastructure required to satisfy the request.
# It includes the necessary VPC and networking components to support the Load Balancer.

# 1. Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 2. Data source to get available Availability Zones
data "aws_availability_zones" "available" {
  state = "available"
}

# 3. Create a VPC for the Load Balancer
resource "aws_vpc" "main_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "main-vpc"
  }
}

# 4. Create Subnets for the Load Balancer (required for ALB/NLB)
resource "aws_subnet" "public_subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.main_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.main_vpc.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-${count.index}"
  }
}

# 5. Create a Security Group for the Load Balancer
resource "aws_security_group" "lb_sg" {
  name        = "lb-sg"
  description = "Allow HTTP traffic"
  vpc_id      = aws_vpc.main_vpc.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 6. Create the Elastic Load Balancer named "main"
resource "aws_lb" "main" {
  name               = "main"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = aws_subnet.public_subnets[*].id

  tags = {
    Environment = "production"
  }
}

# 7. Create the Route 53 Hosted Zone named "primary"
# Note: A hosted zone requires a valid domain name. We use "primary.example.com" here.
resource "aws_route53_zone" "primary" {
  name = "primary.example.com"

  tags = {
    Name = "primary"
  }
}

# 8. Create the Route 53 DNS entry pointing to the Load Balancer
resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "www.primary.example.com"
  type    = "A"

  alias {
    name                   = aws_lb.main.dns_name
    zone_id                = aws_lb.main.zone_id
    evaluate_target_health = true
  }
}

