# This configuration sets up the infrastructure required to satisfy the request.
# It includes the necessary VPC and networking components to support the Load Balancer.

# 1. Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 2. Data source to get available Availability Zones
data "aws_availability_zones" "available" {
