terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Provider Aliases
provider "aws" {
  region = "us-west-1"
  alias  = "main"
}

provider "aws" {
  region = "us-east-1"
  alias  = "us-east"
}

provider "aws" {
  region = "eu-central-1"
  alias  = "eu-central"
}

provider "aws" {
  region = "ap-southeast-1"
  alias  = "ap-southeast"
}

# Variable for DB credentials
variable "db_username" {
  default = "admin"
}

variable "db_password" {
  sensitive = true
}

# Primary DB Instance in us-west-1
resource "aws_db_instance" "primary" {
  provider = aws.main

  identifier             = "primary"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp2"
  username               = var.db_username
  password               = var.db_password
  db_name                = "maindb"
  parameter_group_name   = "default.mysql8.0"
  skip_final_snapshot    = true
  backup_retention_period = 1 # Required for cross-region replication
  publicly_accessible    = true # For demonstration purposes
}

# Route 53 Hosted Zone
resource "aws_route53_zone" "main" {
  provider = aws.main
  name     = "example.com" # Using a generic domain name as required by Route 53
}

# Replica in us-east-1
resource "aws_db_instance" "replica_us_east" {
  provider = aws.us-east

  identifier          = "replica_us_east"
  replicate_source_db = aws_db_instance.primary.arn
  instance_class      = "db.t3.micro"
  skip_final_snapshot = true
  publicly_accessible = true

  # Tags to identify the replica
  tags = {
    Role = "replica"
  }
}

# Replica in eu-central-1
resource "aws_db_instance" "replica_eu_central" {
  provider = aws.eu-central

  identifier          = "replica_eu_central"
  replicate_source_db = aws_db_instance.primary.arn
  instance_class      = "db.t3.micro"
  skip_final_snapshot = true
  publicly_accessible = true

  tags = {
    Role = "replica"
  }
}

# Replica in ap-southeast-1
resource "aws_db_instance" "replica_ap_southeast" {
  provider = aws.ap-southeast

  identifier          = "replica_ap_southeast"
  replicate_source_db = aws_db_instance.primary.arn
  instance_class      = "db.t3.micro"
  skip_final_snapshot = true
  publicly_accessible = true

  tags = {
    Role = "replica"
  }
}

# Route 53 Weighted Records for Replicas
resource "aws_route53_record" "replica_us_east" {
  provider = aws.main

  zone_id = aws_route53_zone.main.zone_id
  name    = "db-read.example.com"
  type    = "CNAME"
  ttl     = "300"

  records = [aws_db_instance.replica_us_east.endpoint]

  weighted_routing_policy {
    weight = 34
  }

  set_identifier = "replica-us-east"
}

resource "aws_route53_record" "replica_eu_central" {
  provider = aws.main

  zone_id = aws_route53_zone.main.zone_id
  name    = "db-read.example.com"
  type    = "CNAME"
  ttl     = "300"

  records = [aws_db_instance.replica_eu_central.endpoint]

  weighted_routing_policy {
    weight = 33
  }

  set_identifier = "replica-eu-central"
}

resource "aws_route53_record" "replica_ap_southeast" {
  provider = aws.main

  zone_id = aws_route53_zone.main.zone_id
  name    = "db-read.example.com"
  type    = "CNAME"
  ttl     = "300"

  records = [aws_db_instance.replica_ap_southeast.endpoint]

  weighted_routing_policy {
    weight = 33
  }

  set_identifier = "replica-ap-southeast"
}

