terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# 1. Networking Resources (VPC, Subnets, IGW)
# -----------------------------------------------------------------------------

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# Create two subnets in different AZs for the DB Subnet Group
resource "aws_subnet" "subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = element(["us-east-1a", "us-east-1b"], count.index)
  map_public_ip_on_launch = true

  tags = {
    Name = "subnet-${count.index + 1}"
  }
}

# Route Table for Public Subnets (needed for Public RDS connectivity)
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public-rt"
  }
}

resource "aws_route_table_association" "public" {
  count          = 2
  subnet_id      = aws_subnet.subnets[count.index].id
  route_table_id = aws_route_table.public.id
}

# -----------------------------------------------------------------------------
# 2. Security Groups
# -----------------------------------------------------------------------------

resource "aws_security_group" "internal_db_sg" {
  name        = "internal-db-sg"
  description = "Allow internal access to the Internal DB"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "internal-db-sg"
  }
}

resource "aws_security_group" "public_db_sg" {
  name        = "public-db-sg"
  description = "Allow public access to the Public DB"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "public-db-sg"
  }
}

# -----------------------------------------------------------------------------
# 3. Database Subnet Group
# -----------------------------------------------------------------------------

resource "aws_db_subnet_group" "main" {
  name       = "main"
  subnet_ids = aws_subnet.subnets[*].id

  tags = {
    Name = "main-db-subnet-group"
  }
}

# -----------------------------------------------------------------------------
# 4. RDS Instances
# -----------------------------------------------------------------------------

resource "random_password" "db_password" {
  length  = 16
  special = false
}

# Internal RDS
resource "aws_db_instance" "internal" {
  identifier             = "internal"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.internal_db_sg.id]
  publicly_accessible    = false
  skip_final_snapshot    = true
  username               = "admin"
  password               = random_password.db_password.result

  tags = {
    Name = "internal-db"
  }
}

# Public RDS
resource "aws_db_instance" "public" {
  identifier             = "public"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.public_db_sg.id]
  publicly_accessible    = true
  skip_final_snapshot    = true
  username               = "admin"
  password               = random_password.db_password.result

  tags = {
    Name = "public-db"
  }
}

# -----------------------------------------------------------------------------
# 5. Route 53 Configuration
# -----------------------------------------------------------------------------

# Private Hosted Zone
resource "aws_route53_zone" "private" {
  name = "example.com"

  vpc {
    vpc_id = aws_vpc.main.id
  }

  tags = {
    Name = "private-hosted-zone"
  }
}

# Public Hosted Zone
resource "aws_route53_zone" "public" {
  name = "example.com"

  tags = {
    Name = "public-hosted-zone"
  }
}

# Record in Private Zone pointing to Internal DB
resource "aws_route53_record" "internal_db" {
  zone_id = aws_route53_zone.private.zone_id
  name    = "db.example.com"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_db_instance.internal.endpoint]
}

# Record in Public Zone pointing to Public DB
resource "aws_route53_record" "public_db" {
  zone_id = aws_route53_zone.public.zone_id
  name    = "db.example.com"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_db_instance.public.endpoint]
}

