response:
Here is the Terraform configuration to set up the Route 53 hosted zone and weighted DNS routing for your database instances.

This configuration includes:
1.  An AWS provider block.
2.  A Route 53 Hosted Zone named "main".
3.  Weighted routing records that distribute traffic between "replica-1" and "replica-2".
4.  A standard record for the "primary" instance (to satisfy the naming requirement, though typically primary instances handle writes and are not part of the weighted read routing).
5.  Variables to represent the endpoints of the database instances.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Variables to simulate the endpoints of the database instances.
# In a real scenario, these would be outputs from an RDS module or data sources.
variable "primary_db_endpoint" {
  default = "primary-db.example.com"
  description = "The DNS endpoint of the primary DB instance"
}

variable "replica_1_endpoint" {
  default = "replica-1-db.example.com"
  description = "The DNS endpoint of read-replica 1"
}

variable "replica_2_endpoint" {
  default = "replica-2-db.example.com"
  description = "The DNS endpoint of read-replica 2"
}

# 1. Create the Hosted Zone named "main"
resource "aws_route53_zone" "main" {
  name = "main"
  # Note: In a real-world scenario, this would typically be a valid domain name (e.g., example.com).
  # We are using "main" strictly per the naming requirements.
}

# 2. Record for the Primary Instance
# This creates a standard DNS record for the primary instance.
resource "aws_route53_record" "primary" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "primary-db.main"
  type    = "CNAME"
  ttl     = "300"
  records = [var.primary_db_endpoint]
}

# 3. Weighted Routing Configuration for Replica 1
resource "aws_route53_record" "replica_1" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "read-db.main"
  type    = "CNAME"
  ttl     = "300"
  records = [var.replica_1_endpoint]

  weighted_routing_policy {
    weight = 50
  }

  set_identifier = "replica-1"
}

# 4. Weighted Routing Configuration for Replica 2
resource "aws_route53_record" "replica_2" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "read-db.main"
  type    = "CNAME"
  ttl     = "300"
  records = [var.replica_2_endpoint]

  weighted_routing_policy {
    weight = 50
  }

  set_identifier = "replica-2"
}
```

