  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# 2. Attach the AWS managed policy for Elastic Beanstalk to the role
resource "aws_iam_role_policy_attachment" "eb_ec2_role_policy_attach" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# 3. Create the Instance Profile
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# 4. Create the Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "my_api_app" {
  name        = "my_api_app"
  description = "My API Application"
}

# 5. Create the Elastic Beanstalk Environment with Auto Scaling
resource "aws_elastic_beanstalk_environment" "my_api_app_env" {
  name                = "my-api-app-env"
  application         = aws_elastic_beanstalk_application.my_api_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.1.0 running Python 3.11"

  # Link the Instance Profile
  instance_profile = aws_iam_instance_profile.eb_ec2_profile.name

  # Auto Scaling Group Configuration
  setting {
