}

# 1. IAM Role for Elastic Beanstalk EC2 Instances
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the Worker Tier policy to allow access to SQS and S3
resource "aws_iam_role_policy_attachment" "eb_worker_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWorkerTier"
}

# 2. Instance Profile
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# 3. SQS Queue for the Worker Environment
resource "aws_sqs_queue" "batch_job_queue" {
  name = "batch_job_queue"

  # SQS settings for a worker tier often require visibility timeout adjustments
  # depending on task duration, but defaults are used here.
}

# 4. S3 Bucket
# Note: In a real scenario, the object would need to exist in the bucket 
# before the application version is created. We define the bucket here.
resource "aws_s3_bucket" "sample_bucket" {
  bucket = "sampleapril26426"
}

# 5. Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "batch_job_app" {
  name        = "batch_job_app"
  description = "Application for batch processing jobs"
}

# 6. Application Version
resource "aws_elastic_beanstalk_application_version" "version" {
  name        = "version"
  application = aws_elastic_beanstalk_application.batch_job_app.name
  description = "Application version for batch job"
  bucket      = aws_s3_bucket.sample_bucket.bucket
  key         = "examplebucket_object"

  # Ensure the bucket exists before creating the version (though object existence is not checked by TF)
  depends_on = [
    aws_s3_bucket.sample_bucket
  ]
}

# 7. Elastic Beanstalk Worker Environment
resource "aws_elastic_beanstalk_environment" "worker_env" {
  name                = "batch-job-worker-env"
  application         = aws_elastic_beanstalk_application.batch_job_app.name
  solution_stack_name = "64bit Amazon Linux 2 v5.9.0 running Python 3.9" # Example worker stack
  version_label       = aws_elastic_beanstalk_application_version.version.name
  tier                = "Worker"

  # Settings to link the IAM Instance Profile
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  # Settings to link the Worker Queue
  setting {
    namespace = "aws:elasticbeanstalk:sqsd"
    name      = "WorkerQueueURL"
    value     = aws_sqs_queue.batch_job_queue.id
  }

  # Setting to specify the environment type explicitly (though tier attribute handles this)
  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "Worker"
  }
}

