terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Generate a unique suffix for the bucket name
resource "random_pet" "unique_suffix" {
  length = 2
}

# IAM Role for EC2 Instances
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the Elastic Beanstalk WebTier policy to the role (required for basic functionality)
resource "aws_iam_role_policy_attachment" "eb_web_tier" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# IAM Instance Profile
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# S3 Bucket (Uniquely named)
resource "aws_s3_bucket" "app_bucket" {
  bucket = "my-unique-bucket-${random_pet.unique_suffix.id}"
}

# Create a dummy zip file for the application version
data "archive_file" "dummy_app" {
  type        = "zip"
  output_path = "${path.module}/app_source.zip"
  source {
    content = "<html><body><h1>Hello from Terraform</h1></body></html>"
    filename = "index.html"
  }
}

# S3 Object
resource "aws_s3_object" "examplebucket_object" {
  bucket = aws_s3_bucket.app_bucket.id
  key    = "examplebucket_object"
  source = data.archive_file.dummy_app.output_path
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "myapp" {
  name        = "myapp"
  description = "My Application"
}

# Elastic Beanstalk Application Version
resource "aws_elastic_beanstalk_application_version" "version" {
  name        = "version"
  application = aws_elastic_beanstalk_application.myapp.name
  description = "Application version 1"
  bucket      = aws_s3_bucket.app_bucket.id
  key         = aws_s3_object.examplebucket_object.key

  depends_on = [
    aws_s3_object.examplebucket_object
  ]
}

# Get the latest solution stack for Node.js
data "aws_elastic_beanstalk_solution_stack" "nodejs" {
  most_recent = true
  name_regex  = "^64bit Amazon Linux (.*) running Node.js"
}

# Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "eb_env" {
  name                = "eb-env"
  application         = aws_elastic_beanstalk_application.myapp.name
  solution_stack_name = data.aws_elastic_beanstalk_solution_stack.nodejs.name
  version_label       = aws_elastic_beanstalk_application_version.version.name

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# Route 53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = "main"
}

# Route 53 Record to route requests to the EB Environment
resource "aws_route53_record" "eb_alias" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www.main"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_elastic_beanstalk_environment.eb_env.cname]
}

