terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# 1. Elastic Beanstalk Setup
# ------------------------------------------------------------------------------

# Create the Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "app" {
  name        = "my-blue-green-app"
  description = "Application for Blue-Green Deployment"
}

# Create an S3 bucket to store the application version
resource "aws_s3_bucket" "app_bucket" {
  bucket = "my-blue-green-app-bucket"
}

# Create a dummy zip file for the application version
resource "aws_s3_object" "app_zip" {
  bucket = aws_s3_bucket.app_bucket.id
  key    = "app.zip"
  source = "${path.module}/app.zip" # Assumes a dummy app.zip exists or is created locally
}

# Create the Application Version
resource "aws_elastic_beanstalk_application_version" "app_version" {
  name        = "v1"
  application = aws_elastic_beanstalk_application.app.name
  bucket      = aws_s3_bucket.app_bucket.id
  key         = aws_s3_object.app_zip.id
}

# ------------------------------------------------------------------------------
# 2. Elastic Beanstalk Environments (Blue & Green)
# ------------------------------------------------------------------------------

# Resource to look up the latest solution stack (Platform)
data "aws_elastic_beanstalk_solution_stack" "latest" {
  most_recent = true
  name_regex  = "^64bit Amazon Linux 2.* running Tomcat"
}

# Environment: Blue
resource "aws_elastic_beanstalk_environment" "blue" {
  name                = "blue"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = data.aws_elastic_beanstalk_solution_stack.latest.name
  version_label       = aws_elastic_beanstalk_application_version.app_version.name

  setting {
    namespace = "aws:elasticbeanstalk:environment:name"
    name      = "EnvironmentName"
    value     = "blue"
  }

  # CNAME prefix must be unique
  cname_prefix = "my-app-blue-env"
}

# Environment: Green
resource "aws_elastic_beanstalk_environment" "green" {
  name                = "green"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = data.aws_elastic_beanstalk_solution_stack.latest.name
  version_label       = aws_elastic_beanstalk_application_version.app_version.name

  setting {
    namespace = "aws:elasticbeanstalk:environment:name"
    name      = "EnvironmentName"
    value     = "green"
  }

  # CNAME prefix must be unique
  cname_prefix = "my-app-green-env"
}

# ------------------------------------------------------------------------------
# 3. Route 53 Weighted Routing
# ------------------------------------------------------------------------------

# Create a Hosted Zone for the domain
resource "aws_route53_zone" "main" {
  name = "example.com"
}

# Route 53 Record for Blue Environment
resource "aws_route53_record" "blue" {
  zone_id = aws_route53_zone.main.id
  name    = "www.example.com"
  type    = "CNAME"
  ttl     = "300"

  # Identifiers allow multiple records with the same name and type
  set_identifier = "blue-env"

  # Weighted Routing Policy
  weighted_routing_policy {
    weight = 50 # 50% of traffic
  }

  records = [
    aws_elastic_beanstalk_environment.blue.cname
  ]
}

# Route 53 Record for Green Environment
resource "aws_route53_record" "green" {
  zone_id = aws_route53_zone.main.id
  name    = "www.example.com"
  type    = "CNAME"
  ttl     = "300"

  # Identifiers allow multiple records with the same name and type
  set_identifier = "green-env"

  # Weighted Routing Policy
  weighted_routing_policy {
    weight = 50 # 50% of traffic
  }

  records = [
    aws_elastic_beanstalk_environment.green.cname
  ]
}

# ------------------------------------------------------------------------------
# Outputs
# ------------------------------------------------------------------------------

output "blue_environment_url" {
  value = aws_elastic_beanstalk_environment.blue.cname
}

output "green_environment_url" {
  value = aws_elastic_beanstalk_environment.green.cname
}

output "route53_dns_name" {
  value = "www.example.com"
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}


provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_iam_role" "eb_ec2_role" {
  name = "elastic_beanstalk_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "ec2.amazonaws.com"
        },
      },
    ]
  })
}

# Attach the AWS managed policy for Elastic Beanstalk to the role
resource "aws_iam_role_policy_attachment" "eb_managed_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}


# Create an instance profile tied to the role
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "elastic_beanstalk_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

resource "aws_s3_bucket" "sample_bucket" {
  bucket_prefix = "sample-"
}

resource "aws_s3_object" "examplebucket_blue_object" {
  key    = "blue_app"
  bucket = aws_s3_bucket.sample_bucket.id
  source = "./supplement/app.zip"
}

resource "aws_s3_object" "examplebucket_green_object" {
  key    = "green_app"
  bucket = aws_s3_bucket.sample_bucket.id
  source = "./supplement/app.zip"
}

# Elastic Beanstalk application
resource "aws_elastic_beanstalk_application" "blue_app" {
  name        = "blue-app"
  description = "An application for Blue deployment."
}

resource "aws_elastic_beanstalk_application_version" "blue_version" {
  name        = "v1"
  application = aws_elastic_beanstalk_application.blue_app.name
  bucket = aws_s3_object.examplebucket_blue_object.bucket
  key    = aws_s3_object.examplebucket_blue_object.key
}

resource "aws_elastic_beanstalk_application" "green_app" {
  name        = "green-app"
  description = "An application for Green deployment."
}

resource "aws_elastic_beanstalk_application_version" "green_version" {
  name        = "v2"
  application = aws_elastic_beanstalk_application.green_app.name
  bucket = aws_s3_object.examplebucket_green_object.bucket
  key    = aws_s3_object.examplebucket_green_object.key
}

# Blue environment
resource "aws_elastic_beanstalk_environment" "blue" {
  name                = "${aws_elastic_beanstalk_application.blue_app.name}"
  application         = aws_elastic_beanstalk_application.blue_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"
  version_label = aws_elastic_beanstalk_application_version.blue_version.name

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# Green environment (New version)
resource "aws_elastic_beanstalk_environment" "green" {
  name                = "${aws_elastic_beanstalk_application.green_app.name}-green"
  application         = aws_elastic_beanstalk_application.green_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"
  version_label = aws_elastic_beanstalk_application_version.green_version.name

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# Route53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = "example53.com"
}

# Weighted DNS records for Blue and Green environments
resource "aws_route53_record" "blue" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "CNAME"
  ttl     = "60"
  weighted_routing_policy {
    weight = 120
  }
  set_identifier = "BlueEnvironment"
  records = [
    aws_elastic_beanstalk_environment.blue.cname
  ]
}

resource "aws_route53_record" "green" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "CNAME"
  ttl     = "60"
  weighted_routing_policy {
    weight = 60
  }
  set_identifier = "GreenEnvironment"
  records = [
    aws_elastic_beanstalk_environment.green.cname
  ]
}

response:
Here is the step-by-step plan for the Terraform configuration:

1.  **Provider Configuration**: Set up the AWS provider.
2.  **Elastic Beanstalk Application**: Create the application container.
3.  **S3 Bucket & Application Version**: Create a bucket and upload a dummy application version (required to provision an environment).
4.  **Elastic Beanstalk Environments**: Create two environments, "blue" and "green", using a standard solution stack.
5.  **Route 53 Hosted Zone**: Create a hosted zone (e.g., `example.com`) to manage the domain.
6.  **Route 53 Records**: Create two `aws_route53_record` resources.
    *   Both will point to the same DNS name (e.g., `www.example.com`).
    *   They will use the `weighted_routing_policy` block to split traffic (e.g., 50/50).
    *   They will use `set_identifier` to distinguish the records within Route 53.
    *   They will point to the CNAME of the respective Elastic Beanstalk environments.

