# Terraform configuration for Multi-Region Elastic Beanstalk with Route 53 Latency-Based Routing

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# -----------------------------------------------------------------------------
# Provider Configuration
# We use aliases to manage resources in multiple regions within the same state.
# -----------------------------------------------------------------------------

# Default provider (used for Route 53, which is a global service, usually managed from us-east-1)
provider "aws" {
  region = "us-east-1"
}

# Provider for US West Region
provider "aws" {
  alias  = "us_west"
  region = "us-west-2"
}

# Provider for EU Central Region
provider "aws" {
  alias  = "eu_central"
  region = "eu-central-1"
}

# -----------------------------------------------------------------------------
# Data Sources
# Fetching a standard Elastic Beanstalk solution stack (platform)
# -----------------------------------------------------------------------------
data "aws_elastic_beanstalk_solution_stack" "nodejs" {
  most_recent = true
  name_regex  = "^64bit Amazon Linux 2023 v4.\d+\.\d+ running Node.js 20"
}

# -----------------------------------------------------------------------------
# IAM Roles and Instance Profiles
# These must be created in each region where EB environments are deployed.
# -----------------------------------------------------------------------------

# --- US West IAM Resources ---
resource "aws_iam_role" "eb_service_role_us_west" {
  provider = aws.us_west
  name     = "eb-service-role-us-west"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = { Service = "elasticbeanstalk.amazonaws.com" }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb_service_attach_us_west" {
  provider   = aws.us_west
  role       = aws_iam_role.eb_service_role_us_west.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSElasticBeanstalkManagedUpdatesCustomerRolePolicy"
}

resource "aws_iam_instance_profile" "eb_instance_profile_us_west" {
  provider = aws.us_west
  name     = "eb-instance-profile-us-west"
  role     = aws_iam_role.eb_service_role_us_west.name
}

# --- EU Central IAM Resources ---
resource "aws_iam_role" "eb_service_role_eu_central" {
  provider = aws.eu_central
  name     = "eb-service-role-eu-central"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = { Service = "elasticbeanstalk.amazonaws.com" }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb_service_attach_eu_central" {
  provider   = aws.eu_central
  role       = aws_iam_role.eb_service_role_eu_central.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSElasticBeanstalkManagedUpdatesCustomerRolePolicy"
}

resource "aws_iam_instance_profile" "eb_instance_profile_eu_central" {
  provider = aws.eu_central
  name     = "eb-instance-profile-eu-central"
  role     = aws_iam_role.eb_service_role_eu_central.name
}

# -----------------------------------------------------------------------------
# Elastic Beanstalk Applications
# One application definition per region.
# -----------------------------------------------------------------------------

resource "aws_elastic_beanstalk_application" "app_us_west" {
  provider    = aws.us_west
  name        = "multi-region-app"
  description = "Application deployed in US West"
}

resource "aws_elastic_beanstalk_application" "app_eu_central" {
  provider    = aws.eu_central
  name        = "multi-region-app"
  description = "Application deployed in EU Central"
}

# -----------------------------------------------------------------------------
# Elastic Beanstalk Application Versions (Placeholder)
# EB requires at least one version to create an environment.
# -----------------------------------------------------------------------------

resource "aws_elastic_beanstalk_application_version" "version_us_west" {
  provider        = aws.us_west
  name            = "v1.0.0"
  application     = aws_elastic_beanstalk_application.app_us_west.name
  description     = "Sample version for US West"
  bucket          = "elasticbeanstalk-us-west-2-123456789012" # Placeholder bucket name (EB usually creates one or requires S3)
  key             = "sample-app.zip"     # Placeholder key
  # In a real scenario, you would upload a zip file to S3 first.
  # For this example, we rely on the fact that the resource creates the entry, 
  # though deployment might fail without real code. 
  # To make this code fully runnable without external dependencies, 
  # we would typically comment out the bucket/key or use a data source. 
  # However, keeping the structure correct for the environment logic is the priority.

  # Workaround for valid TF syntax without actual file upload:
  # We will set the 'bucket' to the default Elastic Beanstalk bucket in that region (if it exists) 
  # or create an S3 bucket. For brevity, we assume the bucket string is valid or handled externally,
  # but we will include the block to show the relationship.

  # Note: Without a real zip file, the environment creation might hang/fail. 
  # This config represents the Infrastructure setup.
}

resource "aws_elastic_beanstalk_application_version" "version_eu_central" {
  provider        = aws.eu_central
  name            = "v1.0.0"
  application     = aws_elastic_beanstalk_application.app_eu_central.name
  description     = "Sample version for EU Central"
  bucket          = "elasticbeanstalk-eu-central-1-123456789012"
  key             = "sample-app.zip"
}

# -----------------------------------------------------------------------------
# Elastic Beanstalk Environments
# The core compute resources requested.
# -----------------------------------------------------------------------------

resource "aws_elastic_beanstalk_environment" "us_west_env" {
  provider                 = aws.us_west
  name                     = "us_west"
  application              = aws_elastic_beanstalk_application.app_us_west.name
  solution_stack_name      = data.aws_elastic_beanstalk_solution_stack.nodejs.name
  tier                     = "WebServer"

  # Setting specific instance type to ensure stability
  setting {
    namespace = "aws:elasticbeanstalk:environment:server"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  # Ensure we use the IAM roles created above
  service_role = aws_iam_role.eb_service_role_us_west.name

  # Link to application version (using default placeholder logic)
  # version_label = aws_elastic_beanstalk_application_version.version_us_west.name
  # Note: Removing explicit version_label dependency allows EB to use the default sample app 
  # if the bucket logic isn't fully set up, ensuring the Environment resource is created successfully.
}

resource "aws_elastic_beanstalk_environment" "eu_central_env" {
  provider                 = aws.eu_central
  name                     = "eu_central"
  application              = aws_elastic_beanstalk_application.app_eu_central.name
  solution_stack_name      = data.aws_elastic_beanstalk_solution_stack.nodejs.name
  tier                     = "WebServer"

  setting {
    namespace = "aws:elasticbeanstalk:environment:server"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  service_role = aws_iam_role.eb_service_role_eu_central.name
}

# -----------------------------------------------------------------------------
# Route 53 Configuration
# Latency-based routing records to direct traffic to the nearest region.
# -----------------------------------------------------------------------------

# Create a Hosted Zone (Example Domain)
resource "aws_route53_zone" "main" {
  name = "my-app-example.com"
}

# Latency Record for US West
resource "aws_route53_record" "us_west_latency" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www.my-app-example.com"
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.us_west_env.cname
    zone_id                = aws_elastic_beanstalk_environment.us_west_env.hosted_zone_id
    evaluate_target_health = true
  }

  set_identifier = "us-west-2"
  latency_routing_policy {
    region = "us-west-2"
  }
}

# Latency Record for EU Central
resource "aws_route53_record" "eu_central_latency" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www.my-app-example.com"
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.eu_central_env.cname
    zone_id                = aws_elastic_beanstalk_environment.eu_central_env.hosted_zone_id
    evaluate_target_health = true
  }

  set_identifier = "eu-central-1"
  latency_routing_policy {
    region = "eu-central-1"
  }
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"

      configuration_aliases = [ aws.default, aws.west, aws.europe ]
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1" # Default region
  alias  = "default"

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  region = "us-west-1"
  alias  = "west"

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  region = "eu-central-1"
  alias  = "europe"

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_iam_role" "eb_ec2_role" {
  provider = aws.default
  name = "elastic_beanstalk_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "ec2.amazonaws.com"
        },
      },
    ]
  })
}

# Attach the AWS managed policy for Elastic Beanstalk to the role
resource "aws_iam_role_policy_attachment" "eb_managed_policy" {
  provider = aws.default
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# Create an instance profile tied to the role
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  provider = aws.default
  name = "elastic_beanstalk_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

resource "aws_s3_bucket" "us_west_sample_bucket" {
  provider = aws.west
  bucket_prefix = "sample-"
}

resource "aws_s3_object" "us_west_examplebucket_object" {
  provider = aws.west
  key    = "app"
  bucket = aws_s3_bucket.us_west_sample_bucket.id
  source = "./supplement/app.zip"
}

# Elastic Beanstalk application
resource "aws_elastic_beanstalk_application" "us_west" {
  provider = aws.west
  name        = "my-global-app"
  description = "A global application deployed in US-West."
}

resource "aws_elastic_beanstalk_application_version" "us_west_version" {
  provider = aws.west
  name        = "v1"
  application = aws_elastic_beanstalk_application.us_west.name
  bucket = aws_s3_object.us_west_examplebucket_object.bucket
  key    = aws_s3_object.us_west_examplebucket_object.key
}

# US-West Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "us_west" {
  provider            = aws.west
  name                = "my-global-app-us-west"
  application         = aws_elastic_beanstalk_application.us_west.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

resource "aws_s3_bucket" "eu_sample_bucket" {
  provider = aws.europe
  bucket_prefix = "sample-"
}

resource "aws_s3_object" "eu_examplebucket_object" {
  provider = aws.europe
  key    = "app"
  bucket = aws_s3_bucket.eu_sample_bucket.id
  source = "./supplement/app.zip"
}

# Elastic Beanstalk Application (EU-Central Region)
resource "aws_elastic_beanstalk_application" "eu_central" {
  provider = aws.europe
  name        = "my-global-app"
  description = "A global application deployed in EU-Central."
}

resource "aws_elastic_beanstalk_application_version" "europe_version" {
  provider = aws.europe
  name        = "v1"
  application = aws_elastic_beanstalk_application.eu_central.name
  bucket = aws_s3_object.eu_examplebucket_object.bucket
  key    = aws_s3_object.eu_examplebucket_object.key
}

# EU-Central Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "eu_central" {
  provider            = aws.europe
  name                = "my-global-app-eu-central"
  application         = aws_elastic_beanstalk_application.eu_central.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# Route53 Hosted Zone for the domain
resource "aws_route53_zone" "main" {
  provider = aws.default
  name     = "myglobalapp.com"
}

# Geolocation Routing Policy Records for Route 53 to direct traffic based on location
resource "aws_route53_record" "us_west" {
  provider    = aws.default
  zone_id     = aws_route53_zone.main.zone_id
  name        = "west.myglobalapp.com"
  type        = "CNAME"
  ttl         = "60"
  set_identifier = "us-west"
  geolocation_routing_policy {
    continent = "NA"
  }
  records = [
    aws_elastic_beanstalk_environment.us_west.name
  ]
}

resource "aws_route53_record" "eu_central" {
  provider    = aws.default
  zone_id     = aws_route53_zone.main.zone_id
  name        = "central.myglobalapp.com"
  type        = "CNAME"
  ttl         = "60"
  set_identifier = "eu-central"
  geolocation_routing_policy {
    continent = "EU"
  }
  records = [
    aws_elastic_beanstalk_environment.eu_central.name
  ]
}

