  region = "us-east-1"
}

# 1. Generate a random password for the RDS instances
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "_!%^"
}

# 2. IAM Instance Profile
# Create the IAM Role and Instance Profile as requested
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb_ec2_attach" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# 3. Data Sources for Default VPC and Subnets
# Using default VPC networking for simplicity in this example
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# 4. Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "app" {
  name        = "multi-env-app"
  description = "Application for Production and Staging"
}

# 5. Security Groups
# We need explicit SGs for the EB environments so we can allow traffic from them to the RDS instances.

# Production Security Group
resource "aws_security_group" "prod_eb_sg" {
  name        = "prod-eb-sg"
  description = "Security group for Production EB instances"
  vpc_id      = data.aws_vpc.default.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "prod_rds_sg" {
  name        = "prod-rds-sg"
  description = "Security group for Production RDS"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.prod_eb_sg.id]
  }
}

# Staging Security Group
resource "aws_security_group" "staging_eb_sg" {
  name        = "staging-eb-sg"
  description = "Security group for Staging EB instances"
  vpc_id      = data.aws_vpc.default.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "staging_rds_sg" {
  name        = "staging-rds-sg"
  description = "Security group for Staging RDS"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.staging_eb_sg.id]
  }
}

# 6. RDS Instances
# Production DB
resource "aws_db_instance" "prod_db" {
  identifier             = "prod_db"
  allocated_storage      = 20
  storage_type           = "gp2"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  db_name                = "productiondb"
  username               = "admin"
  password               = random_password.db_password.result
  parameter_group_name   = "default.mysql8.0"
  skip_final_snapshot    = true
  vpc_security_group_ids = [aws_security_group.prod_rds_sg.id]
  db_subnet_group_name   = aws_db_subnet_group.default.name
}

# Staging DB
resource "aws_db_instance" "staging_db" {
  identifier             = "staging_db"
  allocated_storage      = 20
  storage_type           = "gp2"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  db_name                = "stagingdb"
  username               = "admin"
  password               = random_password.db_password.result
  parameter_group_name   = "default.mysql8.0"
  skip_final_snapshot    = true
  vpc_security_group_ids = [aws_security_group.staging_rds_sg.id]
  db_subnet_group_name   = aws_db_subnet_group.default.name
}

# DB Subnet Group (Shared for simplicity)
resource "aws_db_subnet_group" "default" {
  name       = "main-subnet-group"
  subnet_ids = data.aws_subnets.default.ids
}

# 7. Elastic Beanstalk Environments

# Production Environment
resource "aws_elastic_beanstalk_environment" "prod" {
  name                = "production-env"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.4 running Python 3.11"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "SecurityGroups"
    value     = aws_security_group.prod_eb_sg.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = data.aws_vpc.default.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = join(",", data.aws_subnets.default.ids)
  }

  # Pass DB connection details to the application via Environment Variables
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.prod_db.endpoint
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_NAME"
    value     = aws_db_instance.prod_db.db_name
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_USER"
    value     = aws_db_instance.prod_db.username
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_PASS"
    value     = random_password.db_password.result
  }
}

# Staging Environment
resource "aws_elastic_beanstalk_environment" "staging" {
  name                = "staging-env"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.4 running Python 3.11"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

