provider "aws" {
  region = "us-east-1" # Default region, can be overridden
}

# ---------------------------------------------------------
# Step 1: IAM Setup
# Create the specific Instance Profile requested: "ec2_eb_profile1"
# ---------------------------------------------------------

resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role_for_profile1"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the default AWS Elastic Beanstalk Web Tier policy
resource "aws_iam_role_policy_attachment" "eb_web_policy_attach" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# Attach the default AWS Elastic Beanstalk Worker Tier policy (often needed for logs/health)
resource "aws_iam_role_policy_attachment" "eb_worker_policy_attach" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWorkerTier"
}

resource "aws_iam_instance_profile" "ec2_eb_profile1" {
  name = "ec2_eb_profile1"
  role = aws_iam_role.eb_ec2_role.name
}

# ---------------------------------------------------------
# Step 2: Networking & Security
# ---------------------------------------------------------

data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# Security Group for the Database (RDS)
resource "aws_security_group" "rds_sg" {
  name        = "rds-sg-eb"
  description = "Allow traffic from Elastic Beanstalk"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.eb_instance_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-sg-eb"
  }
}

# Security Group for Elastic Beanstalk Instances
resource "aws_security_group" "eb_instance_sg" {
  name        = "eb-instance-sg"
  description = "Security group for Elastic Beanstalk instances"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "eb-instance-sg"
  }
}

# ---------------------------------------------------------
# Step 3: RDS Database Configuration
# Database Name: "my_db"
# ---------------------------------------------------------

# Generate a random password for the database
resource "random_password" "db_password" {
  length  = 16
  special = true
}

resource "aws_db_instance" "main" {
  identifier     = "my-db-instance"
  engine         = "mysql"
  engine_version = "8.0"
  instance_class = "db.t3.micro"

  allocated_storage     = 20
  storage_type          = "gp2"
  db_name               = "my_db" # Specific DB Name requested
  username              = "admin"
  password              = random_password.db_password.result
  publicly_accessible   = false
  skip_final_snapshot   = false # We want to manage snapshots manually or via backup
  final_snapshot_identifier = "my-db-final-snapshot"

  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  db_subnet_group_name   = aws_db_subnet_group.default.name

  tags = {
    Name = "my_db_rds"
  }
}

resource "aws_db_subnet_group" "default" {
  name       = "main-subnet-group"
  subnet_ids = data.aws_subnets.default.ids

  tags = {
    Name = "My DB Subnet Group"
  }
}

# ---------------------------------------------------------
# Step 4: Database Snapshot (Pre-deployment)
# ---------------------------------------------------------

resource "aws_db_snapshot" "pre_deployment_snapshot" {
  db_instance_identifier = aws_db_instance.main.identifier
  db_snapshot_identifier = "pre-deployment-snapshot-${timestamp()}"

  # Ensure the DB is fully created before taking the snapshot
  depends_on = [aws_db_instance.main]
}

# ---------------------------------------------------------
# Step 5: Elastic Beanstalk Application & Environments
# Blue-Green Infrastructure Setup
# ---------------------------------------------------------

resource "aws_elastic_beanstalk_application" "app" {
  name        = "my-blue-green-app"
  description = "Application for Blue-Green Deployment"
}

# Helper locals for Environment Settings
locals {
  eb_settings = [
    {
      name      = "VPCId"
      value     = data.aws_vpc.default.id
      namespace = "aws:ec2:vpc"
    },
    {
      name      = "Subnets"
      value     = join(",", data.aws_subnets.default.ids)
      namespace = "aws:ec2:vpc"
    },
    {
      name      = "SecurityGroups"
      value     = aws_security_group.eb_instance_sg.id
      namespace = "aws:autoscaling:launchconfiguration"
    },
    {
      name      = "InstanceProfile"
      value     = aws_iam_instance_profile.ec2_eb_profile1.name
      namespace = "aws:autoscaling:launchconfiguration"
    },
    {
      name      = "DBHost"
      value     = aws_db_instance.main.address
      namespace = "aws:elasticbeanstalk:application:environment"
    },
    {
      name      = "DBName"
      value     = "my_db"
      namespace = "aws:elasticbeanstalk:application:environment"
    },
    {
      name      = "DBUser"
      value     = aws_db_instance.main.username
      namespace = "aws:elasticbeanstalk:application:environment"
    },
    {
      name      = "DBPass"
      value     = random_password.db_password.result
      namespace = "aws:elasticbeanstalk:application:environment"
    }
  ]
}

# BLUE Environment
resource "aws_elastic_beanstalk_environment" "blue_env" {
  name                = "my-app-blue"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2 v5.9.2 running Python 3.9" # Example stack

  setting = local.eb_settings

  # Ensure we don't attempt to create until DB is ready
  depends_on = [aws_db_instance.main]
}

# GREEN Environment
# Initially identical to Blue, used for swapping traffic during deployment
resource "aws_elastic_beanstalk_environment" "green_env" {
  name                = "my-app-green"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2 v5.9.2 running Python 3.9" # Example stack

  setting = local.eb_settings

  # Ensure we don't attempt to create until DB is ready
  depends_on = [aws_db_instance.main]
}

# ---------------------------------------------------------
# Outputs
# ---------------------------------------------------------

output "blue_environment_url" {
  value = aws_elastic_beanstalk_environment.blue_env.cname
}

output "green_environment_url" {
  value = aws_elastic_beanstalk_environment.green_env.cname
}

output "rds_endpoint" {
  value = aws_db_instance.main.endpoint
}

output "snapshot_id" {
  value = aws_db_snapshot.pre_deployment_snapshot.id
}

