Here is the Terraform configuration to set up an AWS Elastic Beanstalk environment with Auto Scaling and an attached RDS database.

### Step-by-Step Explanation:

1.  **IAM Instance Profile (`eb_ec2_profile`)**: We create an IAM role and an instance profile named `eb_ec2_profile`. This is required for the Elastic Beanstalk EC2 instances to interact with other AWS services. We attach the `AWSElasticBeanstalkWebTier` managed policy to ensure it has necessary permissions.
2.  **RDS Database (`my_db1`)**: We provision a MySQL database instance identified as `my_db1`. We use a `random_password` resource to securely generate the password, avoiding hardcoding secrets.
3.  **Elastic Beanstalk Application**: A container for the environment.
4.  **Elastic Beanstalk Environment**: This is the core resource.
    *   **Auto Scaling**: We configure `aws:autoscaling:asg` settings to define min/max capacity (1 to 4) and `aws:autoscaling:trigger` settings to scale based on `CPUUtilization`.
    *   **Database Attachment**: We pass the RDS connection details (Endpoint, Username, Password, Database Name) to the application as Environment Variables. This allows the application code running on Beanstalk to connect to the `my_db1` database.

### Terraform Code:

```hcl
provider "aws" {
  region = "us-east-1"
}

# ----------------------------------------------------------------------------
# 1. IAM Resources
# ----------------------------------------------------------------------------
# Create the Instance Profile named "eb_ec2_profile" as requested
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb_attach" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# ----------------------------------------------------------------------------
# 2. RDS Database
# ----------------------------------------------------------------------------
# Generate a secure password for the database
resource "random_password" "db_password" {
  length  = 16
  special = true
}

resource "aws_db_instance" "my_db1" {
  identifier         = "my_db1"
  engine             = "mysql"
  engine_version     = "8.0"
  instance_class     = "db.t3.micro"
  allocated_storage  = 20
  storage_encrypted  = true
  username           = "adminuser"
  password           = random_password.db_password.result
  db_name            = "myappdb"
  skip_final_snapshot = true

  # Ensure DB is in a VPC (default VPC used here for simplicity)
  # In production, explicitly define subnet_group and security groups
}

# ----------------------------------------------------------------------------
# 3. Elastic Beanstalk Application
# ----------------------------------------------------------------------------
resource "aws_elastic_beanstalk_application" "my_app" {
  name        = "my-scaling-app"
  description = "Application with Auto Scaling and RDS"
}

# ----------------------------------------------------------------------------
# 4. Elastic Beanstalk Environment with Auto Scaling
# ----------------------------------------------------------------------------
resource "aws_elastic_beanstalk_environment" "my_env" {
  name                = "my-scaling-env"
  application         = aws_elastic_beanstalk_application.my_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.0 running Node.js 20"

  # Use the specific instance profile name requested
  instance_profile = aws_iam_instance_profile.eb_ec2_profile.name

  # Auto Scaling Configuration based on CPU
  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MinSize"
    value     = "1"
  }
  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MaxSize"
    value     = "4"
  }
  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "MeasureName"
    value     = "CPUUtilization"
  }
  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "Statistic"
    value     = "Average"
  }
  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "Unit"
    value     = "Percent"
  }
  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "UpperThreshold"
    value     = "75" # Scale up if CPU > 75%
  }
  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "LowerThreshold"
    value     = "20" # Scale down if CPU < 20%
  }
  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "BreachDuration"
    value     = "300" # 5 minutes
  }

  # Attach Database via Environment Variables
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.my_db1.endpoint
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_USER"
    value     = aws_db_instance.my_db1.username
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_PASS"
    value     = random_password.db_password.result
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_NAME"
    value     = aws_db_instance.my_db1.db_name
  }
}
```

