provider "aws" {
  region = "us-east-1"
}

# Step 1: Create the Reverse DNS Hosted Zone
# Since a PTR record maps an IP address to a domain name, the hosted zone
# name must correspond to the reverse IP mapping (in-addr.arpa).
# For this example, we assume the IP address is 192.0.2.5 (RFC 5737 TEST-NET-1).
# Therefore, the zone covers the /24 subnet: 2.0.192.in-addr.arpa.
resource "aws_route53_zone" "reverse_zone" {
  name = "2.0.192.in-addr.arpa"

  # If this is for a VPC (Private Reverse DNS), uncomment the vpc block below:
  # vpc {
  #   vpc_id = "vpc-xxxxxxxx"
  # }
}

# Step 2: Configure the PTR (Pointer) Record
# This record points the specific IP (last octet) to the hostname.
# For IP 192.0.2.5, the record name is "5".
resource "aws_route53_record" "ptr_record" {
  zone_id = aws_route53_zone.reverse_zone.zone_id
  name    = "5"
  type    = "PTR"
  ttl     = "300"
  records = ["host.example53.com"]
}

