    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Default region, can be overridden
}

# ---------------------------------------------------
# Variables
# ---------------------------------------------------

variable "domain_name" {
  description = "The domain name to host in Route 53"
  type        = string
  default     = "example.com"
}

variable "db_username" {
  description = "The master username for the RDS database"
  type        = string
  default     = "admin"
}

variable "db_password" {
  description = "The master password for the RDS database"
  type        = string
  sensitive   = true
}

# ---------------------------------------------------
# Data Sources
# ---------------------------------------------------

# Get the default VPC
data "aws_vpc" "default" {
  default = true
}

# Get the default subnets in the VPC
data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# Get the latest Elastic Beanstalk solution stack for Python (or Node.js/Java)
data "aws_elastic_beanstalk_solution_stack" "latest" {
  name_regex = "^64bit Amazon Linux 2 .* Tomcat .*"
  most_recent = true
}

# ---------------------------------------------------
# Security Groups
# ---------------------------------------------------

# Security Group for Elastic Beanstalk
resource "aws_security_group" "eb_sg" {
  name_prefix = "eb-security-group-"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Security Group for RDS
resource "aws_security_group" "rds_sg" {
  name_prefix = "rds-security-group-"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.eb_sg.id] # Allow traffic only from EB
  }
}

# ---------------------------------------------------
# RDS Database
# ---------------------------------------------------

resource "aws_db_subnet_group" "default" {
  name       = "main-db-subnet-group"
  subnet_ids = data.aws_subnets.default.ids

  tags = {
    Name = "My DB Subnet Group"
  }
}

resource "aws_db_instance" "default" {
  allocated_storage      = 20
  storage_type           = "gp2"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  db_name                = "myapp_db"
  username               = var.db_username
  password               = var.db_password
  parameter_group_name   = "default.mysql8.0"
  db_subnet_group_name   = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  skip_final_snapshot    = true
  publicly_accessible    = false # Best practice: DB should not be public

  tags = {
    Name = "myapp-db"
  }
}

# ---------------------------------------------------
# Elastic Beanstalk
# ---------------------------------------------------

resource "aws_elastic_beanstalk_application" "app" {
  name        = "my-application"
  description = "Application for myapp_db"
}

resource "aws_elastic_beanstalk_environment" "env" {
  name                = "myenv"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = data.aws_elastic_beanstalk_solution_stack.latest.name

  # VPC Configuration
  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = data.aws_vpc.default.id
  }
  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = join(",", data.aws_subnets.default.ids)
  }
  setting {
    namespace = "aws:ec2:vpc"
    name      = "AssociatePublicIpAddress"
    value     = "true"
  }

  # Instance Configuration
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = "eb_ec2_profile1" # Requested Instance Profile
  }
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "SecurityGroups"
    value     = aws_security_group.eb_sg.id
  }
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  # Environment Variables (Linking to RDS)
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.default.endpoint
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_NAME"
    value     = "myapp_db"
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_USER"
    value     = var.db_username
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_PASS"
    value     = var.db_password
  }
}

# ---------------------------------------------------
# Route 53
# ---------------------------------------------------

resource "aws_route53_zone" "main" {
  name = var.domain_name

  tags = {
    Environment = "Production"
  }
}

resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www.${var.domain_name}"
  type    = "CNAME"
  ttl     = "300"
  records = [aws_elastic_beanstalk_environment.env.cname]
}

# Output the Environment URL and DB Endpoint
output "eb_environment_url" {
  value = aws_elastic_beanstalk_environment.env.cname
}

output "rds_endpoint" {
  value = aws_db_instance.default.endpoint
}
