# ---------------------------------------------------------
# IAM Resources (Global)
# ---------------------------------------------------------

# IAM Role for Elastic Beanstalk EC2 Instances
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role_for_profile3"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach Managed Policy for Elastic Beanstalk Web Tier
resource "aws_iam_role_policy_attachment" "eb_web_tier" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# Instance Profile with the requested name
resource "aws_iam_instance_profile" "eb_ec2_profile3" {
  name = "eb_ec2_profile3"
  role = aws_iam_role.eb_ec2_role.name
}

# ---------------------------------------------------------
# Provider Configuration
# ---------------------------------------------------------

provider "aws" {
  region = "us-east-1"
  alias  = "us_east"
}

provider "aws" {
  region = "eu-west-1"
  alias  = "eu_west"
}

# ---------------------------------------------------------
# US-East-1 Resources
# ---------------------------------------------------------

# Get Default VPC
data "aws_vpc" "default_us_east" {
  provider = aws.us_east
  default  = true
}

# Get Default Subnets
data "aws_subnets" "default_us_east" {
  provider = aws.us_east
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default_us_east.id]
  }
}

# Security Group for RDS (Allow VPC CIDR for simplicity in this example)
resource "aws_security_group" "rds_sg_us_east" {
  provider    = aws.us_east
  name        = "rds_sg_us_east"
  description = "Allow MySQL access from within VPC"
  vpc_id      = data.aws_vpc.default_us_east.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = [data.aws_vpc.default_us_east.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "main_db_us_east" {
  provider   = aws.us_east
  name       = "main_db_us_east_subnet_group"
  subnet_ids = data.aws_subnets.default_us_east.ids

  tags = {
    Name = "My DB subnet group US East"
  }
}

# RDS Instance
resource "aws_db_instance" "main_db_us_east" {
  provider             = aws.us_east
  identifier           = "main-db-us-east"
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  db_name              = "mydbus"
  username             = "admin"
  password             = "ChangeMe123!" # In production, use a random_password resource or SSM
  parameter_group_name = "default.mysql8.0"
  skip_final_snapshot  = true
  db_subnet_group_name = aws_db_subnet_group.main_db_us_east.name
  vpc_security_group_ids = [aws_security_group.rds_sg_us_east.id]
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "myapp_us_east" {
  provider    = aws.us_east
  name        = "myapp_us_east"
  description = "Application in US East"
}

# Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "myenv_us_east" {
  provider    = aws.us_east
  name        = "myenv_us_east"
  application = aws_elastic_beanstalk_application.myapp_us_east.name

  solution_stack_name = "64bit Amazon Linux 2 v5.9.4 running Node.js 18"

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile3.name
  }

  # Pass DB connection details to the application
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_ENDPOINT"
    value     = aws_db_instance.main_db_us_east.endpoint
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_DB_NAME"
    value     = aws_db_instance.main_db_us_east.db_name
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_USERNAME"
    value     = aws_db_instance.main_db_us_east.username
  }
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_PASSWORD"
    value     = aws_db_instance.main_db_us_east.password
  }
}

# ---------------------------------------------------------
# EU-West-1 Resources
