# ---------------------------------------------------------
# Route 53 Resources (Global)
# ---------------------------------------------------------

# Route 53 Zone (example domain)
resource "aws_route53_zone" "primary" {
  name = "example-app.com"
}

# Record for US-East (Latency Based)
resource "aws_route53_record" "www_us_east" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "www.example-app.com"
  type    = "CNAME"
  ttl     = "300"

  set_identifier = "us-east-1"
  latency_routing_policy {
    region = "us-east-1"
  }

  records = [aws_elastic_beanstalk_environment.myenv_us_east.cname]
}

# Record for EU-West (Latency Based)
resource "aws_route53_record" "www_eu_west" {
  zone_id = aws_route53_zone.primary.zone_id
