# Public Subnets for EC2 Instances
resource "aws_subnet" "public_blue" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone       = "us-east-1a"

  tags = {
    Name = "public-subnet-blue"
  }
}

resource "aws_subnet" "public_green" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  map_public_ip_on_launch = true
  availability_zone       = "us-east-1b"

  tags = {
    Name = "public-subnet-green"
  }
}

# Private Subnets for RDS
resource "aws_subnet" "private_db_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.10.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "private-subnet-db-1"
  }
}

resource "aws_subnet" "private_db_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.11.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "private-subnet-db-2"
  }
}

resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }
}

resource "aws_route_table_association" "public_blue" {
  subnet_id      = aws_subnet.public_blue.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "public_green" {
  subnet_id      = aws_subnet.public_green.id
  route_table_id = aws_route_table.public.id
}

# -----------------------------------------------------------------------------
# 2. IAM Configuration
# -----------------------------------------------------------------------------

resource "aws_iam_role" "ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Explicitly naming the instance profile as requested
resource "aws_iam_instance_profile" "profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.ec2_role.name
}

# -----------------------------------------------------------------------------
# 3. Shared RDS Database
# -----------------------------------------------------------------------------

resource "aws_db_subnet_group" "main" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_subnet.private_db_1.id, aws_subnet.private_db_2.id]

  tags = {
    Name = "My DB subnet group"
  }
}

resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Allow access to RDS"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.ec2_sg.id] # Allow access from EC2 instances
  }
}

resource "random_password" "password" {
  length  = 16
  special = false
}

resource "aws_db_instance" "default" {
  allocated_storage      = 20
  storage_type           = "gp2"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  db_name                = "myapp_db"
  username               = "admin"
  password               = random_password.password.result
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  skip_final_snapshot    = true
  publicly_accessible    = false
}

# -----------------------------------------------------------------------------
# 4. Compute Resources (Blue & Green)
# -----------------------------------------------------------------------------

resource "aws_security_group" "ec2_sg" {
  name        = "ec2-security-group"
  description = "Allow web traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

resource "aws_instance" "blue" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.micro"
  subnet_id     = aws_subnet.public_blue.id
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]
  iam_instance_profile = aws_iam_instance_profile.profile.name

  user_data = <<-EOF
              #!/bin/bash
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Blue Environment</h1>" > /var/www/html/index.html
              EOF

  tags = {
    Name = "blue-environment"
  }
}

resource "aws_instance" "green" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.micro"
  subnet_id     = aws_subnet.public_green.id
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]
  iam_instance_profile = aws_iam_instance_profile.profile.name

  user_data = <<-EOF
              #!/bin/bash
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Green Environment</h1>" > /var/www/html/index.html
              EOF

  tags = {
    Name = "green-environment"
  }
}

# -----------------------------------------------------------------------------
# 5. Route 53 Configuration
# -----------------------------------------------------------------------------

resource "aws_route53_zone" "main" {
  name = "myapp.internal"
}

# Health Check for Blue
resource "aws_route53_health_check" "blue" {
  fqdn              = aws_instance.blue.public_ip
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  request_interval  = "30"
  failure_threshold = "3"
}

# Health Check for Green
resource "aws_route53_health_check" "green" {
  fqdn              = aws_instance.green.public_ip
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  request_interval  = "30"
  failure_threshold = "3"
}

# Primary Record (Blue)
resource "aws_route53_record" "blue" {
  zone_id = aws_route53_zone.main.id
  name    = "failover.myapp.internal"
  type    = "A"
  ttl     = "60"

  set_identifier = "blue"
  health_check_id = aws_route53_health_check.blue.id

  failover_routing_policy {
    type = "PRIMARY"
  }

  alias {
    name                   = aws_instance.blue.public_ip
    zone_id                = aws_route53_zone.main.id
    evaluate_target_health = true
  }
}

# Secondary Record (Green)
resource "aws_route53_record" "green" {
  zone_id = aws_route53_zone.main.id
  name    = "failover.myapp.internal"
  type    = "A"
  ttl     = "60"

  set_identifier = "green"
  health_check_id = aws_route53_health_check.green.id

  failover_routing_policy {
    type = "SECONDARY"
  }

  alias {
    name                   = aws_instance.green.public_ip
    zone_id                = aws_route53_zone.main.id
    evaluate_target_health = true
  }
}
```

