terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

# ---------------------------------------------------------
# Variables
# ---------------------------------------------------------

variable "aws_region" {
  description = "AWS region where resources will be created"
  type        = string
  default     = "us-east-1"
}

variable "app_name" {
  description = "The name of the Elastic Beanstalk Application"
  type        = string
  default     = "my-tf-app"
}

variable "env_name" {
  description = "The name of the Elastic Beanstalk Environment"
  type        = string
  default     = "my-tf-env"
}

variable "instance_type" {
  description = "Instance type for the EC2 instances"
  type        = string
  default     = "t2.micro"
}

variable "solution_stack_name" {
  description = "Elastic Beanstalk solution stack name (Platform)"
  type        = string
  # Note: Solution stack names are region-specific. This default is for Amazon Linux 2023 running Node.js 20.
  # Verify valid stacks for your region via AWS CLI: aws elasticbeanstalk list-available-solution-stacks
  default     = "64bit Amazon Linux 2023 v4.0.0 running Node.js 20"
}

variable "vpc_id" {
  description = "VPC ID where the environment will be deployed"
  type        = string
  default     = "" # Set to a specific VPC ID or leave empty to use default VPC logic
}

variable "subnet_ids" {
  description = "List of subnet IDs for the Elastic Beanstalk environment"
  type        = list(string)
  default     = [] # Set to specific Subnet IDs
}

# ---------------------------------------------------------
# IAM Roles
# ---------------------------------------------------------

# 1. IAM Role for EC2 Instances (Instance Profile)
resource "aws_iam_role" "eb_ec2_role" {
  name = "${var.app_name}-ec2-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach managed policy for Web Tier
resource "aws_iam_role_policy_attachment" "eb_ec2_attach" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# Create Instance Profile
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "${var.app_name}-instance-profile"
  role = aws_iam_role.eb_ec2_role.name
}

# 2. IAM Role for Elastic Beanstalk Service
resource "aws_iam_role" "eb_service_role" {
  name = "${var.app_name}-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        }
      }
    ]
  })
}

# Attach managed policy for Enhanced Health
resource "aws_iam_role_policy_attachment" "eb_service_attach" {
  role       = aws_iam_role.eb_service_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkEnhancedHealth"
}

# ---------------------------------------------------------
# Elastic Beanstalk Application
# ---------------------------------------------------------

resource "aws_elastic_beanstalk_application" "app" {
  name        = var.app_name
  description = "Terraform generated Elastic Beanstalk Application"
}

# ---------------------------------------------------------
# Elastic Beanstalk Environment
# ---------------------------------------------------------

resource "aws_elastic_beanstalk_environment" "env" {
  name                = var.env_name
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = var.solution_stack_name

  # Set a unique CNAME prefix to avoid collisions
  cname_prefix = "${var.app_name}-${var.env_name}"

  # Instance Profile and Service Role
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "ServiceRole"
    value     = aws_iam_role.eb_service_role.name
  }

  # Instance Type
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = var.instance_type
  }

  # VPC Configuration (Conditional logic to handle empty inputs)
  dynamic "setting" {
    for_each = length(var.subnet_ids) > 0 ? [1] : []
    content {
      namespace = "aws:ec2:vpc"
      name      = "VPCId"
      value     = var.vpc_id
    }
  }

  dynamic "setting" {
    for_each = length(var.subnet_ids) > 0 ? [1] : []
    content {
      namespace = "aws:ec2:vpc"
      name      = "Subnets"
      value     = join(",", var.subnet_ids)
    }
  }

  # Tags
  tags = {
    Terraform   = "true"
    Environment = var.env_name
  }
}

# ---------------------------------------------------------
# Outputs
# ---------------------------------------------------------

output "application_name" {
  description = "Name of the Elastic Beanstalk Application"
  value       = aws_elastic_beanstalk_application.app.name
}

output "environment_name" {
  description = "Name of the Elastic Beanstalk Environment"
  value       = aws_elastic_beanstalk_environment.env.name
}

output "endpoint_url" {
  description = "URL of the Elastic Beanstalk Environment"
  value       = aws_elastic_beanstalk_environment.env.endpoint_url
}

output "instance_profile_name" {
  description = "Name of the EC2 Instance Profile"
  value       = aws_iam_instance_profile.eb_ec2_profile.name
}

