# ------------------------------------------------------------------------------
# 1. IAM Service Role for Application Version Lifecycle
# The lifecycle policy needs permission to manage versions and S3 buckets.
# ------------------------------------------------------------------------------

resource "aws_iam_role" "eb_service_role" {
  name = "elastic_beanstalk_lifecycle_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the managed policy that provides necessary permissions for the service role
resource "aws_iam_role_policy_attachment" "eb_service_role_policy_attach" {
  role       = aws_iam_role.eb_service_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSElasticBeanstalkServiceRolePolicy"
}

# ------------------------------------------------------------------------------
# 2. Elastic Beanstalk Application with Lifecycle Config
# ------------------------------------------------------------------------------

resource "aws_elastic_beanstalk_application" "app" {
  name        = "my-secure-app"
  description = "My secure application with version lifecycle management"

  # Configuration for the Application Version Lifecycle
  appversion_lifecycle {
    # The IAM service role created above
    service_role = aws_iam_role.eb_service_role.arn

    # Delete the source bundle from S3 when the application version is deleted
    delete_source_from_s3 = true

    # Maximum number of application versions to retain
    max_count = 10

    # Maximum age (in days) of an application version to retain
    max_age_in_days = 30
  }
}

