terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ---------------------------------------------------------
# 1. IAM Role for CodeBuild
# ---------------------------------------------------------
resource "aws_iam_role" "codebuild_role" {
  name = "example-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the managed policy for CodeBuild access (Logs, S3, etc.)
resource "aws_iam_role_policy_attachment" "codebuild_policy_attach" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildDeveloperAccess"
}

# ---------------------------------------------------------
# 2. AWS CodeBuild Project
# ---------------------------------------------------------

# Variable for the GitHub OAuth Token (In production, use AWS Secrets Manager)
variable "github_token" {
  description = "GitHub Personal Access Token or OAuth Token"
  type        = string
  sensitive   = true
  default     = "placeholder-token" 
}

resource "aws_codebuild_project" "example_project" {
  name         = "example-codebuild-project"
  description  = "Example CodeBuild project with GitHub source and Cache"
  service_role = aws_iam_role.codebuild_role.arn

  # Artifacts Configuration
  artifacts {
    type = "NO_ARTIFACTS"
  }

  # Cache Configuration (Local Cache)
  cache {
    type  = "LOCAL"
    modes = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE"]
  }

  # Environment Configuration
  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:6.0" # Standard managed image
    type            = "LINUX_CONTAINER"
    privileged_mode = false

    # Environment Variables
    environment_variable {
      name  = "NODE_ENV"
      value = "production"
    }

    environment_variable {
      name  = "AWS_REGION"
      value = "us-east-1"
    }
  }

  # Source Configuration (GitHub)
  source {
    type            = "GITHUB"
    location        = "https://github.com/my-org/my-repo.git" # Replace with your repo
    git_clone_depth = 1
    buildspec       = "buildspec.yml"

    # GitHub Authentication (OAuth)
    auth {
      type     = "OAUTH"
      resource = var.github_token
    }
  }

  # Logs Configuration
  logs_config {
    cloudwatch_logs {
      group_name = "aws/codebuild/example-project"
      stream_name = "build-logs"
    }
  }

  # Optional: VPC Configuration if needed
  # vpc_config {
  #   vpc_id = aws_vpc.main.id
  #   subnets = aws_subnet.private[*].id
  #   security_group_ids = [aws_security_group.codebuild.id]
  # }
}

