  # Source Configuration: GitHub
  source {
    type            = "GITHUB"
    location        = "https://github.com/username/sample-repo.git"
    git_clone_depth = 1

    # Optional: Use if managing git submodules
    # git_submodules_config = { fetch_submodules = true }
  }

  # Build Artifacts Configuration: S3
  artifacts {
    type = "S3"
    location = aws_s3_bucket.codebuild_artifacts.id
    name     = "build-artifact"
    packaging = "ZIP"
    path     = "artifacts/"
  }

  # Cache Configuration: Local caching (Docker layers and source)
  cache {
    type  = "LOCAL"
    modes = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE"]
  }

  # Environment Configuration
  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    # Optional: Environment variables
    # environment_variable {
    #   name  = "EXAMPLE_VAR"
    #   value = "example-value"
    # }
  }

  # Logs Configuration
  logs_config {
    cloudwatch_logs {
      group_name  = "aws/codebuild"
      stream_name = "example-project"
    }

    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.codebuild_artifacts.id}/build-logs"
    }
  }
}
