      phases:
        build:
          commands:
            - echo "Hello from batch build"
    EOF
  }

  # Step 3: Define the Build Batch Configuration
  build_batch_config {
    timeout_in_mins = 180
    combine_artifacts = true

    # Define restrictions for the batch builds
    restrictions {
      maximum_builds_allowed = 100
      compute_types_allowed = ["BUILD_GENERAL1_SMALL"]
    }

    # Optional: Define how batch reports are generated
    batch_report_mode = "REPORT_AGGREGATED_BATCH"
  }
}

