terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_lex_intent" "order_flowers" {
  name = "OrderFlowers"
  description = "Intent to order a bouquet of flowers for pick up"

  sample_utterances = [
    "I would like to pick up flowers",
    "I would like to order some flowers",
  ]

  slot {
    name                     = "FlowerType"
    description              = "Type of flower to order"
    slot_constraint          = "Required" 
    slot_type                = "AMAZON.AlphaNumeric"
    priority                 = 1

    sample_utterances = ["I would like to get {FlowerType} flower."]

    value_elicitation_prompt {
      message {
        content             = "What type of flower would you like?"
        content_type        = "PlainText"
      }
      max_attempts         = 2
    }
  }

  slot {
    name                     = "PickupDate"
    description              = "Date of flower pickup"
    slot_constraint          = "Required" 
    slot_type                = "AMAZON.DATE"
    priority                 = 2

    value_elicitation_prompt {
      message {
        content             = "When would you like to pickup your flower?"
        content_type        = "PlainText"
      }
      max_attempts         = 2
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "Okay, your {FlowerType} will be ready for pickup on {PickupDate}.  Does this sound okay?"
      content_type = "PlainText"
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }

  rejection_statement {
    message {
      content      = "Okay, I will not place your order."
      content_type = "PlainText"
    }
  }
}

resource "aws_lex_bot" "order_flowers" {
  name     = "OrderFlowers"
  description = "Bot to order flowers on the behalf of a user"
  locale   = "en-US"
  process_behavior = "BUILD"
  voice_id = "Salli"
  child_directed = false
  create_version = false
  detect_sentiment            = false
  idle_session_ttl_in_seconds = 600

  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Sorry, I am not able to assist at this time"
    }
  }

  clarification_prompt {
    max_attempts = 2

    message {
      content_type = "PlainText"
      content      = "I didn't understand you, what would you like to do?"
    }
  }

  intent {
    intent_name    = aws_lex_intent.order_flowers.name
    intent_version = aws_lex_intent.order_flowers.version
  }
}

response:
To build an AWS Lex chatbot using Terraform, we need to create several components in a specific order. Lex V1 is used here for its relative simplicity in defining resources within a single Terraform configuration file compared to the newer V2 API, which requires significantly more complex dependency management.

**Step-by-Step Plan:**

1.  **IAM Role:** Create an IAM role that the Lex service will assume. This role needs permissions to write logs to CloudWatch and optionally invoke Lambda functions. We will attach the `AmazonLexBotPolicy` managed policy to grant the necessary permissions.
2.  **Lex Intent:** Define an intent. An intent represents what the user wants (e.g., a greeting). We will specify sample utterances (things a user might say) and a fulfillment action (how the bot responds).
3.  **Lex Bot:** Create the bot resource itself. This ties together the intents, defines the voice (optional), session timeouts, and interaction logic (like what to say if it doesn't understand).
4.  **Bot Alias:** Create an alias for the bot (e.g., `Production` or `Test`). This allows us to point our client applications to a specific version of the bot without changing the underlying code if we update the bot later.

Here is the complete Terraform configuration in HCL.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ---------------------------------------------------------
# 1. IAM Role for Lex Bot
# ---------------------------------------------------------
resource "aws_iam_role" "lex_bot_role" {
  name = "lex-chatbot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the AWS Managed Policy for Lex Bots (includes CloudWatch Logs permissions)
resource "aws_iam_role_policy_attachment" "lex_bot_attach" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonLexBotPolicy"
}

# ---------------------------------------------------------
# 2. Lex Intent (e.g., Greeting)
# ---------------------------------------------------------
resource "aws_lex_intent" "greeting_intent" {
  name = "Greeting"

  # Create a version ($LATEST) immediately
  create_version = true

  sample_utterances {
    utterance = "Hi"
  }

  sample_utterances {
    utterance = "Hello"
  }

  sample_utterances {
    utterance = "Good morning"
  }

  # What happens when the intent is successfully identified
  fulfillment_activity {
    type = "ReturnIntent"
  }
}

# ---------------------------------------------------------
# 3. Lex Bot
# ---------------------------------------------------------
resource "aws_lex_bot" "chatbot" {
  name           = "DemoChatbot"
  child_directed = false
  locale         = "en-US"

  # The IAM role created in Step 1
  iam_role_arn   = aws_iam_role.lex_bot_role.arn

  # Timeout for user inactivity
  idle_session_ttl_in_seconds = 300

  # The intent(s) linked to this bot
  intent {
    intent_name    = aws_lex_intent.greeting_intent.name
    intent_version = "$LATEST"
  }

  # Configuration for when the bot doesn't understand the user (Clarification)
  clarification_prompt {
    max_attempts = 2

    message {
      content      = "I'm sorry, I didn't understand that. Can you say 'Hi'?"
      content_type = "PlainText"
    }

    message {
      content      = "Can you please repeat?"
      content_type = "PlainText"
    }
  }

  # Configuration for when the conversation fails or is aborted
  abort_statement {
    message {
      content      = "Sorry, I am having trouble understanding you. Let's try again later."
      content_type = "PlainText"
    }
  }

  # Voice settings (Optional)
  voice_id = "Joanna"

  process_behavior = "BUILD"
}

# ---------------------------------------------------------
# 4. Lex Bot Alias
# ---------------------------------------------------------
resource "aws_lex_bot_alias" "chatbot_alias" {
  bot_name    = aws_lex_bot.chatbot.name
  bot_version = "$LATEST"
  name        = "ProductionAlias"
}

# ---------------------------------------------------------
# Outputs
# ---------------------------------------------------------
output "bot_name" {
  value = aws_lex_bot.chatbot.name
}

output "bot_alias_name" {
  value = aws_lex_bot_alias.chatbot_alias.name
}
```

