      {
        Effect = "Allow"
        Action = [
          "polly:SynthesizeSpeech",
          "comprehend:DetectSentiment",
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      }
    ]
  })
}

# ---------------------------------------------------------
# Lex V2 Bot Definition
# ---------------------------------------------------------
resource "aws_lexv2models_bot" "booking_bot" {
  name                        = "HotelBookingBot"
  role_arn                    = aws_iam_role.lex_bot_role.arn
  data_privacy {
    child_directed = false
  }
  idle_session_ttl_in_seconds = 300
  type                        = "Bot"

  # Using a dependency to ensure the bot is ready before creating intents
  depends_on = [aws_iam_role_policy.lex_bot_policy]
}

# ---------------------------------------------------------
# Custom Slot Type: Room Types
# ---------------------------------------------------------
resource "aws_lexv2models_slot_type" "room_type" {
  bot_id       = aws_lexv2models_bot.booking_bot.id
  bot_version  = "DRAFT"
  locale_id    = "en_US"
  name         = "RoomType"
  description  = "Types of rooms available for booking"

  value_selection_setting {
    resolution_strategy = "ORIGINAL_VALUE"
    regex_filter         = null
  }

  slot_type_values {
    sample_value {
      value = "King"
    }
    synonyms {
      value = "King Bed"
    }
  }

  slot_type_values {
    sample_value {
      value = "Queen"
    }
    synonyms {
      value = "Queen Bed"
    }
  }

  slot_type_values {
    sample_value {
      value = "Suite"
    }
  }
}

# ---------------------------------------------------------
# Intent: BookHotel
# ---------------------------------------------------------
resource "aws_lexv2models_intent" "book_hotel" {
  bot_id      = aws_lexv2models_bot.booking_bot.id
  bot_version = "DRAFT"
  locale_id   = "en_US"
  name        = "BookHotel"
  description = "Intent to book a hotel room"

  sample_utterances {
    utterance = "I want to book a hotel"
  }
  sample_utterances {
    utterance = "Book a room in {City}"
  }
  sample_utterances {
    utterance = "I need a {RoomType} for {Nights} nights"
  }

  # Slot 1: City (Built-in Type)
  slot {
    name           = "City"
    description    = "The city where the hotel is located"
    slot_type_id   = "AMAZON.City"
    value_elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        max_retries = 2
        message_groups {
          message {
            plain_text_message {
              value = "In which city would you like to book a hotel?"
            }
          }
        }
      }
    }
  }

  # Slot 2: Nights (Built-in Type)
  slot {
    name           = "Nights"
    description    = "Number of nights for the stay"
    slot_type_id   = "AMAZON.Number"
    value_elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        max_retries = 2
        message_groups {
          message {
            plain_text_message {
              value = "How many nights will you be staying?"
            }
          }
        }
      }
    }
  }

  # Slot 3: RoomType (Custom Type)
  slot {
    name           = "RoomType"
    description    = "Preference of room type"
    slot_type_id   = aws_lexv2models_slot_type.room_type.id
    value_elicitation_setting {
      slot_constraint = "Optional"
      prompt_specification {
        max_retries = 2
        message_groups {
          message {
            plain_text_message {
              value = "Do you have a preference for the room type (e.g., King, Queen, Suite)?"
            }
          }
        }
      }
    }
  }

  # Slot 4: Date (Built-in Type)
  slot {
    name           = "CheckInDate"
    description    = "Date to check in"
    slot_type_id   = "AMAZON.Date"
    value_elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        max_retries = 2
        message_groups {
          message {
            plain_text_message {
              value = "What date do you want to check in?"
            }
          }
        }
      }
    }
  }

  closing_setting {
    active = true
    response {
      message_groups {
        message {
          plain_text_message {
            value = "Alright, I have noted your request for a hotel in {City} for {Nights} nights on {CheckInDate}."
          }
        }
      }
    }
  }
}

# ---------------------------------------------------------
# Bot Version
# ---------------------------------------------------------
# We create a version to snapshot the DRAFT changes (Intent and Slots)
resource "aws_lexv2models_bot_version" "v1" {
  bot_id = aws_lexv2models_bot.booking_bot.id
  locale_specification {
    locale_id = "en_US"
    bot_version_locale_details {
      source_bot_version = "DRAFT"
    }
  }
  depends_on = [aws_lexv2models_intent.book_hotel]
}

# ---------------------------------------------------------
# Bot Alias
# ---------------------------------------------------------
resource "aws_lexv2models_bot_alias" "production" {
  bot_id           = aws_lexv2models_bot.booking_bot.id
  bot_alias_name   = "Production"
  bot_version      = aws_lexv2models_bot_version.v1.bot_version
  bot_alias_locale_settings {
    locale_id                    = "en_US"
    enabled                      = true
  }
}

