  policy_arn = "arn:aws:iam::aws:policy/AmazonLexBotPolicy"
}

# -----------------------------------------------------------------------------
# Lex V2 Slot Types
# -----------------------------------------------------------------------------
resource "aws_lexv2models_slot_type" "pizza_size" {
  name                 = "PizzaSize"
  description          = "The size of the pizza: Small, Medium, or Large"
  value_selection_setting {
    resolution_strategy = "ORIGINAL_VALUE"
  }
  slot_type_values {
    sample_value {
      value = "Small"
    }
    synonyms {
      value = "S"
    }
    synonyms {
      value = "Small"
    }
  }
  slot_type_values {
    sample_value {
      value = "Medium"
    }
    synonyms {
      value = "M"
    }
    synonyms {
      value = "Medium"
    }
  }
  slot_type_values {
    sample_value {
      value = "Large"
    }
    synonyms {
      value = "L"
    }
    synonyms {
      value = "Large"
    }
  }
}

resource "aws_lexv2models_slot_type" "pizza_type" {
  name                 = "PizzaType"
  description          = "The type of pizza ordered"
  value_selection_setting {
    resolution_strategy = "ORIGINAL_VALUE"
  }
  slot_type_values {
    sample_value {
      value = "Pepperoni"
    }
  }
  slot_type_values {
    sample_value {
      value = "Cheese"
    }
  }
  slot_type_values {
    sample_value {
      value = "Veggie"
    }
  }
}

# -----------------------------------------------------------------------------
# Lex V2 Intent (OrderPizza)
# -----------------------------------------------------------------------------
resource "aws_lexv2models_intent" "order_pizza" {
  name                 = "OrderPizza"
  description          = "Intent to order a pizza"
  sample_utterances {
    utterance = "I want to order a pizza"
  }
  sample_utterances {
    utterance = "Order pizza"
  }
  sample_utterances {
    utterance = "Get me a {Size} {Type} pizza"
  }

  # Slots definition
  slots {
    name           = "Size"
    description    = "Size of the pizza"
    slot_type_id   = aws_lexv2models_slot_type.pizza_size.id
    value_elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        message_group {
          message {
            plain_text_message {
              value = "What size pizza would you like? We have Small, Medium, or Large."
            }
          }
        }
        max_retries = 2
      }
    }
  }

  slots {
    name           = "Type"
    description    = "Type of the pizza"
    slot_type_id   = aws_lexv2models_slot_type.pizza_type.id
    value_elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        message_group {
          message {
            plain_text_message {
              value = "What type of pizza do you want? We have Pepperoni, Cheese, or Veggie."
            }
          }
        }
        max_retries = 2
      }
    }
  }

  # Subsequent Follow-up Prompt (Confirmation)
  confirmation_setting {
    prompt_specification {
      message_group {
        message {
          plain_text_message {
            # This acts as the follow-up summarizing the order
            value = "Just to confirm, you want a {Size} {Type} pizza. Should I place this order for you?"
          }
        }
      }
      max_retries = 1
    }
    declination_response {
      message_group {
        message {
          plain_text_message {
            value = "Okay, I have cancelled your pizza order."
          }
        }
      }
    }
  }

  closing_setting {
    active = true
    response {
      message_group {
        message {
          plain_text_message {
            value = "Great! Your {Size} {Type} pizza is on the way."
          }
        }
      }
    }
  }
}

# -----------------------------------------------------------------------------
# Lex V2 Bot
# -----------------------------------------------------------------------------
resource "aws_lexv2models_bot" "pizza_bot" {
  name                        = "PizzaOrderingBot"
  role_arn                    = aws_iam_role.lex_bot_role.arn
  data_privacy {
    child_directed = false
  }
  idle_session_ttl_in_seconds = 300
  type                        = "Bot"
}

# -----------------------------------------------------------------------------
# Lex V2 Bot Version (Assembles the Intent into the Bot)
# -----------------------------------------------------------------------------
resource "aws_lexv2models_bot_version" "pizza_bot_version" {
  bot_id = aws_lexv2models_bot.pizza_bot.id
  locale_specification = {
    "en_US" = {
      nlu_confidence_threshold = 0.40
    }
  }

  bot_version_locale_details {
    locale_id = "en_US"

    # Reference the Intent created earlier
    intent {
      intent_id = aws_lexv2models_intent.order_pizza.id
      intent_name = aws_lexv2models_intent.order_pizza.name
    }
  }
}

# -----------------------------------------------------------------------------
# Lex V2 Bot Alias
# -----------------------------------------------------------------------------
resource "aws_lexv2models_bot_alias" "pizza_bot_alias" {
  bot_id           = aws_lexv2models_bot.pizza_bot.id
  bot_alias_name   = "Production"
  bot_version      = aws_lexv2models_bot_version.pizza_bot_version.bot_version
  bot_alias_locale_settings {
    locale_id                    = "en_US"
    enabled                      = true
  }
}

# -----------------------------------------------------------------------------
# Outputs
# -----------------------------------------------------------------------------
output "bot_id" {
  value = aws_lexv2models_bot.pizza_bot.id
}

output "bot_alias_id" {
  value = aws_lexv2models_bot_alias.pizza_bot_alias.bot_alias_id
}
