# -----------------------------------------------------------------------------
# 5. Create Intent: OrderPizza
# -----------------------------------------------------------------------------
resource "aws_lexv2models_intent" "order_pizza" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = "DRAFT"
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "OrderPizza"

