  slot {
    name           = "PizzaSize"
    description     = "Size of the pizza"
    slot_type_id    = aws_lexv2models_slot_type.size.id
    value_elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        message_group {
          message {
            plain_text_message {
              value = "What size would you like? We have Small, Medium, or Large."
            }
          }
        }
        max_retries = 2
      }
    }
  }

  # Slot: Type (Custom)
  slot {
    name           = "PizzaType"
    description     = "Type of pizza toppings"
    slot_type_id    = aws_lexv2models_slot_type.type.id
    value_elicitation_setting {
      slot_constraint = "Required"
