provider "aws" {
  region = "us-east-1"
}

# First, we need to define an Intent that the Bot will use.
# A Bot needs at least one Intent configured.
resource "aws_lex_intent" "book_trip" {
  name        = "BookTrip"
  description = "Intent to book a trip for the user"

  sample_utterances = [
    "I want to book a trip",
    "Book a vacation",
    "I want to travel"
  ]

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

# The main Bot resource with every parameter populated
resource "aws_lex_bot" "trip_reservation" {
  name                         = "TripReservationBot"
  child_directed               = false
  locale                       = "en-US"
  description                  = "A conversational bot designed to assist users with booking trips, flights, and hotels."
  create_version               = true
  detect_sentiment             = true
  enable_model_improvements    = true
  idle_session_ttl_in_seconds  = 300
  nlu_confidence_threshold     = 0.80
  process_behavior             = "BUILD"
  timeout_in_seconds           = 300
  voice_id                     = "Joanna"

  tags = {
    Environment = "production"
    Project     = "TravelAutomation"
    ManagedBy   = "Terraform"
  }

  # Configuration for when the bot encounters an error or cannot understand
  abort_statement {
    message {
      content      = "I'm sorry, I encountered an error and could not complete your request. Please start over."
      content_type = "PlainText"
    }
  }

  # Configuration for when the user input is ambiguous
  clarification_prompt {
    max_attempts = 2

    message {
      content      = "I'm not sure I understood. Did you want to book a flight or a hotel?"
      content_type = "PlainText"
    }

    message {
      content      = "Can you please clarify if you are looking for a flight or a hotel reservation?"
      content_type = "PlainText"
    }
  }

  # Linking the Intent created above
