provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# 1. IAM Role for the Lex Bot
# ------------------------------------------------------------------------------
resource "aws_iam_role" "lex_bot_role" {
  name = "pizza_ordering_bot_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the standard AWS Lex Bot Policy to allow CloudWatch logging
resource "aws_iam_role_policy_attachment" "lex_bot_policy_attach" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonLexBotPolicy"
}

# ------------------------------------------------------------------------------
# 2. Custom Slot Types
# ------------------------------------------------------------------------------

resource "aws_lex_slot_type" "pizza_size" {
  name        = "PizzaSize"
  description = "Size of the pizza: Small, Medium, or Large"

  enumeration_value {
    value = "Small"
  }
  enumeration_value {
    value = "Medium"
  }
  enumeration_value {
    value = "Large"
  }
}

resource "aws_lex_slot_type" "pizza_crust" {
  name        = "PizzaCrust"
  description = "Type of crust for the pizza"

  enumeration_value {
    value = "Thin"
  }
  enumeration_value {
    value = "Thick"
  }
  enumeration_value {
    value = "Stuffed"
  }
}

resource "aws_lex_slot_type" "pizza_topping" {
  name        = "PizzaTopping"
  description = "Available toppings"

  enumeration_value {
    value = "Pepperoni"
  }
  enumeration_value {
    value = "Mushrooms"
  }
  enumeration_value {
    value = "Onions"
  }
  enumeration_value {
    value = "Sausage"
  }
  enumeration_value {
    value = "Extra Cheese"
  }
}

# ------------------------------------------------------------------------------
# 3. Intents
# ------------------------------------------------------------------------------

# Intent 1: OrderPizza
resource "aws_lex_intent" "order_pizza" {
  name        = "OrderPizza"
  description = "Intent to order a pizza"

  sample_utterances = [
    "I want to order a pizza",
    "Order a {Size} pizza",
    "Get me a {Crust} crust pizza",
    "I want a {Size} {Crust} pizza with {Toppings}"
  ]

  slot {
    name         = "Size"
    slot_type    = aws_lex_slot_type.pizza_size.name
    priority     = 1
    value_elicitation_prompt {
      message {
        content_type = "PlainText"
        content      = "What size would you like? Small, Medium, or Large?"
      }
      max_attempts = 2
    }
  }

  slot {
    name         = "Crust"
    slot_type    = aws_lex_slot_type.pizza_crust.name
    priority     = 2
    value_elicitation_prompt {
      message {
        content_type = "PlainText"
        content      = "What crust do you prefer? Thin, Thick, or Stuffed?"
      }
      max_attempts = 2
    }
  }

  slot {
    name         = "Toppings"
    slot_type    = aws_lex_slot_type.pizza_topping.name
    priority     = 3
    value_elicitation_prompt {
      message {
        content_type = "PlainText"
        content      = "What toppings would you like to add?"
      }
      max_attempts = 2
    }
  }

  conclusion {
    statement {
      message {
        content_type = "PlainText"
        content      = "Got it. I have ordered a {Size} {Crust} crust pizza with {Toppings}."
      }
    }
  }
}

# Intent 2: GetMenu
resource "aws_lex_intent" "get_menu" {
  name        = "GetMenu"
  description = "Intent to see the menu"

  sample_utterances = [
    "What's on the menu",
    "Show me the menu",
    "What do you have",
    "What pizzas do you sell"
  ]

  conclusion {
    statement {
      message {
        content_type = "PlainText"
        content      = "We offer Small, Medium, and Large pizzas. You can choose from Thin, Thick, or Stuffed crusts with toppings like Pepperoni, Mushrooms, Onions, Sausage, and Extra Cheese."
      }
    }
  }
}

# Intent 3: GetOrderStatus
resource "aws_lex_intent" "get_order_status" {
  name        = "GetOrderStatus"
  description = "Intent to check the status of an existing order"

  sample_utterances = [
    "Where is my order",
    "Order status",
    "Check my order",
    "Has my pizza arrived"
  ]

  conclusion {
    statement {
      message {
        content_type = "PlainText"
        content      = "Your pizza is currently being prepared and will be ready in 20 minutes."
      }
    }
  }
}

# Intent 4: CancelOrder
resource "aws_lex_intent" "cancel_order" {
  name        = "CancelOrder"
  description = "Intent to cancel the current order"

  sample_utterances = [
    "Cancel my order",
    "I don't want the pizza anymore",
    "Stop the order",
    "Nevermind"
  ]

  conclusion {
    statement {
      message {
        content_type = "PlainText"
        content      = "I have cancelled your order."
      }
    }
  }
}

# Intent 5: Greeting
resource "aws_lex_intent" "greeting" {
  name        = "Greeting"
  description = "Intent to greet the user"

  sample_utterances = [
    "Hi",
    "Hello",
    "Hey",
    "Good morning",
    "Good evening"
  ]

  conclusion {
    statement {
      message {
        content_type = "PlainText"
        content      = "Hello! Welcome to the Pizza Ordering Bot. You can say 'Order a pizza' to get started."
      }
    }
  }
}

# ------------------------------------------------------------------------------
# 4. Bot Configuration
# ------------------------------------------------------------------------------
resource "aws_lex_bot" "pizza_bot" {
  name           = "PizzaOrderingBot"
  child_directed = false
  locale         = "en-US"
  voice_id       = "Salli" # Amazon Kendra voice
  process_behavior = "BUILD"

  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Sorry, I could not understand your request."
    }
  }

  clarification_prompt {
    max_attempts = 2
    message {
      content_type = "PlainText"
      content      = "I didn't understand you. Would you like to order a pizza, check the menu, or check your order status?"
    }
  }

  intent {
    intent_name    = aws_lex_intent.greeting.name
    intent_version = "$LATEST"
  }

  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = "$LATEST"
  }

  intent {
    intent_name    = aws_lex_intent.get_menu.name
    intent_version = "$LATEST"
  }

  intent {
    intent_name    = aws_lex_intent.get_order_status.name
    intent_version = "$LATEST"
  }

  intent {
    intent_name    = aws_lex_intent.cancel_order.name
    intent_version = "$LATEST"
  }

  timeout_in_seconds = 300

  depends_on = [
    aws_iam_role_policy_attachment.lex_bot_policy_attach
  ]
}

