    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic policy for CloudWatch Logs (optional but recommended)
resource "aws_iam_role_policy_attachment" "lex_logs" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/CloudWatchLogsFullAccess"
}

# ---------------------------------------------------------
# 2. Bot Definition
# ---------------------------------------------------------
resource "aws_lexv2models_bot" "kids_pizza_bot" {
  name                        = "KidsPizzaOrderBot"
  role_arn                    = aws_iam_role.lex_bot_role.arn
  data_privacy {
    child_directed = true # Requirement: Designed for children
  }
  idle_session_ttl_in_seconds = 300
  type                        = "Bot"
  test_bot_alias_tags = {
    Purpose = "ChildrensPizzaOrdering"
  }
}

# ---------------------------------------------------------
# 3. Custom Slot Types
# ---------------------------------------------------------

# Slot Type: Pizza Size
resource "aws_lexv2models_slot_type" "pizza_size" {
  bot_id      = aws_lexv2models_bot.kids_pizza_bot.id
  bot_version = "DRAFT"
  locale_id   = "en_US"
  name        = "PizzaSize"

  slot_type_values {
    sample_value {
      value = "Small"
    }
    synonyms {
      value = "Little"
    }
  }
  slot_type_values {
    sample_value {
      value = "Medium"
    }
  }
  slot_type_values {
    sample_value {
      value = "Large"
    }
    synonyms {
      value = "Huge"
    }
  }
}

# Slot Type: Pizza Toppings
resource "aws_lexv2models_slot_type" "pizza_topping" {
  bot_id      = aws_lexv2models_bot.kids_pizza_bot.id
  bot_version = "DRAFT"
  locale_id   = "en_US"
  name        = "PizzaTopping"

  slot_type_values {
    sample_value {
      value = "Cheese"
    }
  }
  slot_type_values {
    sample_value {
      value = "Pepperoni"
    }
  }
  slot_type_values {
    sample_value {
      value = "Sausage"
    }
  }
  slot_type_values {
    sample_value {
      value = "Veggie"
    }
  }
}

# ---------------------------------------------------------
# 4. Intent: OrderPizza
# ---------------------------------------------------------
resource "aws_lexv2models_intent" "order_pizza" {
  bot_id      = aws_lexv2models_bot.kids_pizza_bot.id
  bot_version = "DRAFT"
  name        = "OrderPizza"

  sample_utterances {
    utterance = "I want to order a pizza"
  }
  sample_utterances {
    utterance = "I want a {Size} pizza"
  }
  sample_utterances {
    utterance = "Can I have a {Topping} pizza"
  }
  sample_utterances {
    utterance "Order pizza"
  }

  # Slot: Size
  slots {
    name           = "Size"
    slot_type_id   = aws_lexv2models_slot_type.pizza_size.slot_type_id
    value_elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        message_group {
          message {
            plain_text_message {
              value = "What size pizza do you want? Small, medium, or large?"
            }
          }
        }
        max_retries = 2
        allow_interrupt = true
      }
    }
  }

  # Slot: Topping
  slots {
    name           = "Topping"
    slot_type_id   = aws_lexv2models_slot_type.pizza_topping.slot_type_id
    value_elicitation_setting {
      slot_constraint = "Required"
      prompt_specification {
        message_group {
          message {
            plain_text_message {
              value = "What topping do you like? We have Cheese, Pepperoni, Sausage, or Veggie."
            }
          }
        }
        max_retries = 2
        allow_interrupt = true
      }
    }
  }

  # Closing Response
  closing_setting {
    active = true
    response_specification {
      message_group {
        message {
          plain_text_message {
            value = "Yay! I ordered a {Size} {Topping} pizza for you. It will be there soon!"
          }
        }
      }
      allow_interrupt = true
    }
  }
}

# ---------------------------------------------------------
# 5. Locale Definition
# ---------------------------------------------------------
resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                   = aws_lexv2models_bot.kids_pizza_bot.id
  bot_version              = "DRAFT"
  locale_id                = "en_US"
  nlu_confidence_threshold = 0.40
}

# ---------------------------------------------------------
# 6. Version and Alias
# ---------------------------------------------------------

# Create a version of the bot based on the Draft configuration
resource "aws_lexv2models_bot_version" "v1" {
  bot_id = aws_lexv2models_bot.kids_pizza_bot.id
  locale_specification = {
    en_US = {
      source_bot_version = "DRAFT"
    }
  }
}

# Create an alias to point to the version (e.g., 'Production')
resource "aws_lexv2models_bot_alias" "production" {
  bot_id           = aws_lexv2models_bot.kids_pizza_bot.id
  bot_alias_name   = "Production"
  bot_version      = aws_lexv2models_bot_version.v1.bot_version
  bot_alias_locale_settings {
    locale_id                    = "en_US"
    enabled                      = true
  }
}

