}

# 3. The Lambda Function for processing the order
resource "aws_lambda_function" "pizza_order_function" {
  function_name = "PizzaOrderHandler"
  role          = aws_iam_role.lambda_execution_role.arn
  handler       = "index.handler"
  runtime       = "python3.9"

  filename      = "pizza_order.zip"
  source_code_hash = filebase64sha256("pizza_order.zip")

  environment {
    variables = {
      Pizza_Shop_Name = "Terraform Pizzeria"
    }
  }
}

# 4. Permission for Lex V1 to invoke the Lambda function
resource "aws_lambda_permission" "allow_lex" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.pizza_order_function.function_name
  principal     = "lex.amazonaws.com"
  source_arn    = aws_lex_bot.pizza_bot.arn
}

# 5. Custom Slot Type for Pizza Types
resource "aws_lex_slot_type" "pizza_type" {
  name        = "PizzaType"
  description = "Types of pizza available"
  value_selection_strategy = "ORIGINAL_VALUE"

  enumeration_value {
    value = "Pepperoni"
  }
  enumeration_value {
    value = "Cheese"
  }
  enumeration_value {
    value = "Veggie"
  }
  enumeration_value {
    value = "Meat Lovers"
  }
}

# 6. The Lex Bot (V1)
# Note: aws_lex_bot refers to the legacy Lex V1 service.
resource "aws_lex_bot" "pizza_bot" {
  name           = "PizzaOrderBot"
  child_directed = false
  locale         = "en-US"
  process_behavior = "BUILD"

  voice_id       = "Salli" # Amazon Polly voice

  abort_statement {
    message {
      content      = "Sorry, I couldn't understand your order."
      content_type = "PlainText"
    }
  }

  clarification_prompt {
    max_attempts = 2
    message {
      content      = "I didn't catch that. What pizza would you like to order?"
      content_type = "PlainText"
    }
  }

  intent {
    name            = "OrderPizza"
    description     = "Order a pizza"
    fulfillment_activity {
      type = "CodeHook"
      code_hook {
        message_version = "1.0"
        uri             = aws_lambda_function.pizza_order_function.arn
      }
    }

    sample_utterances = [
      "I want a {PizzaType} pizza",
      "Order a {PizzaType}",
      "Get me a {PizzaType} pizza"
    ]

    slot {
      name             = "PizzaType"
      description      = "The type of pizza to order"
      priority         = 1
      slot_constraint  = "Required"
      slot_type        = aws_lex_slot_type.pizza_type.name

      value_elicitation_prompt {
        max_attempts = 2
        message {
          content      = "What type of pizza would you like? We have Pepperoni, Cheese, Veggie, or Meat Lovers."
          content_type = "PlainText"
        }
      }
    }

    conclusion_statement {
      message {
        content      = "Your order for a {PizzaType} pizza has been placed!"
        content_type = "PlainText"
      }
    }
  }

  timeout_in_seconds = 300
}

# Output the Bot Name
output "bot_name" {
  value = aws_lex_bot.pizza_bot.name
}

