# 1. Create the IAM Role required by the Lex Bot
# This role allows the bot to write logs to CloudWatch and perform necessary actions.
resource "aws_iam_role" "lex_kids_bot_role" {
  name = "lex_kids_bot_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the standard AmazonLexBotPolicy to the role
resource "aws_iam_role_policy_attachment" "lex_bot_policy_attach" {
  role       = aws_iam_role.lex_kids_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexBotPolicy"
}

# 2. Create the AWS Lex V2 Bot
resource "aws_lexv2models_bot" "kids_companion_bot" {
  name                        = "KidsCompanionBot"
  role_arn                    = aws_iam_role.lex_kids_bot_role.arn
  data_privacy {
    # Set to true to indicate the bot is intended for children (COPPA compliance)
    child_directed = true
  }
  idle_session_ttl_in_seconds = 600 # 10 minutes (generous for kids)
  type                        = "Bot"

  # Define tags for the resource
  tags = {
    Project     = "KidsAI"
    Environment = "Development"
  }

  # Configure the Test Bot Alias settings directly within the bot creation
  # This sets up the initial voice and locale behavior
  test_bot_alias_settings {
    bot_alias_locale_settings {
      bot_alias_locale_setting_id = "test_locale_1"
      enabled                    = true
      locale_id                  = "en_US"

      locale_settings {
        enabled = true

        # Use Neural engine for a high-quality, natural voice suitable for children
        voice_settings {
          voice_id = "Joanna" # Joanna is a friendly, neutral American voice
          engine   = "neural"
        }
      }
    }
  }

  # Lifecycle precaution:
  # Once a bot is marked as child_directed, it cannot be deleted immediately.
  # Terraform state management might require manual intervention if trying to destroy/recreate rapidly.
}

