Here is the Terraform configuration to create a Kinesis Data Stream and a Kinesis Data Analytics application that uses that stream as input.

```hcl
provider "aws" {
  region = "us-east-1"
}

# 1. Create the Kinesis Data Stream to act as the input source
resource "aws_kinesis_stream" "input_stream" {
  name             = "example-input-stream"
  shard_count      = 1
  retention_period = 24

  tags = {
    Environment = "test"
  }
}

# 2. Create an IAM Role for the Kinesis Analytics application
# This role allows the application to read from the Kinesis Stream
resource "aws_iam_role" "analytics_role" {
  name = "kinesis-analytics-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# 3. Attach a policy to the role granting read access to the specific stream
resource "aws_iam_role_policy" "analytics_policy" {
  name = "analytics-stream-policy"
  role = aws_iam_role.analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:ListShards"
        ]
        Resource = aws_kinesis_stream.input_stream.arn
      },
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStreamSummary"
        ]
        Resource = "*"
      }
    ]
  })
}

# 4. Create the Kinesis Data Analytics Application
resource "aws_kinesis_analytics_application" "app" {
  name = "example-analytics-application"

  # Define the input configuration
  inputs {
    name = "input_stream"

    # Reference the Kinesis Data Stream created in step 1
    kinesis_stream {
      resource_arn = aws_kinesis_stream.input_stream.arn
      role_arn     = aws_iam_role.analytics_role.arn
    }

    # Define the schema for the incoming data
    # Kinesis Analytics requires a schema to discover the columns in the stream
    schema {
      record_columns {
        name     = "data"
        sql_type = "VARCHAR(256)"
        mapping  = "$.data"
      }
      record_format {
        record_format_type = "JSON"
      }
      record_encoding = "UTF-8"
    }
  }
}
