extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# 1. IAM Role for Kinesis Data Analytics
# ------------------------------------------------------------------------------
resource "aws_iam_role" "kinesis_analytics_v2_role" {
  name = "kinesis-analytics-flink-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# Attach a policy that allows reading from Kinesis and writing to CloudWatch
resource "aws_iam_role_policy_attachment" "kinesis_analytics_attach" {
  role       = aws_iam_role.kinesis_analytics_v2_role.name
  # Note: For production, scope this down to specific resources.
  policy_arn = "arn:aws:iam::aws:policy/AmazonKinesisAnalyticsFullAccess"
}

# Explicit permission to write logs to the specific CloudWatch Log Group
resource "aws_iam_role_policy" "kinesis_logging_policy" {
  name = "kinesis-analytics-logging-policy"
  role = aws_iam_role.kinesis_analytics_v2_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "${aws_cloudwatch_log_group.app_logs.arn}:*"
      }
    ]
  })
}

# ------------------------------------------------------------------------------
# 2. CloudWatch Log Resources
# ------------------------------------------------------------------------------
resource "aws_cloudwatch_log_group" "app_logs" {
  name              = "/aws/kinesis-analytics/MyFlinkApp"
  retention_in_days = 7
}

resource "aws_cloudwatch_log_stream" "app_logs_stream" {
  name           = "kinesis-analytics-log-stream"
  log_group_name = aws_cloudwatch_log_group.app_logs.name
}

# ------------------------------------------------------------------------------
# 3. Kinesis Data Analytics V2 Application (Flink)
# ------------------------------------------------------------------------------
resource "aws_kinesisanalyticsv2_application" "flink_app" {
  name                   = "my-flink-application"
  description            = "Apache Flink application for data processing"
  runtime_environment    = "FLINK-1_15"
  service_execution_role = aws_iam_role.kinesis_analytics_v2_role.arn

  application_configuration {
    # Configuration for the Application Code (JAR file stored in S3)
    application_code_configuration {
      code_content {
        # Replace with your actual S3 bucket and JAR file key
        s3_content_location {
          bucket_arn = "arn:aws:s3:::my-flink-code-bucket"
          file_key   = "my-flink-app.jar"
        }
      }
      code_content_type = "ZIPFILE"
    }

    # Flink-specific operational settings
    flink_application_configuration {
      checkpoint_configuration {
        configuration_type = "DEFAULT"
      }

      monitoring_configuration {
        configuration_type = "DEFAULT"
        log_level          = "INFO"
        metrics_level      = "APPLICATION"
      }

      parallelism_configuration {
        configuration_type = "CUSTOM"
        parallelism        = 2
      }
    }

    # Environment properties passed to the Flink app
    environment_properties {
      property_groups {
        property_group_id = "FlinkApplicationProperties"
        properties = {
          "InputStreamName"   = "ExampleInputStream"
          "OutputStreamName"  = "ExampleOutputStream"
        }
      }
    }
  }

  # Link the CloudWatch logging options
  cloudwatch_logging_options {
    log_stream_arn = aws_cloudwatch_log_stream.app_logs_stream.arn
  }
}

