terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# 1. Create the S3 Bucket to act as the destination
resource "aws_s3_bucket" "destination" {
  bucket = "my-firehose-extended-s3-bucket"
}

# 2. Create the IAM Role that Kinesis Firehose assumes to write to S3
resource "aws_iam_role" "firehose_role" {
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# 3. Attach a policy to the role granting S3 permissions
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_s3_access"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.destination.arn,
          "${aws_s3_bucket.destination.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "kms:Decrypt",
          "kms:GenerateDataKey"
        ]
        Resource = "*" # Specific key ARN recommended for production
      }
    ]
  })
}

# 4. Create the Kinesis Data Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "example_stream" {
  name        = "extended-s3-dynamic-partitioning-stream"
  destination = "extended_s3"

  # Configuration for the Extended S3 destination
  extended_s3_config {
    role_arn           = aws_iam_role.firehose_role.arn
    bucket_arn         = aws_s3_bucket.destination.arn

    # Optional: Buffering hints
    buffer_size         = 5
    buffer_interval     = 300

    # Optional: Prefix configuration using dynamic partitioning syntax
    prefix             = "data/"
    error_output_prefix = "errors/"

    # Dynamic Partitioning Configuration
    dynamic_partitioning {
      enabled         = true
      retry_duration  = 300
    }
  }

  # Server-side encryption configuration (Optional but standard)
  server_side_encryption {
    enabled = false
  }
}

