provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# 1. Networking Setup (VPC, Subnet, Security Group)
# -----------------------------------------------------------------------------

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "firehose-redshift-vpc"
  }
}

resource "aws_subnet" "main" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = false

  tags = {
    Name = "firehose-redshift-subnet"
  }
}

# Security Group to allow Redshift traffic (Port 5439)
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow inbound Redshift traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # In production, restrict to Firehose VPC endpoints or specific IPs
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# -----------------------------------------------------------------------------
# 2. IAM Roles for Kinesis Firehose
# -----------------------------------------------------------------------------

resource "aws_iam_role" "firehose_role" {
  name = "firehose-redshift-delivery-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# Policy allowing Firehose to access S3, Redshift, and Secrets Manager
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-redshift-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.bucket.arn,
          "${aws_s3_bucket.bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "redshift:DescribeClusters",
          "redshift:GetClusterCredentials"
        ]
        Resource = "*" # Restrict to specific ARN in production
      },
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue"
        ]
        Resource = aws_secretsmanager_secret.redshift_secret.arn
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "kms:Decrypt" # Required if S3 bucket is encrypted
        ]
        Resource = "*" # Restrict to specific KMS key in production
      }
    ]
  })
}

# -----------------------------------------------------------------------------
# 3. S3 Bucket (Required for Firehose buffering & backup)
# -----------------------------------------------------------------------------

resource "aws_s3_bucket" "bucket" {
  bucket = "my-firehose-redshift-backup-bucket-unique-id"
}

resource "aws_s3_bucket_ownership_controls" "bucket_ownership" {
  bucket = aws_s3_bucket.bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.bucket_ownership]
  bucket     = aws_s3_bucket.bucket.id
  acl        = "private"
}

# -----------------------------------------------------------------------------
# 4. AWS Secrets Manager (Storing Redshift Credentials)
# -----------------------------------------------------------------------------

resource "aws_secretsmanager_secret" "redshift_secret" {
  name = "redshift/firehose/credentials"
}

resource "aws_secretsmanager_secret_version" "redshift_secret_version" {
  secret_id = aws_secretsmanager_secret.redshift_secret.id
  secret_string = jsonencode({
    username = var.redshift_username
    password = var.redshift_password
  })
}

# -----------------------------------------------------------------------------
# 5. Amazon Redshift Cluster
# -----------------------------------------------------------------------------

resource "aws_redshift_cluster" "main" {
  cluster_identifier  = "firehose-target-cluster"
  database_name       = "firehose_db"
  master_username     = var.redshift_username
  master_password     = var.redshift_password
  node_type           = "dc2.large"
  cluster_type        = "single-node"
  skip_final_snapshot = true

  # Networking
  cluster_subnet_group_name = aws_redshift_subnet_group.main.name
  vpc_security_group_ids    = [aws_security_group.redshift_sg.id]

  # IAM roles for the cluster (optional, but good practice for loading data from S3)
  iam_roles = [aws_iam_role.firehose_role.arn]
}

resource "aws_redshift_subnet_group" "main" {
  name       = "firehose-redshift-subnet-group"
  subnet_ids = [aws_subnet.main.id]

  tags = {
    Name = "Firehose Redshift Subnet Group"
  }
}

# -----------------------------------------------------------------------------
# 6. Kinesis Data Firehose Delivery Stream
# -----------------------------------------------------------------------------

resource "aws_kinesis_firehose_delivery_stream" "extended_s3_stream" {
  name        = "firehose-to-redshift-stream"
  destination = "redshift"

  # Configuration specific to Redshift destination
  redshift_configuration {
    cluster_jdbcurl = "jdbc:redshift://${aws_redshift_cluster.main.endpoint}:${aws_redshift_cluster.main.port}/${aws_redshift_cluster.main.database_name}"
    username        = var.redshift_username
    password        = var.redshift_password
    role_arn        = aws_iam_role.firehose_role.arn

    # S3 configuration is required for intermediate staging before Redshift COPY
    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.bucket.arn
      buffer_size        = 5
      buffer_interval    = 300
      compression_format = "UNCOMPRESSED"

      # CloudWatch logging for the delivery stream
      cloudwatch_logging_options {
        enabled         = true
        log_group_name  = aws_cloudwatch_log_group.firehose_logs.name
        log_stream_name = aws_cloudwatch_log_stream.firehose_logs_stream.name
      }
    }

    # Copy command options
    copy_options = "DELIMITER ','"

    # Data processing (optional)
    # processing_configuration { ... }
  }

  # S3 Backup Configuration (Where failed records go)
  s3_backup_mode = "FailedDataOnly"

  s3_backup_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    bucket_arn         = aws_s3_bucket.bucket.arn
    prefix             = "backup/"
    buffer_size        = 5
    buffer_interval    = 300
  }
}

# -----------------------------------------------------------------------------
# 7. CloudWatch Logging (Optional but recommended)
# -----------------------------------------------------------------------------

resource "aws_cloudwatch_log_group" "firehose_logs" {
  name              = "/aws/kinesisfirehose/firehose-to-redshift-stream"
  retention_in_days = 7
}

resource "aws_cloudwatch_log_stream" "firehose_logs_stream" {
  name           = "S3Delivery"
  log_group_name = aws_cloudwatch_log_group.firehose_logs.name
}

# -----------------------------------------------------------------------------
# Variables
# -----------------------------------------------------------------------------

variable "redshift_username" {
  description = "Master username for Redshift"
  type        = string
  default     = "admin"
}

variable "redshift_password" {
  description = "Master password for Redshift"
  type        = string
  sensitive   = true
  # It is recommended to use a random resource or environment variable for this
}

