extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- 1. S3 Bucket for Backup ---
# Kinesis Firehose requires an S3 location to back up documents that failed to be delivered to OpenSearch.
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "firehose-opensearch-backup-bucket-example"
}

# Disable versioning for this simple example
resource "aws_s3_bucket_versioning" "firehose_backup" {
  bucket = aws_s3_bucket.firehose_backup.id
  versioning_configuration {
    status = "Disabled"
  }
}

# --- 2. IAM Role for Firehose ---
# This role allows Firehose to access the S3 bucket and the OpenSearch domain.
resource "aws_iam_role" "firehose_role" {
  name = "firehose-opensearch-delivery-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# Policy attachment allowing Firehose to write to S3 and OpenSearch
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-opensearch-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "es:ESHttpPut",
          "es:ESHttpPost"
        ]
        # Note: We restrict this to the specific domain ARN created below
        Resource = "arn:aws:es:us-east-1:*:domain/firehose-destination-domain/*" 
      }
    ]
  })
}

# --- 3. OpenSearch Domain ---
# The destination for the streaming data.
resource "aws_opensearch_domain" "firehose_destination" {
  domain_name    = "firehose-destination-domain"
  engine_version = "OpenSearch_2.5"

  cluster_config {
    instance_type          = "t3.small.search"
    instance_count         = 1
    dedicated_master_enabled = false
    zone_awareness_enabled   = false
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
    volume_type = "gp2"
  }

  # Access policy allowing the Firehose Role to write to the domain
  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "es:ESHttp*"
        ]
        Effect = "Allow"
        Principal = {
          AWS = aws_iam_role.firehose_role.arn
        }
        Resource = "arn:aws:es:us-east-1:*:domain/firehose-destination-domain/*"
      }
    ]
  })

  # Enforce HTTPS to ensure the IAM Auth works securely
  encrypt_at_rest {
    enabled = true
  }

  node_to_node_encryption {
    enabled = true
  }
}

# --- 4. Kinesis Data Firehose Delivery Stream ---
resource "aws_kinesis_firehose_delivery_stream" "extended_s3_opensearch_stream" {
  name        = "firehose-to-opensearch-stream"
  destination = "opensearch"

  # Configuration for the OpenSearch destination
  opensearch_configuration {
    domain_arn     = aws_opensearch_domain.firehose_destination.arn
    role_arn       = aws_iam_role.firehose_role.arn
    index_name     = "firehose-data"
    type_name      = "_doc" # OpenSearch uses _doc as the default type name
    s3_backup_mode = "FailedDocumentsOnly"

    # buffering is optional, default is 60s / 5MB
    buffering_interval = 60
    buffering_size     = 5
  }

  # S3 Configuration is mandatory for Firehose (used for backup)
  s3_configuration {
    bucket_arn = aws_s3_bucket.firehose_backup.arn
    role_arn   = aws_iam_role.firehose_role.arn

    # Optional: Buffering hints for S3 backup
    buffer_size = 5
    buffer_interval = 300
  }

  # Wait for the OpenSearch domain to be created before creating the stream
  # This prevents issues where Firehose tries to validate a domain that doesn't exist yet
  depends_on = [
    aws_opensearch_domain.firehose_destination
  ]
}

