# ------------------------------------------------------------------------------
# 1. S3 Bucket (Required for Firehose buffering/backup)
# ------------------------------------------------------------------------------
resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "firehose-serverless-destination-bucket"
}

# Ensure the bucket is not publicly accessible
resource "aws_s3_bucket_public_access_block" "firehose_bucket_pab" {
  bucket = aws_s3_bucket.firehose_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# ------------------------------------------------------------------------------
# 2. OpenSearch Serverless Collection
# ------------------------------------------------------------------------------
resource "aws_opensearchserverless_collection" "example" {
  name = "firehose-serverless-collection"
  type = "SEARCH" # Options: SEARCH, TIMESERIES, VECTORSEARCH

  standby_replicas = "0" # Options: 0, 1, 2, 3
}

# ------------------------------------------------------------------------------
# 3. OpenSearch Serverless Security Policy (Data Access)
# Firehose needs permission to write to the index.
# ------------------------------------------------------------------------------
resource "aws_opensearchserverless_security_policy" "firehose_data_access" {
  name        = "firehose-access-policy"
  type        = "data"
  description = "Grants Firehose access to write to the collection"

  policy = jsonencode({
    Rules = [
      {
        ResourceType = "index"
        Resource     = ["index/${aws_opensearchserverless_collection.example.name}/*"]
        Permission   = ["aoss:CreateIndex", "aoss:WriteDocument", "aoss:UpdateIndex"]
      }
    ]
    Principal = [aws_iam_role.firehose_role.arn]
  })
}

# ------------------------------------------------------------------------------
# 4. IAM Role for Kinesis Firehose
# ------------------------------------------------------------------------------
resource "aws_iam_role" "firehose_role" {
  name = "kinesis-firehose-opensearch-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

# Policy granting Firehose permissions for S3 and OpenSearch Serverless
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-opensearch-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_bucket.arn,
          "${aws_s3_bucket.firehose_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents"
        ]
        Resource = "*" # Restrict to specific Log Group ARN in production
      },
      {
        Effect = "Allow"
        Action = [
          "aoss:APIAccessAll"
        ]
        Resource = "*"
      }
    ]
  })
}

# ------------------------------------------------------------------------------
# 5. Kinesis Data Firehose Delivery Stream
# ------------------------------------------------------------------------------
resource "aws_kinesis_firehose_delivery_stream" "example" {
  name        = "firehose-to-opensearch-serverless"
  destination = "opensearch_serverless"

  # Configuration for the OpenSearch Serverless destination
  opensearch_serverless_configuration {
    collection_arn = aws_opensearchserverless_collection.example.arn
    index_name     = "firehose-index"
    role_arn       = aws_iam_role.firehose_role.arn

    # Buffering hints
    buffering_interval = 60
    buffering_size     = 64
  }

  # S3 Configuration is mandatory for Firehose (used for backup/processing failure)
  s3_configuration {
    bucket_arn = aws_s3_bucket.firehose_bucket.arn
    role_arn   = aws_iam_role.firehose_role.arn

    # If buffering is not specified, defaults are used.
    # We usually enable simple encryption
    # encryption_enabled = true 
  }

  # CloudWatch logging configuration (Optional but recommended)
  # Note: Creating the Log Group and Log Stream manually is often required for strict policies, 
  # but Firehose can create them if permissions allow.
}

