    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Principal = {
          Service = "firehose.amazonaws.com"
        },
        Action = "sts:AssumeRole"
      }
    ]
  })
}

resource "aws_iam_policy" "firehose_policy" {
  name        = "firehose_opensearch_s3_policy"
  description = "Policy for Kinesis Firehose to access S3 and OpenSearch Serverless"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:PutObject",
          "s3:PutObjectAcl",
          "s3:GetBucketLocation",
          "s3:ListBucket",
          "s3:GetObject"
        ],
        Resource = [
          aws_s3_bucket.januarysixth.arn,
          "${aws_s3_bucket.januarysixth.arn}/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "es:ESHttpPut",
          "es:ESHttpPost",
          "es:ESHttpGet"
        ],
        Resource = [
          "arn:aws:es:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:collection/${aws_opensearchserverless_collection.test_collection.name}/*",
        ]
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "firehose_policy_attach" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = aws_iam_policy.firehose_policy.arn
}

resource "aws_s3_bucket" "januarysixth" {
  bucket = "januarysixth"
}
resource "aws_opensearchserverless_security_policy" "example" {
  name = "example"
  type = "encryption"
  policy = jsonencode({
    "Rules" = [
      {
        "Resource" = [
          "collection/example"
        ],
        "ResourceType" = "collection"
      }
    ],
    "AWSOwnedKey" = true
  })
}

resource "aws_opensearchserverless_collection" "test_collection" {
  name = "example"
  depends_on = [aws_opensearchserverless_security_policy.example]
}

resource "aws_kinesis_firehose_delivery_stream" "test_stream" {
  name        = "terraform-kinesis-firehose-test-stream"
  destination = "opensearchserverless"

  opensearchserverless_configuration {
    collection_endpoint = aws_opensearchserverless_collection.test_collection.collection_endpoint
    role_arn            = aws_iam_role.firehose_role.arn
    index_name          = "test"

    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.januarysixth.arn
      buffering_size     = 10
      buffering_interval = 400
      compression_format = "GZIP"
    }
  }
}

response:
To create an Amazon Kinesis Data Firehose delivery stream targeting Amazon OpenSearch Serverless, several resources are required to set up the infrastructure securely and correctly.

**Step-by-Step Implementation Plan:**

1.  **IAM Role:** Create a role that Kinesis Firehose can assume (`firehose.amazonaws.com`). This role must have permissions to write to the S3 bucket (required for buffering/backups) and permissions to interact with OpenSearch Serverless (`aoss:APIAccessAll` or specific document permissions).
2.  **S3 Bucket:** Kinesis Firehose requires an S3 bucket for backing up data that fails to process or for intermediate buffering. We will create a bucket and the necessary access policies.
3.  **OpenSearch Serverless Collection:** Create the target collection where the data will be indexed.
4.  **OpenSearch Serverless Security Policy:** Create a data access policy that grants the Firehose IAM role permissions to write documents (`aoss:WriteDocument`, `aoss:CreateIndex`, etc.) to the specific collection.
5.  **Kinesis Firehose Delivery Stream:** Configure the stream with `opensearch_serverless` as the destination, linking the IAM role, the collection ARN, and the S3 backup configuration.

Here is the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# 1. S3 Bucket (Required for Firehose buffering/backup)
# ------------------------------------------------------------------------------
resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "firehose-serverless-destination-bucket"
}

# Ensure the bucket is not publicly accessible
resource "aws_s3_bucket_public_access_block" "firehose_bucket_pab" {
  bucket = aws_s3_bucket.firehose_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# ------------------------------------------------------------------------------
# 2. OpenSearch Serverless Collection
# ------------------------------------------------------------------------------
resource "aws_opensearchserverless_collection" "example" {
  name = "firehose-serverless-collection"
  type = "SEARCH" # Options: SEARCH, TIMESERIES, VECTORSEARCH

  standby_replicas = "0" # Options: 0, 1, 2, 3
}

# ------------------------------------------------------------------------------
# 3. OpenSearch Serverless Security Policy (Data Access)
# Firehose needs permission to write to the index.
# ------------------------------------------------------------------------------
resource "aws_opensearchserverless_security_policy" "firehose_data_access" {
  name        = "firehose-access-policy"
  type        = "data"
  description = "Grants Firehose access to write to the collection"

  policy = jsonencode({
    Rules = [
      {
        ResourceType = "index"
        Resource     = ["index/${aws_opensearchserverless_collection.example.name}/*"]
        Permission   = ["aoss:CreateIndex", "aoss:WriteDocument", "aoss:UpdateIndex"]
      }
    ]
    Principal = [aws_iam_role.firehose_role.arn]
  })
}

# ------------------------------------------------------------------------------
# 4. IAM Role for Kinesis Firehose
# ------------------------------------------------------------------------------
resource "aws_iam_role" "firehose_role" {
  name = "kinesis-firehose-opensearch-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

# Policy granting Firehose permissions for S3 and OpenSearch Serverless
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-opensearch-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_bucket.arn,
          "${aws_s3_bucket.firehose_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents"
        ]
        Resource = "*" # Restrict to specific Log Group ARN in production
      },
      {
        Effect = "Allow"
        Action = [
          "aoss:APIAccessAll"
        ]
        Resource = "*"
      }
    ]
  })
}

# ------------------------------------------------------------------------------
# 5. Kinesis Data Firehose Delivery Stream
# ------------------------------------------------------------------------------
resource "aws_kinesis_firehose_delivery_stream" "example" {
  name        = "firehose-to-opensearch-serverless"
  destination = "opensearch_serverless"

  # Configuration for the OpenSearch Serverless destination
  opensearch_serverless_configuration {
    collection_arn = aws_opensearchserverless_collection.example.arn
    index_name     = "firehose-index"
    role_arn       = aws_iam_role.firehose_role.arn

    # Buffering hints
    buffering_interval = 60
    buffering_size     = 64
  }

  # S3 Configuration is mandatory for Firehose (used for backup/processing failure)
  s3_configuration {
    bucket_arn = aws_s3_bucket.firehose_bucket.arn
    role_arn   = aws_iam_role.firehose_role.arn

    # If buffering is not specified, defaults are used.
    # We usually enable simple encryption
    # encryption_enabled = true 
  }

  # CloudWatch logging configuration (Optional but recommended)
  # Note: Creating the Log Group and Log Stream manually is often required for strict policies, 
  # but Firehose can create them if permissions allow.
}
```

