provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# 1. Networking Setup (VPC, Subnets, Security Groups)
# ------------------------------------------------------------------------------

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "firehose-vpc"
  }
}

resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "firehose-subnet-${count.index}"
  }
}

# Data source to fetch available AZs
data "aws_availability_zones" "available" {}

# Security Group for OpenSearch Domain
resource "aws_security_group" "opensearch" {
  name        = "opensearch-sg"
  description = "Allow inbound HTTPS traffic from Firehose"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 443
    to_port         = 443
    protocol        = "tcp"
    security_groups = [aws_security_group.firehose.id] # Allow traffic from Firehose ENIs
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "opensearch-sg"
  }
}

# Security Group for Kinesis Firehose ENIs
resource "aws_security_group" "firehose" {
  name        = "firehose-sg"
  description = "Security group for Kinesis Firehose VPC ENIs"
  vpc_id      = aws_vpc.main.id

  egress {
    from_port       = 443
    to_port         = 443
    protocol        = "tcp"
    security_groups = [aws_security_group.opensearch.id] # Allow traffic to OpenSearch
  }

  tags = {
    Name = "firehose-sg"
  }
}

# ------------------------------------------------------------------------------
# 2. IAM Role for Firehose
# ------------------------------------------------------------------------------

resource "aws_iam_role" "firehose_role" {
  name = "firehose-delivery-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# Policy allowing Firehose to write to OpenSearch and manage VPC ENIs
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-opensearch-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "es:DescribeDomain",
          "es:DescribeDomains",
          "es:DescribeDomainConfig",
          "es:ESHttpPut",
          "es:ESHttpPost",
          "es:ESHttpHead"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeSubnets",
          "ec2:DescribeVpcs"
        ]
        Resource = "*"
      }
    ]
  })
}

# ------------------------------------------------------------------------------
# 3. OpenSearch Domain
# ------------------------------------------------------------------------------

resource "aws_opensearch_domain" "main" {
  domain_name    = "firehose-log-domain"
  engine_version = "OpenSearch_1.0"

  cluster_config {
    instance_type          = "t2.small.search"
    instance_count         = 1
    zone_awareness_enabled = false
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
    volume_type = "gp2"
  }

  # VPC Configuration
  vpc_options {
    subnet_ids         = aws_subnet.private[*].id
    security_group_ids = [aws_security_group.opensearch.id]
  }

  # Access Policy allowing the Firehose Role to write data
  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect    = "Allow"
        Principal = { AWS = aws_iam_role.firehose_role.arn }
        Action    = "es:ESHttp*"
        Resource  = "arn:aws:es:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:domain/${aws_opensearch_domain.main.domain_name}/*"
      }
    ]
  })

  tags = {
    Name = "firehose-destination"
  }
}

data "aws_region" "current" {}
data "aws_caller_identity" "current" {}

# ------------------------------------------------------------------------------
# 4. Kinesis Data Firehose Delivery Stream
# ------------------------------------------------------------------------------

resource "aws_kinesis_firehose_delivery_stream" "delivery_stream" {
  name        = "vpc-firehose-stream"
  destination = "elasticsearch"

  # Configuration for the Elasticsearch (OpenSearch) destination
  elasticsearch_configuration {
    domain_arn = aws_opensearch_domain.main.arn
    role_arn   = aws_iam_role.firehose_role.arn

    # Index configuration
    index_name = "firehose-data"
    type_name  = "_doc" 

    # VPC Configuration is required to access VPC-protected OpenSearch
    vpc_config {
      subnet_ids         = aws_subnet.private[*].id
      security_group_ids = [aws_security_group.firehose.id]
      role_arn           = aws_iam_role.firehose_role.arn
    }

    # S3 Backup Configuration (Required for ES destinations)
    s3_backup_mode = "FailedDocumentsOnly"

    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.backup.arn
      buffering_size     = 5
      buffering_interval = 300
    }
  }

  # Note: In a real-world scenario, the Firehose role needs S3 permissions 
  # for the backup bucket. Added below for completeness.
}

# S3 Bucket for failed records (Required by Firehose ES destination)
resource "aws_s3_bucket" "backup" {
  bucket = "firehose-es-backup-bucket-example-12345"
}

resource "aws_iam_role_policy" "s3_backup_policy" {
  name = "firehose-s3-backup-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.backup.arn,
          "${aws_s3_bucket.backup.arn}/*"
        ]
      }
    ]
  })
}

