  bucket = aws_s3_bucket.firehose_backup_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# Set ACL based on ownership controls
resource "aws_s3_bucket_acl" "firehose_backup_bucket" {
  depends_on = [aws_s3_bucket_ownership_controls.firehose_backup_bucket]
  bucket     = aws_s3_bucket.firehose_backup_bucket.id
  acl        = "private"
}

# 3. Create the IAM Role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_http_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
