provider "aws" {
  region = "us-east-1"
}

# ---------------------------------------------------------
# 1. VPC Infrastructure for OpenSearch
# ---------------------------------------------------------

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "firehose-opensearch-vpc"
  }
}

resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone = element(data.aws_availability_zones.available.names, count.index)

  tags = {
    Name = "firehose-opensearch-subnet-${count.index}"
  }
}

data "aws_availability_zones" "available" {}

resource "aws_security_group" "opensearch" {
  name        = "opensearch-sg"
  description = "Security group for OpenSearch domain"
  vpc_id      = aws_vpc.main.id

  # Allow HTTPS traffic from anywhere (or restrict to Firehose VPC endpoints if configured)
  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "opensearch-sg"
  }
}

# ---------------------------------------------------------
# 2. S3 Bucket (Required for Firehose Buffering/Backup)
# ---------------------------------------------------------

resource "random_pet" "bucket_suffix" {
  length = 2
}

resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "firehose-opensearch-bucket-${random_pet.bucket_suffix.id}"

  tags = {
    Name = "firehose-backup-bucket"
  }
}

# ---------------------------------------------------------
# 3. IAM Role for Firehose
# ---------------------------------------------------------

resource "aws_iam_role" "firehose_role" {
  name = "firehose-delivery-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the standard AWS managed policy for Firehose (includes S3 access)
resource "aws_iam_role_policy_attachment" "firehose_s3" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKinesisFirehoseFullAccess" 
  # Note: For production, scope this down to specific S3 buckets and minimal OpenSearch permissions.
}

# Custom Inline Policy for specific OpenSearch access
resource "aws_iam_role_policy" "firehose_opensearch_policy" {
  name = "firehose-opensearch-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "es:ESHttpPut",
          "es:ESHttpPost"
        ]
        # Resource is set to the ARN of the domain we create below
        Resource = "${aws_opensearch_domain.domain.arn}/*" 
      }
    ]
  })
}

# ---------------------------------------------------------
# 4. Amazon OpenSearch Domain (VPC Access)
# ---------------------------------------------------------

resource "aws_opensearch_domain" "domain" {
  domain_name    = "firehose-logs-domain"
  engine_version = "OpenSearch_2.11"

  cluster_config {
    instance_type          = "t3.small.search"
    instance_count         = 1
    dedicated_master_enabled = false
  }

  vpc_options {
    subnet_ids         = aws_subnet.private[*].id
    security_group_ids = [aws_security_group.opensearch.id]
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
  }

  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action    = "es:*"
        Effect    = "Allow"
        Principal = { AWS = aws_iam_role.firehose_role.arn }
        Resource  = "${aws_opensearch_domain.domain.arn}/*"
      }
    ]
  })

  # Enforce HTTPS
  domain_endpoint_options {
    enforce_https = true
    tls_security_policy = "Policy-Min-TLS-1-2-2019-07"
  }

  tags = {
    Name = "firehose-opensearch-domain"
  }
}

# ---------------------------------------------------------
# 5. Kinesis Data Firehose Delivery Stream
# ---------------------------------------------------------

resource "aws_kinesis_firehose_delivery_stream" "stream" {
  name        = "opensearch-delivery-stream"
  destination = "opensearch"

  # S3 Configuration is mandatory for Firehose (for backup or buffering)
  s3_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    bucket_arn         = aws_s3_bucket.firehose_bucket.arn
    buffer_size        = 5
    buffer_interval    = 300
    compression_format = "UNCOMPRESSED"
  }

  opensearch_configuration {
    domain_arn    = aws_opensearch_domain.domain.arn
    role_arn      = aws_iam_role.firehose_role.arn
    index_name    = "firehose-index"
    type_name     = "_doc" # OpenSearch uses _doc as the type name
    s3_backup_mode = "FailedDocumentsOnly"

    buffering_interval = 60
    buffering_size     = 5

    # CloudWatch Logging Options for the OpenSearch destination
    cloudwatch_logging_options {
      enabled = true
      log_group_name = aws_cloudwatch_log_group.firehose_logs.name
      log_stream_name = aws_cloudwatch_log_stream.firehose_stream.name
    }
  }

  # Explicitly depend on the OpenSearch domain to ensure the endpoint is ready
  depends_on = [
    aws_opensearch_domain.domain
  ]
}

# ---------------------------------------------------------
# 6. CloudWatch Logs (Optional but Recommended)
# ---------------------------------------------------------

resource "aws_cloudwatch_log_group" "firehose_logs" {
  name              = "/aws/kinesisfirehose/opensearch-delivery-stream"
  retention_in_days = 7
}

resource "aws_cloudwatch_log_stream" "firehose_stream" {
  name           = "delivery-stream-log"
  log_group_name = aws_cloudwatch_log_group.firehose_logs.name
}

