# Terraform configuration for an AWS Kendra Web Crawler Data Source
# with URL inclusion and exclusion patterns.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM Role for Kendra to access resources
resource "aws_iam_role" "kendra_role" {
  name = "kendra-web-crawler-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy attachment for basic Kendra access (Simplified for example)
resource "aws_iam_role_policy_attachment" "kendra_attach" {
  role       = aws_iam_role.kendra_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKendraFullAccess"
}

# Kendra Index
resource "aws_kendra_index" "example" {
  name        = "example-kendra-index"
  edition     = "DEVELOPER_EDITION"
  role_arn    = aws_iam_role.kendra_role.arn

  tags = {
    Environment = "test"
  }
}

# Kendra Data Source (Web Crawler)
resource "aws_kendra_data_source" "web_crawler" {
  name     = "web-crawler-datasource"
  index_id = aws_kendra_index.example.id
  type     = "WEBCRAWLER"
  role_arn = aws_iam_role.kendra_role.arn

  # Optional: Schedule for synchronization
  schedule {
    expression = "cron(0 9 * * ? *)"
  }

  configuration {
    web_crawler_configuration {
      # Define patterns to include specific URLs
      url_inclusion_patterns = [
        "https://example.com/docs/.*",
        "https://example.com/public/.*"
      ]

      # Define patterns to exclude specific URLs
      url_exclusion_patterns = [
        "https://example.com/private/.*",
        "https://example.com/admin/.*",
        ".*\.pdf$"
      ]

      # Seed URL configuration is required for Web Crawlers
      seed_url_configuration {
        seed_urls = [
          "https://example.com"
        ]
        web_crawler_mode = "HOST_ONLY"
      }
    }
  }

  description = "Web crawler data source with URL filtering"
}

