  document_metadata_configuration {
    name = "_category"
    type = "STRING_VALUE"
    search {
      facetable = true
      searchable = true
    }
  }

  # _created_at: Standard date field
  document_metadata_configuration {
    name = "_created_at"
    type = "DATE_VALUE"
    search {
      searchable = true
      sortable = true
    }
  }

  # _last_updated_at: Standard date field
  document_metadata_configuration {
    name = "_last_updated_at"
    type = "DATE_VALUE"
    search {
      searchable = true
      sortable = true
    }
  }

  # _source_uri: Useful for returning document links
  document_metadata_configuration {
    name = "_source_uri"
    type = "STRING_VALUE"
    search {
      searchable = true
    }
  }

  # _view_count: Standard integer field
  document_metadata_configuration {
    name = "_view_count"
    type = "INTEGER_VALUE"
    search {
      sortable = true
    }
  }

  tags = {
    Environment = "example"
  }
}

