response:
Here is the Terraform configuration to set up the requested infrastructure.

This configuration does the following:
1.  Creates a Hosted Zone named `primary.example.com` (representing the "primary" hosted zone).
2.  Defines an Amazon Route 53 Traffic Policy using a **Weighted** Round Robin rule. While Route 53 cannot dynamically check server CPU "load," Weighted routing is the standard method for distributing traffic load across multiple endpoints.
3.  Configures endpoints for both `us-east-1` and `eu-central-1`.
4.  Creates a Traffic Policy Instance to apply this policy to a specific DNS record (e.g., `app.primary.example.com`).

```hcl
provider "aws" {
  region = "us-east-1"
}

# 1. Create the "primary" hosted zone
# In a real scenario, you might reference an existing zone using data "aws_route53_zone".
resource "aws_route53_zone" "primary" {
  name = "primary.example.com"
  tags = {
    Name = "primary"
  }
}

# 2. Define the Traffic Policy
# This policy uses a "weighted" rule to distribute traffic (load balancing) across the two regions.
resource "aws_route53_traffic_policy" "low_load_policy" {
  name    = "cross-region-load-balancer"
  comment = "Directs clients to endpoints in us-east-1 or eu-central-1 based on weighted distribution."

  # The document defines the traffic logic in JSON format
  document = jsonencode({
    AWSPolicyFormatVersion = "2015-10-01"
    RecordType             = "A"
    StartPoint             = "load-distribution-rule"

    # Define the endpoints (IPs or DNS names) for the specific regions
    Endpoints = {
      "us-east-endpoint" = {
        Type   = "value"
        # Replace with your actual US endpoint IP or CNAME
        Value  = "192.0.2.10" 
        Region = "us-east-1"
      },
      "eu-central-endpoint" = {
        Type   = "value"
        # Replace with your actual EU endpoint IP or CNAME
        Value  = "192.0.2.11"
        Region = "eu-central-1"
      }
    }

    # Define the rules for routing
    Rules = {
      "load-distribution-rule" = {
        Type = "weighted"
        Items = [
          {
            EndpointReference = "us-east-endpoint"
            Weight            = "1"
          },
          {
            EndpointReference = "eu-central-endpoint"
            Weight            = "1"
          }
        ]
      }
    }
  })
}

# 3. Create the Traffic Policy Instance
# This associates the policy with a specific record name within the hosted zone.
resource "aws_route53_traffic_policy_instance" "example" {
  name = "app" # Creates record: app.primary.example.com
  hosted_zone_id = aws_route53_zone.primary.id
  traffic_policy_id = aws_route53_traffic_policy.low_load_policy.id
  traffic_policy_version = 1
  ttl = 60
}
```

