}

# 1. Create the "primary" Hosted Zone
# Note: Route 53 zones require a domain name. We use "primary.example.com" to satisfy the "primary" naming requirement.
resource "aws_route53_zone" "primary" {
  name = "primary.example.com"
}

# 2. Define the Traffic Policy Document
# This document configures the logic to route traffic based on geographic location.
locals {
  traffic_policy_document = {
    AWSPolicyFormatVersion = "2015-10-01"
    RecordType             = "A"
    # Define endpoints. In a real scenario, these would be valid IPs or DNS names.
    Endpoints = {
      endpoint_us = {
        Type  = "value"
        Value = "203.0.113.10" # Placeholder IP for US
      }
      endpoint_eu = {
        Type  = "value"
        Value = "198.51.100.20" # Placeholder IP for EU
      }
    }
    Rules = {
      # The rule that handles geographic routing
      geo_rule = {
        Type = "geographic"
        Rules = {
          # Map "US" continent request to North America (NA) code
          NA = {
            Type              = "endpoint"
            EndpointReference = "endpoint_us"
          }
          # Map "EU" continent request to Europe (EU) code
          EU = {
            Type              = "endpoint"
            EndpointReference = "endpoint_eu"
          }
        }
      }
    }
    StartRule = "geo_rule"
  }
}

# 3. Create the Traffic Policy resource
resource "aws_route53_traffic_policy" "geo_policy" {
  name    = "geo-routing-policy"
  comment = "Routes traffic to US (NA) or EU endpoints based on location"
  # Terraform requires the document to be a JSON string
  document = jsonencode(local.traffic_policy_document)
