# Terraform configuration for Amazon Route 53 Traffic Management Policies
# This configuration demonstrates Weighted, Latency, and Failover routing policies.

provider "aws" {
  region = "us-east-1"
}

# 1. Create a Hosted Zone
resource "aws_route53_zone" "example" {
  name = "example-app.com"
}

# 2. Create a Health Check (Required for Failover routing)
resource "aws_route53_health_check" "primary" {
  fqdn              = "primary-server.example-app.com"
  port              = 80
  type              = "HTTPS"
  resource_path     = "/health"
  request_interval  = 30
  failure_threshold = 3
}

# ---------------------------------------------------------
# 3. Weighted Routing Policy
# Distributes traffic based on assigned weights (e.g., Blue/Green deployment)
# ---------------------------------------------------------

resource "aws_route53_record" "www_weighted_v1" {
  zone_id = aws_route53_zone.example.zone_id
  name    = "www"
  type    = "CNAME"

  # Target endpoint (e.g., Load Balancer)
  records = ["lb-v1-123456.us-east-1.elb.amazonaws.com"]
  ttl     = 60

  weighted_routing_policy {
    weight = 80 # 80% of traffic
  }

  set_identifier = "version-1"
}

resource "aws_route53_record" "www_weighted_v2" {
  zone_id = aws_route53_zone.example.zone_id
  name    = "www"
  type    = "CNAME"

  # Target endpoint
  records = ["lb-v2-789010.us-east-1.elb.amazonaws.com"]
  ttl     = 60

  weighted_routing_policy {
    weight = 20 # 20% of traffic
  }

  set_identifier = "version-2"
}

# ---------------------------------------------------------
# 4. Latency Routing Policy
# Routes traffic to the region that provides the lowest latency
# ---------------------------------------------------------

resource "aws_route53_record" "app_latency_us_east" {
  zone_id = aws_route53_zone.example.zone_id
  name    = "app"
  type    = "A"

  alias {
    name                   = "dualstack.lb-us-east-1.elb.amazonaws.com"
    zone_id                = "Z35SXDOTBQH7ASA" # Example ELB Zone ID
    evaluate_target_health = true
  }

  latency_routing_policy {
    region = "us-east-1"
  }

  set_identifier = "us-east-1"
}

resource "aws_route53_record" "app_latency_eu_west" {
  zone_id = aws_route53_zone.example.zone_id
  name    = "app"
  type    = "A"

  alias {
    name                   = "dualstack.lb-eu-west-1.elb.amazonaws.com"
    zone_id                = "Z215JYRZRJTT8W" # Example ELB Zone ID
    evaluate_target_health = true
  }

  latency_routing_policy {
    region = "eu-west-1"
  }

  set_identifier = "eu-west-1"
}

# ---------------------------------------------------------
# 5. Failover Routing Policy
# Routes traffic to a primary site; falls over to a secondary site if the health check fails
# ---------------------------------------------------------

resource "aws_route53_record" "api_primary" {
  zone_id = aws_route53_zone.example.zone_id
  name    = "api"
  type    = "CNAME"

  records = ["primary-api.example-app.com"]
  ttl     = 10

  failover_routing_policy {
    type = "PRIMARY"
  }

  health_check_id = aws_route53_health_check.primary.id

  set_identifier = "primary-failover"
}

resource "aws_route53_record" "api_secondary" {
  zone_id = aws_route53_zone.example.zone_id
  name    = "api"
  type    = "CNAME"

  records = ["backup-api.example-app.com"]
  ttl     = 10

  failover_routing_policy {
    type = "SECONDARY"
  }

  set_identifier = "secondary-failover"
}

