terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Declare a string variable called `cluster_name`
variable "cluster_name" {
  description = "The name of the EKS cluster"
  type        = string
}

# Additional variables to make the configuration functional (Subnets and VPC ID)
variable "subnet_ids" {
  description = "A list of subnet IDs for the EKS cluster"
  type        = list(string)
}

variable "vpc_id" {
  description = "The ID of the VPC where the cluster will be provisioned"
  type        = string
}

# Data source to fetch the current region for the local-exec command
data "aws_region" "current" {}

# 2. Define the IAM role for the EKS Cluster
resource "aws_iam_role" "eks_cluster_role" {
  name = "${var.cluster_name}-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "eks.amazonaws.com"
        }
      }
    ]
  })
}

# 3. Attach the Amazon EKS Cluster Policy and VPC Resource Controller Policy
resource "aws_iam_role_policy_attachment" "eks_cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.eks_cluster_role.name
}

resource "aws_iam_role_policy_attachment" "eks_vpc_resource_controller" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSVPCResourceController"
  role       = aws_iam_role.eks_cluster_role.name
}

# Security Group for the EKS Cluster (Required for provisioning)
resource "aws_security_group" "eks_cluster_sg" {
  name        = "${var.cluster_name}-sg"
  description = "Security group for the EKS cluster"
  vpc_id      = var.vpc_id

  tags = {
    Name = "${var.cluster_name}-sg"
  }
}

# 4. Provision the AWS EKS Cluster
resource "aws_eks_cluster" "this" {
  name     = var.cluster_name
  role_arn = aws_iam_role.eks_cluster_role.arn
  version  = "1.29" # Example version

  vpc_config {
    subnet_ids         = var.subnet_ids
    security_group_ids = [aws_security_group.eks_cluster_sg.id]
  }

  # Manage IAM role dependencies so permissions are applied appropriately before creation
  depends_on = [
    aws_iam_role_policy_attachment.eks_cluster_policy,
    aws_iam_role_policy_attachment.eks_vpc_resource_controller
  ]

  # Local-exec provisioner to update kubectl configuration on creation
  provisioner "local-exec" {
    command = "aws eks update-kubeconfig --name ${self.name} --region ${data.aws_region.current.name}"
  }

  # Local-exec provisioner to remove kubectl configuration on destruction
  provisioner "local-exec" {
    when    = destroy
    command = "kubectl config delete-context ${self.name} || true"
  }
}

