terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    helm = {
      source  = "hashicorp/helm"
      version = "~> 2.0"
    }
    kubernetes = {
      source  = "hashicorp/kubernetes"
      version = "~> 2.0"
    }
  }
}

# -----------------------------------------------------------------------------
# 1. Configure AWS Provider
# -----------------------------------------------------------------------------
provider "aws" {
  region = var.aws_region
}

# -----------------------------------------------------------------------------
# 2. Data Sources: Caller Identity and ECR Image
# -----------------------------------------------------------------------------
data "aws_caller_identity" "current" {}

# Optional: Look up the most recent stable ECR image
data "aws_ecr_image" "service_image" {
  repository_name = var.ecr_repository_name
  image_tag       = "stable"
  most_recent     = true
}

# -----------------------------------------------------------------------------
# 3. Locals
# -----------------------------------------------------------------------------
locals {
  image_tag = "stable" # Matches the ECR data source lookup

  aws_tags = {
    Environment = terraform.workspace
    ManagedBy   = "Terraform"
    Project     = "EKS-Demo"
  }

  workspace_name = terraform.workspace
}

# -----------------------------------------------------------------------------
# 4. EKS Module
# -----------------------------------------------------------------------------
module "eks" {
  source  = "terraform-aws-modules/eks/aws"
  version = "~> 19.17"

  cluster_name    = var.cluster_name
  cluster_version = var.kubernetes_version

  # VPC Configuration (Assumes existing VPC/Subnets passed as variables)
  vpc_id     = var.vpc_id
  subnet_ids = var.private_subnet_ids

  # Cluster Tags
  tags = local.aws_tags

  # Cluster Add-ons
  cluster_addons = {
    coredns = {
      most_recent = true
    }
    kube-proxy = {
      most_recent = true
    }
    vpc-cni = {
      most_recent = true
    }
  }

  # EKS Managed Node Group(s)
  eks_managed_node_groups = {
    main_nodes = {
      name           = "${local.workspace_name}-node-group"
      desired_size   = var.desired_node_count
      min_size       = 1
      max_size       = 3
      instance_types = var.instance_types

      # IAM Policies
      iam_role_additional_policies = {
        # Allow nodes to pull images from ECR
        AmazonEC2ContainerRegistryReadOnly = "arn:aws:iam::aws:policy/AmazonEC2ContainerRegistryReadOnly"
        # Additional policy example (SSM)
        AmazonSSMManagedInstanceCore = "arn:aws:iam::aws:policy/AmazonSSMManagedInstanceCore"
      }

      tags = merge(local.aws_tags, {
        Type = "Worker-Node"
      })
    }
  }

  # Cluster IAM Role Additional Policies (Optional)
  cluster_iam_role_additional_policies = {
    example_policy = "arn:aws:iam::aws:policy/AmazonEKSVPCResourceController"
  }
}

# -----------------------------------------------------------------------------
# 5. EKS Cluster Metadata and Authentication
# -----------------------------------------------------------------------------
data "aws_eks_cluster" "cluster" {
  name = module.eks.cluster_name
}

data "aws_eks_cluster_auth" "cluster" {
  name = module.eks.cluster_name
}

# -----------------------------------------------------------------------------
# 6. Kubernetes and Helm Providers Configuration
# -----------------------------------------------------------------------------

provider "kubernetes" {
  host                   = data.aws_eks_cluster.cluster.endpoint
  cluster_ca_certificate = base64decode(data.aws_eks_cluster.cluster.certificate_authority[0].data)
  token                  = data.aws_eks_cluster_auth.cluster.token
}

provider "helm" {
  kubernetes {
    host                   = data.aws_eks_cluster.cluster.endpoint
    cluster_ca_certificate = base64decode(data.aws_eks_cluster.cluster.certificate_authority[0].data)
    token                  = data.aws_eks_cluster_auth.cluster.token
  }
}

# -----------------------------------------------------------------------------
# Variables
# -----------------------------------------------------------------------------
variable "aws_region" {
  description = "AWS region where resources will be created"
  type        = string
  default     = "us-east-1"
}

variable "cluster_name" {
  description = "Name of the EKS cluster"
  type        = string
  default     = "terraform-ai-cluster"
}

variable "kubernetes_version" {
  description = "Kubernetes version to use for the EKS cluster"
  type        = string
  default     = "1.27"
}

variable "ecr_repository_name" {
  description = "Name of the ECR repository to look up the 'stable' image"
  type        = string
  default     = "my-app-repo"
}

variable "vpc_id" {
  description = "ID of the VPC where the EKS cluster will be deployed"
  type        = string
}

variable "private_subnet_ids" {
  description = "List of private subnet IDs for the EKS cluster"
  type        = list(string)
}

variable "instance_types" {
  description = "Instance types for the EKS node group"
  type        = list(string)
  default     = ["t3.medium"]
}

variable "desired_node_count" {
  description = "Desired number of worker nodes"
  type        = number
  default     = 2
}

