provider "aws" {
  region = "us-east-1" # Replace with your preferred region
}

# ---------------------------------------------------------
# Variable Definitions
# ---------------------------------------------------------

variable "cluster_name" {
  description = "The name of the EKS cluster."
  type        = string
  default     = "my-eks-cluster"
}

variable "principal_arn" {
  description = "The ARN of the IAM user or role to associate the policy with."
  type        = string
  # Example: "arn:aws:iam::123456789012:role/MyDeveloperRole"
}

variable "policy_arn" {
  description = "The ARN of the EKS Access Policy to attach."
  type        = string
  default     = "arn:aws:eks::aws:cluster-access-policy/AmazonEKSViewPolicy"
}

variable "target_namespace" {
  description = "The specific namespace to restrict access to."
  type        = string
  default     = "development"
}

# ---------------------------------------------------------
# EKS Access Entry
# ---------------------------------------------------------

# Before attaching a policy, the principal must be added as an Access Entry.
resource "aws_eks_access_entry" "example" {
  cluster_name  = var.cluster_name
  principal_arn = var.principal_arn
  type          = "STANDARD"
}

# ---------------------------------------------------------
# EKS Access Policy Association
# ---------------------------------------------------------

# This resource attaches the policy to the principal and configures the scope.
resource "aws_eks_access_policy_association" "example" {
  cluster_name  = var.cluster_name
  policy_arn    = var.policy_arn
  principal_arn = var.principal_arn

  # Configure the access scope to be restricted to a particular namespace
  access_scope {
    type       = "namespace"
    namespaces = [var.target_namespace]
  }
}

