terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Default region, can be overridden
}

# Variables to represent the "provided VPC settings"
variable "vpc_subnet_ids" {
  description = "List of subnet IDs for the EKS cluster"
  type        = list(string)
}

variable "cluster_security_group_ids" {
  description = "List of security group IDs for the EKS cluster"
  type        = list(string)
  default     = []
}

# 1. Create the IAM Role for the EKS Cluster
resource "aws_iam_role" "demo_eks" {
  name = "demo_eks"

  # Trust policy allowing the EKS service to assume this role
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "eks.amazonaws.com"
        }
      }
    ]
  })
}

# 2. Attach the AmazonEKSClusterPolicy
resource "aws_iam_role_policy_attachment" "demo_eks_cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.demo_eks.name
}

# 3. Attach the AmazonEKSVPCResourceController
resource "aws_iam_role_policy_attachment" "demo_eks_vpc_resource_controller" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSVPCResourceController"
  role       = aws_iam_role.demo_eks.name
}

# 4. Create the EKS Cluster
resource "aws_eks_cluster" "demo_eks" {
  name     = "demo_eks"
  role_arn = aws_iam_role.demo_eks.arn
  version  = "1.29" # Specify a desired version or remove for latest

  vpc_config {
    subnet_ids         = var.vpc_subnet_ids
    security_group_ids = var.cluster_security_group_ids
  }

  # Ensure that the IAM Policy attachments are complete before the cluster
  # is created/updated to avoid permission errors during provisioning.
  depends_on = [
    aws_iam_role_policy_attachment.demo_eks_cluster_policy,
    aws_iam_role_policy_attachment.demo_eks_vpc_resource_controller,
  ]
}

