# Data source to get available availability zones
data "aws_availability_zones" "available" {}

# Create a VPC
resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "example-vpc"
  }
}

# Create Subnets (EKS requires at least 2 subnets in different AZs)
resource "aws_subnet" "example" {
  count                   = 2
  vpc_id                  = aws_vpc.example.id
  cidr_block              = cidrsubnet(aws_vpc.example.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "example-subnet-${count.index}"
  }
}

# Create the IAM Role for the EKS Cluster
resource "aws_iam_role" "example" {
  name = "example"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "eks.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the AmazonEKSClusterPolicy to the IAM Role
resource "aws_iam_role_policy_attachment" "example_eks_cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.example.name
}

# Create the EKS Cluster
resource "aws_eks_cluster" "example" {
  name     = "example"
  role_arn = aws_iam_role.example.arn
  version  = "1.29" # Using a recent version, can be variable

  vpc_config {
    subnet_ids              = aws_subnet.example[*].id
    endpoint_private_access = false
    endpoint_public_access  = true
  }

  # Ensure the cluster is not created until the policy attachment exists
  depends_on = [
    aws_iam_role_policy_attachment.example_eks_cluster_policy
  ]
}
