response:
To satisfy this request, we will create the following resources:

1.  **`aws_s3_bucket`**: Creates the bucket named 'test-bucket'.
2.  **`aws_s3_bucket_versioning`**: Enables versioning to retain previous versions of objects, allowing recovery in case of accidental deletion or overwriting.
3.  **`aws_s3_bucket_ownership_controls`**: Sets `object_ownership` to `BucketOwnerEnforced`. This disables Access Control Lists (ACLs) and ensures the bucket owner has full control, fulfilling the "private ACL" requirement via modern best practices.
4.  **`aws_s3_bucket_server_side_encryption_configuration`**: Configures the bucket to apply AES256 server-side encryption by default to all objects.
5.  **`aws_s3_bucket_public_access_block`**: Configures the bucket to block all public access settings.

Here is the complete Terraform configuration in a single code block:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your preferred region
}

# 1. Create the S3 Bucket
resource "aws_s3_bucket" "test_bucket" {
  bucket = "test-bucket"
}

# 2. Enable Versioning to prevent accidental deletion
resource "aws_s3_bucket_versioning" "test_bucket_versioning" {
  bucket = aws_s3_bucket.test_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# 3. Configure Private ACL (Disable ACLs)
resource "aws_s3_bucket_ownership_controls" "test_bucket_ownership" {
  bucket = aws_s3_bucket.test_bucket.id
  rule {
    object_ownership = "BucketOwnerEnforced"
  }
}

# 4. Enable AES256 Default Server-Side Encryption
resource "aws_s3_bucket_server_side_encryption_configuration" "test_bucket_encryption" {
  bucket = aws_s3_bucket.test_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# 5. Apply Public Access Block to block all public access
resource "aws_s3_bucket_public_access_block" "test_bucket_public_access" {
  bucket = aws_s3_bucket.test_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}
```

