Here is the Terraform configuration to create the S3 bucket with Object Lock enabled in Governance mode for 90 days.

**Step-by-step reasoning:**
1.  **Create the S3 Bucket**: We use the `aws_s3_bucket` resource to create the bucket named 'example-bucket'.
2.  **Enable Versioning**: S3 Object Lock requires bucket versioning to be enabled. We use the `aws_s3_bucket_versioning` resource to set this status to "Enabled".
3.  **Configure Object Lock**: We use the `aws_s3_bucket_object_lock_configuration` resource.
    *   We set `object_lock_enabled` to `Enabled`.
    *   We define a `rule` block with `default_retention`.
    *   Inside `default_retention`, we set `mode` to `GOVERNANCE` and `days` to `90`.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

resource "aws_s3_bucket" "example" {
  bucket = "example-bucket"
}

resource "aws_s3_bucket_versioning" "example" {
  bucket = aws_s3_bucket.example.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_object_lock_configuration" "example" {
  bucket = aws_s3_bucket.example.id

  object_lock_enabled = "Enabled"

  rule {
    default_retention {
      mode  = "GOVERNANCE"
      days  = 90
    }
  }
}
```

