terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

variable "bucket_suffix" {
  description = "The suffix to append to the bucket names"
  default     = "test"
}

# Resource 1: CloudGoat Data Bucket
resource "aws_s3_bucket" "cloudgoat_data" {
  bucket = "cloudgoat-data-${var.bucket_suffix}"
}

resource "aws_s3_bucket_ownership_controls" "cloudgoat_ownership" {
  bucket = aws_s3_bucket.cloudgoat_data.id
  rule {
    object_ownership = "ObjectWriter"
  }
}

resource "aws_s3_bucket_acl" "cloudgoat_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.cloudgoat_ownership]

  bucket = aws_s3_bucket.cloudgoat_data.id
  acl    = "private"
}

# Resource 2: Website Data Bucket
resource "aws_s3_bucket" "website_data" {
  bucket = "website-data-${var.bucket_suffix}"
}

resource "aws_s3_bucket_public_access_block" "website_pab" {
  bucket = aws_s3_bucket.website_data.id

  ignore_public_acls      = true
  block_public_acls       = true
  restrict_public_buckets = true
}

# Upload the CSV file
resource "aws_s3_object" "order_upload" {
  bucket = aws_s3_bucket.website_data.id
  key    = "order_data2.csv"
  source = "./order_data2.csv"

  # The etag is required for the file to be uploaded correctly if it changes
  etag = filemd5("./order_data2.csv")
}

# Bucket Policy allowing all principals to PutObject
resource "aws_s3_bucket_policy" "website_policy" {
  bucket = aws_s3_bucket.website_data.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowAllPrincipalsPutObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:PutObject"
        Resource  = "${aws_s3_bucket.website_data.arn}/*"
      }
    ]
  })
}

