  ignore_public_acls      = true
  block_public_acls       = true
  block_public_policy     = false
  restrict_public_buckets = true
}


resource "aws_s3_bucket_policy" "put_object" {
  bucket = aws_s3_bucket.cg-data-from-web.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "Statement1"
        Action    = ["s3:PutObject"]
        Effect    = "Allow"
        Resource  = "${aws_s3_bucket.cg-data-from-web.arn}/*"
        Principal = "*"
      }
    ]
  })
  depends_on = [aws_s3_bucket_public_access_block.access_block]
}

response:
Here is the step-by-step reasoning followed by the Terraform configuration:

1.  **Define Variables**: We need a variable for the `bucket_suffix` to satisfy the requirement for dynamic naming. The default is set to "test" as requested.
2.  **CloudGoat Data Bucket**:
    *   Create an `aws_s3_bucket` resource with a name constructed using the suffix variable.
    *   Configure `aws_s3_bucket_ownership_controls` to set the rule to `ObjectWriter`.
    *   Configure `aws_s3_bucket_acl` to set the ACL to `private`. Note that the ACL resource must depend on the ownership controls to ensure proper application.
3.  **Website Data Bucket**:
    *   Create a second `aws_s3_bucket` resource with a similarly dynamic name.
    *   Create an `aws_s3_bucket_public_access_block` resource. The user requested: `ignore_public_acls`, `block_public_acls`, and `restrict_public_buckets`.
4.  **File Upload**:
    *   Use the `aws_s3_object` resource to upload `order_data2.csv` into the website bucket. I will assume the local file exists at the root relative to where Terraform is run (e.g., `./order_data2.csv`).
5.  **Bucket Policy**:
    *   Create an `aws_s3_bucket_policy` resource attached to the website bucket.
    *   The policy document must allow `Principal: "*"` (All Principals) to perform the Action `s3:PutObject` on the Resource `arn:aws:s3:::[bucket-name]/*`.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

variable "bucket_suffix" {
  description = "The suffix to append to the bucket names"
  default     = "test"
}

# Resource 1: CloudGoat Data Bucket
resource "aws_s3_bucket" "cloudgoat_data" {
  bucket = "cloudgoat-data-${var.bucket_suffix}"
}

resource "aws_s3_bucket_ownership_controls" "cloudgoat_ownership" {
  bucket = aws_s3_bucket.cloudgoat_data.id
  rule {
    object_ownership = "ObjectWriter"
  }
}

resource "aws_s3_bucket_acl" "cloudgoat_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.cloudgoat_ownership]

  bucket = aws_s3_bucket.cloudgoat_data.id
  acl    = "private"
}

# Resource 2: Website Data Bucket
resource "aws_s3_bucket" "website_data" {
  bucket = "website-data-${var.bucket_suffix}"
}

resource "aws_s3_bucket_public_access_block" "website_pab" {
  bucket = aws_s3_bucket.website_data.id

  ignore_public_acls      = true
  block_public_acls       = true
  restrict_public_buckets = true
}

# Upload the CSV file
resource "aws_s3_object" "order_upload" {
  bucket = aws_s3_bucket.website_data.id
  key    = "order_data2.csv"
  source = "./order_data2.csv"

  # The etag is required for the file to be uploaded correctly if it changes
  etag = filemd5("./order_data2.csv")
}

# Bucket Policy allowing all principals to PutObject
resource "aws_s3_bucket_policy" "website_policy" {
  bucket = aws_s3_bucket.website_data.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowAllPrincipalsPutObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:PutObject"
        Resource  = "${aws_s3_bucket.website_data.arn}/*"
      }
    ]
  })
}
