    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Generate a random suffix to ensure the bucket name is globally unique
resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# Create the S3 Bucket
resource "aws_s3_bucket" "example" {
  # Using the requested name with a random suffix for uniqueness
  bucket = "my_unique_bucket_name-${random_id.bucket_suffix.hex}"
}

# Apply a Bucket ACL (Access Control List)
# Note: While ACLs are deprecated in favor of Bucket Policies and IAM,
# this satisfies the specific requirement to apply an ACL.
resource "aws_s3_bucket_acl" "example" {
  bucket = aws_s3_bucket.example.id
  acl    = "private"
}

# Control Public Access Block settings
# To allow the Bucket Policy to permit public access (Principal: "*"), 
# we must ensure these blocks are disabled.
resource "aws_s3_bucket_public_access_block" "example" {
  bucket = aws_s3_bucket.example.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# Set the Bucket Policy
resource "aws_s3_bucket_policy" "example" {
  bucket = aws_s3_bucket.example.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowGetObjectWithReferer"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.example.arn}/*"
        Condition = {
          StringLike = {
            # Replace the value below with your specific expected referer header
            "aws:Referer" = "http://www.example.com/*"
          }
        }
      }
    ]
  })
}

