provider "aws" {
  region = "us-east-1" # Replace with your preferred region
}

# Resource: Create the S3 Bucket
# Object lock must be enabled at the bucket creation level to apply retention policies
resource "aws_s3_bucket" "mybucket" {
  bucket = "mybucket"

  # Enabling object lock configuration capability on the bucket
  object_lock_enabled = true
}

# Resource: Enable Versioning
# We reference the bucket ID created above
resource "aws_s3_bucket_versioning" "versioning" {
  bucket = aws_s3_bucket.mybucket.id

  versioning_configuration {
    status = "Enabled"
  }
}

# Resource: Apply Object Lock Configuration
# We reference the bucket ID to ensure the policy targets the correct bucket
resource "aws_s3_bucket_object_lock_configuration" "lock_config" {
  bucket = aws_s3_bucket.mybucket.id

  # Ensure the object lock configuration is active
  object_lock_enabled = true

  rule {
    default_retention {
      mode = "COMPLIANCE"
      days = 5
    }
  }
}

# Output: Display the Bucket ARN to verify the reference
output "bucket_arn" {
  value = aws_s3_bucket.mybucket.arn
  description = "The ARN of the S3 bucket"
}

