  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ---------------------------------------------------------
# 1. Variables for inputs
# ---------------------------------------------------------

variable "kms_key_description" {
  description = "The description for the KMS key."
  type        = string
  default     = "KMS key for S3 Server-Side Encryption"
}

variable "kms_deletion_window_in_days" {
  description = "The waiting period, specified in number of days, before the KMS key is deleted."
  type        = number
  default     = 10
}

variable "bucket_name" {
  description = "The name of the S3 bucket."
  type        = string
  default     = "my-secure-terraform-bucket"
}

# ---------------------------------------------------------
# 2. Create KMS Key
# ---------------------------------------------------------

resource "aws_kms_key" "my_kms_key" {
  description             = var.kms_key_description
  deletion_window_in_days = var.kms_deletion_window_in_days
  enable_key_rotation     = true
}

# ---------------------------------------------------------
# 3. Provision S3 Bucket
# ---------------------------------------------------------

resource "aws_s3_bucket" "my_bucket" {
  bucket = var.bucket_name
}

# ---------------------------------------------------------
# 4. Enable Server-Side Encryption using the KMS Key
# ---------------------------------------------------------

resource "aws_s3_bucket_server_side_encryption_configuration" "encryption" {
  bucket = aws_s3_bucket.my_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      # Specifying AWS's KMS encryption algorithm
      sse_algorithm = "aws:kms"

      # Using the ARN of the KMS key created above
      kms_master_key_id = aws_kms_key.my_kms_key.arn
    }
  }
}

# ---------------------------------------------------------
# Outputs
# ---------------------------------------------------------

output "s3_bucket_name" {
  value = aws_s3_bucket.my_bucket.id
}

output "kms_key_arn" {
  value = aws_kms_key.my_kms_key.arn
}
