# Step 1: Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Step 2: Generate a unique suffix to ensure globally unique bucket names
resource "random_pet" "this" {
  length = 2
}

# Step 3: Create the Target (Log) Bucket
# This bucket will receive the logs.
resource "aws_s3_bucket" "log_bucket" {
  bucket = "my-log-bucket-${random_pet.this.id}"
}

# Step 4: Configure Ownership Controls for the Log Bucket
# We must set this to BucketOwnerPreferred to allow ACLs to be set,
# as we are applying explicit ACLs per the requirements.
resource "aws_s3_bucket_ownership_controls" "log_bucket" {
  bucket = aws_s3_bucket.log_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# Step 5: Apply Explicit ACL to the Log Bucket
# "log-delivery-write" grants the Log Delivery group WRITE and READ_ACP permissions.
resource "aws_s3_bucket_acl" "log_bucket" {
  depends_on = [aws_s3_bucket_ownership_controls.log_bucket]
  bucket     = aws_s3_bucket.log_bucket.id
  acl        = "log-delivery-write"
}

# Step 6: Create the Source (Content) Bucket
# This is the bucket whose access will be logged.
resource "aws_s3_bucket" "content_bucket" {
  bucket = "my-content-bucket-${random_pet.this.id}"
}

# Step 7: Configure Ownership Controls for the Content Bucket
# Setting to BucketOwnerPreferred to allow explicit ACL configuration.
resource "aws_s3_bucket_ownership_controls" "content_bucket" {
  bucket = aws_s3_bucket.content_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# Step 8: Apply Explicit ACL to the Content Bucket
# "private" ensures that only the bucket owner has access.
resource "aws_s3_bucket_acl" "content_bucket" {
  depends_on = [aws_s3_bucket_ownership_controls.content_bucket]
  bucket     = aws_s3_bucket.content_bucket.id
  acl        = "private"
}

# Step 9: Enable Server Access Logging
# Configures the content bucket to deliver logs to the log bucket with a specified prefix.
resource "aws_s3_bucket_logging" "content_logging" {
  depends_on = [aws_s3_bucket_acl.log_bucket]

  bucket = aws_s3_bucket.content_bucket.id

  # Connects the log bucket via its ID
  target_bucket = aws_s3_bucket.log_bucket.id
  target_prefix = "logs/"
}

