  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

# ------------------------------------------------------------------------------
# VPC and Networking
# ------------------------------------------------------------------------------

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "terraform-fleet-vpc"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "terraform-fleet-igw"
  }
}

# Public Subnets
resource "aws_subnet" "public" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = element(["us-east-1a", "us-east-1b"], count.index)
  map_public_ip_on_launch = true

  tags = {
    Name = "terraform-public-subnet-${count.index + 1}"
  }
}

# Private Subnets
resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index + 10)
  availability_zone = element(["us-east-1a", "us-east-1b"], count.index)

  tags = {
    Name = "terraform-private-subnet-${count.index + 1}"
  }
}

# Route Table for Public Subnets
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "terraform-public-rt"
  }
}

resource "aws_route_table_association" "public" {
  count          = 2
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

# Security Group for EC2 Instances
resource "aws_security_group" "ec2_sg" {
  name        = "fleet-sg"
  description = "Allow SSH and HTTP traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "fleet-sg"
  }
}

# ------------------------------------------------------------------------------
# EC2 Fleet Resources
# ------------------------------------------------------------------------------

resource "aws_launch_template" "fleet_template" {
  name_prefix   = "fleet-template-"
  image_id      = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.micro"
  key_name      = "example-key-pair" # Replace with your actual key pair name or remove if not needed

  network_interfaces {
    associate_public_ip_address = true
    security_groups             = [aws_security_group.ec2_sg.id]
  }

  tag_specifications {
    resource_type = "instance"

    tags = {
      Name = "Fleet-Instance"
    }
  }

  user_data = filebase64("${path.module}/user_data.sh") # Optional: Create a user_data.sh file or remove this line
}

resource "aws_ec2_fleet" "example_fleet" {
  terminate_instances_with_expiration = false
  replace_unhealthy_instances         = true
  type                                = "maintain"

  target_capacity_specification {
    total_target_capacity       = 9
    on_demand_target_capacity   = 5
    spot_target_capacity        = 4
    default_target_capacity_type = "on-demand"
  }

  launch_template_config {
    launch_template_specification {
      id      = aws_launch_template.fleet_template.id
      version = "$Latest"
    }

    override {
      subnet_id = aws_subnet.public[0].id
    }

    override {
      subnet_id = aws_subnet.public[1].id
    }
  }

  spot_options {
    allocation_strategy = "lowest-price"
  }

  on_demand_options {
    allocation_strategy = "lowest-price"
  }

  tags = {
    Name = "terraform-ec2-fleet"
  }

  # Wait for the fleet to be created/fulfilled (optional, prevents Terraform from finishing too early)
  # Note: Fulfillment can take time depending on Spot capacity.
}
