# Create a Virtual Private Cloud (VPC)
resource "aws_vpc" "my_vpc" {
  cidr_block = "10.0.0.0/16"
}

# Create Public Subnet
resource "aws_subnet" "public_subnet" {
  vpc_id                  = aws_vpc.my_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true
}

data "aws_availability_zones" "azs" {
    state = "available"
}

# Create Private Subnet
resource "aws_subnet" "private_subnet" {
  vpc_id            = aws_vpc.my_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.azs.names[0]
}

# Create EC2 Placement Group
resource "aws_placement_group" "my_placement_group" {
  name     = "my-placement-group"
  strategy = "cluster"
}

# Create Security Group for EC2 instances
resource "aws_security_group" "ec2_sg" {
  vpc_id = aws_vpc.my_vpc.id
  name   = "ec2_sg"
}

data "aws_ami" "amzn2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["*ubuntu-noble-24.04-amd64-server-*"]
  }
}

# Create EC2 instances in the Placement Group in the Private Subnet
resource "aws_instance" "ec2_instance" {
  count           = 3
  ami             = data.aws_ami.amzn2.id
  instance_type   = "m5.large"
  subnet_id       = aws_subnet.private_subnet.id
  security_groups = [aws_security_group.ec2_sg.id]
  placement_group = aws_placement_group.my_placement_group.name
}

response:
To fulfill the request, I will generate Terraform code that performs the following steps:

1.  **Define the Provider**: Configure the AWS provider (defaulting to `us-east-1`).
2.  **Network Infrastructure**:
    *   Create a VPC.
    *   Create a **Public Subnet** (with an Internet Gateway and Public Route Table) to allow outbound internet access.
    *   Create a **Private Subnet** (with a NAT Gateway and Private Route Table) so the instances can access the internet for updates without being publicly accessible.
    *   **Crucial Step**: I will explicitly pin both subnets to the same Availability Zone (e.g., `us-east-1a`). EC2 Placement Groups are regional constructs that group instances within a single Availability Zone to ensure low latency.
3.  **Placement Group**: Create a placement group with the `cluster` strategy.
4.  **Security Group**: Create a security group to allow SSH access (for management/testing) and general egress traffic.
5.  **Compute Resources**: Provision three EC2 instances (`count = 3`) within the private subnet, assigned to the specific placement group and security group.

Here is the complete Terraform configuration in a single code block.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Data Source: Latest Amazon Linux 2 AMI ---
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# --- VPC Networking ---
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "terraform-placement-group-vpc"
  }
}

# Define a single availability zone to ensure resources (subnets and instances) 
# are colocated, which is required for Placement Groups.
locals {
  az_name = "us-east-1a"
}

# Public Subnet
resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = local.az_name
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet"
  }
}

# Private Subnet
resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = local.az_name

  tags = {
    Name = "private-subnet"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# Elastic IP for NAT Gateway
resource "aws_eip" "nat_eip" {
  domain = "vpc"
}

# NAT Gateway
resource "aws_nat_gateway" "nat" {
  allocation_id = aws_eip.nat_eip.id
  subnet_id     = aws_subnet.public.id # NAT must be in the public subnet to reach the IGW

  tags = {
    Name = "main-nat-gateway"
  }

  # Ensure IGW exists before creating NAT
  depends_on = [aws_internet_gateway.igw]
}

# Public Route Table
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public-rt"
  }
}

resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

# Private Route Table
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat.id
  }

  tags = {
    Name = "private-rt"
  }
}

resource "aws_route_table_association" "private_assoc" {
  subnet_id      = aws_subnet.private.id
  route_table_id = aws_route_table.private.id
}

# --- Placement Group ---
resource "aws_placement_group" "cluster_group" {
  name     = "ec2-cluster-placement"
  strategy = "cluster"
}

# --- Security Group ---
resource "aws_security_group" "web_sg" {
  name        = "web_sg"
  description = "Allow SSH and outbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "SSH from anywhere"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    description = "Outbound allowed"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "web-sg"
  }
}

# --- EC2 Instances ---
resource "aws_instance" "app_server" {
  count           = 3
  ami             = data.aws_ami.amazon_linux_2.id
  instance_type   = "t3.medium" # Using medium to be safe with placement group requirements
  subnet_id       = aws_subnet.private.id

  # Placement Group Configuration
  placement_group = aws_placement_group.cluster_group.id

  # Security Group
  vpc_security_group_ids = [aws_security_group.web_sg.id]

  tags = {
    Name = "App-Server-${count.index + 1}"
  }
}
```

