}

provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# Step 1: Lookup existing Default VPC networking
# ------------------------------------------------------------------------------
# We fetch the default VPC and its subnets to deploy the Redis instance without 
# creating a complex network from scratch.

data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# ------------------------------------------------------------------------------
# Step 2: Security Group
# ------------------------------------------------------------------------------
# Create a security group to allow access to the Redis port (6379).
# For this example, we allow traffic from within the VPC.

resource "aws_security_group" "redis_sg" {
  name        = "redis-security-group"
  description = "Allow inbound Redis traffic"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    description = "Redis from VPC"
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = [data.aws_vpc.default.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redis-security-group"
  }
}

# ------------------------------------------------------------------------------
# Step 3: Subnet Group
# ------------------------------------------------------------------------------
# ElastiCache requires a subnet group. We select the first two available subnets
# from the default VPC to satisfy the requirement of spanning at least two AZs
# (standard practice for redundancy, even for single nodes).

resource "aws_elasticache_subnet_group" "redis_subnet_group" {
  name       = "redis-subnet-group"
  subnet_ids = slice(data.aws_subnets.default.ids, 0, 2)

  tags = {
    Name = "redis-subnet-group"
  }
}

# ------------------------------------------------------------------------------
# Step 4: Redis Instance (ElastiCache Replication Group)
# ------------------------------------------------------------------------------
# We use a Replication Group with a single cluster (node) to set up a standalone
# Redis server instance. This is the recommended resource over the legacy
# 'elasticache_cluster'.

resource "aws_elasticache_replication_group" "redis_replication_group" {
  replication_group_id          = "tf-redis-instance"
  description                   = "Redis instance managed by Terraform"

  # Configuration
  engine                        = "redis"
  engine_version                = "7.0"
  node_type                     = "cache.t3.micro"
  number_cache_clusters         = 1 #设置为1即为单实例

  # Networking
  subnet_group_name             = aws_elasticache_subnet_group.redis_subnet_group.name
  security_group_ids            = [aws_security_group.redis_sg.id]

  # Settings
  parameter_group_name          = "default.redis7"
  automatic_failover_enabled    = false # Disabled for single node
  snapshot_retention_limit      = 5
  snapshot_window               = "03:00-05:00"
  apply_immediately             = true

  tags = {
    Name = "terraform-redis-server"
  }
}

# ------------------------------------------------------------------------------
# Outputs
# ------------------------------------------------------------------------------

output "redis_endpoint" {
  description = "The primary endpoint address of the Redis instance"
  value       = aws_elasticache_replication_group.redis_replication_group.primary_endpoint_address
}

output "redis_port" {
  description = "The port of the Redis instance"
  value       = 6379
}

