terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Generate a random password for the master user
resource "random_password" "redshift_password" {
  length  = 16
  special = true
}

resource "aws_redshift_cluster" "example" {
  cluster_identifier = "tf-redshift-cluster"
  database_name      = "dev"

  # Master user credentials
  master_username = "admin"
  master_password = random_password.redshift_password.result

  # Node configuration
  cluster_type     = "multi-node"
  node_type        = "dc2.large"
  number_of_nodes  = 2

  # Networking (defaults to VPC in the region)
  # cluster_subnet_group_name = aws_redshift_subnet_group.example.name
  # vpc_security_group_ids    = [aws_security_group.example.id]

  # Concurrency Scaling and Usage Capping via WLM Configuration
  # We configure WLM to:
  # 1. Enable concurrency scaling (by setting max_concurrency_scaling_clusters > 0).
  # 2. Cap usage by defining a Query Monitoring Rule (QMR) to hop/stop queries 
  #    running longer than 60 minutes (3600 seconds).
  wlm_json_configuration = jsonencode([
    {
      name                         = "default_queue"
      query_concurrency            = 5
      max_concurrency_scaling_clusters = 1 # Limits the number of scaling clusters
      rules                        = [
        {
          rule_name = "limit_60_minutes"
          predicate = [
            {
              metric_name = "query_execution_time"
              operator    = ">"
              value       = 3600 # 60 minutes in seconds
            }
          ]
          action = "hop"
        }
      ]
    }
  ])

  # Snapshot configuration
  skip_final_snapshot = true
  publicly_accessible = false

  tags = {
    Environment = "test"
  }
}

