terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Generate a random password for the master user
resource "random_password" "master_password" {
  length  = 16
  special = true
}

# Create a VPC for the Redshift cluster
resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "redshift-vpc"
  }
}

# Create two subnets in different availability zones
resource "aws_subnet" "redshift_subnet_1" {
  vpc_id     = aws_vpc.redshift_vpc.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "redshift-subnet-1"
  }
}

resource "aws_subnet" "redshift_subnet_2" {
  vpc_id     = aws_vpc.redshift_vpc.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "redshift-subnet-2"
  }
}

# Create a subnet group for Redshift
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]

  tags = {
    Name = "redshift-subnet-group"
  }
}

# Create a Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow inbound traffic for Redshift"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# Provision the 2-node Redshift Cluster
resource "aws_redshift_cluster" "default" {
  cluster_identifier = "tf-two-node-cluster"
  database_name      = "mydb"
  master_username    = "admin"
  master_password    = random_password.master_password.result
  node_type          = "dc2.large"
  cluster_type       = "multi-node"
  number_of_nodes    = 2

  # Networking
  cluster_subnet_group_name   = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids      = [aws_security_group.redshift_sg.id]
  publicly_accessible         = true

  # Snapshot settings
  skip_final_snapshot = false
  final_snapshot_identifier = "tf-final-snapshot"

  tags = {
    Environment = "production"
  }
}

# Set up the Redshift Endpoint Authorization for the specified account
resource "aws_redshift_endpoint_authorization" "auth" {
  cluster_identifier = aws_redshift_cluster.default.cluster_identifier
  account_to_authorize = "012345678910"

  # Authorizing access within the VPC created above
  vpc_ids = [aws_vpc.redshift_vpc.id]
}

