# ---------------------------------------------------------
# Provider Configuration
# ---------------------------------------------------------
provider "aws" {
  region = "us-east-1"
}

# ---------------------------------------------------------
# Variables
# ---------------------------------------------------------
variable "redshift_master_password" {
  type        = string
  description = "The master password for the Redshift cluster"
  sensitive   = true
}

# ---------------------------------------------------------
# Network Resources (VPC, Subnet, Security Group)
# ---------------------------------------------------------
resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "redshift-vpc"
  }
}

resource "aws_subnet" "redshift_subnet" {
  vpc_id     = aws_vpc.redshift_vpc.id
  cidr_block = "10.0.1.0/24"

  tags = {
    Name = "redshift-subnet"
  }
}

resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name        = "redshift-subnet-group"
  description = "Subnet group for Redshift cluster"
  subnet_ids  = [aws_subnet.redshift_subnet.id]
}

resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow inbound traffic for Redshift"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# ---------------------------------------------------------
# Redshift Snapshot Schedule
# ---------------------------------------------------------
resource "aws_redshift_snapshot_schedule" "twice_daily" {
  name_prefix  = "schedule-"
  description  = "Snapshot every 12 hours"
  # Cron expression: Run at 0 minutes past 0 and 12th hour (UTC) every day
  definitions = ["cron(0 0,12 * * ? *)"]
}

# ---------------------------------------------------------
# Redshift Cluster
# ---------------------------------------------------------
resource "aws_redshift_cluster" "main" {
  cluster_identifier = "single-node-redshift"
  database_name      = "dev"
  master_username    = "admin"
  master_password    = var.redshift_master_password

  # Single Node Configuration
  node_type    = "dc2.large"
  cluster_type = "single-node"

  # Networking
  cluster_subnet_group_name = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids    = [aws_security_group.redshift_sg.id]
  publicly_accessible       = true

  # Snapshots
  # We associate the specific schedule here to enforce the "every 12 hours" rule
  snapshot_schedule_identifier = aws_redshift_snapshot_schedule.twice_daily.id

  # Set a retention period as well to ensure snapshots are kept
  automated_snapshot_retention_period = 1

  skip_final_snapshot = true

  tags = {
    Environment = "test"
  }
}

