provider "aws" {
  region = "us-east-1"
}

# 1. Generate a secure random password for the Master User
resource "random_password" "redshift_password" {
  length  = 16
  special = true
}

# 2. Networking Configuration

# Create a VPC
resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-vpc"
  }
}

# Create Subnet in us-east-1a
resource "aws_subnet" "redshift_subnet_a" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "redshift-subnet-us-east-1a"
  }
}

# Create Subnet in us-east-1b
resource "aws_subnet" "redshift_subnet_b" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "redshift-subnet-us-east-1b"
  }
}

# Create a Redshift Subnet Group spanning both AZs
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_a.id, aws_subnet.redshift_subnet_b.id]

  tags = {
    Name = "My Redshift Subnet Group"
  }
}

# Create a Security Group to allow access to Redshift
resource "aws_security_group" "redshift_security_group" {
  name        = "redshift-security-group"
  description = "Allow inbound Redshift traffic"
  vpc_id      = aws_vpc.redshift_vpc.id

  # Ingress rule for Redshift (Default port 5439)
  # Note: In production, restrict the cidr_blocks to specific IP ranges.
  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# Internet Gateway for public access (Optional, required for client connectivity if not using VPN/PrivateLink)
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.redshift_vpc.id
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.redshift_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
}

resource "aws_route_table_association" "a" {
  subnet_id      = aws_subnet.redshift_subnet_a.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "b" {
  subnet_id      = aws_subnet.redshift_subnet_b.id
  route_table_id = aws_route_table.public_rt.id
}

# 3. IAM Configuration

# IAM Role for Redshift to access S3
resource "aws_iam_role" "redshift_role" {
  name = "redshift_service_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

# Attach policy to the role (S3 Read/Write access for example)
resource "aws_iam_role_policy_attachment" "attach_s3" {
  role       = aws_iam_role.redshift_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# 4. Redshift Cluster Configuration

resource "aws_redshift_cluster" "main" {
  cluster_identifier = "tf-redshift-cluster"
  database_name      = "dev"
  master_username    = "admin"
  master_password    = random_password.redshift_password.result

  # RA3 node type is required for Multi-AZ
  node_type       = "ra3.xlplus"
  cluster_type    = "multi-node"
  number_of_nodes = 2

  # Enable Multi-AZ for fault tolerance
  multi_az = true

  # Networking
  cluster_subnet_group_name   = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids      = [aws_security_group.redshift_security_group.id]
  publicly_accessible         = true
  availability_zone_relocation_enabled = true

  # IAM Role association
  iam_roles = [aws_iam_role.redshift_role.arn]

  # Version
  cluster_version = "1.0"

  # Logging (Optional)
  enable_logging = true

  tags = {
    Environment = "production"
    Terraform   = "true"
  }
}

