response:
To fulfill this request, we need to provision a Redshift cluster in `us-east-1` and set up the necessary components to enable cross-region replication (specifically, automated snapshot copying) to `us-east-2`.

Here is the step-by-step plan:

1.  **Providers**: Configure the AWS provider for `us-east-1` (Primary) and `us-east-2` (Secondary) using aliases to manage resources in both regions.
2.  **Random Password**: Generate a secure password for the master user using the `random_password` resource.
3.  **Networking (Primary Region)**: Create a VPC, Subnet, Subnet Group, and Security Group in `us-east-1` to host the primary Redshift cluster.
4.  **Encryption (Both Regions)**:
    *   Create a KMS Key in `us-east-1` to encrypt the primary cluster.
    *   Create a KMS Key in `us-east-2` to encrypt the replicated snapshots.
5.  **Snapshot Copy Grant (Secondary Region)**: Create a `redshift_snapshot_copy_grant` in `us-east-2`. This grants the Redshift service permission to use the KMS key in the secondary region to encrypt the copied snapshots.
6.  **Primary Redshift Cluster**: Create the `aws_redshift_cluster` resource in `us-east-1`.
    *   Set `cluster_type` to `multi-node` and `number_of_nodes` to `2`.
    *   Enable `encrypted` using the primary KMS key.
    *   Configure the `snapshot_copy` block to point to `us-east-2` and reference the Snapshot Copy Grant created in step 5.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source = "hashicorp/random"
    }
  }
}

# Configure AWS Providers for both regions
provider "aws" {
  region = "us-east-1"
  alias  = "primary"
}

provider "aws" {
  region = "us-east-2"
  alias  = "secondary"
}

# Resource 1: Generate a secure random password
resource "random_password" "redshift" {
  length  = 16
  special = true
}

# Resource 2: Primary Region Networking (us-east-1)
resource "aws_vpc" "primary" {
  provider   = aws.primary
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "redshift-primary-vpc"
  }
}

resource "aws_subnet" "primary" {
  provider             = aws.primary
  vpc_id               = aws_vpc.primary.id
  cidr_block           = "10.0.1.0/24"
  availability_zone    = "us-east-1a"

  tags = {
    Name = "redshift-primary-subnet"
  }
}

resource "aws_redshift_subnet_group" "primary" {
  provider       = aws.primary
  name           = "redshift-subnet-group"
  subnet_ids     = [aws_subnet.primary.id]

  tags = {
    Name = "redshift-subnet-group"
  }
}

resource "aws_security_group" "primary" {
  provider    = aws.primary
  name        = "redshift-security-group"
  description = "Allow Redshift inbound traffic"
  vpc_id      = aws_vpc.primary.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Resource 3: Encryption Keys (Both regions)
# Primary Key
resource "aws_kms_key" "primary" {
  provider             = aws.primary
  description          = "KMS key for Primary Redshift Cluster"
  enable_key_rotation  = true

  tags = {
    Name = "redshift-primary-key"
  }
}

# Secondary Key (Used to encrypt snapshots in the destination region)
resource "aws_kms_key" "secondary" {
  provider    = aws.secondary
  description = "KMS key for Replicated Redshift Snapshots"

  tags = {
    Name = "redshift-secondary-key"
  }
}

# Resource 4: Snapshot Copy Grant (us-east-2)
# This allows the primary cluster to encrypt snapshots using the secondary region's KMS key
resource "aws_redshift_snapshot_copy_grant" "secondary" {
  provider               = aws.secondary
  name                   = "redshift-copy-grant"
  kms_key_id             = aws_kms_key.secondary.id

  tags = {
    Name = "redshift-copy-grant"
  }
}

# Resource 5: Primary Redshift Cluster (us-east-1)
resource "aws_redshift_cluster" "primary" {
  provider                 = aws.primary
  cluster_identifier       = "tf-redshift-cluster"
  database_name            = "dev"
  master_username          = "admin"
  master_password          = random_password.redshift.result

  # Node configuration: 2-node cluster
  node_type                = "dc2.large"
  cluster_type             = "multi-node"
  number_of_nodes          = 2

  # Networking
  cluster_subnet_group_name = aws_redshift_subnet_group.primary.name
  vpc_security_group_ids    = [aws_security_group.primary.id]
  publicly_accessible       = true

  # Encryption
  encrypted                 = true
  kms_key_id               = aws_kms_key.primary.arn

  # Replication Configuration
  snapshot_copy {
    destination_region = "us-east-2"
    grant_name         = aws_redshift_snapshot_copy_grant.secondary.name
    retention_period   = 7 # Keep snapshots for 7 days in secondary region
  }

  # Skip final snapshot for clean destroy (optional, strictly for demo convenience)
  skip_final_snapshot      = true
  final_snapshot_identifier = "final-snapshot"

  tags = {
    Environment = "Production"
  }
}
```

