  }
}

resource "aws_subnet" "redshift_subnet_b" {
  vpc_id     = aws_vpc.redshift_vpc.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "redshift-subnet-b"
  }
}

# Redshift requires a Subnet Group spanning at least two subnets
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [
    aws_subnet.redshift_subnet_a.id,
    aws_subnet.redshift_subnet_b.id
  ]

  tags = {
    Name = "My Redshift Subnet Group"
  }
}

# Security Group to allow access to Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow inbound traffic to Redshift"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# -----------------------------------------------------------------------------
# 2. IAM Role
# -----------------------------------------------------------------------------

# The IAM Role that Redshift will assume
resource "aws_iam_role" "redshift_role" {
  name = "redshift_iam_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

# Attach a policy to the role (e.g., S3 Read Access for loading data)
resource "aws_iam_role_policy" "redshift_s3_access" {
  name = "redshift_s3_access_policy"
  role = aws_iam_role.redshift_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = "*"
      }
    ]
  })
}

# -----------------------------------------------------------------------------
# 3. Redshift Cluster
# -----------------------------------------------------------------------------

# Generate a random password for the master user
resource "random_password" "master_password" {
  length  = 16
  special = true
}

resource "aws_redshift_cluster" "default" {
  cluster_identifier = "tf-redshift-cluster"
  database_name      = "mydb"
  master_username    = "admin"
  master_password    = random_password.master_password.result

  node_type       = "dc2.large"
