# -----------------------------------------------------------------------------

resource "aws_redshift_cluster_iam_roles" "attach_role" {
  cluster_identifier = aws_redshift_cluster.default.cluster_identifier
  iam_role_arns      = [aws_iam_role.redshift_role.arn]
}

