Here is the Terraform configuration to set up an Amazon Redshift cluster with two nodes and configure endpoint access.

This configuration includes the necessary networking components (VPC, Subnets), security groups, IAM roles, and the specific Redshift resources requested.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# Networking Configuration
# -----------------------------------------------------------------------------

resource "aws_vpc" "redshift_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "redshift-vpc"
  }
}

resource "aws_subnet" "redshift_subnet_1" {
  vpc_id     = aws_vpc.redshift_vpc.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "redshift-subnet-1"
  }
}

resource "aws_subnet" "redshift_subnet_2" {
  vpc_id     = aws_vpc.redshift_vpc.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "redshift-subnet-2"
  }
}

# -----------------------------------------------------------------------------
# Security Configuration
# -----------------------------------------------------------------------------

resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow inbound traffic for Redshift"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# -----------------------------------------------------------------------------
# Redshift Subnet Group
# -----------------------------------------------------------------------------

resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name        = "redshift-subnet-group"
  description = "Subnet group for Redshift cluster"
  subnet_ids  = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]

  tags = {
    Name = "redshift-subnet-group"
  }
}

# -----------------------------------------------------------------------------
# IAM Role for Redshift
# -----------------------------------------------------------------------------

resource "aws_iam_role" "redshift_role" {
  name = "redshift-iam-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "redshift_attach_s3" {
  role       = aws_iam_role.redshift_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# -----------------------------------------------------------------------------
# Redshift Cluster
# -----------------------------------------------------------------------------

resource "random_password" "admin_password" {
  length  = 16
  special = true
}

resource "aws_redshift_cluster" "default" {
  cluster_identifier = "tf-redshift-cluster"
  database_name      = "mydb"
  master_username    = "admin"
  master_password    = random_password.admin_password.result

  # Request: Two nodes
  node_type       = "dc2.large"
  cluster_type    = "multi-node"
  number_of_nodes = 2

  skip_final_snapshot = true
  publicly_accessible = false

  cluster_subnet_group_name   = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids      = [aws_security_group.redshift_sg.id]
  iam_roles_arns              = [aws_iam_role.redshift_role.arn]

  tags = {
    Environment = "terraform-demo"
  }
}

# -----------------------------------------------------------------------------
# Redshift Endpoint Access
# -----------------------------------------------------------------------------

resource "aws_redshift_endpoint_access" "example" {
