# 1. IAM Role with Trust Policy
# This role defines the permissions the Lambda function has.
# The trust policy specifically allows the Lambda service to assume this role.
resource "aws_iam_role" "lambda_execution_role" {
  name = "lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# 2. IAM Policy Attachment
# Attaches the basic execution policy to the role. 
# This is required for the Lambda function to write logs to CloudWatch.
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 3. Deployment Package
# Archives the local source file "lambda.js" into a zip file required for deployment.
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = "lambda.js"
  output_path = "lambda_function_payload.zip"
}

# 4. AWS Lambda Function
# Defines the function using the Node.js 18 runtime, the specified handler, 
# and the generated deployment package.
resource "aws_lambda_function" "this" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "example_lambda"
  role             = aws_iam_role.lambda_execution_role.arn
  handler          = "lambda.handler"
  runtime          = "nodejs18.x"
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
}

