terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    archive = {
      source  = "hashicorp/archive"
      version = "~> 2.0"
    }
    local = {
      source  = "hashicorp/local"
      version = "~> 2.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create the IAM Role for Lambda Execution
resource "aws_iam_role" "lambda_exec_role" {
  name = "example_lambda_exec_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the basic execution policy (allows logging to CloudWatch)
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_exec_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 2. Create a dummy Python script for the Lambda
resource "local_file" "lambda_script" {
  content  = <<-EOT
    import json

    def lambda_handler(event, context):
        return {
            'statusCode': 200,
            'body': json.dumps('Hello from example_lambda!')
        }
    EOT
  filename = "${path.module}/lambda_function.py"
}

# 3. Zip the Python script
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = local_file.lambda_script.filename
  output_path = "${path.module}/lambda_function_payload.zip"

  depends_on = [
    local_file.lambda_script
  ]
}

# 4. Create the AWS Lambda Function
resource "aws_lambda_function" "example_lambda" {
  filename      = data.archive_file.lambda_zip.output_path
  function_name = "example_lambda"
  role          = aws_iam_role.lambda_exec_role.arn
  handler       = "lambda_function.lambda_handler"

  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  runtime = "python3.9"
}

# 5. Invoke the Lambda Function
resource "aws_lambda_invocation" "example_invoke" {
  function_name = aws_lambda_function.example_lambda.function_name
  input         = jsonencode({
    "key1" = "value1"
    "key2" = "value2"
  })

  depends_on = [
    aws_lambda_function.example_lambda
  ]
}

# Output the result of the invocation
output "lambda_result" {
  value = aws_lambda_invocation.example_invoke.result
}

