provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# 1. Create the IAM Role for the Lambda function
resource "aws_iam_role" "lambda_execution_role" {
  name = "lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the Basic Execution Policy to the IAM Role
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 2. Create a simple Python script locally for the Lambda to execute
resource "local_file" "lambda_handler_source" {
  filename = "${path.module}/lambda_function.py"
  content  = <<-EOT
import json

def lambda_handler(event, context):
    print("Lambda function executed at 15-minute interval.")
    return {
        'statusCode': 200,
        'body': json.dumps('Success!')
    }
  EOT
}

# 3. Archive the Python script into a ZIP file
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = local_file.lambda_handler_source.filename
  output_path = "${path.module}/lambda_function_payload.zip"
}

# 4. Create the AWS Lambda Function
resource "aws_lambda_function" "scheduled_lambda" {
  filename      = data.archive_file.lambda_zip.output_path
  function_name = "15_Minute_Interval_Lambda"
  role          = aws_iam_role.lambda_execution_role.arn
  handler       = "lambda_function.lambda_handler"
  runtime       = "python3.9"

  # Ensures that if the source code changes, the Lambda is updated
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  depends_on = [
    aws_iam_role_policy_attachment.lambda_basic_execution
  ]
}

# 5. Create a CloudWatch Events Rule to trigger every 15 minutes
resource "aws_cloudwatch_event_rule" "every_15_minutes" {
  name                = "trigger-every-15-minutes"
  description         = "Fires every 15 minutes"
  schedule_expression = "rate(15 minutes)"
}

# 6. Set the Lambda function as the target for the Event Rule
resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.every_15_minutes.name
  target_id = "TargetLambdaFunction"
  arn       = aws_lambda_function.scheduled_lambda.arn
}

# 7. Grant CloudWatch Events permission to invoke the Lambda function
resource "aws_lambda_permission" "allow_cloudwatch_events" {
  statement_id  = "AllowExecutionFromCloudWatch"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.scheduled_lambda.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.every_15_minutes.arn
}

