  depends_on = [
    aws_iam_role_policy_attachment.lambda_basic_execution
  ]
}

# 5. Create a CloudWatch Events Rule to trigger every 15 minutes
resource "aws_cloudwatch_event_rule" "every_15_minutes" {
  name                = "trigger-every-15-minutes"
  description         = "Fires every 15 minutes"
  schedule_expression = "rate(15 minutes)"
}

# 6. Set the Lambda function as the target for the Event Rule
resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.every_15_minutes.name
  target_id = "TargetLambdaFunction"
  arn       = aws_lambda_function.scheduled_lambda.arn
}

# 7. Grant CloudWatch Events permission to invoke the Lambda function
resource "aws_lambda_permission" "allow_cloudwatch_events" {
