# ---------------------------------------------------
# Variables: Tailored Configuration Options
# ---------------------------------------------------

variable "aws_region" {
  description = "The AWS region where the resources will be created."
  type        = string
  default     = "us-east-1"
}

variable "table_name" {
  description = "The name of the existing DynamoDB table to enable Contributor Insights on."
  type        = string
}

variable "index_name" {
  description = "Optional: The name of the Global Secondary Index (GSI) to enable insights on. If left null, only the table-level insights are enabled."
  type        = string
  default     = null
}

variable "tags" {
  description = "A map of tags to assign to the Contributor Insights resources."
  type        = map(string)
  default     = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

# ---------------------------------------------------
# Resources: DynamoDB Contributor Insights
# ---------------------------------------------------

# This resource enables Contributor Insights for the DynamoDB Table itself.
resource "aws_dynamodb_contributor_insights" "table_insights" {
  table_name = var.table_name
  tags       = var.tags
}

# This resource conditionally enables Contributor Insights for a specific Global Secondary Index.
# It is only created if the 'index_name' variable is provided.
resource "aws_dynamodb_contributor_insights" "index_insights" {
  count = var.index_name != null ? 1 : 0

  table_name = var.table_name
  index_name = var.index_name
  tags       = var.tags
}

# ---------------------------------------------------
# Outputs
# ---------------------------------------------------

output "table_insights_arn" {
  description = "The ARN of the Contributor Insights rule for the table."
  value       = aws_dynamodb_contributor_insights.table_insights.arn
}

output "index_insights_arn" {
  description = "The ARN of the Contributor Insights rule for the index (if created)."
  value       = var.index_name != null ? aws_dynamodb_contributor_insights.index_insights[0].arn : null
}

