terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# Network Configuration (VPC & Subnets)
# -----------------------------------------------------------------------------
resource "aws_vpc" "dax_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "dax-vpc"
  }
}

# Create two subnets in different Availability Zones for the Subnet Group
resource "aws_subnet" "dax_subnet_1" {
  vpc_id            = aws_vpc.dax_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "dax-subnet-1"
  }
}

resource "aws_subnet" "dax_subnet_2" {
  vpc_id            = aws_vpc.dax_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "dax-subnet-2"
  }
}

# -----------------------------------------------------------------------------
# Security Group
# -----------------------------------------------------------------------------
resource "aws_security_group" "dax_sg" {
  name        = "dax-security-group"
  description = "Allow inbound traffic for DAX"
  vpc_id      = aws_vpc.dax_vpc.id

  # DAX default port is 8111
  ingress {
    from_port   = 8111
    to_port     = 8111
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "dax-sg"
  }
}

# -----------------------------------------------------------------------------
# IAM Role for DAX
# -----------------------------------------------------------------------------
resource "aws_iam_role" "dax_role" {
  name = "dax-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dax.amazonaws.com"
        }
      }
    ]
  })
}

# Attach a policy allowing DAX to access DynamoDB
resource "aws_iam_role_policy_attachment" "dax_policy_attach" {
  role       = aws_iam_role.dax_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonDynamoDBFullAccess"
}

# -----------------------------------------------------------------------------
# DAX Subnet Group
# -----------------------------------------------------------------------------
resource "aws_dax_subnet_group" "main" {
  name       = "dax-subnet-group"
  subnet_ids = [
    aws_subnet.dax_subnet_1.id,
    aws_subnet.dax_subnet_2.id
  ]

  tags = {
    Name = "dax-subnet-group"
  }
}

# -----------------------------------------------------------------------------
# DAX Cluster
# -----------------------------------------------------------------------------
resource "aws_dax_cluster" "main" {
  cluster_name              = "terraform-dax-cluster"
  iam_role_arn              = aws_iam_role.dax_role.arn
  node_type                 = "dax.r4.large"
  replication_factor        = 1
  subnet_group_name         = aws_dax_subnet_group.main.name
  security_group_ids        = [aws_security_group.dax_sg.id]

  tags = {
    Name = "terraform-dax-cluster"
    Environment = "test"
  }
}

