# Step 1: Define the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Step 2: Define variables for the SageMaker Image configuration
variable "image_name" {
  description = "The unique name of the SageMaker Image."
  type        = string
  default     = "my-custom-sagemaker-image"
}

variable "display_name" {
  description = "The display name of the SageMaker Image (shown in UI)."
  type        = string
  default     = "My Custom SageMaker Image"
}

variable "image_description" {
  description = "A description for the SageMaker Image."
  type        = string
  default     = "A custom image created via Terraform."
}

variable "container_image_uri" {
  description = "The URI of the Docker container image in ECR."
  type        = string
  # Example: "123456789012.dkr.ecr.us-east-1.amazonaws.com/my-repo:latest"
  default     = "123456789012.dkr.ecr.us-east-1.amazonaws.com/my-repo:latest"
}

# Step 3: Create the SageMaker Image resource
# This resource defines the metadata for the image in SageMaker.
resource "aws_sagemaker_image" "this" {
  name         = var.image_name
  display_name = var.display_name
  description  = var.image_description

  # Optional: Define a role ARN if the image needs specific permissions
  # role_arn = aws_iam_role.custom_role.arn
}

# Step 4: Create a SageMaker Image Version
# An image requires a version to point to a specific container image (Docker URI).
resource "aws_sagemaker_image_version" "this" {
  image_name = aws_sagemaker_image.this.name

  container_image {
    # The actual ECR URI of the Docker image
    image_uri = var.container_image_uri
  }
}

# Step 5: Output the SageMaker Image ARN
output "sagemaker_image_arn" {
  description = "The ARN of the created SageMaker Image"
  value       = aws_sagemaker_image.this.arn
}

output "sagemaker_image_version_arn" {
  description = "The ARN of the created SageMaker Image Version"
  value       = aws_sagemaker_image_version.this.arn
}

