# Provider configuration
provider "aws" {
  region = var.aws_region
}

# Variables
variable "aws_region" {
  description = "The AWS region where resources will be created."
  default     = "us-east-1"
}

variable "model_name" {
  description = "The name of the SageMaker model."
  default     = "kmeans-model"
}

variable "s3_model_data_url" {
  description = "The S3 path where the model artifacts (model.tar.gz) are located."
  # Note: In a real scenario, this must point to a valid S3 location of the trained model.
  default     = "s3://my-bucket/model.tar.gz"
}

# IAM Role for SageMaker
# SageMaker requires an execution role to access model artifacts and container images.
resource "aws_iam_role" "sagemaker_execution_role" {
  name = "${var.model_name}-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

# Attach a policy to the role to allow SageMaker to access necessary resources.
# For production, scope this down to specific buckets/arns.
resource "aws_iam_role_policy_attachment" "sagemaker_policy_attachment" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# SageMaker Model Resource
resource "aws_sagemaker_model" "kmeans_model" {
  name               = var.model_name
  execution_role_arn = aws_iam_role.sagemaker_execution_role.arn

  primary_container {
    # This specifies the KMeans algorithm image provided by AWS.
    # Account ID 683313688378 corresponds to SageMaker built-in algorithms.
    image = "683313688378.dkr.ecr.${var.aws_region}.amazonaws.com/kmeans:1"

    # The location of the trained model artifacts in S3.
    model_data_url = var.s3_model_data_url
  }

  tags = {
    Algorithm = "KMeans"
  }
}

