# Terraform configuration for an Amazon SageMaker Pipeline

provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# IAM Role for SageMaker Pipeline
# ------------------------------------------------------------------------------
# The pipeline needs a role to access other AWS services (S3, ECR, CloudWatch).

resource "aws_iam_role" "sagemaker_pipeline_role" {
  name = "sagemaker-pipeline-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Purpose = "SageMakerPipelineExecution"
  }
}

# Attach a policy allowing SageMaker to perform necessary tasks.
# In production, you should scope this down to specific buckets/resources.
resource "aws_iam_role_policy_attachment" "sagemaker_execution_policy" {
  role       = aws_iam_role.sagemaker_pipeline_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# ------------------------------------------------------------------------------
# SageMaker Pipeline
# ------------------------------------------------------------------------------

resource "aws_sagemaker_pipeline" "example_pipeline" {
  name                = "example-ml-pipeline"
  role_arn            = aws_iam_role.sagemaker_pipeline_role.arn
  pipeline_display_name = "Example ML Pipeline"
  pipeline_description = "An example SageMaker pipeline managed by Terraform"

  # The pipeline definition is a JSON string. 
  # In real-world scenarios, this is often generated by the SageMaker Python SDK 
  # and referenced via file("${path.module}/pipeline.json").
  # Here we provide a minimal valid structure inline.
  pipeline_definition = <<EOF
{
  "Version": "2020-12-01",
  "Parameters": [
    {
      "Name": "InputDataUrl",
      "Type": "String",
      "DefaultValue": "s3://my-bucket/input-data/"
    },
    {
      "Name": "InstanceType",
      "Type": "String",
      "DefaultValue": "ml.m5.xlarge"
    }
  ],
  "PipelineExperimentConfig": {
    "ExperimentName": "MyExperiment",
    "TrialName": "MyTrial"
  },
  "Steps": []
}
EOF

  # Optional: Parallelism configuration
  parallelism_configuration {
    MaxParallelExecutionSteps = 1
  }

  tags = {
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}

