  region = "us-east-1" # Replace with your AWS region
}

# Variable for the name of the existing SageMaker model
variable "existing_model_name" {
  description = "The name of the already existing SageMaker model to associate with this endpoint."
  type        = string
}

# Variable for the endpoint configuration name
variable "endpoint_config_name" {
  description = "The name of the SageMaker endpoint configuration."
  type        = string
  default     = "my-inference-endpoint-config"
}

# Variable for instance type
variable "instance_type" {
  description = "The ML compute instance type for the endpoint."
  type        = string
  default     = "ml.m5.large"
}

# Variable for initial instance count
variable "initial_instance_count" {
  description = "The initial number of instances to run in the endpoint."
  type        = number
  default     = 1
}

resource "aws_sagemaker_endpoint_configuration" "this" {
  name = var.endpoint_config_name

  # Production Variants define the models that serve requests
  production_variants {
    # Name of the existing SageMaker Model
    model_name             = var.existing_model_name

    # The name of the variant. 
    # "AllTraffic" is a common convention for single-model endpoints.
    variant_name           = "AllTraffic"

    # Initial number of instances to launch
    initial_instance_count = var.initial_instance_count

    # Type of ML compute instance
    instance_type          = var.instance_type

    # (Optional) Determines how traffic is distributed among variants if multiple exist.
    # For a single variant, this is usually set to 1.
    initial_variant_weight = 1
  }

  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

