response:
To set up an Amazon SageMaker endpoint, we need to establish a dependency chain of resources. First, we need an IAM Role that SageMaker can assume to access other AWS resources (like pulling container images from ECR or reading model artifacts from S3). Next, we define the SageMaker Model, which specifies the container image and the location of the model artifacts. Then, we create an Endpoint Configuration, which dictates the instance type and count for the deployment. Finally, we create the SageMaker Endpoint itself, which makes the model available for inference.

Here is the complete Terraform configuration:

```hcl
# 1. Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# 2. IAM Role for SageMaker
# SageMaker needs permission to access ECR (for images) and S3 (for model artifacts).
resource "aws_iam_role" "sagemaker_execution_role" {
  name = "sagemaker-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the standard SageMaker Full Access policy for demonstration purposes.
# In production, you should restrict this to only necessary permissions.
resource "aws_iam_role_policy_attachment" "sagemaker_attach" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# 3. SageMaker Model
# Defines the model artifacts and the container image.
# We use a pre-built XGBoost image from AWS for this example.
resource "aws_sagemaker_model" "example_model" {
  name               = "example-xgboost-model"
  execution_role_arn = aws_iam_role.sagemaker_execution_role.arn

  primary_container {
    image = "683313688378.dkr.ecr.us-east-1.amazonaws.com/xgboost:latest"
    # Replace this S3 URI with the actual location of your trained model artifacts (e.g., model.tar.gz)
    model_data_url = "s3://my-bucket/model.tar.gz"
  }
}

# 4. SageMaker Endpoint Configuration
# Defines the hardware configuration for the endpoint.
resource "aws_sagemaker_endpoint_configuration" "example_config" {
  name = "example-endpoint-config"

  production_variants {
    variant_name           = "AllTraffic"
    model_name             = aws_sagemaker_model.example_model.name
    initial_instance_count = 1
    instance_type          = "ml.t2.medium"
  }
}

# 5. SageMaker Endpoint
# The actual resource that serves inference requests.
resource "aws_sagemaker_endpoint" "example_endpoint" {
  name                 = "example-endpoint"
  endpoint_config_name = aws_sagemaker_endpoint_configuration.example_config.name
}

# Output the Endpoint Name
output "endpoint_name" {
  value = aws_sagemaker_endpoint.example_endpoint.name
}
```

