provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role: The Lambda function needs an execution role to operate.
# This role allows the service (lambda.amazonaws.com) to assume the role.
resource "aws_iam_role" "lambda_exec_role" {
  name = "lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# 2. IAM Policy Attachment: Attach the basic execution policy to the role.
# This provides permissions to write logs to CloudWatch.
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_exec_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 3. Archive File: Terraform requires a .zip file to deploy Lambda code.
# This data source takes the local 'lambda.js' file and compresses it into 'lambda_function_payload.zip'.
# Note: For the handler 'index.handler' to work, the file inside the zip usually needs to be named index.js.
# If the local file is strictly named 'lambda.js', ensure your handler logic matches that filename, 
# or rename the file locally before running Terraform.
data "archive_file" "lambda_source_package" {
  type        = "zip"
  source_file = "lambda.js"
  output_path = "lambda_function_payload.zip"
}

# 4. Lambda Function: The core resource provisioning the function.
resource "aws_lambda_function" "this" {
  function_name = "nodejs_lambda_function"

  # The S3 bucket/key can be used instead of filename for larger deployments, 
  # but filename is sufficient here referencing the local archive created above.
  filename         = data.archive_file.lambda_source_package.output_path
  source_code_hash = data.archive_file.lambda_source_package.output_base64sha256

  role    = aws_iam_role.lambda_exec_role.arn
  handler = "index.handler" # Maps to the file index.js and the exported handler function

  runtime = "nodejs18.x"
}

