provider "aws" {
  region = "us-east-1" # Default region, can be overridden
}

# Data source to fetch the most recent Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

# Resource to provision the EC2 instance
resource "aws_instance" "this" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.small" # t3.small provides 2 vCPUs

  # Explicitly configure CPU options for 2 threads per core
  # t3.small has 2 vCPUs, so we set core_count to 1 to result in 2 threads.
  cpu_options {
    core_count       = 1
    threads_per_core = 2
  }

  tags = {
    Name = "Amazon-Linux-2-Instance"
  }
}

