provider "aws" {
  region = "us-east-1" # Change region as needed
}

# 1. VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "fleet-vpc"
  }
}

# 2. Subnets
resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone       = "us-east-1a"

  tags = {
    Name = "public-subnet"
  }
}

resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "private-subnet"
  }
}

# 3. Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# 4. NAT Gateway (Required for Private Subnet to access internet for updates)
resource "aws_eip" "nat_eip" {
  domain = "vpc"
}

resource "aws_nat_gateway" "nat" {
  allocation_id = aws_eip.nat_eip.id
  subnet_id     = aws_subnet.public.id

  tags = {
    Name = "main-nat-gateway"
  }

  depends_on = [aws_internet_gateway.igw]
}

# 5. Route Tables
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public-rt"
  }
}

resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat.id
  }

  tags = {
    Name = "private-rt"
  }
}

# 6. Route Table Associations
resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "private_assoc" {
  subnet_id      = aws_subnet.private.id
  route_table_id = aws_route_table.private.id
}

# 7. Data Source: Latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

# 8. Security Group
resource "aws_security_group" "fleet_sg" {
  name        = "fleet-security-group"
  description = "Allow SSH and HTTP traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "fleet-sg"
  }
}

# 9. Launch Template
resource "aws_launch_template" "fleet_lt" {
  name_prefix   = "fleet-lt-"
  image_id      = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.micro"
  key_name      = "example-key" # Replace with your actual key pair name or remove if not needed

  network_interfaces {
    associate_public_ip_address = false # Private instances generally don't need public IPs behind NAT
    security_groups             = [aws_security_group.fleet_sg.id]
  }

  tag_specifications {
    resource_type = "instance"
    tags = {
      Name = "Fleet-Instance"
    }
  }

  lifecycle {
    create_before_destroy = true
  }
}

# 10. EC2 Fleet
resource "aws_ec2_fleet" "example_fleet" {
  name        = "example-ec2-fleet"
  description = "Example fleet with mixed On-Demand and Spot instances"

  target_capacity_specification {
    total_target_capacity       = 9
    on_demand_target_capacity   = 5
    spot_target_capacity        = 4
    default_target_capacity_type = "on-demand"
  }

  launch_template_config {
    launch_template_specification {
      id      = aws_launch_template.fleet_lt.id
      version = "$Latest"
    }

    override {
      subnet_id = aws_subnet.public.id
    }

    override {
      subnet_id = aws_subnet.private.id
    }
  }

  # Ensure Spot instances are interrupted appropriately
  spot_options {
    maintenance_strategies {
      capacity_rebalance {
        replacement_strategy = "launch-before-terminate"
      }
    }
  }

  type = "maintain"

  tags = {
    Name = "Main-EC2-Fleet"
  }
}

