terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

# Create a Virtual Private Cloud (VPC)
resource "aws_vpc" "my_vpc" {
  cidr_block = "10.0.0.0/16"
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Create Public Subnet
resource "aws_subnet" "public_subnet" {
  vpc_id                  = aws_vpc.my_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = data.aws_availability_zones.available.names[0]
  map_public_ip_on_launch = true
}

# Create Private Subnet
resource "aws_subnet" "private_subnet" {
  vpc_id            = aws_vpc.my_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[1]
}


data "aws_ami" "latest_amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["*ubuntu-noble-24.04-amd64-server-*"]
  }
}

# Create Launch Template for EC2 instances
resource "aws_launch_template" "ec2_launch_template" {
  name = "my-launch-template"

  instance_type = "t2.micro"
  image_id = data.aws_ami.latest_amazon_linux_2.id
}

# Create EC2 Fleet
resource "aws_ec2_fleet" "ec2_fleet" {
  launch_template_config {
    launch_template_specification {
      launch_template_id = aws_launch_template.ec2_launch_template.id
      version            = aws_launch_template.ec2_launch_template.latest_version
    }
  }

  target_capacity_specification {
    default_target_capacity_type = "on-demand"
    total_target_capacity        = 9
    on_demand_target_capacity    = 5
    spot_target_capacity         = 4
  }

  excess_capacity_termination_policy = "termination"
  replace_unhealthy_instances = true
  terminate_instances = true

  # Additional configurations can be added as needed
}

response:
Here is the step-by-step thought process for the requested Terraform configuration:

1.  **Provider Setup**: Initialize the AWS provider to interact with AWS resources.
2.  **VPC and Networking**:
    *   Create a new VPC to isolate the infrastructure.
    *   Create **one public subnet** and **one private subnet** within the VPC.
    *   Create an Internet Gateway (IGW) and attach it to the VPC to allow public internet access.
    *   Create an Elastic IP and a NAT Gateway in the public subnet. This allows the private subnet to initiate outbound traffic (e.g., for updates) while remaining inaccessible from the internet.
    *   Configure Route Tables:
        *   **Public Route Table**: Route traffic to the Internet Gateway.
        *   **Private Route Table**: Route traffic to the NAT Gateway.
    *   Associate the respective subnets with their route tables.
3.  **Data Source - AMI**: Use a `data "aws_ami"` block to dynamically fetch the latest Amazon Linux 2 AMI ID owned by Amazon.
4.  **Security Group**: Create a basic security group allowing SSH access (for demonstration) and standard HTTP/HTTPS traffic if needed.
5.  **Launch Template**: Define a `aws_launch_template` that references the fetched AMI, a default instance type (e.g., `t3.micro`), and the security group. This template standardizes the configuration for the fleet.
6.  **EC2 Fleet**: Configure the `aws_ec2_fleet` resource:
    *   Set the `launch_template_config` to use the template created above and target both subnets (though distribution isn't strictly specified, using the available subnets is standard practice).
    *   Set the `target_capacity_specification`:
        *   `total_target_capacity`: 9 (5 On-Demand + 4 Spot).
        *   `on_demand_target_capacity`: 5.
        *   `spot_target_capacity`: 4.
        *   `default_target_capacity_type`: `on-demand`.
    *   Set `type` to `maintain` to ensure the fleet replaces any terminated instances to maintain the count.

