  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# Create the Cluster Placement Group
# Cluster placement groups pack instances close together inside an Availability Zone.
resource "aws_placement_group" "cluster_pg" {
  name     = "tf-cluster-placement-group"
  strategy = "cluster"
}

# Launch 3 EC2 Instances in the Placement Group
# Note: Cluster placement groups require that instances be in the same Availability Zone.
# We select the first available subnet from the default VPC to ensure this.
resource "aws_instance" "web" {
  count           = 3
  ami             = data.aws_ami.amazon_linux_2.id
  instance_type   = "t2.micro"
  placement_group = aws_placement_group.cluster_pg.id
  subnet_id       = tolist(data.aws_subnets.default.ids)[0]

  tags = {
    Name = "WebServer-${count.index + 1}"
  }
}

