provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# Data Sources: Fetch existing VPC and Subnets to deploy the cache securely
# ------------------------------------------------------------------------------
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "private" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# ------------------------------------------------------------------------------
# Security Group: Controls access to the Redis Cluster
# ------------------------------------------------------------------------------
resource "aws_security_group" "redis_sg" {
  name        = "redis-cache-sg"
  description = "Security group for Redis Cache Cluster"
  vpc_id      = data.aws_vpc.default.id

  # Allow inbound Redis traffic from within the VPC (e.g., your EC2/ECS/Fargate instances)
  ingress {
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = [data.aws_vpc.default.cidr_block]
  }

  # Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redis-cache-sg"
  }
}

# ------------------------------------------------------------------------------
# ElastiCache Subnet Group: Defines which subnets the cache resides in
# ------------------------------------------------------------------------------
resource "aws_elasticache_subnet_group" "redis_subnet_group" {
  name        = "tf-redis-subnet-group"
  description = "Subnet group for Redis cluster"
  subnet_ids  = data.aws_subnets.private.ids
}

# ------------------------------------------------------------------------------
# ElastiCache Replication Group: Deploys the Redis Cluster
# ------------------------------------------------------------------------------
resource "aws_elasticache_replication_group" "redis_cluster" {
  replication_group_id          = "tf-replication-group"
  replication_group_description = "Redis cluster for caching to reduce DB load"

  # Engine Configuration
  engine               = "redis"
  engine_version       = "6.x"
  node_type            = "cache.t3.micro"
  number_cache_clusters = 1 # Set to > 1 for Multi-AZ with automatic failover
  port                 = 6379

  # Network Configuration
  subnet_group_name    = aws_elasticache_subnet_group.redis_subnet_group.name
  security_group_ids   = [aws_security_group.redis_sg.id]

  # Parameter and Maintenance
  parameter_group_name = "default.redis6.x"
  apply_immediately    = true
  snapshot_window      = "03:00-05:00"

  tags = {
    Purpose = "DB-Query-Reduction"
  }
}

# ------------------------------------------------------------------------------
# Outputs
# ------------------------------------------------------------------------------
output "redis_endpoint" {
  description = "The primary endpoint address of the Redis cluster"
  value       = aws_elasticache_replication_group.redis_cluster.primary_endpoint_address
}

