provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# 1. Network Configuration (Prerequisites)
# ------------------------------------------------------------------------------

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "elasticache-iam-vpc"
  }
}

resource "aws_subnet" "subnet_1" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "elasticache-subnet-1"
  }
}

resource "aws_subnet" "subnet_2" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "elasticache-subnet-2"
  }
}

resource "aws_elasticache_subnet_group" "main" {
  name        = "redis-subnet-group"
  subnet_ids  = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  tags = {
    Name = "redis-subnet-group"
  }
}

resource "aws_security_group" "redis" {
  name_prefix = "redis-sg-"
  description = "Security group for ElastiCache Redis"
  vpc_id      = aws_vpc.main.id

  # Allow ingress from within the VPC on port 6379
  ingress {
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  tags = {
    Name = "redis-security-group"
  }
}

# ------------------------------------------------------------------------------
# 2. ElastiCache User (The IAM Identity)
# ------------------------------------------------------------------------------

# We create a user that does NOT require a password.
# When using IAM Auth, the user provides an IAM token instead of a static password.
resource "aws_elasticache_user" "app_user" {
  user_id       = "iam-user-id"
  user_name     = "app_user"
  access_string = "on ~* &* +@all" # Access control string (ACL rules)
  engine        = "REDIS"
  no_password_required = true # Essential for IAM-only authentication
}

# ------------------------------------------------------------------------------
# 3. ElastiCache User Group
# ------------------------------------------------------------------------------

# Users must be added to a User Group, which is then assigned to the Cluster.
resource "aws_elasticache_user_group" "app_group" {
  user_group_id = "app-user-group"
  engine        = "REDIS"
  user_ids      = [aws_elasticache_user.app_user.user_id]
}

# ------------------------------------------------------------------------------
# 4. ElastiCache Replication Group (Cluster)
# ------------------------------------------------------------------------------

resource "aws_elasticache_replication_group" "redis_cluster" {
  replication_group_id          = "redis-iam-cluster"
  description                   = "Redis cluster with IAM Authentication"

  # Engine Configuration
  engine                        = "redis"
  engine_version                = "6.2" # IAM requires version 6.x or higher
  node_type                     = "cache.t3.micro"
  num_cache_clusters            = 1
  parameter_group_name          = "default.redis6.x"

  # Network Configuration
  subnet_group_name             = aws_elasticache_subnet_group.main.name
  security_group_ids            = [aws_security_group.redis.id]

  # IAM Authentication Configuration
  # 1. Transit encryption MUST be enabled for IAM authentication
  transit_encryption_enabled    = true

  # 2. Attach the User Group created earlier
  user_group_ids                = [aws_elasticache_user_group.app_group.id]

  # Note: 'auth_token' is not used here because we are relying on User Groups 
  # and IAM tokens for the default user or specific users.
}

# ------------------------------------------------------------------------------
# 5. IAM Policy (Client Permissions)
# ------------------------------------------------------------------------------

# This is the policy that needs to be attached to the EC2/Lambda/Role
# that is trying to connect to the Redis instance.
data "aws_iam_policy_document" "elasticache_connect" {
  statement {
    actions = [
      "elasticache:Connect"
    ]
    resources = [
      aws_elasticache_replication_group.redis_cluster.arn
    ]
  }
}

resource "aws_iam_policy" "elasticache_connect_policy" {
  name        = "ElastiCacheRedisConnectPolicy"
  description = "Policy to allow connecting to Redis via IAM"
  policy      = data.aws_iam_policy_document.elasticache_connect.json
}

# Output connection details for reference
output "redis_endpoint" {
  description = "The primary endpoint address of the Redis cluster"
  value       = aws_elasticache_replication_group.redis_cluster.primary_endpoint_address
}

output "iam_user_id" {
  description = "The ID of the ElastiCache user to use as the username"
  value       = aws_elasticache_user.app_user.user_id
}

