  user_id   = "user_one_id"
  username  = "user_one"
  engine    = "redis"
  access_string = "on ~* +@all"

  authentication_mode {
    type = "no-password"
  }
}

# Create the second ElastiCache User
resource "aws_elasticache_user" "user_two" {
  user_id   = "user_two_id"
  username  = "user_two"
  engine    = "redis"
  access_string = "on ~* +@all"

  authentication_mode {
    type = "no-password"
  }
}

# Create the third ElastiCache User
resource "aws_elasticache_user" "user_three" {
  user_id   = "user_three_id"
  username  = "user_three"
  engine    = "redis"
  access_string = "on ~* +@all"

  authentication_mode {
    type = "no-password"
  }
}

# Create the ElastiCache User Group including the three users
