# Step 1: Define the provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Step 2: Retrieve Default VPC and Subnets to ensure resources are placed in a network
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# Step 3: Create IAM Role required by DAX to access DynamoDB
resource "aws_iam_role" "dax_role" {
  name = "dax-access-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dax.amazonaws.com"
        }
      }
    ]
  })
}

# Step 4: Attach Policy to the IAM Role
resource "aws_iam_role_policy_attachment" "dax_policy" {
  role       = aws_iam_role.dax_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonDynamoDBFullAccess"
}

# Step 5: Create a Security Group for the DAX Cluster
resource "aws_security_group" "dax_sg" {
  name        = "dax-security-group"
  description = "Allow inbound traffic for DAX"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 8111
    to_port     = 8111
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Step 6: Create a Subnet Group for DAX
resource "aws_dax_subnet_group" "example" {
  name       = "dax-subnet-group"
  subnet_ids = data.aws_subnets.default.ids
}

# Step 7: Provision the DAX Cluster
resource "aws_dax_cluster" "example" {
  cluster_name             = "terraform-dax-cluster"
  iam_role_arn             = aws_iam_role.dax_role.arn
  node_type                = "dax.r4.large"
  replication_factor       = 1
  subnet_group_name        = aws_dax_subnet_group.example.name
  security_group_ids       = [aws_security_group.dax_sg.id]

  tags = {
    Environment = "example"
  }
}

