response:
Here is the step-by-step reasoning for the requested Terraform configuration:

1.  **Define the Provider**: We need to configure the AWS provider and explicitly set the region to `us-east-1` as requested.
2.  **Create Networking Resources**: Amazon MSK requires a VPC and subnets to deploy the broker nodes. To support high availability with 3 brokers, we will create a VPC and three subnets spread across three different Availability Zones (`us-east-1a`, `us-east-1b`, `us-east-1c`).
3.  **Configure Security**: We need a Security Group to control access to the Kafka cluster. We will open the standard Kafka port (9094) for PLAINTEXT/TLS traffic.
4.  **Set Up Logging (Optional but Recommended)**: MSK integrates with CloudWatch for logging. We need a CloudWatch Log Group and an IAM Role that allows MSK to write logs to it.
5.  **Create the MSK Cluster**: This is the core resource.
    *   `cluster_name`: A unique identifier.
    *   `kafka_version`: A recent stable version.
    *   `number_of_broker_nodes`: Set to **3** as requested.
    *   `broker_node_group_info`: Defines the instance type (e.g., `kafka.m5.large`), the subnets created in step 2, and the security group from step 3.
    *   `encryption_info`: We will enable encryption in transit.
    *   `client_authentication`: We will enable SASL/SCRAM for a secure but standard authentication setup.
    *   `logging_info`: Links the cluster to the CloudWatch Log Group and IAM Role.

Here is the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# 1. Networking (VPC and Subnets)
# ------------------------------------------------------------------------------
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

# Create 3 subnets in 3 different Availability Zones for High Availability
resource "aws_subnet" "msk_subnet" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone       = element(["us-east-1a", "us-east-1b", "us-east-1c"], count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-${count.index + 1}"
  }
}

# ------------------------------------------------------------------------------
# 2. Security
# ------------------------------------------------------------------------------
resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow inbound traffic for MSK"
  vpc_id      = aws_vpc.msk_vpc.id

  # Kafka brokers typically communicate on port 9094 (with encryption) or 9092
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-security-group"
  }
}

# ------------------------------------------------------------------------------
# 3. Logging Configuration
# ------------------------------------------------------------------------------
resource "aws_cloudwatch_log_group" "msk_log_group" {
  name              = "/aws/msk/cluster/logs"
  retention_in_days = 7
}

# IAM Role for MSK to write logs to CloudWatch
data "aws_iam_policy_document" "msk_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["kafka.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "msk_logging_role" {
  name               = "msk-logging-role"
  assume_role_policy = data.aws_iam_policy_document.msk_assume_role.json
}

# Attach the policy to allow logging
resource "aws_iam_role_policy_attachment" "msk_logging_policy" {
  role       = aws_iam_role.msk_logging_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonMSKClusterServiceRolePolicy"
}

# ------------------------------------------------------------------------------
# 4. Amazon MSK Cluster
# ------------------------------------------------------------------------------
resource "aws_msk_cluster" "main" {
  cluster_name           = "terraform-msk-cluster"
  kafka_version          = "3.6.1"
  number_of_broker_nodes = 3

  # Configuration for the broker nodes
  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_sg.id]

    # Storage configuration
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  # Encryption settings
  encryption_info {
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  # Client Authentication (SASL/SCRAM)
  client_authentication {
    sasl {
      scram = true
    }
  }

  # Logging settings
  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_log_group.name
      }
    }
  }

  # IAM Role required for the cluster to manage itself and log
  configuration_info {
    arn      = aws_msk_configuration.example.arn
    revision = aws_msk_configuration.example.latest_revision
  }

  # Ensure the role exists before the cluster
  depends_on = [aws_iam_role_policy_attachment.msk_logging_policy]

  tags = {
    Environment = "Production"
  }
}

# MSK Configuration Resource (custom Kafka settings)
resource "aws_msk_configuration" "example" {
  kafka_versions = ["3.6.1"]
  name           = "msk-config"

  server_properties = <<PROPERTIES
auto.create.topics.enable=true
default.replication.factor=3
min.insync.replicas=2
num.network.threads=3
num.io.threads=8
socket.send.buffer.bytes=102400
socket.receive.buffer.bytes=102400
socket.request.max.bytes=104857600
num.partitions=1
num.recovery.threads.per.data.dir=1
log.retention.hours=168
log.segment.bytes=1073741824
log.retention.check.interval.ms=300000
zookeeper.connect.timeout.ms=18000
PROPERTIES
}
```

