response:
Here is the step-by-step thought process to generate the Terraform configuration:

1.  **Provider Configuration**: Define the AWS provider and explicitly set the region to `us-east-2` (Ohio) as requested.
2.  **Networking Foundation**: MSK clusters require a VPC and subnets.
    *   Create a VPC with a standard CIDR block (e.g., `10.0.0.0/16`).
    *   Retrieve available Availability Zones in `us-east-2` using a data source to ensure high availability.
    *   Create three subnets, each in a distinct Availability Zone, to satisfy the requirement for three broker instances (AWS recommends one subnet per AZ for brokers).
3.  **Security Group**: Create a Security Group to control access to the Kafka cluster.
    *   Allow inbound traffic on the default Kafka port (9094) for client access.
4.  **MSK Cluster Configuration**: Define the `aws_msk_cluster` resource.
    *   Set `number_of_broker_nodes` to `3`.
    *   Specify a Kafka version (e.g., `3.5.1`).
    *   Configure `broker_node_group_info`:
        *   Attach the previously created subnets and security group.
        *   Define an instance type (e.g., `kafka.m5.large`).
        *   Configure EBS storage volume size.
5.  **Encryption & Access**: Configure basic settings for encryption. For this example, we will use `PLAINTEXT` for encryption in transit to keep the configuration standalone without requiring ACM certificates, and use default AWS service-side encryption for encryption at rest.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-2"
}

# Fetch available Availability Zones to distribute the brokers
data "aws_availability_zones" "available" {
  state = "available"
}

# Create a VPC for the MSK cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

# Create 3 subnets in different AZs (one for each broker)
resource "aws_subnet" "msk_subnet" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = "10.0.${count.index + 1}.0/24"
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-${count.index + 1}"
  }
}

# Security Group to allow access to the Kafka brokers
resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow inbound traffic for MSK"
  vpc_id      = aws_vpc.msk_vpc.id

  # Allow Kafka traffic on default plaintext port (9094)
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow Kafka traffic on default plaintext port (9092)
  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-security-group"
  }
}

# Provision the Amazon MSK Cluster
resource "aws_msk_cluster" "example" {
  cluster_name           = "terraform-msk-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  # Configuration for Encryption
  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk.arn

    encryption_in_transit {
      client_broker = "PLAINTEXT"
      in_cluster    = true
    }
  }

  tags = {
    Name = "terraform-msk-cluster"
  }
}

# KMS Key required for MSK encryption at rest
resource "aws_kms_key" "msk" {
  description = "MSK Cluster Key"
}

resource "aws_kms_alias" "msk" {
  name          = "alias/msk-key"
  target_key_id = aws_kms_key.msk.key_id
}
