response:
Toprovision an Amazon MSK cluster in `us-east-1` with logging enabled for CloudWatch Logs, we need to perform the following steps:

1.  **Configure the AWS Provider**: Set the region to `us-east-1`.
2.  **Create Networking Resources**: MSK requires a VPC and subnets (at least 3 in different Availability Zones for high availability). We also need a Security Group to allow traffic.
3.  **Create the CloudWatch Log Group**: This is the destination for the logs.
4.  **Create IAM Service-Linked Role**: MSK requires specific permissions to write logs to CloudWatch. The standard way to provide this via Terraform is by creating the Service-Linked Role for MSK (`kafka.amazonaws.com`), as the `aws_msk_cluster` resource does not accept a custom IAM role ARN as an argument.
5.  **Provision the MSK Cluster**: Define the cluster configuration, including the broker nodes, client subnets, security groups, and the specific `logging_info` block referencing the CloudWatch Log Group.

Here is the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# 1. Networking Setup (VPC, Subnets, Security Group)
# ------------------------------------------------------------------------------

# Fetch available Availability Zones
data "aws_availability_zones" "available" {
  state = "available"
}

# Create VPC
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "msk-vpc"
  }
}

# Create 3 Subnets (Required for Multi-AZ MSK)
resource "aws_subnet" "msk_subnet" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-${count.index}"
  }
}

# Create Security Group for MSK
resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow inbound traffic for MSK"
  vpc_id      = aws_vpc.msk_vpc.id

  # Inbound rule for Kafka broker access (plaintext for example, usually 9094 for TLS)
  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-sg"
  }
}

# ------------------------------------------------------------------------------
# 2. CloudWatch Logs
# ------------------------------------------------------------------------------

resource "aws_cloudwatch_log_group" "msk_logs" {
  name              = "/aws/msk/cluster/logs"
  retention_in_days = 7

  tags = {
    Name = "msk-cloudwatch-logs"
  }
}

# ------------------------------------------------------------------------------
# 3. IAM Service-Linked Role
# ------------------------------------------------------------------------------

# MSK requires a Service-Linked Role to publish logs to CloudWatch.
# If this role does not exist, the cluster creation will fail logging setup.
resource "aws_iam_service_linked_role" "msk_role" {
  aws_service_name = "kafka.amazonaws.com"
  description      = "Service-linked role for Amazon MSK to manage CloudWatch Logs."

  # Attempt to create only if it doesn't exist to avoid conflicts
  # Note: In production, you might want to manage this externally or ignore errors if it exists.
}

# ------------------------------------------------------------------------------
# 4. Amazon MSK Cluster
# ------------------------------------------------------------------------------

resource "aws_msk_cluster" "example" {
  cluster_name           = "terraform-msk-logging-example"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  # Broker Node Configuration
  broker_node_group_info {
    instance_type   = "kafka.t3.small"
    client_subnets  = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_sg.id]

    # Storage configuration
    storage_info {
      ebs_storage_info {
        volume_size = 20
      }
    }
  }

  # Logging Configuration
  logging_info {
    broker_logs {
      cloudwatch_logs {
        log_group_arn = aws_cloudwatch_log_group.msk_logs.arn
        enabled       = true
      }
    }
  }

  # Encryption Info (Optional but recommended)
  encryption_info {
    encryption_at_rest_kms_key_id = null # Uses AWS managed key

    encryption_in_transit {
      client_broker = "PLAINTEXT"
      in_cluster    = true
    }
  }

  # Client Authentication (Optional - Unauthenticated for demo purposes)
  client_authentication {
    sasl {
      scram = false
    }
    tls_certificate_authority_arns = []
  }

  tags = {
    Name = "terraform-msk-cluster"
  }
}
