provider "aws" {
  region = "us-east-1"
}

# Generate a random suffix to ensure unique resource names
resource "random_pet" "this" {
  length = 2
}

# Data source for available availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

# --- Networking ---

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc-${random_pet.this.id}"
  }
}

# Create 2 subnets in different AZs (MSK requirement)
resource "aws_subnet" "msk_subnet" {
  count                   = 2
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-${count.index}-${random_pet.this.id}"
  }
}

resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group-${random_pet.this.id}"
  description = "Allow MSK inbound traffic"
  vpc_id      = aws_vpc.msk_vpc.id

  # Kafka plaintext traffic
  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  # Kafka encrypted traffic (SASL/SSL)
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  # Zookeeper access (if needed internally)
  ingress {
    from_port   = 2181
    to_port     = 2181
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-sg-${random_pet.this.id}"
  }
}

# --- S3 Logging ---

resource "aws_s3_bucket" "msk_logs" {
  bucket = "msk-logs-${random_pet.this.id}"

  tags = {
    Name = "msk-logs-${random_pet.this.id}"
  }
}

resource "aws_s3_bucket_ownership_controls" "msk_logs" {
  bucket = aws_s3_bucket.msk_logs.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "msk_logs" {
  depends_on = [aws_s3_bucket_ownership_controls.msk_logs]

  bucket = aws_s3_bucket.msk_logs.id
  acl    = "private"
}

resource "aws_s3_bucket_policy" "allow_msk_logging" {
  bucket = aws_s3_bucket.msk_logs.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "kafka.amazonaws.com"
        }
        Action   = "s3:PutObject"
        Resource = "${aws_s3_bucket.msk_logs.arn}/*"
      }
    ]
  })
}

# --- MSK Cluster ---

resource "aws_msk_cluster" "main" {
  cluster_name           = "msk-cluster-${random_pet.this.id}"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  # Encryption settings (default encryption at rest)
  encryption_info {
    encryption_at_rest_kms_key_id = aws_kms_key.msk.arn
  }

  # Configuration for logging to S3
  logging_info {
    broker_logs {
      s3 {
        bucket = aws_s3_bucket.msk_logs.id
        prefix = "logs/msk-"
        enabled = true
      }
    }
  }

  tags = {
    Name = "msk-cluster-${random_pet.this.id}"
  }
}

# KMS Key for encryption at rest (optional but recommended)
resource "aws_kms_key" "msk" {
  description             = "MSK Cluster Key"
  deletion_window_in_days = 10
}

resource "aws_kms_alias" "msk" {
  name          = "alias/msk-${random_pet.this.id}"
  target_key_id = aws_kms_key.msk.key_id
}

# --- Outputs ---

output "msk_cluster_arn" {
  value = aws_msk_cluster.main.arn
}

output "msk_bootstrap_brokers_plaintext" {
  value = aws_msk_cluster.main.bootstrap_brokers
}

