    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-security-group"
  }
}

# ------------------------------------------------------------------------------
# 2. Kinesis Data Firehose Setup
# ------------------------------------------------------------------------------

# S3 Bucket for Firehose to dump logs
resource "aws_s3_bucket" "log_bucket" {
  bucket = "msk-firehose-logs-unique-id-123"
}

# IAM Role for Firehose to access S3
resource "aws_iam_role" "firehose_role" {
  name = "msk-firehose-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# Policy allowing Firehose to write to S3
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-s3-access"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.log_bucket.arn,
          "${aws_s3_bucket.log_bucket.arn}/*"
        ]
      }
    ]
  })
}

# The Kinesis Data Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "msk_log_stream" {
  name        = "msk-broker-logs-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.log_bucket.arn

    # Buffering hints are optional but recommended
    buffer_size     = 5
    buffer_interval = 300
  }
}

# ------------------------------------------------------------------------------
# 3. MSK Service Linked Role & Permissions
# ------------------------------------------------------------------------------

# Ensure the MSK Service Linked Role exists
resource "aws_iam_service_linked_role" "msk_slr" {
  aws_service_name = "kafka.amazonaws.com"
  description      = "Service Linked Role for Amazon MSK"
}

# Policy to allow MSK to write to the specific Firehose stream
# We attach this to the Service Linked Role
resource "aws_iam_role_policy" "msk_firehose_logging_policy" {
  name = "msk-firehose-logging-policy"
  role = aws_iam_service_linked_role.msk_slr.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "firehose:PutRecord",
          "firehose:PutRecordBatch"
        ]
        Resource = aws_kinesis_firehose_delivery_stream.msk_log_stream.arn
      }
    ]
  })
}

# ------------------------------------------------------------------------------
# 4. Amazon MSK Cluster
# ------------------------------------------------------------------------------

resource "aws_msk_cluster" "main" {
  cluster_name           = "terraform-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 2

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = [aws_subnet.msk_subnet_1.id, aws_subnet.msk_subnet_2.id]
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 20
      }
    }
  }

  # Configuration for sending logs to Firehose
  logging_info {
    broker_logs {
      firehose {
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_log_stream.arn
        enabled         = true
      }
    }
  }

  # Wait for the SLR and Policy to be ready before creating cluster
  depends_on = [
    aws_iam_role_policy.msk_firehose_logging_policy,
    aws_kinesis_firehose_delivery_stream.msk_log_stream
  ]

  tags = {
    Name = "terraform-msk-cluster"
  }
}

