response:
To fulfill the request, we need to provision an Amazon MSK (Managed Streaming for Kafka) cluster with a specific focus on enabling encryption for data at rest.

Here is the step-by-step plan:

1.  **Network Infrastructure**: MSK requires a VPC and subnets in at least two different Availability Zones to ensure high availability. We will create a VPC and two subnets.
2.  **Security Group**: We will create a security group to control access to the cluster brokers (although we will keep the rules open for this demonstration).
3.  **KMS Key**: To demonstrate encryption at rest explicitly, we will provision a Customer Managed KMS Key.
4.  **KMS Key Policy**: This is a critical step. We must attach a policy to the KMS key allowing the Amazon MSK service principal (`kafka.amazonaws.com`) to use the key for encryption and decryption operations.
5.  **MSK Cluster**: We will define the `aws_msk_cluster` resource. Inside the `encryption_info` block, we will specify the `encryption_at_rest_kms_key_arn` pointing to our created KMS key.

Here is the complete Terraform configuration in a single code block:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# 1. Network Infrastructure (VPC & Subnets)
# ------------------------------------------------------------------------------

resource "aws_vpc" "msk_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "msk-vpc"
  }
}

# Create two subnets in different Availability Zones (required for MSK)
resource "aws_subnet" "msk_subnet" {
  count             = 2
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone = element(["us-east-1a", "us-east-1b"], count.index)

  tags = {
    Name = "msk-subnet-${count.index}"
  }
}

# ------------------------------------------------------------------------------
# 2. Security Group
# ------------------------------------------------------------------------------

resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow traffic for MSK cluster"
  vpc_id      = aws_vpc.msk_vpc.id

  # Inbound rules (Open for demonstration purposes)
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Outbound rules
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-sg"
  }
}

# ------------------------------------------------------------------------------
# 3. KMS Key for Encryption at Rest
# ------------------------------------------------------------------------------

resource "aws_kms_key" "msk_encryption_key" {
  description             = "KMS key for MSK cluster encryption at rest"
  deletion_window_in_days = 10

  # Policy allows AWS MSK service to use this key
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable MSK Service Permissions"
        Effect = "Allow"
        Principal = {
          Service = "kafka.amazonaws.com"
        }
        Action = [
          "kms:CreateGrant",
          "kms:Decrypt",
          "kms:DescribeKey",
          "kms:Encrypt",
          "kms:GenerateDataKey*",
          "kms:ReEncrypt*"
        ]
        Resource = "*"
      },
      {
        Sid    = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action   = "kms:*"
        Resource = "*"
      }
    ]
  })

  tags = {
    Name = "msk-encryption-key"
  }
}

resource "aws_kms_alias" "msk_key_alias" {
  name          = "alias/msk-key"
  target_key_id = aws_kms_key.msk_encryption_key.id
}

data "aws_caller_identity" "current" {}

# ------------------------------------------------------------------------------
# 4. Amazon MSK Cluster
# ------------------------------------------------------------------------------

resource "aws_msk_cluster" "example" {
  cluster_name           = "terraform-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 2

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_sg.id]

    # Storage configuration
    storage_info {
      ebs_storage_info {
        volume_size = 1000
      }
    }
  }

  # Configuration: Encryption at Rest
  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_encryption_key.arn

    # Also enabling encryption in transit (Best Practice)
    encryption_in_transit {
      client_broker = "TLS_PLAINTEXT"
      in_cluster    = true
    }
  }

  tags = {
    Name = "terraform-msk-cluster"
  }
}
