Here is the Terraform configuration to provision an Amazon MSK Serverless cluster.

This configuration includes the necessary networking resources (VPC and Subnets) required by MSK, a Security Group to allow traffic, and the `aws_msk_cluster` resource configured with the specific `serverless` block.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC for the MSK Cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "msk-serverless-vpc"
  }
}

# 2. Create two Subnets in different Availability Zones
# MSK Serverless requires at least 2 subnets in different AZs.
resource "aws_subnet" "msk_subnet" {
  count                   = 2
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone       = element(["us-east-1a", "us-east-1b"], count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-serverless-subnet-${count.index}"
  }
}

# 3. Create a Security Group for the cluster
resource "aws_security_group" "msk_sg" {
  name        = "msk-serverless-sg"
  description = "Allow inbound traffic for MSK Serverless"
  vpc_id      = aws_vpc.msk_vpc.id

  tags = {
    Name = "msk-serverless-sg"
  }
}

# 4. Create an Ingress Rule for the Security Group
# Opening port 9098 for IAM authentication (standard for MSK Serverless)
resource "aws_vpc_security_group_ingress_rule" "allow_msk_traffic" {
  security_group_id = aws_security_group.msk_sg.id
  cidr_ipv4         = aws_vpc.msk_vpc.cidr_block
  from_port         = 9098
  ip_protocol       = "tcp"
  to_port           = 9098
}

# 5. Provision the MSK Serverless Cluster
resource "aws_msk_cluster" "serverless_example" {
  cluster_name = "msk-serverless-cluster"
  kafka_version = "3.5.1"

  # Configure Client Authentication (IAM is recommended for Serverless)
  client_authentication {
    sasl {
      iam = true
    }
  }

  # Configure Encryption
  encryption_info {
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  # Serverless-specific configuration
  serverless {
    vpc_config {
      subnet_ids         = aws_subnet.msk_subnet[*].id
