extracted_code:
# ----------------------------------------------------------------------------
# Thought Process:
# 1. Analyze Request: The user wants an Amazon MSK "Serverless" cluster.
# 2. Conflict Identification: The user also requested "three broker nodes".
#    - In Amazon MSK, "Serverless" is a specific mode that abstracts away
#      infrastructure management. Users cannot specify the number of broker
#      nodes in Serverless mode; AWS automatically handles capacity.
#    - In "Provisioned" mode, users *can* specify the number of broker nodes.
# 3. Resolution: Since "MSK Serverless" is the primary noun phrase and the
#    specific product name requested, I will provision an `aws_msk_serverless_cluster`.
#    To respect the "three" requirement regarding availability/capacity, I will
#    provision the cluster across three distinct subnets (Availability Zones),
#    which is the best practice for high availability in MSK Serverless.
# ----------------------------------------------------------------------------

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
  required_version = ">= 1.0"
}

provider "aws" {
  region = "us-east-1"
}

# Data source to get available AZs
data "aws_availability_zones" "available" {
  state = "available"
}

# 1. Network Infrastructure
# MSK Serverless requires a VPC and Subnets.
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-serverless-vpc"
  }
}

# Create 3 Subnets across different AZs to honor the "three" aspect of the request
# for High Availability.
resource "aws_subnet" "msk_subnet" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-serverless-subnet-${count.index}"
  }
}

# Security Group to control access to the MSK cluster
resource "aws_security_group" "msk_security_group" {
  name        = "msk-serverless-sg"
  description = "Allow inbound traffic for MSK Serverless"
  vpc_id      = aws_vpc.msk_vpc.id

  # MSK Serverless typically uses port 9098
  ingress {
    from_port   = 9098
    to_port     = 9098
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-serverless-sg"
  }
}

# 2. MSK Serverless Cluster
# Note: The 'number_of_broker_nodes' argument does not exist for Serverless clusters.
# AWS automatically manages the broker infrastructure in Serverless mode.
resource "aws_msk_serverless_cluster" "example" {
  cluster_name = "msk-serverless-cluster"

  vpc_config {
    subnet_ids         = aws_subnet.msk_subnet[*].id
    security_group_ids = [aws_security_group.msk_security_group.id]
  }

  tags = {
    Environment = "Production"
  }
}

# Output the Cluster ARN
output "msk_serverless_cluster_arn" {
  description = "The ARN of the MSK Serverless cluster"
  value       = aws_msk_serverless_cluster.example.arn
}

