}

# 1. Create a VPC to host the MSK cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-serverless-vpc"
  }
}

# 2. Create 3 Subnets across different Availability Zones
# Note: MSK Serverless requires subnets in at least 2 AZs. 
# We use 3 to align with the user's request for "three instances/brokers" logic for High Availability.
resource "aws_subnet" "msk_subnet" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = element(["us-east-1a", "us-east-1b", "us-east-1c"], count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-serverless-subnet-${count.index + 1}"
  }
}

# 3. Create a Security Group for the cluster
resource "aws_security_group" "msk_sg" {
  name        = "msk-serverless-sg"
  description = "Security group for Amazon MSK Serverless cluster"
  vpc_id      = aws_vpc.msk_vpc.id

  # Allow inbound traffic on the Kafka port (9098 is standard for MSK Serverless)
  ingress {
    from_port   = 9098
    to_port     = 9098
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-serverless-sg"
  }
}

# 4. Create the Amazon MSK Serverless Cluster
# Note: In Serverless mode, the number of broker instances is managed by AWS 
# and scales automatically. We cannot set a fixed count (e.g., 3), but 
# distributing across 3 subnets ensures the infrastructure spans 3 zones.
resource "aws_msk_serverless_cluster" "main" {
  cluster_name = "msk-serverless-cluster"

  vpc_config {
    subnet_ids         = aws_subnet.msk_subnet[*].id
    security_group_ids = [aws_security_group.msk_sg.id]
  }

  tags = {
    Environment = "Production"
  }
}

