    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_az3" {
    availability_zone = data.aws_availability_zones.azs.names[2]
    cidr_block = "192.168.2.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.vpc.id
}

resource "aws_route_table" "main" {
  vpc_id = aws_vpc.vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
}

resource "aws_route_table_association" "first" {
  subnet_id      = aws_subnet.subnet_az1.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "second" {
  subnet_id      = aws_subnet.subnet_az2.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "third" {
  subnet_id      = aws_subnet.subnet_az3.id
  route_table_id = aws_route_table.main.id
}

resource "aws_security_group" "sg" {
    vpc_id = aws_vpc.vpc.id
}

resource "aws_vpc_security_group_ingress_rule" "ingress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4 = "0.0.0.0/0"
  ip_protocol = "-1"
}

resource "aws_vpc_security_group_egress_rule" "egress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4         = "0.0.0.0/0"
  ip_protocol       = "-1"
}

resource "aws_msk_serverless_cluster" "example" {
    cluster_name = "Example"

    vpc_config {
        subnet_ids = [aws_subnet.subnet_az1.id, aws_subnet.subnet_az2.id, aws_subnet.subnet_az3.id]
        security_group_ids = [aws_security_group.sg.id]
    }

    client_authentication {
        sasl {
            iam {
                enabled = true
            }
        }
    }
}

response:
To set up an Amazon MSK Serverless cluster in `us-east-2`, we need to perform the following steps:

1.  **Configure the AWS Provider**: Set the region to `us-east-2`.
2.  **Create Network Resources**: MSK requires a VPC and at least two subnets in different Availability Zones. We also need a Security Group to allow traffic on the Kafka ports (9094, 9095, 9096, 9098).
3.  **Create Logging Resources**: A CloudWatch Log Group is typically required for MSK cluster logs.
4.  **Create the MSK Cluster**: Use the `aws_msk_cluster` resource. To make it **Serverless**, we must omit the `broker_node_group_info` argument. We will configure a supported Kafka version (e.g., 2.8.2), enable SASL/SCRAM authentication, and configure encryption.

Here is the complete Terraform configuration.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-2"
}

# Data source for availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

# VPC
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-serverless-vpc"
  }
}

# Subnets (MSK requires subnets in at least 2 AZs)
resource "aws_subnet" "msk_subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-serverless-subnet-${count.index + 1}"
  }
}

# Security Group
resource "aws_security_group" "msk_sg" {
  name        = "msk-serverless-sg"
  description = "Security group for MSK Serverless cluster"
  vpc_id      = aws_vpc.msk_vpc.id

  # Inbound rules for Kafka broker ports
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
  ingress {
    from_port   = 9095
    to_port     = 9095
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
  ingress {
    from_port   = 9096
    to_port     = 9096
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
  ingress {
    from_port   = 9098
    to_port     = 9098
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Outbound rules
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-serverless-sg"
  }
}

# CloudWatch Log Group for broker logs
resource "aws_cloudwatch_log_group" "msk_logs" {
  name              = "/aws/msk/serverless/cluster"
  retention_in_days = 7
}

# MSK Serverless Cluster
resource "aws_msk_cluster" "serverless" {
  cluster_name           = "msk-serverless-example"
  kafka_version          = "2.8.2"
  # NOTE: Omit 'broker_node_group_info' to create a Serverless cluster

  encryption_info {
    encryption_at_rest_kms_key_arn     = "" # Uses AWS Managed KMS key if empty
    encryption_in_transit_kms_key_arn  = "" # Uses AWS Managed KMS key if empty

    in_transit_encryption_configuration {
      client_broker = "TLS_PLAINTEXT" # Options: TLS, TLS_PLAINTEXT, PLAINTEXT
    }
  }

  client_authentication {
    sasl {
      scram = true
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
    }
  }

  vpc_config {
    subnet_ids         = aws_subnet.msk_subnets[*].id
    security_group_ids = [aws_security_group.msk_sg.id]
  }

  tags = {
    Name = "msk-serverless-cluster"
  }
}

# Output the cluster ARN
output "cluster_arn" {
  description = "The ARN of the MSK Serverless cluster"
  value       = aws_msk_cluster.serverless.arn
}
```

extracted_code:
provider "aws" {
  region = "us-east-1"
}

# ---------------------------------------------------
# 1. Networking (VPC, Subnets, Security Group)
# ---------------------------------------------------

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.msk_vpc.id

  tags = {
    Name = "msk-igw"
  }
}

# Get available AZs
data "aws_availability_zones" "available" {
  state = "available"
}

# Create 3 Subnets in distinct AZs
resource "aws_subnet" "msk_subnet" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "msk-subnet-${count.index}"
  }
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.msk_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "msk-public-rt"
  }
}

resource "aws_route_table_association" "public_assoc" {
  count          = 3
  subnet_id      = aws_subnet.msk_subnet[count.index].id
  route_table_id = aws_route_table.public_rt.id
}

# Security Group for MSK
resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow traffic for MSK cluster"
  vpc_id      = aws_vpc.msk_vpc.id

  # Kafka Broker Port (PLAINTEXT)
  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Kafka Broker Port (TLS)
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Zookeeper Port (if needed for connectivity)
  ingress {
    from_port   = 2181
    to_port     = 2181
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-sg"
  }
}

# ---------------------------------------------------
# 2. Encryption (KMS Key)
# ---------------------------------------------------

resource "aws_kms_key" "msk_key" {
  description             = "MSK Cluster Encryption Key"
  deletion_window_in_days = 10

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action   = "kms:*"
        Resource = "*"
      },
      {
        Sid    = "Allow MSK to use the key"
        Effect = "Allow"
        Principal = {
          Service = "kafka.amazonaws.com"
        }
        Action = [
          "kms:GenerateDataKey",
          "kms:Decrypt",
          "kms:Encrypt"
        ]
        Resource = "*"
      }
    ]
  })
}

data "aws_caller_identity" "current" {}

# ---------------------------------------------------
# 3. Logging Destinations
# ---------------------------------------------------

# A. CloudWatch Logs
resource "aws_cloudwatch_log_group" "msk_log_group" {
  name              = "/aws/msk/cluster/logs"
  retention_in_days = 7
}

# B. S3 Bucket (Direct MSK Logs)
resource "aws_s3_bucket" "msk_logs_bucket" {
  bucket = "msk-cluster-logs-unique-id-12345"
}

resource "aws_s3_bucket_ownership_controls" "msk_logs_bucket_ownership" {
  bucket = aws_s3_bucket.msk_logs_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "msk_logs_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.msk_logs_bucket_ownership]
  bucket     = aws_s3_bucket.msk_logs_bucket.id
  acl        = "private"
}

# C. Kinesis Firehose
# Firehose needs its own S3 bucket for delivery
resource "aws_s3_bucket" "firehose_destination_bucket" {
  bucket = "firehose-msk-logs-unique-id-67890"
}

resource "aws_s3_bucket_ownership_controls" "firehose_bucket_ownership" {
  bucket = aws_s3_bucket.firehose_destination_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "firehose_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.firehose_bucket_ownership]
  bucket     = aws_s3_bucket.firehose_destination_bucket.id
  acl        = "private"
}

# IAM Role for Firehose to write to S3
resource "aws_iam_role" "firehose_role" {
  name = "firehose_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "firehose_s3_access" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess" # Keeping it broad for demo, scope down in prod
}

resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-log-delivery-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_destination_bucket.arn
  }
}

# ---------------------------------------------------
# 4. IAM Permissions for MSK Service-Linked Role
# ---------------------------------------------------

# Ensure the Service-Linked Role exists
resource "aws_iam_service_linked_role" "msk_slr" {
  aws_service_name = "kafka.amazonaws.com"
  description      = "Service-Linked Role for Amazon MSK"
}

# Policy allowing MSK to write to CloudWatch, S3, and Firehose
resource "aws_iam_role_policy" "msk_logging_policy" {
  name = "msk-logging-permissions"
  role = aws_iam_service_linked_role.msk_slr.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "${aws_cloudwatch_log_group.msk_log_group.arn}:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject"
        ]
        Resource = "${aws_s3_bucket.msk_logs_bucket.arn}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "firehose:PutRecord"
        ]
        Resource = aws_kinesis_firehose_delivery_stream.msk_firehose.arn
      }
    ]
  })
}

# ---------------------------------------------------
# 5. MSK Cluster
# ---------------------------------------------------

resource "aws_msk_cluster" "example" {
  cluster_name           = "terraform-msk-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_key.arn
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_log_group.name
      }
      s3 {
        enabled = true
        bucket  = aws_s3_bucket.msk_logs_bucket.arn
        prefix  = "logs/msk/"
      }
      firehose {
        enabled         = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_firehose.name
      }
    }
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  client_authentication {
    sasl {
      scram = true
    }
  }
}

