terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_vpc" "vpc" {
    cidr_block = "192.168.0.0/22"
}

data "aws_availability_zones" "azs" {
    state = "available"
}

resource "aws_subnet" "subnet_az1" {
    availability_zone = data.aws_availability_zones.azs.names[0]
    cidr_block = "192.168.0.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_az2" {
    availability_zone = data.aws_availability_zones.azs.names[1]
    cidr_block = "192.168.1.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_subnet" "subnet_az3" {
    availability_zone = data.aws_availability_zones.azs.names[2]
    cidr_block = "192.168.2.0/24"
    vpc_id = aws_vpc.vpc.id
    map_public_ip_on_launch = true
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.vpc.id
}

resource "aws_route_table" "main" {
  vpc_id = aws_vpc.vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
}

resource "aws_route_table_association" "first" {
  subnet_id      = aws_subnet.subnet_az1.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "second" {
  subnet_id      = aws_subnet.subnet_az2.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "third" {
  subnet_id      = aws_subnet.subnet_az3.id
  route_table_id = aws_route_table.main.id
}

resource "aws_security_group" "sg" {
    vpc_id = aws_vpc.vpc.id
}

resource "aws_vpc_security_group_ingress_rule" "ingress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4 = "0.0.0.0/0"
  ip_protocol = "-1"
}

resource "aws_vpc_security_group_egress_rule" "egress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4         = "0.0.0.0/0"
  ip_protocol       = "-1"
}

resource "aws_kms_key" "kms" {
    description = "example"
}

resource "aws_cloudwatch_log_group" "test" {
    name = "msk_broker_logs"
}

resource "aws_s3_bucket" "bucket" {
    bucket_prefix = "msk-broker-logs-"
}

resource "aws_s3_bucket_ownership_controls" "example" {
    bucket = aws_s3_bucket.bucket.id
    rule {
        object_ownership = "BucketOwnerPreferred"
    }
}

resource "aws_s3_bucket_acl" "example" {
    depends_on = [aws_s3_bucket_ownership_controls.example]

    bucket = aws_s3_bucket.bucket.id
    acl = "private"
}

data "aws_iam_policy_document" "assume_role" {
    statement {
        effect = "Allow"
        principals {
            type = "Service"
            identifiers = ["firehose.amazonaws.com"]
        }
        actions = ["sts:AssumeRole"]
    }
}

resource "aws_iam_role" "firehose_role" {
    name = "firehose_test_role"
    assume_role_policy = data.aws_iam_policy_document.assume_role.json
}

resource "aws_kinesis_firehose_delivery_stream" "test_stream" {
    name = "terraform-kinesis-firehose-msk-broker-logs-stream"
    destination = "extended_s3"

    extended_s3_configuration {
        role_arn = aws_iam_role.firehose_role.arn
        bucket_arn = aws_s3_bucket.bucket.arn
    }

    tags = {
        LogDeliveryEnabled = "placeholder"
    }

    lifecycle {
        ignore_changes = [
            tags["LogDeliveryEnabled"],
        ]
    }
}

resource "aws_msk_cluster" "example" {
    cluster_name = "example"
    kafka_version = "3.2.0"
    number_of_broker_nodes = 3

    broker_node_group_info {
        instance_type = "kafka.t3.small"
        client_subnets = [
            aws_subnet.subnet_az1.id,
            aws_subnet.subnet_az2.id,
            aws_subnet.subnet_az3.id,
        ]
        storage_info {
            ebs_storage_info {
                volume_size = 1000
            }
        }
        security_groups = [aws_security_group.sg.id]
    }

    encryption_info {
        encryption_at_rest_kms_key_arn = aws_kms_key.kms.arn
    }

    open_monitoring {
        prometheus {
            jmx_exporter {
                enabled_in_broker = true
            }
            node_exporter {
                enabled_in_broker = true
            }
        }
    }

    logging_info {
        broker_logs {
            cloudwatch_logs {
                enabled = true
                log_group = aws_cloudwatch_log_group.test.name
            }
            firehose {
                enabled = true
                delivery_stream = aws_kinesis_firehose_delivery_stream.test_stream.name
            }
            s3 {
                enabled = true
                bucket = aws_s3_bucket.bucket.id
                prefix = "logs/msk-"
            }
        }
    }
}

output "zookeeper_connect_string" {
    value = aws_msk_cluster.example.zookeeper_connect_string
}

output "bootstrap_brokers_tls" {
    description = "TLS connection host:port pairs"
    value = aws_msk_cluster.example.bootstrap_brokers_tls
}

response:
Here is the step-by-step reasoning followed by the complete Terraform configuration.

### Step-by-Step Reasoning

1.  **Networking Foundation**:
    *   An Amazon MSK cluster requires a VPC and subnets. The subnets must be in distinct Availability Zones because MSK distributes broker nodes across them.
    *   I will create a VPC, an Internet Gateway, and 3 subnets (one for each broker).
    *   A Security Group is required to allow traffic to the Kafka brokers (typically ports 9094, 9092, 9096, etc.).

2.  **Encryption**:
    *   The request specifies "encryption at rest enabled". This requires a Customer Managed Key (CMK) in AWS KMS.
    *   I will create an `aws_kms_key` and grant the MSK service principal (`kafka.amazonaws.com`) permission to use it via a key policy.

3.  **Logging Destinations**:
    *   **CloudWatch Logs**: Create an `aws_cloudwatch_log_group`.
    *   **S3 Bucket (Direct)**: Create an `aws_s3_bucket` for MSK to deliver logs directly.
    *   **Kinesis Data Firehose**:
        *   Firehose needs a destination. I will create a second `aws_s3_bucket` to serve as the destination for Firehose.
        *   Create an IAM role that allows Firehose to write to this S3 bucket.
        *   Create the `aws_kinesis_firehose_delivery_stream` resource pointing to that S3 bucket and IAM role.

4.  **IAM Permissions for MSK**:
    *   MSK uses a Service-Linked Role to write logs to CloudWatch, S3, and Firehose.
    *   I will ensure the Service-Linked Role exists (`aws_iam_service_linked_role`).
    *   I need to attach a policy to this role that grants MSK permission to:
        *   Create log streams and put events into the CloudWatch Log Group.
        *   Put objects into the Direct S3 bucket.
        *   Put records into the Kinesis Firehose delivery stream.

5.  **MSK Cluster Configuration**:
    *   **Instance Count**: Set `number_of_broker_nodes` to `3`.
    *   **Broker Node Group**: Use `kafka.m5.large` (a common instance type) and assign the previously created subnets and security group.
    *   **Encryption Info**: Reference the KMS Key ARN.
    *   **Open Monitoring**: Enable the `prometheus` block with `jmx_exporter` enabled.
    *   **Logging Info**: Configure the `broker_logs` block to enable `cloudwatch_logs`, `s3`, and `firehose`, passing the ARNs of the resources created in step 3.

### Final Terraform Code

```hcl
provider "aws" {
  region = "us-east-1"
}

# ---------------------------------------------------
# 1. Networking (VPC, Subnets, Security Group)
# ---------------------------------------------------

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.msk_vpc.id

  tags = {
    Name = "msk-igw"
  }
}

# Get available AZs
data "aws_availability_zones" "available" {
  state = "available"
}

# Create 3 Subnets in distinct AZs
resource "aws_subnet" "msk_subnet" {
  count                   = 3
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "msk-subnet-${count.index}"
  }
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.msk_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "msk-public-rt"
  }
}

resource "aws_route_table_association" "public_assoc" {
  count          = 3
  subnet_id      = aws_subnet.msk_subnet[count.index].id
  route_table_id = aws_route_table.public_rt.id
}

# Security Group for MSK
resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow traffic for MSK cluster"
  vpc_id      = aws_vpc.msk_vpc.id

  # Kafka Broker Port (PLAINTEXT)
  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Kafka Broker Port (TLS)
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Zookeeper Port (if needed for connectivity)
  ingress {
    from_port   = 2181
    to_port     = 2181
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-sg"
  }
}

# ---------------------------------------------------
# 2. Encryption (KMS Key)
# ---------------------------------------------------

resource "aws_kms_key" "msk_key" {
  description             = "MSK Cluster Encryption Key"
  deletion_window_in_days = 10

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action   = "kms:*"
        Resource = "*"
      },
      {
        Sid    = "Allow MSK to use the key"
        Effect = "Allow"
        Principal = {
          Service = "kafka.amazonaws.com"
        }
        Action = [
          "kms:GenerateDataKey",
          "kms:Decrypt",
          "kms:Encrypt"
        ]
        Resource = "*"
      }
    ]
  })
}

data "aws_caller_identity" "current" {}

# ---------------------------------------------------
# 3. Logging Destinations
# ---------------------------------------------------

# A. CloudWatch Logs
resource "aws_cloudwatch_log_group" "msk_log_group" {
  name              = "/aws/msk/cluster/logs"
  retention_in_days = 7
}

# B. S3 Bucket (Direct MSK Logs)
resource "aws_s3_bucket" "msk_logs_bucket" {
  bucket = "msk-cluster-logs-unique-id-12345"
}

resource "aws_s3_bucket_ownership_controls" "msk_logs_bucket_ownership" {
  bucket = aws_s3_bucket.msk_logs_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "msk_logs_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.msk_logs_bucket_ownership]
  bucket     = aws_s3_bucket.msk_logs_bucket.id
  acl        = "private"
}

# C. Kinesis Firehose
# Firehose needs its own S3 bucket for delivery
resource "aws_s3_bucket" "firehose_destination_bucket" {
  bucket = "firehose-msk-logs-unique-id-67890"
}

resource "aws_s3_bucket_ownership_controls" "firehose_bucket_ownership" {
  bucket = aws_s3_bucket.firehose_destination_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "firehose_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.firehose_bucket_ownership]
  bucket     = aws_s3_bucket.firehose_destination_bucket.id
  acl        = "private"
}

# IAM Role for Firehose to write to S3
resource "aws_iam_role" "firehose_role" {
  name = "firehose_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "firehose_s3_access" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess" # Keeping it broad for demo, scope down in prod
}

resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-log-delivery-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_destination_bucket.arn
  }
}

# ---------------------------------------------------
# 4. IAM Permissions for MSK Service-Linked Role
# ---------------------------------------------------

# Ensure the Service-Linked Role exists
resource "aws_iam_service_linked_role" "msk_slr" {
  aws_service_name = "kafka.amazonaws.com"
  description      = "Service-Linked Role for Amazon MSK"
}

# Policy allowing MSK to write to CloudWatch, S3, and Firehose
resource "aws_iam_role_policy" "msk_logging_policy" {
  name = "msk-logging-permissions"
  role = aws_iam_service_linked_role.msk_slr.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "${aws_cloudwatch_log_group.msk_log_group.arn}:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject"
        ]
        Resource = "${aws_s3_bucket.msk_logs_bucket.arn}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "firehose:PutRecord"
        ]
        Resource = aws_kinesis_firehose_delivery_stream.msk_firehose.arn
      }
    ]
  })
}

# ---------------------------------------------------
# 5. MSK Cluster
# ---------------------------------------------------

resource "aws_msk_cluster" "example" {
  cluster_name           = "terraform-msk-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_key.arn
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_log_group.name
      }
      s3 {
        enabled = true
        bucket  = aws_s3_bucket.msk_logs_bucket.arn
        prefix  = "logs/msk/"
      }
      firehose {
        enabled         = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_firehose.name
      }
    }
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  client_authentication {
    sasl {
      scram = true
    }
  }
}
```

extracted_code:
# Step 1: Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Step 2: Create VPC and Networking Resources
# MSK requires a VPC with at least 3 subnets in distinct Availability Zones.
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

# Create 3 subnets for the 3 broker nodes
resource "aws_subnet" "msk_subnet" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = element(["us-east-1a", "us-east-1b", "us-east-1c"], count.index)

  tags = {
    Name = "msk-subnet-${count.index}"
  }
}

# Security Group for MSK Cluster
resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow traffic for MSK Cluster"
  vpc_id      = aws_vpc.msk_vpc.id

  # Allow inbound traffic within the VPC (for clients and MSK Connect)
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  # Allow broker-to-broker communication
  ingress {
    from_port = 9092
    to_port   = 9092
    protocol  = "tcp"
    self      = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-sg"
  }
}

# Step 3: Provision the Amazon MSK Cluster
resource "aws_msk_cluster" "example" {
  cluster_name           = "terraform-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.t3.small"
    client_subnets  = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 20
      }
    }
  }

  # Configuration for the cluster
  configuration_info {
    arn      = aws_msk_configuration.example.arn
    revision = aws_msk_configuration.example.latest_revision
  }

  encryption_info {
    encryption_at_rest_kms_key_id = aws_kms_key.msk.arn
    encryption_in_transit {
      client_broker = "PLAINTEXT" # Using PLAINTEXT for simplicity; TLS is recommended for production
    }
  }

  tags = {
    Name = "terraform-msk-cluster"
  }
}

# MSK Configuration
resource "aws_msk_configuration" "example" {
  kafka_versions = ["2.8.1"]
  name           = "msk-config"

  server_properties = <<PROPERTIES
auto.create.topics.enable=true
log.segment.bytes=1073741824
PROPERTIES
}

# KMS Key for encryption
resource "aws_kms_key" "msk" {
  description             = "MSK Cluster Key"
  deletion_window_in_days = 10
}

# Step 4: MSK Connect - S3 Bucket for Custom Plugin
resource "aws_s3_bucket" "plugin_bucket" {
  bucket = "msk-connect-plugins-bucket-unique-id"
}

# This resource represents the uploaded 'debezium.zip' file.
# Note: Ensure 'debezium.zip' exists locally in the working directory before running 'terraform apply'.
resource "aws_s3_object" "debezium_plugin" {
  bucket = aws_s3_bucket.plugin_bucket.id
  key    = "debezium.zip"
  source = "debezium.zip" 

  # This forces a refresh if the local file changes
  etag = filemd5("debezium.zip")
}

# IAM Role for MSK Connect
resource "aws_iam_role" "msk_connect_role" {
  name = "msk_connect_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafkaconnect.amazonaws.com"
        }
      }
    ]
  })
}

# Attach policy to allow MSK Connect to access S3 (for plugin) and CloudWatch (for logs)
resource "aws_iam_role_policy_attachment" "msk_connect_policy_attachment" {
  role       = aws_iam_role.msk_connect_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSKafkaConnectServiceRolePolicy"
}

# Step 5: Create MSK Connect Custom Plugin
resource "aws_mskconnect_custom_plugin" "debezium" {
  name         = "debezium-plugin"
  content_type = "ZIP"

  location {
    s3 {
      bucket_arn = aws_s3_bucket.plugin_bucket.arn
      file_key   = aws_s3_object.debezium_plugin.key
    }
  }

  depends_on = [ aws_s3_object.debezium_plugin ]
}

# Step 6: Deploy MSK Connect Connector
resource "aws_mskconnect_connector" "example" {
  name               = "debezium-connector"
  kafkaconnect_version = "2.8.1"

  capacity {
    provisioned {
      mcu_count    = 1
      worker_count = 1
    }
  }

  connector_configuration = {
    # Debezium Generic Example Properties
    "connector.class"                    = "io.debezium.connector.postgresql.PostgresConnector"
    "database.hostname"                  = "your-database-hostname.com"
    "database.port"                      = "5432"
    "database.user"                      = "dbuser"
    "database.password"                  = "dbpass"
    "database.dbname"                    = "dbname"
    "topic.prefix"                       = "debezium-"
    "plugin.name"                        = "pgoutput"

    # Common Connector Properties
    "tasks.max"                          = "1"
  }

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.example.bootstrap_brokers_sasl_iam

      vpc {
        subnet_ids = aws_subnet.msk_subnet[*].id
        security_groups_security_group_ids = [aws_security_group.msk_sg.id]
      }
    }
  }

  kafka_cluster_client_authentication {
    authentication_type = "IAM"
  }

  kafka_cluster_encryption {
    encryption_type = "SASL_SSL" # Must match the cluster encryption_in_transit and authentication
  }

  log_delivery {
    worker_log_delivery {
      cloudwatch_logs {
        enabled = true
        log_group {
          name = "/aws/msk/connect/debezium-connector"
        }
      }
    }
  }

  plugins {
    custom_plugin {
      arn      = aws_mskconnect_custom_plugin.debezium.arn
      revision = aws_mskconnect_custom_plugin.debezium.latest_revision
    }
  }

  service_execution_role_arn = aws_iam_role.msk_connect_role.arn
}

# Outputs
output "msk_cluster_arn" {
  description = "The ARN of the MSK Cluster"
  value       = aws_msk_cluster.example.arn
}

output "msk_bootstrap_servers" {
  description = "The Bootstrap Brokers SASL IAM"
  value       = aws_msk_cluster.example.bootstrap_brokers_sasl_iam
}

output "connector_arn" {
  description = "The ARN of the MSK Connect Connector"
  value       = aws_mskconnect_connector.example.arn
}

