```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ---------------------------------------------------
# Random Resources for Unique Naming
# ---------------------------------------------------
resource "random_pet" "this" {
  length = 2
}

# ---------------------------------------------------
# Networking Infrastructure
# ---------------------------------------------------
resource "aws_vpc" "this" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc-${random_pet.this.id}"
  }
}

resource "aws_subnet" "this" {
  count                   = 3
  vpc_id                  = aws_vpc.this.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "msk-subnet-${count.index}-${random_pet.this.id}"
  }
}

data "aws_availability_zones" "available" {}

resource "aws_security_group" "msk_broker" {
  name   = "msk-broker-sg-${random_pet.this.id}"
  vpc_id = aws_vpc.this.id

  # Kafka Broker Port
  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.this.cidr_block]
  }

  # Zookeeper Port (if applicable/access needed)
  ingress {
    from_port   = 2181
    to_port     = 2181
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.this.cidr_block]
  }

  # MSK Connect Access
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.this.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# ---------------------------------------------------
# Logging Infrastructure
# ---------------------------------------------------

# 1. CloudWatch Logs Group
resource "aws_cloudwatch_log_group" "msk" {
  name = "/aws/msk/cluster-${random_pet.this.id}"
}

# 2. S3 Bucket (for direct S3 logs and Firehose destination)
resource "aws_s3_bucket" "logs" {
  bucket = "msk-logs-bucket-${random_pet.this.id}"
}

resource "aws_s3_bucket_ownership_controls" "logs" {
  bucket = aws_s3_bucket.logs.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "logs" {
  depends_on = [aws_s3_bucket_ownership_controls.logs]
  bucket     = aws_s3_bucket.logs.id
  acl        = "private"
}

# 3. Kinesis Data Firehose
# IAM Role for Firehose
resource "aws_iam_role" "firehose" {
  name = "msk-firehose-role-${random_pet.this.id}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "firehose" {
  role       = aws_iam_role.firehose.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonKinesisFirehoseServiceRole"
}

# Allow Firehose to write to the specific S3 bucket
resource "aws_iam_role_policy" "firehose_s3" {
  name = "firehose-s3-access"
  role = aws_iam_role.firehose.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.logs.arn,
          "${aws_s3_bucket.logs.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_kinesis_firehose_delivery_stream" "msk_logs" {
  name        = "msk-firehose-logs-${random_pet.this.id}"
  destination = "s3"

  s3_configuration {
    role_arn           = aws_iam_role.firehose.arn
    bucket_arn         = aws_s3_bucket.logs.arn
    buffer_size        = 5
    buffer_interval    = 300
    compression_format = "GZIP"
  }
}

# ---------------------------------------------------
# MSK Cluster
# ---------------------------------------------------
resource "aws_msk_cluster" "this" {
  cluster_name           = "msk-cluster-${random_pet.this.id}"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.this[*].id
    security_groups = [aws_security_group.msk_broker.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  # Encryption at Rest
  encryption_info {
    encryption_at_rest_kms_key_arn = "" # Uses AWS managed key by default if empty
  }

  # Open Monitoring
  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  # Logging Configuration
  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk.name
      }

      firehose {
        enabled         = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_logs.name
      }

      s3 {
        enabled = true
        bucket  = aws_s3_bucket.logs.id
        prefix  = "logs/msk-s3/"
      }
    }
  }

  # Client Authentication needed for Connect
  client_authentication {
    sasl {
      scram = true
    }
  }
}

# ---------------------------------------------------
# MSK Connect Plugin & Connector
# ---------------------------------------------------

# S3 Bucket for Plugins
resource "aws_s3_bucket" "plugins" {
  bucket = "msk-plugins-bucket-${random_pet.this.id}"
}

# Upload the Debezium zip (Assumption: user has this file or logic to mock it)
# In a real scenario, you would upload the file. Here we define the bucket.
# Note: Terraform cannot create the file content for you, so we assume the object exists or is uploaded separately.
# For the purpose of this configuration, we define the plugin resource pointing to the expected path.

# IAM Role for MSK Connect
resource "aws_iam_role" "msk_connect" {
  name = "msk-connect-role-${random_pet.this.id}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafkaconnect.amazonaws.com"
        }
      }
    ]
  })
}

# Policy allowing connector to access MSK and CloudWatch
resource "aws_iam_role_policy" "msk_connect" {
  name = "msk-connect-policy"
  role = aws_iam_role.msk_connect.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kafka-cluster:Connect",
          "kafka-cluster:AlterCluster",
          "kafka-cluster:DescribeCluster"
        ]
        Resource = "arn:aws:kafka:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:cluster/${aws_msk_cluster.this.cluster_name}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "kafka-cluster:*Topic*",
          "kafka-cluster:*Group*"
        ]
        Resource = "arn:aws:kafka:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:cluster/${aws_msk_cluster.this.cluster_name}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# Custom Plugin
resource "aws_mskconnect_custom_plugin" "debezium" {
  name         = "debezium-plugin"
  content_type = "ZIP"

  location {
    s3 {
      bucket_arn = aws_s3_bucket.plugins.arn
      file_key   = "debezium.zip" # Assumes file is uploaded to this location
    }
  }
}

# Worker Configuration
resource "aws_mskconnect_worker_configuration" "this" {
  name       = "msk-worker-config"
  properties_file_content = jsonencode({
    "key.converter" = "org.apache.kafka.connect.storage.StringConverter"
    "value.converter" = "org.apache.kafka.connect.storage.StringConverter"
    "offset.storage.topic" = "connect-offsets"
    "config.storage.topic" = "connect-configs"
    "status.storage.topic" = "connect-statuss"
    # Using the MSK Cluster itself for the offset/config topics
  })
}

# Connector
resource "aws_mskconnect_connector" "this" {
  name               = "msk-connector-debezium"
  kafkacluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.this.bootstrap_brokers_sasl_scram

      vpc {
        subnet_ids = aws_subnet.this[*].id
        security_groups = [aws_security_group.msk_broker.id]
      }

      authentication {
        authentication_type = "SASL_SCRAM_512_AUTH"
      }
    }
  }

  kafkaconnect_worker_configuration {
    properties_file_content = aws_mskconnect_worker_configuration.this.properties_file_content_content_sha256
    revision = aws_mskconnect_worker_configuration.this.latest_revision
  }

  capacity {
    autoscaling {
      max_worker_count = 2
      min_worker_count = 1
      mcu_count        = 2
      scale_in_policy  = {}
      scale_out_policy = {}
    }
    provisioned_capacity {}
  }

  connector_configuration = {
    "connector.class" = "io.debezium.connector.postgresql.PostgresConnector"
    "tasks.max"      = "1"
    "database.hostname" = "example-db.us-east-1.rds.amazonaws.com" # Example placeholder
    "database.port" = "5432"
    "database.user" = "user"
    "database.password" = "password"
    "database.dbname" = "mydb"
    "topic.prefix" = "my-topic"
  }

  kafkaconnect_version = "2.7.1"
  service_execution_role_arn = aws_iam_role.msk_connect.arn

  plugins {
    custom_plugin {
      custom_plugin_arn = aws_mskconnect_custom_plugin.debezium.arn
      revision          = aws_mskconnect_custom_plugin.debezium.latest_revision
    }
  }
}

