}

# Create a DB Subnet Group spanning the provided subnets
resource "aws_db_subnet_group" "aurora_subnet_group" {
  name       = "mysql-cluster-subnet-group"
  subnet_ids = var.subnet_ids
  tags = {
    Name = "MySQL Cluster Subnet Group"
  }
}

# Create a Security Group to allow access to MySQL (Port 3306)
resource "aws_security_group" "aurora_security_group" {
  name        = "mysql-cluster-sg"
  description = "Allow inbound MySQL traffic"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this to your IP range for production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "MySQL Cluster SG"
  }
}

# The Aurora MySQL Cluster
# Note: Aurora storage is automatically replicated across 3 AZs. 
# It grows automatically (min 10GB increments), so "100GB" is handled by usage, not a hard limit.
resource "aws_rds_cluster" "mysql_cluster" {
  engine                = "aurora-mysql"
  engine_version        = "8.0.mysql_aurora.3.02.0"
  database_name         = "mydb"
  master_username       = "admin"
  master_password       = random_password.master_password.result
