  vpc_security_group_ids = [aws_security_group.aurora_security_group.id]

  # Backup and maintenance settings
  backup_retention_period = 7
  preferred_backup_window = "03:00-04:00"

  skip_final_snapshot  = true # Set to false for production to retain snapshots on delete

  tags = {
    Name = "MySQL Aurora Cluster"
  }
}

# Writer Instance in us-east-1a
resource "aws_rds_cluster_instance" "writer" {
  identifier         = "mysql-cluster-writer"
  cluster_identifier = aws_rds_cluster.mysql_cluster.id
