  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Variables to make the module portable into your existing VPC
variable "vpc_id" {
  description = "The ID of the VPC where the cluster will be deployed"
  type        = string
  default     = "" # Replace with your VPC ID
}

variable "subnet_ids" {
  description = "List of subnet IDs to distribute the cluster (must span at least 3 AZs)"
  type        = list(string)
  default     = [] # Replace with your Subnet IDs
}

# Generate a secure random password for the database master user
resource "random_password" "master_password" {
  length           = 16
  special          = true
  override_special = "_%@"
}

# Create a DB Subnet Group spanning the provided subnets
resource "aws_db_subnet_group" "aurora_subnet_group" {
  name       = "mysql-cluster-subnet-group"
  subnet_ids = var.subnet_ids
  tags = {
    Name = "MySQL Cluster Subnet Group"
  }
}

# Create a Security Group to allow access to MySQL (Port 3306)
resource "aws_security_group" "aurora_security_group" {
  name        = "mysql-cluster-sg"
  description = "Allow inbound MySQL traffic"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this to your IP range for production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "MySQL Cluster SG"
  }
}

# The Aurora MySQL Cluster
# Note: Aurora storage is automatically replicated across 3 AZs. 
# It grows automatically (min 10GB increments), so "100GB" is handled by usage, not a hard limit.
resource "aws_rds_cluster" "mysql_cluster" {
  engine                = "aurora-mysql"
  engine_version        = "8.0.mysql_aurora.3.02.0"
  database_name         = "mydb"
  master_username       = "admin"
  master_password       = random_password.master_password.result
  db_subnet_group_name  = aws_db_subnet_group.aurora_subnet_group.name
  vpc_security_group_ids = [aws_security_group.aurora_security_group.id]

  # Backup and maintenance settings
  backup_retention_period = 7
  preferred_backup_window = "03:00-04:00"

  skip_final_snapshot  = true # Set to false for production to retain snapshots on delete

  tags = {
    Name = "MySQL Aurora Cluster"
  }
}

# Writer Instance in us-east-1a
resource "aws_rds_cluster_instance" "writer" {
  identifier         = "mysql-cluster-writer"
  cluster_identifier = aws_rds_cluster.mysql_cluster.id
  instance_class     = "db.t3.small" # Burstable instance class
  engine             = aws_rds_cluster.mysql_cluster.engine
  engine_version     = aws_rds_cluster.mysql_cluster.engine_version
  availability_zone  = "us-east-1a"

  publicly_accessible = false
}

# Reader Instance in us-east-1b
resource "aws_rds_cluster_instance" "reader_b" {
  identifier         = "mysql-cluster-reader-b"
  cluster_identifier = aws_rds_cluster.mysql_cluster.id
  instance_class     = "db.t3.small"
  engine             = aws_rds_cluster.mysql_cluster.engine
  engine_version     = aws_rds_cluster.mysql_cluster.engine_version
  availability_zone  = "us-east-1b"

