Toset up a DynamoDB table with Global Tables replication across `us-west-1` and `us-west-2`, we need to perform the following steps:

1.  **Configure Providers:** Define the AWS provider for both the primary region (`us-west-1`) and the replica region (`us-west-2`) using an alias.
2.  **Create the Primary Table:** Provision a standard DynamoDB table in `us-west-1`. Crucially, this table must have **DynamoDB Streams** enabled to facilitate replication.
3.  **Create the Replica:** Use the `aws_dynamodb_table_replica` resource in the `us-west-2` provider configuration, linking it to the primary table's ARN.

Here is the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Provider for the primary region (us-west-1)
provider "aws" {
  region = "us-west-1"
}

# Provider for the replica region (us-west-2)
provider "aws" {
  alias  = "replica"
  region = "us-west-2"
}

# The Primary DynamoDB Table in us-west-1
resource "aws_dynamodb_table" "main" {
  name           = "global-app-table"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "UserId"

  # Stream must be enabled for replication
  stream_enabled   = true
  stream_view_type = "NEW_AND_OLD_IMAGES"

  attribute {
    name = "UserId"
    type = "S"
  }

  tags = {
    Environment = "production"
    Replicated  = "true"
  }
}

# The Replica in us-west-2
resource "aws_dynamodb_table_replica" "replica" {
  # Use the provider configured for us-west-2
  provider = aws.replica

  # The ARN of the primary table to replicate
  replica_global_table_arn = aws_dynamodb_table.main.arn
}

# Output the ARN of the Global Table
output "global_table_arn" {
  value = aws_dynamodb_table.main.arn
  description = "The ARN of the primary Global Table"
}
```

