  region = var.aws_region
}

# Variable to define the region
variable "aws_region" {
  default = "us-east-1"
  description = "The AWS region where resources will be created"
}

# 1. Provision the AWS VPC
resource "aws_vpc" "main_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "terraform-example-vpc"
  }
}

# 2. Provision a Subnet within the VPC
resource "aws_subnet" "main_subnet" {
  vpc_id                  = aws_vpc.main_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "${var.aws_region}a"
  map_public_ip_on_launch = true

  tags = {
    Name = "terraform-example-subnet"
  }
}

# 3. Provision a Network ACL (NACL)
resource "aws_network_acl" "main_nacl" {
  vpc_id = aws_vpc.main_vpc.id

  tags = {
    Name = "terraform-example-nacl"
  }
}

# 4. Link the NACL to the Subnet
resource "aws_network_acl_association" "main_nacl_assoc" {
  network_acl_id = aws_network_acl.main_nacl.id
  subnet_id      = aws_subnet.main_subnet.id
}

# 5. Manage Inbound Traffic Rules
# Allow SSH (Port 22)
resource "aws_network_acl_rule" "inbound_ssh" {
  network_acl_id = aws_network_acl.main_nacl.id
  rule_number    = 100
  egress         = false
  protocol       = "tcp"
  rule_action    = "allow"
  cidr_block     = "0.0.0.0/0"
  from_port      = 22
  to_port        = 22
}

# Allow HTTP (Port 80)
resource "aws_network_acl_rule" "inbound_http" {
  network_acl_id = aws_network_acl.main_nacl.id
  rule_number    = 110
  egress         = false
  protocol       = "tcp"
  rule_action    = "allow"
  cidr_block     = "0.0.0.0/0"
  from_port      = 80
  to_port        = 80
}

# Allow HTTPS (Port 443)
resource "aws_network_acl_rule" "inbound_https" {
  network_acl_id = aws_network_acl.main_nacl.id
  rule_number    = 120
  egress         = false
  protocol       = "tcp"
  rule_action    = "allow"
  cidr_block     = "0.0.0.0/0"
  from_port      = 443
  to_port        = 443
}

# Allow Ephemeral Ports (Used for return traffic)
resource "aws_network_acl_rule" "inbound_ephemeral" {
  network_acl_id = aws_network_acl.main_nacl.id
  rule_number    = 130
  egress         = false
  protocol       = "tcp"
  rule_action    = "allow"
  cidr_block     = "0.0.0.0/0"
  from_port      = 1024
  to_port        = 65535
}

# 6. Manage Outbound Traffic Rules
# Allow All Outbound Traffic
resource "aws_network_acl_rule" "outbound_all" {
  network_acl_id = aws_network_acl.main_nacl.id
  rule_number    = 100
  egress         = true
  protocol       = "-1" # -1 means all protocols
  rule_action    = "allow"
  cidr_block     = "0.0.0.0/0"
  from_port      = 0
  to_port        = 0
}

