}

# Resource: VPC A
resource "aws_vpc" "vpc_a" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "vpc-a"
  }
}

# Resource: VPC B
resource "aws_vpc" "vpc_b" {
  cidr_block           = "10.1.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "vpc-b"
  }
}

# Resource: VPC Peering Connection (Requester side)
resource "aws_vpc_peering_connection" "peering" {
  vpc_id      = aws_vpc.vpc_a.id
  peer_vpc_id = aws_vpc.vpc_b.id
  auto_accept = false

  tags = {
    Name = "vpc-a-to-vpc-b-peering"
  }
}

# Resource: Accepter configuration for the VPC Peering Connection
resource "aws_vpc_peering_connection_accepter" "accepter" {
  vpc_peering_connection_id = aws_vpc_peering_connection.peering.id
  auto_accept              = true

  tags = {
    Name = "vpc-b-accepter"
  }
}

# Resource: Route Table Update for VPC A (To reach VPC B)
# Using the main route table associated with VPC A
resource "aws_route" "vpc_a_to_vpc_b" {
  route_table_id         = aws_vpc.vpc_a.main_route_table_id
  destination_cidr_block = aws_vpc.vpc_b.cidr_block
  vpc_peering_connection_id = aws_vpc_peering_connection.peering.id
}

# Resource: Route Table Update for VPC B (To reach VPC A)
# Using the main route table associated with VPC B
resource "aws_route" "vpc_b_to_vpc_a" {
  route_table_id         = aws_vpc.vpc_b.main_route_table_id
  destination_cidr_block = aws_vpc.vpc_a.cidr_block
  vpc_peering_connection_id = aws_vpc_peering_connection.peering.id
}

