  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "neptune-vpc"
  }
}

resource "aws_subnet" "neptune_subnet_1" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "neptune-subnet-1"
  }
}

resource "aws_subnet" "neptune_subnet_2" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "neptune-subnet-2"
  }
}

# 2. DB Subnet Group
# Neptune requires a subnet group to launch instances within the VPC.
resource "aws_db_subnet_group" "neptune_subnet_group" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.neptune_subnet_1.id, aws_subnet.neptune_subnet_2.id]

  tags = {
    Name = "My Neptune Subnet Group"
  }
}

# 3. Security Group
# Allows ingress on port 8182 (Neptune default port).
resource "aws_security_group" "neptune_sg" {
  name        = "neptune-security-group"
  description = "Allow Neptune inbound traffic"
  vpc_id      = aws_vpc.neptune_vpc.id

  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production environments
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-sg"
  }
}

# 4. Customized Neptune Parameter Group
# This creates a custom parameter group with a specific configuration.
resource "aws_neptune_parameter_group" "custom_pg" {
  name   = "neptune-custom-parameter-group"
  family = "neptune1.3"

  parameter {
    name  = "neptune_query_timeout"
    value = "120000"
  }

  tags = {
    Name = "neptune-custom-pg"
  }
}

# 5. Neptune Cluster
# The main cluster resource utilizing the parameter group, subnet group, and security group.
resource "aws_neptune_cluster" "main" {
  cluster_identifier              = "terraform-neptune-cluster"
  engine                          = "neptune"
  engine_version                  = "1.3.1.0"
  backup_retention_period         = 5
  preferred_backup_window         = "07:00-09:00"
  skip_final_snapshot             = true
  neptune_parameter_group_name    = aws_neptune_parameter_group.custom_pg.id
  db_subnet_group_name            = aws_db_subnet_group.neptune_subnet_group.name
  vpc_security_group_ids          = [aws_security_group.neptune_sg.id]
  apply_immediately               = true
  iam_database_authentication_enabled = false

  tags = {
    Name = "terraform-neptune-cluster"
  }
}

# 6. Neptune Cluster Instance
# The primary writer instance for the cluster.
resource "aws_neptune_cluster_instance" "writer" {
  count              = 1
  identifier         = "terraform-neptune-writer"
  cluster_identifier = aws_neptune_cluster.main.id
  engine             = "neptune"
  instance_class     = "db.t4g.medium"
  apply_immediately  = true
  publicly_accessible = true # Set to false for production

  tags = {
    Name = "neptune-writer-instance"
  }
}

