  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# 1. Network Configuration
# We create a sample VPC and two subnets to satisfy the requirement of 
# restricting access solely from specific subnets.
# -----------------------------------------------------------------------------

resource "aws_vpc" "neptune_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "neptune-demo-vpc"
  }
}

# Subnet 1 (Sample Subnet A)
resource "aws_subnet" "subnet_1" {
  vpc_id                  = aws_vpc.neptune_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = false

  tags = {
    Name = "neptune-restricted-subnet-1"
  }
}

# Subnet 2 (Sample Subnet B)
# Neptune requires subnets in at least two different Availability Zones.
resource "aws_subnet" "subnet_2" {
  vpc_id                  = aws_vpc.neptune_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = false

  tags = {
    Name = "neptune-restricted-subnet-2"
  }
}

# -----------------------------------------------------------------------------
# 2. Neptune Database Subnet Group
# Defines which subnets the Neptune cluster can reside in.
# -----------------------------------------------------------------------------
resource "aws_db_subnet_group" "neptune_subnet_group" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  tags = {
    Name = "Neptune Subnet Group"
  }
}

# -----------------------------------------------------------------------------
# 3. Custom Parameter Group
# Creates a custom parameter group as requested.
# -----------------------------------------------------------------------------
resource "aws_neptune_parameter_group" "custom" {
  name        = "neptune-custom-parameter-group"
  family      = "neptune1"
  description = "Custom Neptune parameter group"

  parameter {
    name  = "neptune_query_timeout"
    value = "120000"
  }
}

# -----------------------------------------------------------------------------
# 4. Security Group
# Restricts access so it is permitted SOLELY from the two sample subnets.
# -----------------------------------------------------------------------------
resource "aws_security_group" "neptune_sg" {
  name        = "neptune-restricted-sg"
  description = "Security group restricting Neptune access to specific subnets"
  vpc_id      = aws_vpc.neptune_vpc.id

  # Allow Ingress from Subnet 1 only
  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.subnet_1.cidr_block]
    description = "Allow access from Subnet 1"
  }

  # Allow Ingress from Subnet 2 only
  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.subnet_2.cidr_block]
    description = "Allow access from Subnet 2"
  }

  # Egress rule (standard)
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-restricted-sg"
  }
}

# -----------------------------------------------------------------------------
# 5. Neptune Cluster
# The main database cluster resource.
# -----------------------------------------------------------------------------
resource "aws_neptune_cluster" "main" {
  cluster_identifier              = "neptune-cluster-demo"
  engine                          = "neptune"
  engine_version                  = "1.2.1.0"
  backup_retention_period         = 5
  preferred_backup_window         = "07:00-09:00"
  skip_final_snapshot             = true
  apply_immediately               = true

  # Attach the custom parameter group
  neptune_parameter_group_name    = aws_neptune_parameter_group.custom.name

  # Attach the subnet group
  db_subnet_group_name            = aws_db_subnet_group.neptune_subnet_group.name

  # Attach the restricted security group
  vpc_security_group_ids          = [aws_security_group.neptune_sg.id]

  tags = {
    Name = "Neptune Cluster"
  }
}

# -----------------------------------------------------------------------------
# 6. Neptune Cluster Instance
# A compute instance (writer) for the cluster.
# -----------------------------------------------------------------------------
resource "aws_neptune_cluster_instance" "writer" {
  identifier              = "neptune-instance-writer"
  cluster_identifier      = aws_neptune_cluster.main.id
  engine                  = "neptune"
  engine_version          = "1.2.1.0"
  instance_class          = "db.t4g.medium"
  apply_immediately       = true
  neptune_parameter_group_name = aws_neptune_parameter_group.custom.name

  tags = {
    Name = "Neptune Writer Instance"
  }
}

