# 1. Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# 2. Networking Setup
# Create a VPC to host the infrastructure
resource "aws_vpc" "main_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "neptune-vpc"
  }
}

# Create the "Example Subnet" (the only subnet allowed to connect)
resource "aws_subnet" "example_subnet" {
  vpc_id                  = aws_vpc.main_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = false

  tags = {
    Name = "example-subnet-restricted-access"
  }
}

# Create a secondary subnet required for the Neptune Subnet Group (usually requires 2+ AZs)
resource "aws_subnet" "secondary_subnet" {
  vpc_id            = aws_vpc.main_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "neptune-secondary-subnet"
  }
}

# 3. Security Group
# Create a Security Group restricting access to only the example subnet
resource "aws_security_group" "neptune_sg" {
  name        = "neptune-restricted-sg"
  description = "Security group for Neptune cluster restricting access to example subnet"
  vpc_id      = aws_vpc.main_vpc.id

  # Ingress rule: Allow Neptune port (8182) only from the Example Subnet CIDR
  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.example_subnet.cidr_block]
  }

  # Egress rule: Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-sg"
  }
}

# 4. Neptune Subnet Group
# Create a DB Subnet Group grouping the subnets for Neptune
resource "aws_db_subnet_group" "neptune_subnet_group" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.example_subnet.id, aws_subnet.secondary_subnet.id]

  tags = {
    Name = "neptune-subnet-group"
  }
}

# 5. Custom Cluster Parameter Group
resource "aws_neptune_cluster_parameter_group" "custom_cluster_pg" {
  name   = "custom-neptune-cluster-pg"
  family = "neptune1.2"

  parameter {
    name  = "neptune_query_timeout"
    value = "120000"
  }

  tags = {
    Name = "custom-neptune-cluster-pg"
  }
}

# 6. Custom Instance Parameter Group
resource "aws_neptune_parameter_group" "custom_instance_pg" {
  name   = "custom-neptune-instance-pg"
  family = "neptune1.2"

  parameter {
    name  = "neptune_query_cache_size"
    value = "0" # Example parameter
  }

  tags = {
    Name = "custom-neptune-instance-pg"
  }
}

# 7. Neptune Cluster
resource "aws_neptune_cluster" "main" {
  cluster_identifier              = "example-neptune-cluster"
  engine                          = "neptune"
  engine_version                  = "1.2.1.0.R20231117" # Example version
  # Apply the custom cluster parameter group
  cluster_parameter_group_name    = aws_neptune_cluster_parameter_group.custom_cluster_pg.name
  # Apply the subnet group
  neptune_subnet_group_name       = aws_db_subnet_group.neptune_subnet_group.name
  # Apply the restricted security group
  vpc_security_group_ids          = [aws_security_group.neptune_sg.id]

  skip_final_snapshot             = true
  apply_immediately               = true
  deletion_protection             = false

  tags = {
    Name = "example-neptune-cluster"
  }
}

# 8. Neptune Instance
resource "aws_neptune_cluster_instance" "main" {
  count              = 1
  cluster_identifier = aws_neptune_cluster.main.id
  engine             = "neptune"
  instance_class     = "db.t4g.medium"

