}

# 1. Provision an Amazon Kinesis Video Stream
# This stream will receive the media audio/video data from the Chime Voice Connector.
resource "aws_kinesis_video_stream" "chime_stream" {
  name                    = "chime-voice-connector-media-stream"
  data_retention_in_hours = 24
  media_type              = "video/h264"
  tags = {
    Purpose = "ChimeVoiceConnectorStreaming"
  }
}

# 2. Provision an AWS Chime Voice Connector
# This acts as the entry point for SIP trunking communications.
resource "aws_chime_voice_connector" "main" {
  name               = "example-voice-connector"
  require_encryption = true
  aws_region         = "us-east-1"

  tags = {
    Environment = "production"
  }
}

# 3. Configure Streaming to Kinesis
# This links the Voice Connector to the Kinesis Video Stream, enabling real-time media streaming.
resource "aws_chime_voice_connector_streaming_configuration" "streaming_config" {
  voice_connector_id = aws_chime_voice_connector.main.id

  streaming_configuration {
    media_insights_configuration {
      disabled   = false
      stream_arn = aws_kinesis_video_stream.chime_stream.arn
    }
  }
}

