# 1. Provision an AWS VPC
resource "aws_vpc" "redshift_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "redshift-vpc"
  }
}

# 2. Provision two subnets within the VPC
resource "aws_subnet" "subnet_1" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "redshift-subnet-1"
  }
}

resource "aws_subnet" "subnet_2" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "redshift-subnet-2"
  }
}

# Place those subnets into an Amazon Redshift subnet group
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name        = "tf-redshift-subnet-group"
  description = "Redshift subnet group for Terraform demo"
  subnet_ids  = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  tags = {
    Name = "tf-redshift-subnet-group"
  }
}

# Generate a random password for the Redshift cluster
resource "random_password" "redshift_password" {
  length  = 16
  special = true
}

# 3. Create a simple Amazon Redshift cluster using the subnet group
resource "aws_redshift_cluster" "default" {
  cluster_identifier  = "tf-redshift-cluster"
  database_name       = "mydb"
  master_username     = "admin"
  master_password     = random_password.redshift_password.result
  node_type           = "dc2.large"
  cluster_type        = "single-node"
  skip_final_snapshot = true

  # Associate the cluster with the subnet group
  cluster_subnet_group_name = aws_redshift_subnet_group.redshift_subnet_group.name
}

# 4. Create a Redshift endpoint access resource associated with that cluster using the subnet group
resource "aws_redshift_endpoint_access" "example" {
  cluster_identifier = aws_redshift_cluster.default.cluster_identifier
  resource_owner     = data.aws_caller_identity.current.account_id
  subnet_group_name  = aws_redshift_subnet_group.redshift_subnet_group.name
}

