# 1. Provider Configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 2. Variables
variable "notification_email" {
  description = "Email address to receive Redshift event notifications"
  type        = string
}

variable "master_username" {
  description = "Username for the Redshift master user"
  type        = string
  default     = "adminuser"
}

variable "master_password" {
  description = "Password for the Redshift master user"
  type        = string
  sensitive   = true
}

# 3. Network Infrastructure (VPC, Subnets, Security Group)
data "aws_availability_zones" "available" {}

resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "redshift-vpc"
  }
}

resource "aws_subnet" "redshift_subnet" {
  count                   = 2
  vpc_id                  = aws_vpc.redshift_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.redshift_vpc.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "redshift-subnet-${count.index + 1}"
  }
}

resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Allow inbound traffic to Redshift"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # In production, restrict this to specific IPs
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = aws_subnet.redshift_subnet[*].id

  tags = {
    Name = "My Redshift Subnet Group"
  }
}

# 4. SNS Topic for Notifications
resource "aws_sns_topic" "redshift_alerts" {
  name = "redshift-event-notifications"
}

resource "aws_sns_topic_subscription" "email_subscription" {
  topic_arn = aws_sns_topic.redshift_alerts.arn
  protocol  = "email"
  endpoint  = var.notification_email
}

# 5. Redshift Cluster
resource "aws_redshift_cluster" "main" {
  cluster_identifier = "tf-redshift-cluster"
  database_name      = "dev"
  master_username    = var.master_username
  master_password    = var.master_password
  node_type          = "dc2.large"
  cluster_type       = "single-node"

  # Networking
  cluster_subnet_group_name   = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids      = [aws_security_group.redshift_sg.id]
  publicly_accessible         = true # Set to false for private access

  # Configuration
  skip_final_snapshot = true # Set to false in production
  preferred_maintenance_window = "sun:10:00-sun:10:30"

  tags = {
    Environment = "Terraform-Example"
  }
}

# 6. Event Notification Configuration
resource "aws_redshift_event_subscription" "main" {
  name        = "redshift-event-sub"
  sns_topic_arn = aws_sns_topic.redshift_alerts.arn

  # Subscribe to events for the specific cluster created above
  source_type   = "cluster"
  source_ids    = [aws_redshift_cluster.main.cluster_identifier]

  # List of event categories to subscribe to
  event_categories = [
    "configuration-change",
    "management",
    "monitoring",
    "security"
  ]

  # Severity to filter (optional)
  severity = "INFO"

  tags = {
    Name = "RedshiftEventSubscription"
  }
}

