variable "iam_user_name" {
  description = "The name of the IAM user to create."
  type        = string
  default     = "ssh-access-user"
}

# Variable for the SSH Public Key content
variable "ssh_public_key" {
  description = "The SSH public key content (e.g., ssh-rsa AAAA...)."
  type        = string
  sensitive   = true
}

# Resource: IAM User
resource "aws_iam_user" "this" {
  name = var.iam_user_name
  path = "/"
  tags = {
    ManagedBy = "Terraform"
  }
}

# Resource: IAM User SSH Key
resource "aws_iam_user_ssh_key" "this" {
  username   = aws_iam_user.this.name
  public_key = var.ssh_public_key
  encoding   = "SSH"
}

# Outputs
output "iam_user_arn" {
  description = "The ARN of the IAM user."
  value       = aws_iam_user.this.arn
}

output "ssh_key_id" {
  description = "The unique ID for the uploaded SSH public key."
  value       = aws_iam_user_ssh_key.this.ssh_public_key_id
}
```

