extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change this to your preferred AWS region
}

# Variable to define a unique bucket name
variable "bucket_name" {
  description = "The name of the S3 bucket for storing website images."
  type        = string
  default     = "my-website-images-bucket-unique-id"
}

# 1. Create the S3 Bucket
resource "aws_s3_bucket" "images" {
  bucket = var.bucket_name
}

# 2. Configure Ownership Controls
# Essential for managing access permissions via ACLs or Policies if needed
resource "aws_s3_bucket_ownership_controls" "images" {
  bucket = aws_s3_bucket.images.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# 3. Configure Public Access Block
# We must disable specific blocks to allow the bucket policy to grant public read access
resource "aws_s3_bucket_public_access_block" "images" {
  bucket = aws_s3_bucket.images.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# 4. Set the Bucket ACL to Public Read
# This enables the bucket to serve files publicly
resource "aws_s3_bucket_acl" "images" {
  depends_on = [
    aws_s3_bucket_ownership_controls.images,
    aws_s3_bucket_public_access_block.images,
  ]

  bucket = aws_s3_bucket.images.id
  acl    = "public-read"
}

# 5. Create a Bucket Policy
# Explicitly allows anyone on the internet to view (GetObject) the images
resource "aws_s3_bucket_policy" "images" {
  bucket = aws_s3_bucket.images.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.images.arn}/*"
      },
    ]
  })
}

# Output the Bucket Endpoint
output "bucket_endpoint" {
  value = aws_s3_bucket.images.website_endpoint
}

output "bucket_name" {
  value = aws_s3_bucket.images.id
}

response:
To fulfill your request, I have analyzed the requirements step by step:

1.  **Identify the Service:** For storing static assets like images for a website, **Amazon S3 (Simple Storage Service)** is the standard, most cost-effective, and durable AWS solution.
2.  **Create the S3 Bucket:** We need to define a bucket resource to act as the container for the image files.
3.  **Configure Ownership:** We need to configure `BucketOwnerPreferred` for object ownership. This allows the bucket owner to have full control over objects uploaded with ACLs, which is often required for public read scenarios.
4.  **Adjust Public Access Settings:** By default, AWS blocks all public access to S3 buckets. Since these images need to be displayed on a public website, we must update the `aws_s3_bucket_public_access_block` to allow specific public policies.
5.  **Define Access Policy:** We will attach a Bucket Policy that explicitly grants `s3:GetObject` permission to the general public (`*`). This allows web browsers to fetch the images.

Here is the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change this to your preferred AWS region
}

# Variable to define a unique bucket name
variable "bucket_name" {
  description = "The name of the S3 bucket for storing website images."
  type        = string
  default     = "my-website-images-bucket-unique-id"
}

# 1. Create the S3 Bucket
resource "aws_s3_bucket" "images" {
  bucket = var.bucket_name
}

# 2. Configure Ownership Controls
# Essential for managing access permissions via ACLs or Policies if needed
resource "aws_s3_bucket_ownership_controls" "images" {
  bucket = aws_s3_bucket.images.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# 3. Configure Public Access Block
# We must disable specific blocks to allow the bucket policy to grant public read access
resource "aws_s3_bucket_public_access_block" "images" {
  bucket = aws_s3_bucket.images.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# 4. Set the Bucket ACL to Public Read
# This enables the bucket to serve files publicly
resource "aws_s3_bucket_acl" "images" {
  depends_on = [
    aws_s3_bucket_ownership_controls.images,
    aws_s3_bucket_public_access_block.images,
  ]

  bucket = aws_s3_bucket.images.id
  acl    = "public-read"
}

# 5. Create a Bucket Policy
# Explicitly allows anyone on the internet to view (GetObject) the images
resource "aws_s3_bucket_policy" "images" {
  bucket = aws_s3_bucket.images.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.images.arn}/*"
      },
    ]
  })
}

# Output the Bucket Endpoint
output "bucket_endpoint" {
  value = aws_s3_bucket.images.website_endpoint
}

output "bucket_name" {
  value = aws_s3_bucket.images.id
}
```

