  region = "us-east-1" # Replace with your preferred region
}

# 1. Create the Source Bucket
resource "aws_s3_bucket" "source" {
  bucket = "my-source-bucket-unique-id"
}

# Block public access to the source bucket
resource "aws_s3_bucket_public_access_block" "source" {
  bucket = aws_s3_bucket.source.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# 2. Create the Destination Bucket for the Inventory
resource "aws_s3_bucket" "destination" {
  bucket = "my-inventory-bucket-unique-id"
}

# Block public access to the destination bucket
resource "aws_s3_bucket_public_access_block" "destination" {
  bucket = aws_s3_bucket.destination.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# 3. Configure Bucket Policy on the Destination Bucket
# This allows the S3 service to write inventory reports to the destination bucket.
data "aws_caller_identity" "current" {}

resource "aws_s3_bucket_policy" "destination_policy" {
  bucket = aws_s3_bucket.destination.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid = "AllowInventoryDelivery"
        Effect = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
        Action   = "s3:PutObject"
        Resource = "${aws_s3_bucket.destination.arn}/*"
        Condition = {
          ArnLike = {
            "aws:SourceArn" = aws_s3_bucket.source.arn
          }
          StringEquals = {
            "aws:SourceAccount" = data.aws_caller_identity.current.account_id
          }
        }
      }
    ]
  })
}

# 4. Create the S3 Inventory Configuration
resource "aws_s3_bucket_inventory" "weekly_inventory" {
  # The bucket to inventory
  bucket = aws_s3_bucket.source.id

  # Name for the inventory configuration
  name = "WeeklyCSVInventory"

  # Include only the current versions of objects
  included_object_versions = "Current"

  # Generate the report weekly
  schedule {
    frequency = "Weekly"
  }

  # Specify where the inventory reports should be stored
  destination {
    bucket {
      # ARN of the destination bucket
      bucket_arn = aws_s3_bucket.destination.arn
      # Format of the inventory file
      format     = "CSV"
      # Optional: Prefix to organize files in the destination bucket
      prefix     = "inventory-reports/"
    }
  }

  # Optional fields to include in the report (standard defaults usually include Size, LastModifiedDate)
