provider "aws" {
  region = "us-east-1"
}

# Generate a unique suffix for the bucket name to avoid conflicts
resource "random_pet" "this" {
  length = 2
}

# ------------------------------------------------------------------------------
# 1. KMS Key Resource
# ------------------------------------------------------------------------------
resource "aws_kms_key" "s3_encryption_key" {
  description             = "This key is used to encrypt my S3 bucket objects"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  # Key policy allows the root account full access and allows S3 service to use the key
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action   = "kms:*"
        Resource = "*"
      },
      {
        Sid    = "Allow S3 Service to use the key"
        Effect = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
        Action = [
          "kms:Decrypt",
          "kms:GenerateDataKey"
        ]
        Resource = "*"
      }
    ]
  })
}

# Optional: Add an alias to make the key easier to identify
resource "aws_kms_alias" "s3_encryption_key_alias" {
  name          = "alias/s3-bucket-key"
  target_key_id = aws_kms_key.s3_encryption_key.id
}

# Data source to fetch current account ID for the KMS policy
data "aws_caller_identity" "current" {}

# ------------------------------------------------------------------------------
# 2. S3 Bucket Resource
# ------------------------------------------------------------------------------
resource "aws_s3_bucket" "secure_bucket" {
  # Construct a globally unique bucket name
  bucket = "my-secure-bucket-${random_pet.this.id}"
}

# Disable public access block for security best practices
resource "aws_s3_bucket_public_access_block" "secure_bucket_pab" {
  bucket = aws_s3_bucket.secure_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# ------------------------------------------------------------------------------
# 3. Server-Side Encryption Configuration
# ------------------------------------------------------------------------------
resource "aws_s3_bucket_server_side_encryption_configuration" "secure_bucket_sse" {
  bucket = aws_s3_bucket.secure_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      # Reference the specific KMS Key ARN created above
      kms_master_key_id = aws_kms_key.s3_encryption_key.arn
      sse_algorithm     = "aws:kms"
    }

    # Optional: Specify the bucket key setting to reduce KMS costs
    bucket_key_enabled = true
  }
}

# Output the Bucket Name and KMS Key ARN
output "s3_bucket_name" {
  value = aws_s3_bucket.secure_bucket.id
}

output "kms_key_arn" {
  value = aws_kms_key.s3_encryption_key.arn
}

