response:
Here is the step-by-step thought process to generate the Terraform configuration:

1.  **Define the Provider**: First, we need to configure the AWS provider to specify the region and required provider version.
2.  **Create the S3 Bucket**: We define the `aws_s3_bucket` resource. This creates the actual bucket.
3.  **Configure Static Website Hosting**: We use the `aws_s3_bucket_website_configuration` resource. This is the specific resource that turns the bucket into a website host, allowing us to define the `index.html` (the main page) and `error.html` (the custom error page).
4.  **Configure Public Access**: For a static website to be accessible to the public, we must disable the default "Block Public Access" settings using `aws_s3_bucket_public_access_block`.
5.  **Set Ownership Controls**: To allow the bucket to accept public ACLs, we need to define `aws_s3_bucket_ownership_controls` with `BucketOwnerPreferred`.
6.  **Grant Public Read Access via ACL**: We apply the `public-read` ACL using `aws_s3_bucket_acl`. This ensures the bucket content is readable.
7.  **Add a Bucket Policy**: While ACLs handle bucket-level permissions, a Bucket Policy (`aws_s3_bucket_policy`) is best practice to explicitly allow `s3:GetObject` actions to the principal `*` (everyone) so the website files can be served.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create the S3 Bucket
resource "aws_s3_bucket" "static_website_bucket" {
  bucket = "my-static-website-example-bucket"
}

# 2. Configure the Static Website Hosting
resource "aws_s3_bucket_website_configuration" "static_website_config" {
  bucket = aws_s3_bucket.static_website_bucket.id

  index_document {
    suffix = "index.html"
  }

  error_document {
    key = "error.html"
  }
}

# 3. Disable Block Public Access to allow public website hosting
resource "aws_s3_bucket_public_access_block" "public_access_block" {
  bucket = aws_s3_bucket.static_website_bucket.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# 4. Configure Bucket Ownership Controls (Required for ACLs)
resource "aws_s3_bucket_ownership_controls" "ownership_controls" {
  bucket = aws_s3_bucket.static_website_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# 5. Grant Public Read Access via ACL
resource "aws_s3_bucket_acl" "bucket_acl" {
  depends_on = [
    aws_s3_bucket_ownership_controls.ownership_controls,
    aws_s3_bucket_public_access_block.public_access_block
  ]

  bucket = aws_s3_bucket.static_website_bucket.id
  acl    = "public-read"
}

# 6. Bucket Policy to allow public read access to objects
resource "aws_s3_bucket_policy" "bucket_policy" {
  bucket = aws_s3_bucket.static_website_bucket.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource = "${aws_s3_bucket.static_website_bucket.arn}/*"
      }
    ]
  })
}

# Output the Website Endpoint
output "website_endpoint" {
  value = aws_s3_bucket_website_configuration.static_website_config.website_endpoint
}
```

