}

# Resource 2: Configure the bucket payment settings
# This ensures the bucket owner pays for the requests and data transfer
resource "aws_s3_bucket_request_payment_configuration" "example" {
  bucket = aws_s3_bucket.example.id
  payer  = "BucketOwner"
}
