# Resource: S3 Bucket 2 (The Destination/Target Bucket)
# This bucket will receive the access logs.
resource "aws_s3_bucket" "log_target" {
  bucket = "my-log-target-bucket-example"
}

# Resource: Bucket Policy for S3 Bucket 2
# This policy is required to allow the S3 Log Delivery service to write objects
# to the target bucket (especially relevant if ACLs are disabled).
resource "aws_s3_bucket_policy" "log_target_policy" {
  bucket = aws_s3_bucket.log_target.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid = "S3ServerAccessLogsPolicy"
        Effect = "Allow"
        Principal = {
          Service = "logging.s3.amazonaws.com"
        }
        Action = "s3:PutObject"
        Resource = [
          aws_s3_bucket.log_target.arn,
          "${aws_s3_bucket.log_target.arn}/*"
        ]
      }
    ]
  })
}

# Resource: S3 Bucket 1 (The Source Bucket)
# This is the bucket for which we want to enable access logging.
resource "aws_s3_bucket" "source" {
  bucket = "my-source-bucket-example"
}

# Resource: S3 Bucket Logging
# Configures access logging on the first bucket to deliver logs to the second bucket.
resource "aws_s3_bucket_logging" "source_logging" {
  bucket = aws_s3_bucket.source.id

  # Reference the second bucket
  target_bucket = aws_s3_bucket.log_target.id
  # Set the object key prefix as requested
  target_prefix = "log/"
}

