terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
  required_version = ">= 1.0"
}

provider "aws" {
  region = "us-east-1"
}

# ---------------------------------------------------------
# 1. Create the S3 Bucket for storing Server Access Logs
# ---------------------------------------------------------

resource "aws_s3_bucket" "log_bucket" {
  bucket = "my-app-logs-bucket-${random_pet.suffix.id}"
}

# Enable Versioning for the log bucket (good practice)
resource "aws_s3_bucket_versioning" "log_bucket_versioning" {
  bucket = aws_s3_bucket.log_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Enable Server-Side Encryption
resource "aws_s3_bucket_server_side_encryption_configuration" "log_bucket_encryption" {
  bucket = aws_s3_bucket.log_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# Block Public Access for the log bucket
resource "aws_s3_bucket_public_access_block" "log_bucket_pab" {
  bucket = aws_s3_bucket.log_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# CRITICAL: Configure Ownership Controls to allow ACLs
# S3 Server Access Logging requires ACLs to grant the Log Delivery group permissions.
# We must set object ownership to 'BucketOwnerPreferred' to use ACLs.
resource "aws_s3_bucket_ownership_controls" "log_bucket_ownership" {
  bucket = aws_s3_bucket.log_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# CRITICAL: Grant Log Delivery group permissions
# This ACL grants the Log Delivery group WRITE and READ_ACP permissions on the bucket.
resource "aws_s3_bucket_acl" "log_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.log_bucket_ownership]

  bucket = aws_s3_bucket.log_bucket.id
  acl    = "log-delivery-write"
}

# ---------------------------------------------------------
# 2. Create the Main Source S3 Bucket
# ---------------------------------------------------------

resource "aws_s3_bucket" "source_bucket" {
  bucket = "my-app-data-bucket-${random_pet.suffix.id}"
}

# Enable Versioning for the source bucket
resource "aws_s3_bucket_versioning" "source_bucket_versioning" {
  bucket = aws_s3_bucket.source_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Enable Server-Side Encryption
resource "aws_s3_bucket_server_side_encryption_configuration" "source_bucket_encryption" {
  bucket = aws_s3_bucket.source_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# Block Public Access for the source bucket
resource "aws_s3_bucket_public_access_block" "source_bucket_pab" {
  bucket = aws_s3_bucket.source_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Best Practice: Enforce BucketOwnerEnforced for the source bucket (no ACLs needed)
resource "aws_s3_bucket_ownership_controls" "source_bucket_ownership" {
  bucket = aws_s3_bucket.source_bucket.id
  rule {
    object_ownership = "BucketOwnerEnforced"
  }
}

# ---------------------------------------------------------
# 3. Configure Logging on the Source Bucket
# ---------------------------------------------------------

resource "aws_s3_bucket_logging" "source_bucket_logging" {
  # The bucket that needs to be logged
  bucket = aws_s3_bucket.source_bucket.id

  # The destination bucket for the logs
  target_bucket = aws_s3_bucket.log_bucket.id

  # Optional: A prefix for the log files (e.g., "log/")
  target_prefix = "access-logs/"
}

# ---------------------------------------------------------
# Helper: Random Suffix for unique bucket naming
# ---------------------------------------------------------
resource "random_pet" "suffix" {
  length = 2
}

