terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

# ---------------------------------------------------------
# 1. S3 Bucket for Storing Grading Artifacts (Reports)
# ---------------------------------------------------------
resource "aws_s3_bucket" "grading_artifacts" {
  bucket_prefix = "autograder-artifacts-"
}

resource "aws_s3_bucket_versioning" "grading_artifacts" {
  bucket = aws_s3_bucket.grading_artifacts.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "grading_artifacts" {
  bucket = aws_s3_bucket.grading_artifacts.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# ---------------------------------------------------------
# 2. IAM Role for CodeBuild
# ---------------------------------------------------------
data "aws_iam_policy_document" "codebuild_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["codebuild.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "codebuild_role" {
  name               = "autograder-codebuild-role"
  assume_role_policy = data.aws_iam_policy_document.codebuild_assume_role.json
}

# Attach managed policies for basic CodeBuild operations
resource "aws_iam_role_policy_attachment" "codebuild_base_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildDeveloperAccess"
}

resource "aws_iam_role_policy_attachment" "codebuild_logs_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/CloudWatchLogsFullAccess"
}

# Inline policy for S3 artifact access
resource "aws_iam_role_policy" "codebuild_s3_access" {
  name = "codebuild-s3-artifacts"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketAcl"
        ]
        Resource = [
          aws_s3_bucket.grading_artifacts.arn,
          "${aws_s3_bucket.grading_artifacts.arn}/*"
        ]
      }
    ]
  })
}

# ---------------------------------------------------------
# 3. Source Credentials (GitHub Token)
# ---------------------------------------------------------
# This resource authenticates CodeBuild to GitHub to access student repos.
# In production, the token should be fetched from AWS Secrets Manager.
resource "aws_codebuild_source_credential" "github_token" {
  auth_type   = "PERSONAL_ACCESS_TOKEN"
  server_type = "GITHUB"
  token       = var.github_personal_access_token
}

# ---------------------------------------------------------
# 4. CloudWatch Log Group
# ---------------------------------------------------------
resource "aws_cloudwatch_log_group" "codebuild_logs" {
  name              = "/aws/codebuild/autograder"
  retention_in_days = 30
}

# ---------------------------------------------------------
# 5. CodeBuild Project (The Autograder)
# ---------------------------------------------------------
resource "aws_codebuild_project" "autograder" {
  name          = "cs-course-autograder"
  description   = "Checks out student code, runs tests, and records grades."
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "15"
  queued_timeout = "5"

  artifacts {
    type = "S3"
    location = aws_s3_bucket.grading_artifacts.bucket
    # packaging = "NONE" # Keep as ZIP if we want to archive the whole repo
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:7.0" # Supports multiple languages (Java, Py, Node, Go)
    type            = "LINUX_CONTAINER"
    privileged_mode = false

    environment_variable {
      name  = "TEST_SUITE_COMMAND"
      value = var.test_command # e.g., "npm test" or "python -m pytest"
    }
  }

  source {
    type            = "GITHUB"
    location        = var.student_repo_url
    git_clone_depth = 1

    # Triggers build on Push events
    git_submodules_config {
      fetch_submodules = false
    }

    buildspec           = data.template_file.buildspec.rendered

    # We need to explicitly link the credential for private repos in certain configurations,
    # though often passed implicitly if configured in the account.
  }

  # Secondary Source (Optional): Can be used to inject a "Test Suite" repo
  # if tests are separate from student code. 
  # For this example, we assume tests are in the student repo or handled by the buildspec.

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.codebuild_logs.name
      stream_name = "autograder-stream"
    }
  }
}

# ---------------------------------------------------------
# 6. Buildspec Definition (The Grading Logic)
# ---------------------------------------------------------
# We inject a buildspec that installs dependencies, runs tests, 
# and exports a result file.
data "template_file" "buildspec" {
  template = file("${path.module}/buildspec.yml")
}

# ---------------------------------------------------------
# 7. Variables
# ---------------------------------------------------------
variable "aws_region" {
  description = "AWS Region to deploy resources"
  default     = "us-east-1"
}

variable "student_repo_url" {
  description = "The GitHub URL of the student or template repository to grade"
  # Example: "https://github.com/university-cs101/student-submissions.git"
  type        = string
}

variable "github_personal_access_token" {
  description = "GitHub PAT to access private repositories"
  type        = string
  sensitive   = true
}

variable "test_command" {
  description = "The shell command to execute the grading tests"
  default     = "echo 'No tests configured' && exit 1"
}

# ---------------------------------------------------------
# 8. Outputs
# ---------------------------------------------------------
output "artifact_bucket_name" {
  value = aws_s3_bucket.grading_artifacts.bucket
}

output "codebuild_project_name" {
  value = aws_codebuild_project.autograder.name
}

