  bucket_prefix = "autograder-artifacts-"
}

resource "aws_s3_bucket_versioning" "grading_artifacts" {
  bucket = aws_s3_bucket.grading_artifacts.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "grading_artifacts" {
  bucket = aws_s3_bucket.grading_artifacts.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# ---------------------------------------------------------
# 2. IAM Role for CodeBuild
# ---------------------------------------------------------
data "aws_iam_policy_document" "codebuild_assume_role" {
