  assume_role_policy = data.aws_iam_policy_document.codebuild_assume_role.json
}

# Attach managed policies for basic CodeBuild operations
resource "aws_iam_role_policy_attachment" "codebuild_base_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildDeveloperAccess"
}

resource "aws_iam_role_policy_attachment" "codebuild_logs_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/CloudWatchLogsFullAccess"
}

# Inline policy for S3 artifact access
resource "aws_iam_role_policy" "codebuild_s3_access" {
