extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ---------------------------------------------------------------------------
# Variables: Configuration for the Course and Repository
# ---------------------------------------------------------------------------
variable "github_token" {
  description = "GitHub Personal Access Token to authenticate with the student repo."
  type        = string
  sensitive   = true
}

variable "github_owner" {
  description = "The GitHub username or organization name."
  default     = "my-university-org"
}

variable "github_repo" {
  description = "The name of the repository containing student submissions."
  default     = "cs101-homework-submissions"
}

variable "bucket_name" {
  description = "The name of the S3 bucket to store grading results."
  default     = "cs-autograding-results-secure-bucket"
}

# ---------------------------------------------------------------------------
# Resource 1: S3 Bucket for Storing Grading Outputs
# ---------------------------------------------------------------------------
resource "aws_s3_bucket" "grading_results" {
  bucket = var.bucket_name

  # Enable versioning to keep history of grading attempts
  versioning {
    enabled = true
  }

  tags = {
    Name        = "Autograder-Results"
    Environment = "Education"
  }
}

# Ensure the bucket is not publicly accessible
resource "aws_s3_bucket_public_access_block" "grading_results_block" {
  bucket = aws_s3_bucket.grading_results.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Server-side encryption for results
resource "aws_s3_bucket_server_side_encryption_configuration" "grading_results_encryption" {
  bucket = aws_s3_bucket.grading_results.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# ---------------------------------------------------------------------------
# Resource 2: IAM Role and Policies for CodeBuild
# ---------------------------------------------------------------------------
resource "aws_iam_role" "codebuild_autograder_role" {
  name = "codebuild-autograder-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

# Policy to allow CodeBuild to upload logs to CloudWatch
resource "aws_iam_role_policy_attachment" "codebuild_logs_policy" {
  role       = aws_iam_role.codebuild_autograder_role.name
  policy_arn = "arn:aws:iam::aws:policy/CloudWatchLogsFullAccess"
}

# Inline Policy to allow CodeBuild to read/write to the specific S3 bucket
resource "aws_iam_role_policy" "codebuild_s3_access" {
  name = "codebuild-s3-access"
  role = aws_iam_role.codebuild_autograder_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetBucketAcl",
          "s3:GetBucketLocation"
        ]
        Resource = aws_s3_bucket.grading_results.arn
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion"
        ]
        Resource = "${aws_s3_bucket.grading_results.arn}/*"
      }
    ]
  })
}

# ---------------------------------------------------------------------------
# Resource 3: GitHub Credentials (OAuth Token)
# ---------------------------------------------------------------------------
resource "aws_codebuild_source_credential" "github_pat" {
  auth_type   = "PERSONAL_ACCESS_TOKEN"
  server_type = "GITHUB"
  token       = var.github_token
}

# ---------------------------------------------------------------------------
# Resource 4: CodeBuild Project (The Autograder)
# ---------------------------------------------------------------------------
resource "aws_codebuild_project" "autograder" {
  name         = "cs-course-autograder"
  description  = "Executes student code submissions, runs tests, and records grades."
  service_role = aws_iam_role.codebuild_autograder_role.arn

  # Timeout for the grading execution (e.g., 15 minutes)
  timeout_in_minutes = 15

  # Configuration for the GitHub Repository
  source {
    type            = "GITHUB"
    location        = "https://github.com/${var.github_owner}/${var.github_repo}.git"
    git_clone_depth = 1

    # Triggers: Build on push to main branch or Pull Requests
    git_submodules_config {
      fetch_submodules = false
    }

    buildspec = "buildspec.yml" # Assumes the repo contains the grading script
  }

  # Configuration for the Grading Artifacts stored in S3
  artifacts {
    type = "S3"
    location = aws_s3_bucket.grading_results.id

    # The buildspec should define files like 'test-results/', 'grades.json'
    # If packaging is true, it zips the output.
    packaging = "ZIP" 
    name      = "grades-$(AWS_REGION)-$(date +%Y-%m-%d)" 
  }

  # Environment configuration
  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:6.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = false

    # Environment variables to control grading logic
    environment_variable {
      name  = "STUDENT_REPO"
      value = "${var.github_owner}/${var.github_repo}"
    }
  }

  # Logging configuration
  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/autograder"
      stream_name = "student-grades"
    }
    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.grading_results.id}/build-logs"
    }
  }
}

# ---------------------------------------------------------------------------
# Outputs
# ---------------------------------------------------------------------------
output "s3_bucket_id" {
  description = "The ID of the S3 bucket containing grading results."
  value       = aws_s3_bucket.grading_results.id
}

output "codebuild_project_name" {
  description = "The name of the CodeBuild project."
  value       = aws_codebuild_project.autograder.name
}

output "codebuild_project_url" {
  description = "The URL to view the project in the AWS Console."
  value       = "https://console.aws.amazon.com/codesuite/codebuild/projects/${aws_codebuild_project.autograder.name}/build"
}

