        }
      }
    ]
  })
}

# Resource: IAM Policy Attachment for CodeBuild to write to S3 and CloudWatch Logs
resource "aws_iam_role_policy_attachment" "codebuild_policy_attach" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/PowerUserAccess"
}

# Resource: CodeBuild Project
resource "aws_codebuild_project" "example" {
  name         = "example-build-project"
  description  = "Example build project storing artifacts in S3"
  service_role = aws_iam_role.codebuild_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.build_artifacts.bucket
  }

  environment {
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "alpine"
    type         = "LINUX_CONTAINER"
  }

  source {
    type            = "GITHUB"
    location        = "github.com/source-location"
    git_clone_depth = 1
  }
}
