terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# 1. Networking: VPC, Subnets, and Endpoints
# -----------------------------------------------------------------------------

resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "autograder-vpc"
  }
}

# Private Subnets for CodeBuild
# No Internet Gateway or NAT Gateway attached, ensuring no internet access.
resource "aws_subnet" "private_subnet" {
  count             = 2
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "autograder-private-subnet-${count.index}"
  }
}

# VPC Endpoints are required for CodeBuild to function without internet access
# 1. S3 Gateway Endpoint (for reading/writing artifacts)
resource "aws_vpc_endpoint" "s3_endpoint" {
  vpc_id       = aws_vpc.autograder_vpc.id
  service_name = "com.amazonaws.${data.aws_region.current.name}.s3"

  tags = {
    Name = "autograder-s3-endpoint"
  }
}

# 2. CodeBuild Interface Endpoint
resource "aws_vpc_endpoint" "codebuild_endpoint" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${data.aws_region.current.name}.codebuild"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = aws_subnet.private_subnet[*].id
  security_group_ids  = [aws_security_group.vpc_endpoint_sg.id]
  private_dns_enabled = true
}

# 3. CloudWatch Logs Interface Endpoint
resource "aws_vpc_endpoint" "logs_endpoint" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${data.aws_region.current.name}.logs"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = aws_subnet.private_subnet[*].id
  security_group_ids  = [aws_security_group.vpc_endpoint_sg.id]
  private_dns_enabled = true
}

# 4. KMS Interface Endpoint (Required for encrypted CloudWatch logs)
resource "aws_vpc_endpoint" "kms_endpoint" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${data.aws_region.current.name}.kms"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = aws_subnet.private_subnet[*].id
  security_group_ids  = [aws_security_group.vpc_endpoint_sg.id]
  private_dns_enabled = true
}

# Security Group for VPC Endpoints
resource "aws_security_group" "vpc_endpoint_sg" {
  name        = "vpc-endpoint-sg"
  description = "Allow traffic for VPC Interface Endpoints"
  vpc_id      = aws_vpc.autograder_vpc.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Route Table for Private Subnets (Route S3 traffic through Gateway Endpoint)
resource "aws_vpc_endpoint_route_table_association" "s3_route" {
  route_table_id  = aws_vpc.autograder_vpc.main_route_table_id
  vpc_endpoint_id = aws_vpc_endpoint.s3_endpoint.id
}

# -----------------------------------------------------------------------------
# 2. Storage: S3 Bucket for Grading Artifacts
# -----------------------------------------------------------------------------

resource "aws_s3_bucket" "grading_results" {
  bucket = "autograder-results-bucket-unique-id"
}

resource "aws_s3_bucket_versioning" "grading_results_versioning" {
  bucket = aws_s3_bucket.grading_results.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "encryption" {
  bucket = aws_s3_bucket.grading_results.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# -----------------------------------------------------------------------------
# 3. IAM Roles and Policies
# -----------------------------------------------------------------------------

# Assume Role Policy
data "aws_iam_policy_document" "codebuild_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["codebuild.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "codebuild_role" {
  name               = "autograder-codebuild-role"
  assume_role_policy = data.aws_iam_policy_document.codebuild_assume_role.json
}

# Policy granting CodeBuild permissions to write to S3 and Logs, and manage VPC ENIs
resource "aws_iam_role_policy" "codebuild_policy" {
  name = "autograder-codebuild-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetBucketVersioning",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.grading_results.arn,
          "${aws_s3_bucket.grading_results.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups"
        ]
        Resource = "*"
      }
    ]
  })
}

# Attach AWS Managed Policies for basic CloudWatch and S3 access
resource "aws_iam_role_policy_attachment" "attach_logs" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/CloudWatchLogsFullAccess"
}

resource "aws_iam_role_policy_attachment" "attach_s3" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

# -----------------------------------------------------------------------------
# 4. CodeBuild Project
# -----------------------------------------------------------------------------

resource "aws_codebuild_project" "autograder" {
  name          = "student-autograder"
  description   = "Build project to grade student submissions in an isolated VPC"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = 15

  artifacts {
    type = "S3"
    location = aws_s3_bucket.grading_results.bucket
    # Optional: encryption disabled if using default AES256
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:5.0" # Or a custom image with grading tools
    type            = "LINUX_CONTAINER"
    privileged_mode = false

    # Environment variables could be passed here
  }

  # VPC Configuration: Runs inside the isolated subnets
  vpc_config {
    vpc_id = aws_vpc.autograder_vpc.id
    subnets = aws_subnet.private_subnet[*].id
    security_group_ids = [aws_security_group.vpc_endpoint_sg.id]
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/your-org/your-repo.git" 
    # In a real no-internet scenario, source would likely be S3 
    # requiring a CodePipeline to mirror GitHub->S3 first.
    # Using GITHUB here to satisfy prompt structure, but noting VPC isolation limits.

    git_clone_depth = 1

    auth {
      type = "OAUTH"
      resource = aws_codestarconnections_connection.example.arn
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name = "autograder-logs"
      status     = "ENABLED"
    }
    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.grading_results.id}/build-logs"
    }
  }
}

# CodeStar Connection for GitHub Auth
# Note: This needs to be created manually via console CLI first: 
# aws codestar-connections create-connection --provider-name GitHub --connection-name "my-connection"
# Or we reference a placeholder.
resource "aws_codestarconnections_connection" "example" {
  name = "autograder-github-connection"
  provider_type = "GitHub"
}

# Data sources
data "aws_region" "current" {}
data "aws_availability_zones" "available" {}

