provider "aws" {
  region = "us-east-1"
}

# 2. Data Sources
data "aws_caller_identity" "current" {}
data "aws_region" "current" {}

# 3. Networking (VPC, Subnet, Route Table)
# We create a VPC with a single private subnet. 
# There is NO Internet Gateway or NAT Gateway, ensuring no outbound internet access.

resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc"
  }
}

resource "aws_subnet" "private_subnet" {
  vpc_id     = aws_vpc.autograder_vpc.id
  cidr_block = "10.0.1.0/24"

  tags = {
    Name = "autograder-private-subnet"
  }
}

resource "aws_route_table" "private_rt" {
  vpc_id = aws_vpc.autograder_vpc.id

  # Intentionally NO route to 0.0.0.0/0. This blocks all internet access.
  # Routes will be added dynamically for VPC Endpoints (S3, etc) to allow AWS internal access.

  tags = {
    Name = "autograder-private-rt"
  }
}

resource "aws_route_table_association" "subnet_assoc" {
  subnet_id      = aws_subnet.private_subnet.id
  route_table_id = aws_route_table.private_rt.id
}

# 4. VPC Endpoints
# Since we have no internet access, we need VPC endpoints for CodeBuild to function.
# It needs to reach S3 (logs/artifacts), CloudWatch Logs (logs), and ECR (pull build images).

# S3 Gateway Endpoint (Required for S3 Access)
resource "aws_vpc_endpoint" "s3_endpoint" {
  vpc_id       = aws_vpc.autograder_vpc.id
  service_name = "com.amazonaws.${data.aws_region.current.name}.s3"

  route_table_ids = [
    aws_route_table.private_rt.id
  ]

  tags = {
    Name = "autograder-s3-endpoint"
  }
}

# Security Group for Interface VPC Endpoints
resource "aws_security_group" "vpc_endpoint_sg" {
  name        = "vpc-endpoint-sg"
  description = "Security group for VPC Interface Endpoints"
  vpc_id      = aws_vpc.autograder_vpc.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# CloudWatch Logs Interface Endpoint
resource "aws_vpc_endpoint" "logs_endpoint" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${data.aws_region.current.name}.logs"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private_subnet.id]
  security_group_ids  = [aws_security_group.vpc_endpoint_sg.id]
  private_dns_enabled = true
}

# ECR API Interface Endpoint (Required for CodeBuild to pull images)
resource "aws_vpc_endpoint" "ecr_api_endpoint" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${data.aws_region.current.name}.ecr.api"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private_subnet.id]
  security_group_ids  = [aws_security_group.vpc_endpoint_sg.id]
  private_dns_enabled = true
}

# ECR DKR Interface Endpoint (Required for CodeBuild to pull images)
resource "aws_vpc_endpoint" "ecr_dkr_endpoint" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${data.aws_region.current.name}.ecr.dkr"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private_subnet.id]
  security_group_ids  = [aws_security_group.vpc_endpoint_sg.id]
  private_dns_enabled = true
}

# CodeBuild Interface Endpoint
resource "aws_vpc_endpoint" "codebuild_endpoint" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${data.aws_region.current.name}.codebuild"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private_subnet.id]
  security_group_ids  = [aws_security_group.vpc_endpoint_sg.id]
  private_dns_enabled = true
}

# 5. S3 Bucket for Grading Outputs
resource "aws_s3_bucket" "grading_output_bucket" {
  bucket = "autograder-results-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name = "autograder-results"
  }
}

resource "aws_s3_bucket_versioning" "versioning" {
  bucket = aws_s3_bucket.grading_output_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# 6. Security Group for CodeBuild
resource "aws_security_group" "codebuild_sg" {
  name        = "codebuild-sg"
  description = "Security group for CodeBuild in VPC"
  vpc_id      = aws_vpc.autograder_vpc.id

  # Egress is required to access VPC Endpoints (port 443)
  # We restrict egress to the VPC CIDR or specific endpoint SGs for maximum security,
  # but allowing 443 outbound is standard for internal communication.
  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
  }

  # Allow ephemeral ports for callbacks
  egress {
    from_port   = 1024
    to_port     = 65535
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
  }
}

# 7. IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_base_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildDeveloperAccess"
}

resource "aws_iam_role_policy_attachment" "codebuild_vpc_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonVPCFullAccess"
}

# Custom Policy to access S3 and Logs specifically
resource "aws_iam_role_policy" "codebuild_custom_policy" {
  name = "codebuild-custom-policy"
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetBucketVersioning"
        ]
        Resource = [
          aws_s3_bucket.grading_output_bucket.arn,
          "${aws_s3_bucket.grading_output_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ecr:BatchCheckLayerAvailability",
          "ecr:GetDownloadUrlForLayer",
          "ecr:BatchGetImage"
        ]
        Resource = "*"
      }
    ]
  })
}

# 8. CodeBuild Project
resource "aws_codebuild_project" "autograder_project" {
  name          = "autograder-project"
  description   = "Runs student submissions in an isolated VPC without internet access."
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "10"

  artifacts {
    type = "NO_ARTIFACTS"
  }

  # Environment Configuration
  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:5.0" # Standard image includes Python, Java, Node, etc.
    type            = "LINUX_CONTAINER"
    privileged_mode = true

    environment_variable {
      name  = "OUTPUT_BUCKET"
      value = aws_s3_bucket.grading_output_bucket.id
    }
  }

  # Source Configuration (GitHub)
  source {
    type     = "GITHUB"
    location = "https://github.com/your-org/your-repo.git" # Replace with actual repo

    git_clone_depth = 1

    # In a real scenario, use OAUTH token or access details securely stored
  }

  # VPC Configuration for Isolation
  vpc_config {
    vpc_id = aws_vpc.autograder_vpc.id

    subnets = [
      aws_subnet.private_subnet.id
    ]

    security_group_ids = [
      aws_security_group.codebuild_sg.id
    ]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "autograder-logs"
      stream_name = "build-logs"
    }
  }
}

