extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. S3 Bucket for Cat Images
resource "aws_s3_bucket" "cat_images" {
  bucket = "cat-image-store-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

resource "aws_s3_bucket_ownership_controls" "cat_images" {
  bucket = aws_s3_bucket.cat_images.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "cat_images" {
  depends_on = [aws_s3_bucket_ownership_controls.cat_images]
  bucket     = aws_s3_bucket.cat_images.id
  acl        = "private"
}

# 2. IAM Role for Lambda
resource "aws_iam_role" "lambda_role" {
  name = "cat_api_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Policy to allow Lambda to access S3 and CloudWatch Logs
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "lambda_s3_access" {
  name = "lambda_s3_access_policy"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.cat_images.arn,
          "${aws_s3_bucket.cat_images.arn}/*"
        ]
      }
    ]
  })
}

# 3. Lambda Function Code (Python)
# We embed the code directly to keep the configuration self-contained.
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function_payload.zip"
  source {
    content = <<EOF
import json
import base64
import boto3
import random
import os
import uuid

s3 = boto3.client('s3')
BUCKET_NAME = os.environ['BUCKET_NAME']

def lambda_handler(event, context):
    method = event['httpMethod']
    headers = {
        "Content-Type": "image/jpeg",
        "Access-Control-Allow-Origin": "*"
    }

    # Handle GET: Return a random cat image
    if method == 'GET':
        try:
            response = s3.list_objects_v2(Bucket=BUCKET_NAME)

            if 'Contents' not in response or len(response['Contents']) == 0:
                return {
                    'statusCode': 404,
                    'body': json.dumps({'message': 'No cat images found. Please upload one!'})
                }

            # Pick a random file
            random_obj = random.choice(response['Contents'])
            key = random_obj['Key']

            # Get the object from S3
            file_obj = s3.get_object(Bucket=BUCKET_NAME, Key=key)
            file_content = file_obj['Body'].read()

            # Determine content type (defaulting to jpeg if not found)
            content_type = file_obj.get('ContentType', 'image/jpeg')
            headers["Content-Type"] = content_type

            return {
                'statusCode': 200,
                'headers': headers,
                'body': base64.b64encode(file_content).decode('utf-8'),
                'isBase64Encoded': True
            }
        except Exception as e:
            print(e)
            return {'statusCode': 500, 'body': json.dumps({'error': str(e)})}

    # Handle POST: Upload a cat image
    elif method == 'POST':
        try:
            # API Gateway with binary support sends base64 encoded body
            is_base64_encoded = event.get('isBase64Encoded', False)
            body = event['body']

            if is_base64_encoded:
                image_data = base64.b64decode(body)
            else:
                image_data = body.encode('utf-8')

            # Generate a unique filename
            file_extension = 'jpg' # Default, ideally parsed from Content-Type header
            filename = f"{uuid.uuid4()}.{file_extension}"

            # Upload to S3
            s3.put_object(
                Bucket=BUCKET_NAME,
                Key=filename,
                Body=image_data,
                ContentType='image/jpeg'
            )

            return {
                'statusCode': 201,
                'body': json.dumps({'message': 'Cat uploaded successfully', 'key': filename}),
                'headers': {"Content-Type": "application/json"}
            }
        except Exception as e:
            print(e)
            return {'statusCode': 500, 'body': json.dumps({'error': str(e)})}

    return {'statusCode': 400, 'body': json.dumps({'message': 'Unsupported method'})}
EOF
    filename = "lambda_function.py"
  }
}

resource "aws_lambda_function" "cat_api" {
  filename         = data.archive_file.lambda_zip.output_path
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
  function_name    = "CatApiHandler"
  role             = aws_iam_role.lambda_role.arn
  handler          = "lambda_function.lambda_handler"
  runtime          = "python3.9"

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_images.id
    }
  }
}

# 4. API Gateway
resource "aws_api_gateway_rest_api" "cat_api" {
  name        = "CatImageAPI"
  description = "API for uploading and retrieving random cat images"

  # Enable binary support for handling images
