response:
Hereis the step-by-step thought process for the Terraform configuration:

1.  **S3 Bucket**: We need a centralized bucket to store the uploaded cat images. We will block public access to the bucket itself to ensure security, relying on Lambda and pre-signed URLs for access.
2.  **IAM Roles**: The Lambda function requires an IAM role. This role must have permission to write images to the S3 bucket (`s3:PutObject`), list the bucket to find a random image (`s3:ListBucket`), and generate a pre-signed URL (`s3:GetObject`). It also needs basic execution permissions for CloudWatch Logs.
3.  **Lambda Function**: We will create a single Python 3.x Lambda function to handle both logic paths:
    *   **POST /upload**: Decodes the base64 image payload from API Gateway, generates a unique ID, and saves the file to S3.
    *   **GET /random**: Lists objects in the S3 bucket, picks one at random, and generates a time-limited pre-signed URL to return to the client.
4.  **API Gateway**: We will set up a REST API.
    *   It needs `binary_media_types` set to `*/*` so that image uploads are base64-encoded automatically before reaching Lambda.
    *   We will define two resources: `/upload` (POST method) and `/random` (GET method).
    *   Both will integrate with the Lambda function using `AWS_PROXY` integration type.
5.  **Lambda Permissions**: We must explicitly grant API Gateway permission to invoke the Lambda function.
6.  **Deployment**: Finally, we deploy the API Gateway to a stage (e.g., `prod`) so it is accessible via a URL.

Below is the complete Terraform configuration.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source = "hashicorp/random"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Generate a unique suffix for resource naming to avoid collisions
resource "random_pet" "this" {
  length = 2
}

# ---------------------------------------------------------
# 1. S3 Bucket
# ---------------------------------------------------------
resource "aws_s3_bucket" "cat_images" {
  bucket = "cat-images-${random_pet.this.id}"
}

resource "aws_s3_bucket_public_access_block" "cat_images" {
  bucket = aws_s3_bucket.cat_images.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# ---------------------------------------------------------
# 2. IAM Role & Policy for Lambda
# ---------------------------------------------------------
data "aws_iam_policy_document" "lambda_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["lambda.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "lambda_iam" {
  name               = "cat-api-lambda-role-${random_pet.this.id}"
  assume_role_policy = data.aws_iam_policy_document.lambda_assume_role.json
}

data "aws_iam_policy_document" "lambda_s3_access" {
  statement {
    effect = "Allow"
    actions = [
      "s3:PutObject",
      "s3:GetObject",
      "s3:ListBucket"
    ]
    resources = [
      aws_s3_bucket.cat_images.arn,
      "${aws_s3_bucket.cat_images.arn}/*"
    ]
  }
  statement {
    effect = "Allow"
    actions = [
      "logs:CreateLogGroup",
      "logs:CreateLogStream",
      "logs:PutLogEvents"
    ]
    resources = ["arn:aws:logs:*:*:*"]
  }
}

resource "aws_iam_role_policy" "lambda_s3_policy" {
  name   = "cat-api-lambda-policy"
  role   = aws_iam_role.lambda_iam.id
  policy = data.aws_iam_policy_document.lambda_s3_access.json
}

# ---------------------------------------------------------
# 3. Lambda Function
# ---------------------------------------------------------

# Generate the Python code locally to package into the Lambda zip
resource "local_file" "lambda_handler" {
  filename = "${path.module}/lambda_handler.py"
  content  = <<-EOF
import json
import boto3
import base64
import uuid
import os
import random
import logging

logger = logging.getLogger()
logger.setLevel(logging.INFO)

s3 = boto3.client('s3')
BUCKET_NAME = os.environ['BUCKET_NAME']

def lambda_handler(event, context):
    logger.info(f"Received event: {event}")

    http_method = event.get('httpMethod')
    path = event.get('path')

    # Handle POST /upload
    if http_method == 'POST' and path == '/upload':
        try:
            # API Gateway base64 encodes binary bodies if binary media types are set
            is_base64_encoded = event.get('isBase64Encoded', False)
            body_content = event.get('body', '')

            file_data = base64.b64decode(body_content) if is_base64_encoded else body_content.encode('utf-8')

            # Determine content type
            headers = event.get('headers', {})
            content_type = headers.get('Content-Type') or headers.get('content-type') or 'image/jpeg'

            # Generate unique filename
            filename = f"{uuid.uuid4()}"

            s3.put_object(
                Bucket=BUCKET_NAME,
                Key=filename,
                Body=file_data,
                ContentType=content_type
            )

            return {
                'statusCode': 200,
                'body': json.dumps({'message': 'Upload successful', 'key': filename})
            }
        except Exception as e:
            logger.error(f"Upload error: {str(e)}")
            return {
                'statusCode': 500,
                'body': json.dumps({'error': str(e)})
            }

    # Handle GET /random
    elif http_method == 'GET' and path == '/random':
        try:
            response = s3.list_objects_v2(Bucket=BUCKET_NAME)

            if 'Contents' not in response or not response['Contents']:
                return {
                    'statusCode': 404,
                    'body': json.dumps({'error': 'No images found in bucket'})
                }

            # Pick a random object
            random_obj = random.choice(response['Contents'])
            key = random_obj['Key']

            # Generate a pre-signed URL valid for 5 minutes
            url = s3.generate_presigned_url(
                'get_object',
                Params={'Bucket': BUCKET_NAME, 'Key': key},
                ExpiresIn=300
            )

            return {
                'statusCode': 200,
                'body': json.dumps({'url': url})
            }
        except Exception as e:
            logger.error(f"Get random error: {str(e)}")
            return {
                'statusCode': 500,
                'body': json.dumps({'error': str(e)})
            }

    # Invalid route
    return {
        'statusCode': 400,
        'body': json.dumps({'message': 'Unsupported route or method'})
    }
EOF
}

data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = local_file.lambda_handler.filename
  output_path = "${path.module}/lambda_function_payload.zip"
}

resource "aws_lambda_function" "cat_api" {
  filename         = data.archive_file.lambda_zip.output_path
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
  function_name    = "CatApiHandler-${random_pet.this.id}"
  role             = aws_iam_role.lambda_iam.arn
  handler          = "lambda_handler.lambda_handler"
  runtime          = "python3.9"

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_images.id
    }
  }
}

# ---------------------------------------------------------
# 4. API Gateway
# ---------------------------------------------------------
resource "aws_api_gateway_rest_api" "cat_api" {
  name        = "CatImageAPI-${random_pet.this.id}"
  description = "API for uploading and retrieving random cat images"

  # Ensure API Gateway handles binary payloads (images) correctly
  binary_media_types = ["*/*"]
}

# Resource: /upload
resource "aws_api_gateway_resource" "upload" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "upload"
}

# Method: POST /upload
resource "aws_api_gateway_method" "upload_post" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.upload.id
  http_method   = "POST"
  authorization = "NONE"
}

# Integration: POST /upload -> Lambda
resource "aws_api_gateway_integration" "upload_lambda" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.upload.id
  http_method = aws_api_gateway_method.upload_post.http_method

  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.cat_api.invoke_arn
}

# Resource: /random
resource "aws_api_gateway_resource" "random" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "random"
}

# Method: GET /random
resource "aws_api_gateway_method" "random_get" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.random.id
  http_method   = "GET"
  authorization = "NONE"
}

# Integration: GET /random -> Lambda
resource "aws_api_gateway_integration" "random_lambda" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.random.id
  http_method = aws_api_gateway_method.random_get.http_method

  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.cat_api.invoke_arn
}

# Permission for API Gateway to invoke Lambda
resource "aws_lambda_permission" "api_gateway_invoke" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_api.function_name
  principal     = "apigateway.amazonaws.com"

  source_arn = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/*"
}

# Deployment
resource "aws_api_gateway_deployment" "cat_api" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id

  # Trigger deployment if configuration changes
  triggers = {
    redployment = sha1(jsonencode([
      aws_api_gateway_resource.upload.id,
      aws_api_gateway_method.upload_post.id,
      aws_api_gateway_integration.upload_lambda.id,
      aws_api_gateway_resource.random.id,
      aws_api_gateway_method.random_get.id,
      aws_api_gateway_integration.random_lambda.id,
    ]))
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_api_gateway_stage" "prod" {
  deployment_id = aws_api_gateway_deployment.cat_api.id
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  stage_name    = "prod"
}

# ---------------------------------------------------------
# 5. Outputs
# ---------------------------------------------------------
output "api_endpoint" {
  value = "${aws_api_gateway_stage.prod.invoke_url}"
}

output "upload_url" {
  value = "${aws_api_gateway_stage.prod.invoke_url}/upload"
}

output "random_url" {
  value = "${aws_api_gateway_stage.prod.invoke_url}/random"
}
