terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}


provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_dynamodb_table" "caas" {
  name           = "cat_names"
  hash_key       = "name"
  billing_mode   = "PAY_PER_REQUEST"

  attribute {
    name = "name"
    type = "S"
  }
}

resource "aws_s3_bucket" "caas" {
  bucket_prefix = "cat-image"
}

resource "aws_iam_role" "lambda_role" {
  name = "lambda_api_gateway_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lambda_policy" {
  name   = "lambda_policy"
  role   = aws_iam_role.lambda_role.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ]
        Effect   = "Allow"
        Resource = "${aws_s3_bucket.caas.arn}/*"
      },
      {
        Action = [
          "dynamodb:PutItem"
        ]
        Effect   = "Allow"
        Resource = aws_dynamodb_table.caas.arn
      }
    ]
  })
}

resource "aws_api_gateway_rest_api" "caas" {
  name = "caas"
}

resource "aws_api_gateway_resource" "caas_cat" {
  rest_api_id = aws_api_gateway_rest_api.caas.id
  parent_id   = aws_api_gateway_rest_api.caas.root_resource_id
  path_part   = "cat"
}

resource "aws_api_gateway_method" "caas_cat_get" {
  rest_api_id   = aws_api_gateway_rest_api.caas.id
  resource_id   = aws_api_gateway_resource.caas_cat.id
  http_method   = "GET"
  authorization = "NONE"
}

resource "aws_api_gateway_method" "caas_cat_put" {
  rest_api_id   = aws_api_gateway_rest_api.caas.id
  resource_id   = aws_api_gateway_resource.caas_cat.id
  http_method   = "PUT"
  authorization = "NONE"
}

data "archive_file" "caas_cat" {
  type        = "zip"
  source_file = "./supplement/caas_cat.py"
  output_path = "./supplement/caas_cat.zip"
}

resource "aws_lambda_function" "caas_cat" {
  function_name = "caas_cat"
  role          = aws_iam_role.lambda_role.arn
  filename      = data.archive_file.caas_cat.output_path
  source_code_hash = data.archive_file.caas_cat.output_base64sha256
  handler       = "caas_cat.handler"
  runtime       = "python3.12"

  environment {
    variables = {
      CAAS_S3_BUCKET = "${aws_s3_bucket.caas.id}"
      DYNAMODB_TABLE_NAME = "${aws_dynamodb_table.caas.id}"
    }
  }
}

resource "aws_api_gateway_integration" "caas_cat_get" {
  rest_api_id             = aws_api_gateway_rest_api.caas.id
  resource_id             = aws_api_gateway_resource.caas_cat.id
  http_method             = aws_api_gateway_method.caas_cat_get.http_method
  type                    = "AWS_PROXY"
  integration_http_method = "GET"
  uri                     = aws_lambda_function.caas_cat.invoke_arn
}

resource "aws_api_gateway_integration" "caas_cat_put" {
  rest_api_id             = aws_api_gateway_rest_api.caas.id
  resource_id             = aws_api_gateway_resource.caas_cat.id
  http_method             = aws_api_gateway_method.caas_cat_put.http_method
  type                    = "AWS_PROXY"
  integration_http_method = "PUT"
  uri                     = aws_lambda_function.caas_cat.invoke_arn
}

resource "aws_lambda_permission" "caas_cat" {
  action        = "lambda:InvokeFunction"
  principal     = "apigateway.amazonaws.com"
  function_name = aws_lambda_function.caas_cat.function_name

  source_arn = "${aws_api_gateway_rest_api.caas.execution_arn}/*/*"
}

resource "aws_api_gateway_deployment" "api_deployment" {
  rest_api_id = aws_api_gateway_rest_api.caas.id
  depends_on  = [aws_api_gateway_integration.caas_cat_get, 
                 aws_api_gateway_integration.caas_cat_put]
}

resource "aws_api_gateway_stage" "api_stage" {
  deployment_id = aws_api_gateway_deployment.api_deployment.id
  rest_api_id   = aws_api_gateway_rest_api.caas.id
  stage_name    = "dev"
}

output "api_id" {
  value = aws_api_gateway_rest_api.caas.id
  description = "The API Gateway ID"
}

response:
Here is the step-by-step reasoning for the Terraform configuration:

1.  **Provider Configuration**: We need to configure the AWS provider. We'll use a default region (us-east-1) to ensure resources like API Gateway and Lambda are compatible.
2.  **S3 Bucket**: We will create an `aws_s3_bucket` resource to store cat images.
3.  **DynamoDB Table**: We will create an `aws_dynamodb_table` with the `name` attribute as the partition key (Hash Key) and set billing mode to PAY_PER_REQUEST for simplicity.
4.  **IAM Role**: The Lambda functions need an execution role to run. We will create a role with the `AWSLambdaBasicExecutionRole` policy attached.
5.  **Lambda Functions**:
    *   We need two functions: `caas_get` and `caas_put`.
    *   To make this code runnable without external dependencies, I will use `local_file` to create dummy Python scripts and `archive_file` to zip them, satisfying the `filename` requirement for the `aws_lambda_function` resource.
6.  **API Gateway**:
    *   Create the REST API named "caas".
    *   Create a resource named "caas_cat" with the path part "cat" under the root resource.
7.  **Methods and Integrations**:
    *   Create a `GET` method (`caas_get`) and a `PUT` method (`caas_put`) on the "cat" resource.
    *   Create `aws_api_gateway_integration` resources for both, connecting them to their respective Lambda functions using `AWS_PROXY` integration type.
8.  **Permissions**: We need `aws_lambda_permission` resources to allow API Gateway to invoke the specific Lambda functions. The `source_arn` will point to the API Gateway execution ARN for the specific method and path.
9.  **Deployment**: Finally, we create an `aws_api_gateway_deployment` and an `aws_api_gateway_stage` to deploy the API so it is accessible.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    archive = {
      source  = "hashicorp/archive"
      version = "~> 2.0"
    }
    local = {
      source  = "hashicorp/local"
      version = "~> 2.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- 1. S3 Bucket for Cat Images ---
resource "aws_s3_bucket" "cat_images" {
  bucket = "caas-cat-images-bucket"
}

resource "aws_s3_bucket_ownership_controls" "cat_images_ownership" {
  bucket = aws_s3_bucket.cat_images.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "cat_images_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.cat_images_ownership]
  bucket = aws_s3_bucket.cat_images.id
  acl    = "private"
}

# --- 2. DynamoDB Table for Cat Data ---
resource "aws_dynamodb_table" "cats" {
  name           = "caas-cats-table"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "name"

  attribute {
    name = "name"
    type = "S"
  }
}

# --- 3. IAM Role for Lambda ---
resource "aws_iam_role" "lambda_exec_role" {
  name = "caas_lambda_exec_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_exec_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# --- 4. Dummy Lambda Code Generation (For completeness) ---
# GET Lambda
resource "local_file" "get_lambda_src" {
  filename = "${path.module}/get_lambda.py"
  content  = "def handler(event, context): return {'statusCode': 200, 'body': 'Meow'}"
}

resource "archive_file" "get_lambda_zip" {
  type        = "zip"
  source_file = local_file.get_lambda_src.filename
  output_path = "${path.module}/get_lambda_payload.zip"
}

# PUT Lambda
resource "local_file" "put_lambda_src" {
  filename = "${path.module}/put_lambda.py"
  content  = "def handler(event, context): return {'statusCode': 200, 'body': 'Cat Updated'}"
}

resource "archive_file" "put_lambda_zip" {
  type        = "zip"
  source_file = local_file.put_lambda_src.filename
  output_path = "${path.module}/put_lambda_payload.zip"
}

# --- 5. Lambda Functions ---
resource "aws_lambda_function" "caas_get" {
  function_name = "caas_get"
  role          = aws_iam_role.lambda_exec_role.arn
  runtime       = "python3.9"
  handler       = "get_lambda.handler"
  filename      = archive_file.get_lambda_zip.output_path
  source_code_hash = archive_file.get_lambda_zip.output_base64sha256

  environment {
    variables = {
      BUCKET = aws_s3_bucket.cat_images.id
      TABLE  = aws_dynamodb_table.cats.name
    }
  }
}

resource "aws_lambda_function" "caas_put" {
  function_name = "caas_put"
  role          = aws_iam_role.lambda_exec_role.arn
  runtime       = "python3.9"
  handler       = "put_lambda.handler"
  filename      = archive_file.put_lambda_zip.output_path
  source_code_hash = archive_file.put_lambda_zip.output_base64sha256

  environment {
    variables = {
      BUCKET = aws_s3_bucket.cat_images.id
      TABLE  = aws_dynamodb_table.cats.name
    }
  }
}

# --- 6. API Gateway Configuration ---
resource "aws_api_gateway_rest_api" "caas" {
  name        = "caas"
  description = "Cats as a Service API"
}

resource "aws_api_gateway_resource" "caas_cat" {
  rest_api_id = aws_api_gateway_rest_api.caas.id
  parent_id   = aws_api_gateway_rest_api.caas.root_resource_id
  path_part   = "cat"
}

# --- 7. Methods and Integrations ---

# GET Method
resource "aws_api_gateway_method" "caas_get" {
  rest_api_id   = aws_api_gateway_rest_api.caas.id
  resource_id   = aws_api_gateway_resource.caas_cat.id
  http_method   = "GET"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "caas_get_integration" {
  rest_api_id = aws_api_gateway_rest_api.caas.id
  resource_id = aws_api_gateway_resource.caas_cat.id
  http_method = aws_api_gateway_method.caas_get.http_method

  type                    = "AWS_PROXY"
  integration_http_method = "POST"
  uri                     = aws_lambda_function.caas_get.invoke_arn
}

# PUT Method
resource "aws_api_gateway_method" "caas_put" {
  rest_api_id   = aws_api_gateway_rest_api.caas.id
  resource_id   = aws_api_gateway_resource.caas_cat.id
  http_method   = "PUT"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "caas_put_integration" {
  rest_api_id = aws_api_gateway_rest_api.caas.id
  resource_id = aws_api_gateway_resource.caas_cat.id
  http_method = aws_api_gateway_method.caas_put.http_method

  type                    = "AWS_PROXY"
  integration_http_method = "POST"
  uri                     = aws_lambda_function.caas_put.invoke_arn
}

# --- 8. Lambda Permissions for API Gateway ---
resource "aws_lambda_permission" "allow_api_gateway_get" {
  statement_id  = "AllowExecutionFromAPIGatewayGet"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.caas_get.function_name
  principal     = "apigateway.amazonaws.com"

  source_arn = "${aws_api_gateway_rest_api.caas.execution_arn}/*/GET/cat"
}

resource "aws_lambda_permission" "allow_api_gateway_put" {
  statement_id  = "AllowExecutionFromAPIGatewayPut"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.caas_put.function_name
  principal     = "apigateway.amazonaws.com"

  source_arn = "${aws_api_gateway_rest_api.caas.execution_arn}/*/PUT/cat"
}

# --- 9. Deployment ---
resource "aws_api_gateway_deployment" "caas_deploy" {
  rest_api_id = aws_api_gateway_rest_api.caas.id

  triggers = {
    redeployment = sha1(jsonencode([
      aws_api_gateway_resource.caas_cat.id,
      aws_api_gateway_method.caas_get.id,
      aws_api_gateway_method.caas_put.id,
      aws_api_gateway_integration.caas_get_integration.id,
      aws_api_gateway_integration.caas_put_integration.id,
    ]))
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_api_gateway_stage" "caas_stage" {
  deployment_id = aws_api_gateway_deployment.caas_deploy.id
  rest_api_id   = aws_api_gateway_rest_api.caas.id
  stage_name    = "v1"
}
