terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_ami" "amzn2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["*ubuntu-noble-24.04-amd64-server-*"]
  }
}

resource "aws_instance" "cloud_desktop" {
  instance_type = "t2.micro"
  ami = data.aws_ami.amzn2.id
}

resource "aws_backup_plan" "cloud_desktop_backup" {
  name = "cloud_desktop_backup_plan"
  rule {
    rule_name         = "cloud_desktop_backup_rule" # required, not specified
    target_vault_name = aws_backup_vault.valut.name # required, not specified
    schedule          = "cron(0 0 * * ? *)"
  }

  advanced_backup_setting {
    backup_options = {
      WindowsVSS = "enabled"
    }
    resource_type = "EC2"
  }
}

resource "aws_backup_vault" "valut" {
  name = "cloud_desktop_backup_valut"
}

resource "aws_backup_selection" "backup_ec2" {
  iam_role_arn = aws_iam_role.backup.arn

  name    = "backup_ec2"
  plan_id = aws_backup_plan.cloud_desktop_backup.id

  resources = [
    aws_instance.cloud_desktop.arn,
  ]
}

data "aws_iam_policy_document" "backup_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["backup.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "backup" {
  name               = "backup"
  assume_role_policy = data.aws_iam_policy_document.backup_assume_role.json
}

resource "aws_iam_role_policy_attachment" "backup" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup.name
}

response:
Here is the step-by-step thinking process to generate the Terraform configuration:

1.  **Analyze the Request:**
    *   **Goal:** Create an EC2 instance and back it up using AWS Backup.
    *   **Schedule:** Every day at 12:00 AM.
    *   **Provider:** AWS.
    *   **Output:** A single HCL code block.

2.  **Identify Necessary Resources:**
    *   **Networking (VPC, Subnet, Security Group):** An EC2 instance requires network infrastructure to run. I'll create a minimal VPC, Subnet, and a Security Group allowing SSH (for basic accessibility).
    *   **Compute (EC2 Instance):** The target resource. I need to pull a recent AMI (Amazon Linux 2) and create the instance. Crucially, I must tag this instance so AWS Backup can identify it.
    *   **IAM (Role & Policy):** AWS Backup needs permissions to take snapshots of the EC2 instance. I need to create an IAM Role that trusts the `backup.amazonaws.com` service and grants permissions like `ec2:CreateSnapshot`, `ec2:DeleteSnapshot`, etc.
    *   **Backup Infrastructure:**
        *   `aws_backup_vault`: A logical container for backups.
        *   `aws_backup_plan`: Defines *what* to back up, *when* to back it up, and *where* to store it. The schedule needs to be a cron expression for 12:00 AM daily (`cron(0 0 ? * * *)`).
        *   `aws_backup_selection`: Links the Backup Plan to the specific resources (the EC2 instance) via tags.

3.  **Drafting the Configuration (Mental or Scratchpad):**

    *   *VPC:* Standard `aws_vpc`, `aws_subnet` (map_public_ip_on_launch = true for simplicity), and `aws_security_group`.
    *   *EC2:* `aws_instance` with tags `{ Backup = "True" }`.
    *   *IAM Role:*
        *   Assume Role Policy: Allow `backup.amazonaws.com`.
        *   Permission Policy: Allow `ec2:*` on snapshots/volumes/instances for the backup context.
    *   *Backup Plan:*
        *   Rule name: "DailyBackup".
        *   Schedule: `cron(0 0 ? * * *)` (This is 00:00 UTC).
        *   Lifecycle: Keep for 7 days (example).
        *   Target Vault: ARN of the vault created.
    *   *Backup Selection:*
        *   Select resources with tag key `Backup` and value `True`.

4.  **Refining the Schedule:**
    *   AWS Backup cron syntax requires 6 fields: `Minutes Hours Day_of_month Month Day_of_week Year`.
    *   12:00 AM daily -> Minute 0, Hour 0.
    *   AWS requires `?` for either Day-of-month or Day-of-week.
    *   Expression: `cron(0 0 ? * * *)`.

5.  **Constructing the Final HCL:**
    *   Assemble the resources into a cohesive file.
    *   Ensure dependencies (VPC -> Subnet -> EC2) are implicitly handled by Terraform or explicitly referenced where necessary (e.g., `subnet_id` in EC2).
    *   Add comments explaining the schedule and IAM permissions.

6.  **Final Review:**
    *   Does it create an EC2 instance? Yes.
    *   Does it set up AWS Backup? Yes.
    *   Is it scheduled for daily at 12:00 AM? Yes (`cron(0 0 ? * * *)`).
    *   Is it one code block? Yes.

7.  **Generate Output.**

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# 1. Networking Setup (VPC, Subnet, Security Group)
# -----------------------------------------------------------------------------
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "backup-vpc"
  }
}

resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone       = "us-east-1a"

  tags = {
    Name = "backup-subnet"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "backup-igw"
  }
}

resource "aws_route_table" "rt" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "backup-rt"
  }
}

resource "aws_route_table_association" "a" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.rt.id
}

resource "aws_security_group" "allow_ssh" {
  name        = "allow_ssh"
  description = "Allow SSH inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "SSH from anywhere"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "allow_ssh_sg"
  }
}

# -----------------------------------------------------------------------------
# 2. EC2 Instance Setup
# -----------------------------------------------------------------------------

# Data source to fetch the latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

resource "aws_instance" "web_server" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.public.id
  vpc_security_group_ids = [aws_security_group.allow_ssh.id]

  # Important: Tag the instance so AWS Backup can select it
  tags = {
    Name  = "WebServer-To-Backup"
    Backup = "True" 
  }
}

# -----------------------------------------------------------------------------
# 3. IAM Setup for AWS Backup
# -----------------------------------------------------------------------------

# IAM Role that AWS Backup service assumes to perform actions
resource "aws_iam_role" "backup_role" {
  name = "aws_backup_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

# Policy allowing the role to manage EC2 snapshots
resource "aws_iam_role_policy" "backup_ec2_policy" {
  name = "backup_ec2_policy"
  role = aws_iam_role.backup_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateSnapshot",
          "ec2:DeleteSnapshot",
          "ec2:DescribeInstances",
          "ec2:DescribeSnapshots",
          "ec2:DescribeVolumes",
          "ec2:CreateTags"
        ]
        Resource = "*"
      }
    ]
  })
}

# -----------------------------------------------------------------------------
# 4. AWS Backup Configuration
# -----------------------------------------------------------------------------

# The Backup Vault stores the backups
resource "aws_backup_vault" "example_vault" {
  name        = "daily_backup_vault"
}

# The Backup Plan defines the schedule and rules
resource "aws_backup_plan" "daily_plan" {
  name = "ec2_daily_backup_plan"

  rule {
    rule_name         = "daily_12am_rule"
    target_vault_arn  = aws_backup_vault.example_vault.arn
    schedule_expression = "cron(0 0 ? * * *)" # Runs every day at 12:00 AM (UTC)

    # Lifecycle configuration (optional): Keep backups for 7 days
    lifecycle {
      delete_after = 7
    }
  }
}

# The Backup Selection defines which resources are backed up by the plan
resource "aws_backup_selection" "ec2_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "ec2_backup_selection"
  plan_id      = aws_backup_plan.daily_plan.id

  resources = []

  # Select resources based on tags
  selection_tag {
    type  = "STRING_EQUALS"
    key   = "Backup"
    value = "True"
  }
}
```

