    Backup = "true" 
  }
}

# 6. AWS Backup IAM Role
# The Backup Plan requires a service role to perform backup actions
resource "aws_iam_role" "backup_role" {
  name = "default_backup_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the AWS managed policy for backups
resource "aws_iam_role_policy_attachment" "backup_attach" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup_role.name
}

# 7. AWS Backup Vault
resource "aws_backup_vault" "web_vault" {
  name = "web_server_vault"
}

# 8. AWS Backup Plan
resource "aws_backup_plan" "daily_plan" {
  name = "ec2_daily_midnight_plan"

  rule {
    name              = "daily_midnight_rule"
    schedule_expression = "cron(0 0 * * ? *)" # 12:00 AM UTC Daily

    target_vault_name = aws_backup_vault.web_vault.name

    lifecycle {
      delete_after = 30 # Keep backups for 30 days
    }
  }
}

# 9. AWS Backup Selection
# Links the Plan, the Vault, and the Resources (EC2 Instance) together
resource "aws_backup_selection" "daily_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "daily_ec2_selection"
  plan_id      = aws_backup_plan.daily_plan.id

  # Select resources based on the tag we applied to the EC2 instance
  resources = []
  selection_tag {
    type  = "STRING_EQUALS"
    key   = "Backup"
    value = "true"
  }
}

