# 1. Provider Configuration
provider "aws" {
  region = "us-east-1"
}

provider "tls" {
  # Required for generating the key pair
}

# 2. Data Sources
# Get the latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# 3. Networking Resources (Additional Required Components)
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "backup-vpc"
  }
}

resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone       = "us-east-1a"

  tags = {
    Name = "backup-subnet-public"
  }
}

resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "backup-igw"
  }
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }

  tags = {
    Name = "backup-public-rt"
  }
}

resource "aws_route_table_association" "a" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public_rt.id
}

# Security Group to allow SSH access
resource "aws_security_group" "allow_ssh" {
  name        = "allow_ssh_sg"
  description = "Allow SSH inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "SSH from MyIP"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "allow_ssh_sg"
  }
}

# 4. EC2 Key Pair
resource "tls_private_key" "generated" {
  algorithm = "RSA"
  rsa_bits  = 4096
}

resource "aws_key_pair" "generated" {
  key_name   = "terraform-backup-key"
  public_key = tls_private_key.generated.public_key_openssh
}

resource "local_file" "private_key" {
  content  = tls_private_key.generated.private_key_pem
  filename = "terraform-backup-key.pem"
  file_permission = "0400"
}

# 5. EC2 Instance
resource "aws_instance" "web_server" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.public.id
  key_name      = aws_key_pair.generated.key_name

  vpc_security_group_ids = [
    aws_security_group.allow_ssh.id,
  ]

  # Tagging the instance is critical for the Backup Selection to find it
  tags = {
    Name  = "WebServer-Backup-Demo"
    Backup = "true" 
  }
}

# 6. AWS Backup IAM Role
# The Backup Plan requires a service role to perform backup actions
resource "aws_iam_role" "backup_role" {
  name = "default_backup_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the AWS managed policy for backups
resource "aws_iam_role_policy_attachment" "backup_attach" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup_role.name
}

# 7. AWS Backup Vault
resource "aws_backup_vault" "web_vault" {
  name = "web_server_vault"
}

# 8. AWS Backup Plan
resource "aws_backup_plan" "daily_plan" {
  name = "ec2_daily_midnight_plan"

  rule {
    name              = "daily_midnight_rule"
    schedule_expression = "cron(0 0 * * ? *)" # 12:00 AM UTC Daily

    target_vault_name = aws_backup_vault.web_vault.name

    lifecycle {
      delete_after = 30 # Keep backups for 30 days
    }
  }
}

# 9. AWS Backup Selection
# Links the Plan, the Vault, and the Resources (EC2 Instance) together
resource "aws_backup_selection" "daily_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "daily_ec2_selection"
  plan_id      = aws_backup_plan.daily_plan.id

