# 1. IAM Role for Lambda Execution
resource "aws_iam_role" "lambda_execution_role" {
  name = "daily_lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic execution policy to the role (allows logging to CloudWatch)
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 2. Create the Lambda Function code (Zip archive)
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function_payload.zip"

  source {
    content = <<-EOF
      def lambda_handler(event, context):
          print("Daily task executed successfully at 07:00 UTC")
          return {
              "statusCode": 200,
              "body": "Execution Complete"
          }
      EOF
    filename = "lambda_function.py"
  }
}

# Define the Lambda Function
resource "aws_lambda_function" "daily_task_function" {
  filename      = data.archive_file.lambda_zip.output_path
  function_name = "daily_task_function"
  role          = aws_iam_role.lambda_execution_role.arn
  handler       = "lambda_function.lambda_handler"
  runtime       = "python3.9"

  # Ensure the zip file is recreated before the function is updated if content changes
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
}

# 3. Create the EventBridge Rule (Schedule)
# Cron expression: 0 7 * * ? *
# Minutes: 0, Hours: 7, Every Day of Month, Every Month, Every Day of Week
resource "aws_cloudwatch_event_rule" "daily_schedule_rule" {
  name                = "daily-07-00-utc-rule"
  description         = "Triggers Lambda every day at 07:00 UTC"
  schedule_expression = "cron(0 7 * * ? *)"
}

# 4. Set the Lambda as the Target for the EventBridge Rule
resource "aws_cloudwatch_event_target" "daily_lambda_target" {
  rule           = aws_cloudwatch_event_rule.daily_schedule_rule.name
  arn            = aws_lambda_function.daily_task_function.arn
}

# 5. Grant EventBridge permission to invoke the Lambda
resource "aws_lambda_permission" "allow_eventbridge_invoke" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.daily_task_function.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.daily_schedule_rule.arn
}

