  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
}

# 3. Create the EventBridge Rule (Schedule)
# Cron expression: 0 7 * * ? *
# Minutes: 0, Hours: 7, Every Day of Month, Every Month, Every Day of Week
resource "aws_cloudwatch_event_rule" "daily_schedule_rule" {
  name                = "daily-07-00-utc-rule"
  description         = "Triggers Lambda every day at 07:00 UTC"
  schedule_expression = "cron(0 7 * * ? *)"
}

