  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic execution policy to the role (for CloudWatch Logs)
resource "aws_iam_role_policy_attachment" "lambda_policy_attachment" {
  role       = aws_iam_role.lambda_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 2. Prepare the Lambda source code (Zip file)
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function_payload.zip"

  source {
    content = <<EOF
def handler(event, context):
    print("Execution triggered at 07:00 UTC")
    return {
        "statusCode": 200,
        "body": "Hello from Terraform!"
    }
EOF
    filename = "lambda_function.py"
  }
}

# 3. Create the Lambda Function
resource "aws_lambda_function" "daily_function" {
  filename      = data.archive_file.lambda_zip.output_path
  function_name = "daily_07_00_function"
  role          = aws_iam_role.lambda_execution_role.arn
  handler       = "lambda_function.handler"
  runtime       = "python3.9"

