extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Generate a unique suffix for resource names to avoid conflicts
resource "random_id" "unique_suffix" {
  byte_length = 4
}

# ---------------------------------------------------------
# 1. S3 Bucket for Video Storage
# ---------------------------------------------------------
resource "aws_s3_bucket" "video_storage" {
  bucket = "video-streaming-platform-${random_id.unique_suffix.hex}"
}

# Ensure S3 Bucket Ownership is enforced for OAC
resource "aws_s3_bucket_ownership_controls" "video_storage" {
  bucket = aws_s3_bucket.video_storage.id
  rule {
    object_ownership = "BucketOwnerEnforced"
  }
}

# Block all public access to the S3 bucket
resource "aws_s3_bucket_public_access_block" "video_storage" {
  bucket = aws_s3_bucket.video_storage.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Enable versioning (good practice for content management)
resource "aws_s3_bucket_versioning" "video_storage" {
  bucket = aws_s3_bucket.video_storage.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Enable Server Side Encryption
resource "aws_s3_bucket_server_side_encryption_configuration" "video_storage" {
  bucket = aws_s3_bucket.video_storage.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# ---------------------------------------------------------
# 2. CloudFront Origin Access Control (OAC)
# ---------------------------------------------------------
resource "aws_cloudfront_origin_access_control" "video_storage_oac" {
  name                              = "oac-${aws_s3_bucket.video_storage.id}"
  description                       = "Access Control for Video Streaming S3 Bucket"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# ---------------------------------------------------------
# 3. CloudFront Distribution
# ---------------------------------------------------------
resource "aws_cloudfront_distribution" "video_distribution" {
  origin {
    domain_name              = aws_s3_bucket.video_storage.bucket_regional_domain_name
    origin_access_control_id = aws_cloudfront_origin_access_control.video_storage_oac.id
    origin_id                = "S3-${aws_s3_bucket.video_storage.id}"
  }

  enabled             = true
  is_ipv6_enabled     = true
  comment             = "Globally Distributed Video Streaming Distribution"
  default_root_object = "index.html"

  logging_config {
    include_cookies = false
    bucket          = aws_s3_bucket.video_storage.bucket_domain_name
    prefix          = "cloudfront-logs/"
  }

  # Default Cache Behavior
  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-${aws_s3_bucket.video_storage.id}"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 86400
    max_ttl                = 31536000
    compress               = true
  }

  # Price Class: Use only edge locations in North America, Europe, and Asia (Cost optimized)
  # Change to "PriceClass_All" for truly global reach including South America, Australia, etc.
  price_class = "PriceClass_All"

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

# ---------------------------------------------------------
# 4. S3 Bucket Policy (Trust CloudFront)
# ---------------------------------------------------------
resource "aws_s3_bucket_policy" "allow_cloudfront_access" {
  bucket = aws_s3_bucket.video_storage.id
  policy = data.aws_iam_policy_document.cloudfront_access_policy.json
}

# Policy Document to allow CloudFront OAC to read from the bucket
data "aws_iam_policy_document" "cloudfront_access_policy" {
  statement {
    sid    = "AllowCloudFrontServicePrincipalReadOnly"
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["cloudfront.amazonaws.com"]
    }

    actions = [
      "s3:GetObject",
    ]

    resources = [
      "${aws_s3_bucket.video_storage.arn}/*",
    ]

    condition {
      test     = "StringEquals"
      variable = "AWS:SourceArn"
      values   = [aws_cloudfront_distribution.video_distribution.arn]
    }
  }
}

# ---------------------------------------------------------
# Outputs
# ---------------------------------------------------------
output "s3_bucket_name" {
  description = "The name of the S3 bucket storing video content."
  value       = aws_s3_bucket.video_storage.id
}

output "s3_bucket_arn" {
  description = "The ARN of the S3 bucket."
  value       = aws_s3_bucket.video_storage.arn
}

output "cloudfront_domain_name" {
  description = "The domain name of the CloudFront distribution."
  value       = aws_cloudfront_distribution.video_distribution.domain_name
}

output "cloudfront_distribution_id" {
  description = "The ID of the CloudFront distribution."
  value       = aws_cloudfront_distribution.video_distribution.id
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_s3_bucket" "video_content" {
  bucket_prefix = "video-content-"
}

resource "aws_s3_object" "put_website" {
  bucket = aws_s3_bucket.video_content.bucket
  key = "index.html"
  source = "./supplement/index.html"
  content_type = "text/html"
}

resource "aws_s3_object" "put_website_css" {
  bucket = aws_s3_bucket.video_content.bucket
  key = "css/style.css"
  source = "./supplement/css/style.css"
  content_type = "text/css"
}

resource "aws_s3_bucket_policy" "bucket_policy" {
  bucket = aws_s3_bucket.video_content.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "cloudfront.amazonaws.com"
        }
        Action = "s3:GetObject"
        Resource = "${aws_s3_bucket.video_content.arn}/*"
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = aws_cloudfront_distribution.my_distribution.arn
          }
        }
      }
    ]
  })
}


locals {
  s3_origin_id = "s3_video_content_origin"
}

resource "aws_cloudfront_origin_access_control" "s3_oac" {
  name                              = "s3-oac"
  description                       = "aws access control policy"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

resource "aws_cloudfront_distribution" "my_distribution" {
  origin {
    domain_name              = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_access_control_id = aws_cloudfront_origin_access_control.s3_oac.id
    origin_id                = local.s3_origin_id
  }

  enabled             = true
  default_root_object = "index.html"

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = local.s3_origin_id

    forwarded_values {
      query_string = false

      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "allow-all"
  }

  price_class = "PriceClass_200"

  restrictions {
    geo_restriction {
      restriction_type = "whitelist"
      locations        = ["US", "CA", "GB", "DE"]
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

# Route53
resource "aws_route53_zone" "my_zone" {
  name = "my-test-cloudfront.com"
}

resource "aws_route53_record" "cdn_ipv4" {
  type    = "A"
  name    = "cdn"
  zone_id = aws_route53_zone.my_zone.zone_id

  alias {
    name                   = aws_cloudfront_distribution.my_distribution.domain_name
    zone_id                = aws_cloudfront_distribution.my_distribution.hosted_zone_id
    evaluate_target_health = true
  }
}

response:
Todesign a globally distributed video streaming platform, we will create the following AWS resources:

1.  **Amazon S3 Bucket**: This will serve as the origin to store the video files securely. We will configure it to block all public access so that content can only be served through CloudFront.
2.  **CloudFront Origin Access Control (OAC)**: This is a modern security feature that allows CloudFront to securely access the S3 bucket without needing a public bucket policy or complex IAM users.
3.  **Amazon CloudFront Distribution**: This will cache content at edge locations worldwide. We will configure it to use the S3 bucket as the origin, utilizing the OAC for secure connections, and enforce HTTPS.
4.  **S3 Bucket Policy**: We will attach a policy to the S3 bucket that explicitly allows read access only from the specific CloudFront distribution we create.

Here is the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Generate a unique suffix for resource names to avoid conflicts
resource "random_id" "unique_suffix" {
  byte_length = 4
}

# ---------------------------------------------------------
# 1. S3 Bucket for Video Storage
# ---------------------------------------------------------
resource "aws_s3_bucket" "video_storage" {
  bucket = "video-streaming-platform-${random_id.unique_suffix.hex}"
}

# Ensure S3 Bucket Ownership is enforced for OAC
resource "aws_s3_bucket_ownership_controls" "video_storage" {
  bucket = aws_s3_bucket.video_storage.id
  rule {
    object_ownership = "BucketOwnerEnforced"
  }
}

# Block all public access to the S3 bucket
resource "aws_s3_bucket_public_access_block" "video_storage" {
  bucket = aws_s3_bucket.video_storage.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Enable versioning (good practice for content management)
resource "aws_s3_bucket_versioning" "video_storage" {
  bucket = aws_s3_bucket.video_storage.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Enable Server Side Encryption
resource "aws_s3_bucket_server_side_encryption_configuration" "video_storage" {
  bucket = aws_s3_bucket.video_storage.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# ---------------------------------------------------------
# 2. CloudFront Origin Access Control (OAC)
# ---------------------------------------------------------
resource "aws_cloudfront_origin_access_control" "video_storage_oac" {
  name                              = "oac-${aws_s3_bucket.video_storage.id}"
  description                       = "Access Control for Video Streaming S3 Bucket"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# ---------------------------------------------------------
# 3. CloudFront Distribution
# ---------------------------------------------------------
resource "aws_cloudfront_distribution" "video_distribution" {
  origin {
    domain_name              = aws_s3_bucket.video_storage.bucket_regional_domain_name
    origin_access_control_id = aws_cloudfront_origin_access_control.video_storage_oac.id
    origin_id                = "S3-${aws_s3_bucket.video_storage.id}"
  }

  enabled             = true
  is_ipv6_enabled     = true
  comment             = "Globally Distributed Video Streaming Distribution"
  default_root_object = "index.html"

  logging_config {
    include_cookies = false
    bucket          = aws_s3_bucket.video_storage.bucket_domain_name
    prefix          = "cloudfront-logs/"
  }

  # Default Cache Behavior
  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-${aws_s3_bucket.video_storage.id}"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 86400
    max_ttl                = 31536000
    compress               = true
  }

  # Price Class: Use only edge locations in North America, Europe, and Asia (Cost optimized)
  # Change to "PriceClass_All" for truly global reach including South America, Australia, etc.
  price_class = "PriceClass_All"

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

# ---------------------------------------------------------
# 4. S3 Bucket Policy (Trust CloudFront)
# ---------------------------------------------------------
resource "aws_s3_bucket_policy" "allow_cloudfront_access" {
  bucket = aws_s3_bucket.video_storage.id
  policy = data.aws_iam_policy_document.cloudfront_access_policy.json
}

# Policy Document to allow CloudFront OAC to read from the bucket
data "aws_iam_policy_document" "cloudfront_access_policy" {
  statement {
    sid    = "AllowCloudFrontServicePrincipalReadOnly"
    effect = "Allow"

    principals {
      type        = "Service"
