# ---------------------------------------------------------
# 1. Provider Configuration
# ---------------------------------------------------------
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Default provider for regional resources (S3, Route 53)
provider "aws" {
  region = var.aws_region
}

# Specific provider for us-east-1 (Required for CloudFront ACM Certificates)
provider "aws" {
  alias  = "us_east_1"
  region = "us-east-1"
}

# ---------------------------------------------------------
# 2. Variables
# ---------------------------------------------------------
variable "domain_name" {
  description = "The root domain name (e.g., example.com)"
  type        = string
}

variable "subdomain" {
  description = "The subdomain for streaming (e.g., stream)"
  type        = string
  default     = "streaming"
}

variable "aws_region" {
  description = "The AWS region for the S3 bucket and Route 53"
  type        = string
  default     = "eu-west-1"
}

variable "bucket_name_prefix" {
  description = "Prefix for the S3 bucket name"
  type        = string
  default     = "video-streaming-origin"
}

locals {
  full_domain_name = "${var.subdomain}.${var.domain_name}"
}

# ---------------------------------------------------------
# 3. S3 Bucket (Video Origin)
# ---------------------------------------------------------
resource "aws_s3_bucket" "video_bucket" {
  bucket = "${var.bucket_name_prefix}-${var.subdomain}-${random_id.suffix.hex}"
}

# Configure versioning
resource "aws_s3_bucket_versioning" "video_bucket_versioning" {
  bucket = aws_s3_bucket.video_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Server-Side Encryption
resource "aws_s3_bucket_server_side_encryption_configuration" "video_bucket_encryption" {
  bucket = aws_s3_bucket.video_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# Block Public Access (Security Best Practice)
resource "aws_s3_bucket_public_access_block" "video_bucket_block_access" {
  bucket = aws_s3_bucket.video_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "random_id" "suffix" {
  byte_length = 4
}

# ---------------------------------------------------------
# 4. ACM Certificate (SSL/TLS)
# ---------------------------------------------------------
# Request certificate in us-east-1 (Mandatory for CloudFront)
resource "aws_acm_certificate" "cloudfront_cert" {
  provider          = aws.us_east_1
  domain_name       = local.full_domain_name
  validation_method = "DNS"

  lifecycle {
    create_before_destroy = true
  }
}

# Create DNS record to validate the certificate
resource "aws_route53_record" "cert_validation" {
  name    = aws_acm_certificate.cloudfront_cert.domain_validation_options[0].resource_record_name
  type    = aws_acm_certificate.cloudfront_cert.domain_validation_options[0].resource_record_type
  zone_id = data.aws_route53_zone.hosted_zone.id
  records = [aws_acm_certificate.cloudfront_cert.domain_validation_options[0].resource_record_value]
  ttl     = 60
}

# Wait for validation
resource "aws_acm_certificate_validation" "cert_validation" {
  provider                = aws.us_east_1
  certificate_arn         = aws_acm_certificate.cloudfront_cert.arn
  validation_record_fqdns = [aws_route53_record.cert_validation.fqdn]
}

# ---------------------------------------------------------
# 5. CloudFront Distribution & Security
# ---------------------------------------------------------

# Origin Access Control (OAC) - Replaces OAI for enhanced security
resource "aws_cloudfront_origin_access_control" "oac" {
  name                              = "${var.bucket_name_prefix}-oac"
  description                       = "OAC for Video Streaming Bucket"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# S3 Bucket Policy to allow ONLY CloudFront access
resource "aws_s3_bucket_policy" "allow_cloudfront" {
  bucket = aws_s3_bucket.video_bucket.id
  policy = data.aws_iam_policy_document.cloud_front_access.json
}

data "aws_iam_policy_document" "cloud_front_access" {
  statement {
    sid    = "AllowCloudFrontAccess"
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["cloudfront.amazonaws.com"]
    }

    actions   = ["s3:GetObject"]
    resources = ["${aws_s3_bucket.video_bucket.arn}/*"]

    condition {
      test     = "StringEquals"
      variable = "AWS:SourceArn"
      values   = [aws_cloudfront_distribution.streaming.arn]
    }
  }
}

resource "aws_cloudfront_distribution" "streaming" {
  origin {
    domain_name              = aws_s3_bucket.video_bucket.bucket_regional_domain_name
    origin_access_control_id = aws_cloudfront_origin_access_control.oac.id
    origin_id                = "S3-${aws_s3_bucket.video_bucket.id}"
  }

  enabled             = true
  is_ipv6_enabled     = true
  default_root_object = "index.html"

  # Logging configuration (optional but recommended)
  logging_config {
    include_cookies = false
    bucket          = aws_s3_bucket.video_bucket.bucket_domain_name
    prefix          = "cloudfront-logs/"
  }

  aliases = [local.full_domain_name]

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-${aws_s3_bucket.video_bucket.id}"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
    compress               = true

    # Use the OAC to sign requests to S3
    origin_access_control_id = aws_cloudfront_origin_access_control.oac.id
  }

  # Price Class: Use only edge locations in North America and Europe (Cost optimization)
  # Change to PriceClass_All for full global reach (Asia, South America, etc.)
  price_class = "PriceClass_All"

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    acm_certificate_arn      = aws_acm_certificate_validation.cert_validation.certificate_arn
    ssl_support_method       = "sni-only"
    minimum_protocol_version = "TLSv1.2_2021"
  }

  # Ensure certificate validation is complete before creating distribution
  depends_on = [aws_acm_certificate_validation.cert_validation]
}

# ---------------------------------------------------------
# 6. Route 53 (DNS)
# ---------------------------------------------------------
data "aws_route53_zone" "hosted_zone" {
  name         = var.domain_name
  private_zone = false
}

resource "aws_route53_record" "streaming_alias" {
  zone_id = data.aws_route53_zone.hosted_zone.zone_id
  name    = local.full_domain_name
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.streaming.domain_name
    zone_id                = aws_cloudfront_distribution.streaming.hosted_zone_id
    evaluate_target_health = true
  }
}

# ---------------------------------------------------------
# 7. Outputs
# ---------------------------------------------------------
output "cloudfront_domain_name" {
  description = "The domain name of the CloudFront distribution"
  value       = aws_cloudfront_distribution.streaming.domain_name
}

output "streaming_url" {
  description = "The full HTTPS URL for the streaming platform"
  value       = "https://${local.full_domain_name}"
}

output "s3_bucket_name" {
  description = "The name of the origin S3 bucket"
  value       = aws_s3_bucket.video_bucket.id
}

