response:
Here is the step-by-step design and the corresponding Terraform configuration for your video streaming platform.

### Architecture Design Steps

1.  **VPC and Networking (VPC Module):**
    *   We will use the official AWS VPC Terraform module to set up a highly available Virtual Private Cloud.
    *   It will be configured with two Public Subnets (for the Load Balancer) and two Private Subnets (for the EC2 instances) across two Availability Zones to ensure redundancy.
    *   A NAT Gateway will be included to allow the private EC2 instances to download updates and stream content from the internet if necessary.

2.  **Security Groups:**
    *   **Load Balancer Security Group:** Allows inbound HTTP/HTTPS traffic from the world (0.0.0.0/0) and forwards it to the web server security group.
    *   **EC2 Security Group:** Allows inbound traffic only from the Load Balancer on port 80 (or 443), ensuring the servers are not directly exposed to the internet.

3.  **Compute (EC2 & Auto Scaling):**
    *   Instead of individual static instances, we will use an **Auto Scaling Group (ASG)**. This is crucial for a video streaming platform to handle traffic spikes automatically.
    *   A **Launch Template** will define the instance configuration (Amazon Linux 2, `t3.medium` for better network performance) and a User Data script to install and start a web server (Nginx).

4.  **Load Balancing:**
    *   An **Application Load Balancer (ALB)** will be placed in the public subnets. It will distribute incoming video streaming requests across the EC2 instances in the private subnets.
    *   A **Target Group** will be created to register the EC2 instances.
    *   A **Listener** will accept HTTP traffic on port 80.

5.  **DNS (Route 53):**
    *   A **Route 53 Hosted Zone** will be created for the domain (e.g., `streaming.example.com`).
    *   An **Alias Record** will point the domain name to the DNS name of the Application Load Balancer, providing a friendly URL for users.

---

### Terraform Configuration

```hcl
terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# 1. VPC Module: Networking Foundation
# ------------------------------------------------------------------------------
module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "5.1.2"

  name = "streaming-vpc"
  cidr = "10.0.0.0/16"

  azs             = ["us-east-1a", "us-east-1b"]
  private_subnets = ["10.0.1.0/24", "10.0.2.0/24"]
  public_subnets  = ["10.0.101.0/24", "10.0.102.0/24"]

  enable_nat_gateway     = true
  single_nat_gateway     = true
  one_nat_gateway_per_az = false

  # DNS support
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Terraform   = "true"
    Environment = "dev"
  }
}

# ------------------------------------------------------------------------------
# 2. Security Groups
# ------------------------------------------------------------------------------

# Security Group for Load Balancer
resource "aws_security_group" "lb_sg" {
  name        = "streaming-lb-sg"
  description = "Allow HTTP inbound traffic for Load Balancer"
  vpc_id      = module.vpc.vpc_id

  ingress {
    description = "HTTP from world"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "streaming-lb-sg"
  }
}

# Security Group for EC2 Instances
resource "aws_security_group" "web_sg" {
  name        = "streaming-web-sg"
  description = "Allow traffic from LB only"
  vpc_id      = module.vpc.vpc_id

  ingress {
    description     = "HTTP from LB"
    from_port       = 80
    to_port         = 80
    protocol        = "tcp"
    security_groups = [aws_security_group.lb_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "streaming-web-sg"
  }
}

# ------------------------------------------------------------------------------
# 3. Load Balancer (ALB)
# ------------------------------------------------------------------------------
resource "aws_lb" "streaming_lb" {
  name               = "streaming-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = module.vpc.public_subnets

  enable_deletion_protection = false

  tags = {
    Environment = "dev"
  }
}

resource "aws_lb_target_group" "web_tg" {
  name     = "streaming-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id

  health_check {
    path = "/"
  }
}

resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.streaming_lb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.web_tg.arn
  }
}

# ------------------------------------------------------------------------------
# 4. Compute (EC2 + Auto Scaling)
# ------------------------------------------------------------------------------

# Fetch latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# User Data Script to Install Nginx
data "template_file" "user_data" {
  template = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y nginx
              systemctl start nginx
              systemctl enable nginx
              echo "<h1>Video Streaming Server - $(hostname -f)</h1>" > /usr/share/nginx/html/index.html
              EOF
}

resource "aws_launch_template" "web_lt" {
  name_prefix   = "streaming-server-"
  image_id      = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.medium" # Better network performance for streaming
  key_name      = "demo-key"  # Replace with your actual key pair name

  network_interfaces {
    associate_public_ip_address = false
    security_groups             = [aws_security_group.web_sg.id]
  }

  user_data = base64encode(data.template_file.user_data.rendered)

  tag_specifications {
    resource_type = "instance"
    tags = {
      Name = "streaming-server"
    }
  }
}

resource "aws_autoscaling_group" "web_asg" {
  desired_capacity    = 2
  max_size            = 5
  min_size            = 2
  vpc_zone_identifier = module.vpc.private_subnets

  target_group_arns = [aws_lb_target_group.web_tg.arn]

  launch_template {
    id      = aws_launch_template.web_lt.id
    version = "$Latest"
  }
}

# ------------------------------------------------------------------------------
# 5. Route 53
# ------------------------------------------------------------------------------

# Note: This creates a new Hosted Zone. 
# If you already own a domain, you should use data "aws_route53_zone" to import it.
resource "aws_route53_zone" "primary" {
  name = "streaming-platform.local"
}

resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "streaming-platform.local"
  type    = "A"

  alias {
    name                   = aws_lb.streaming_lb.dns_name
    zone_id                = aws_lb.streaming_lb.zone_id
    evaluate_target_health = true
  }
}

# ------------------------------------------------------------------------------
# Outputs
# ------------------------------------------------------------------------------
output "load_balancer_dns" {
  value = aws_lb.streaming_lb.dns_name
}

output "route53_url" {
  value = "http://${aws_route53_record.www.name}"
}
```

