response:
Here is the Terraform configuration to create the infrastructure for the video streaming platform.

This configuration performs the following steps:
1.  **Sets up the Provider**: Configures the AWS provider.
2.  **Retrieves Data**: Fetches the latest Amazon Linux 2023 AMI and Availability Zones.
3.  **Network (VPC Module)**: Uses the official AWS VPC module to create a VPC, public subnets, and an Internet Gateway.
4.  **Security Groups**: Creates one security group for the Load Balancer (allowing web traffic from the world) and one for the EC2 instances (allowing traffic only from the Load Balancer).
5.  **Compute**: Deploys 2 EC2 instances (using `t3.medium` for streaming capability) across different subnets with a simple web server user-data script.
6.  **Load Balancing**: Creates an Application Load Balancer, a Target Group, a Listener, and attaches the EC2 instances to the target group.
7.  **DNS**: Creates a Route53 Hosted Zone and an Alias record pointing to the Load Balancer.

```hcl
# 1. Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# 2. Data Sources
data "aws_ami" "amazon_linux_2023" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["al2023-ami-2023.*-x86_64"]
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# 3. VPC Module
# This module creates the VPC, Subnets, NAT Gateway (if needed), Internet Gateway, and Routing
module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "5.1.2"

  name = "streaming-vpc"
  cidr = "10.0.0.0/16"

  azs             = data.aws_availability_zones.available.names
  public_subnets  = ["10.0.1.0/24", "10.0.2.0/24"]
  private_subnets = ["10.0.10.0/24", "10.0.20.0/24"]

  enable_nat_gateway = false
  single_nat_gateway = false
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Terraform   = "true"
    Environment = "dev"
    Project     = "video-streaming"
  }
}

# 4. Security Groups

# Security Group for Load Balancer (Public facing)
resource "aws_security_group" "lb_sg" {
  name        = "streaming-lb-sg"
  description = "Allow HTTP/HTTPS inbound traffic for Load Balancer"
  vpc_id      = module.vpc.vpc_id

  ingress {
    description = "HTTP from world"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    description = "HTTPS from world"
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "streaming-lb-sg"
  }
}

# Security Group for EC2 Instances (Internal)
resource "aws_security_group" "instance_sg" {
  name        = "streaming-instance-sg"
  description = "Allow traffic from Load Balancer only"
  vpc_id      = module.vpc.vpc_id

  ingress {
    description     = "HTTP from Load Balancer"
    from_port       = 80
    to_port         = 80
    protocol        = "tcp"
    security_groups = [aws_security_group.lb_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "streaming-instance-sg"
  }
}

# 5. Load Balancer Resources

resource "aws_lb" "streaming_lb" {
  name               = "streaming-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = module.vpc.public_subnets

  enable_deletion_protection = false

  tags = {
    Environment = "dev"
    Project     = "video-streaming"
  }
}

resource "aws_lb_target_group" "streaming_tg" {
  name     = "streaming-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id

  health_check {
    enabled = true
    path    = "/"
    matcher = "200"
  }
}

resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.streaming_lb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.streaming_tg.arn
  }
}

# 6. EC2 Instances (Servers)

# Create multiple servers using count
resource "aws_instance" "streaming_server" {
  count                  = 2
  ami                    = data.aws_ami.amazon_linux_2023.id
  instance_type          = "t3.medium" # Medium instance suitable for streaming
  subnet_id              = module.vpc.public_subnets[count.index]
  vpc_security_group_ids = [aws_security_group.instance_sg.id]

  # User data to install a simple web server for demonstration
  user_data = <<-EOF
              #!/bin/bash
              dnf update -y
              dnf install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Streaming Server ${count.index} is Ready</h1>" > /var/www/html/index.html
              EOF

  tags = {
    Name = "streaming-server-${count.index}"
  }
}

# Attach instances to the Target Group
resource "aws_lb_target_group_attachment" "tg_attach" {
  count            = 2
  target_group_arn = aws_lb_target_group.streaming_tg.arn
  target_id        = aws_instance.streaming_server[count.index].id
  port             = 80
}

# 7. Route53 Resources

# Hosted Zone
resource "aws_route53_zone" "primary" {
  name = "streaming-platform.example.com"
  # Comment out vpc_id below if you want a Public Hosted Zone (requires domain registration)
  # For this example, we assume a private or placeholder zone.
}

# DNS Record
resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "streaming.streaming-platform.example.com"
  type    = "A"

  alias {
    name                   = aws_lb.streaming_lb.dns_name
    zone_id                = aws_lb.streaming_lb.zone_id
    evaluate_target_health = true
  }
}
```

