  cidr_block              = "10.0.6.0/24"
  availability_zone       = data.aws_availability_zones.available.names[2]
  map_public_ip_on_launch = true

  tags = {
    Name = "subnet-10.0.6.0"
  }
}

# 3. AWS Security Group
resource "aws_security_group" "alb_sg" {
  name        = "alb-security-group"
  description = "Security group for ALB and EC2"
  vpc_id      = aws_vpc.main.id

  tags = {
    Name = "alb-sg"
  }
}

# Ingress Rule: TCP 80 from VPC CIDR
resource "aws_vpc_security_group_ingress_rule" "allow_http_ingress" {
  security_group_id = aws_security_group.alb_sg.id
  cidr_ipv4         = aws_vpc.main.cidr_block
  from_port         = 80
  ip_protocol       = "tcp"
  to_port           = 80
}

# Egress Rule: TCP 80 to Any IP
resource "aws_vpc_security_group_egress_rule" "allow_http_egress" {
  security_group_id = aws_security_group.alb_sg.id
  cidr_ipv4         = "0.0.0.0/0"
  from_port         = 80
  ip_protocol       = "tcp"
  to_port           = 80
}

# EC2 Instance (Latest Ubuntu) to be attached to the target group
resource "aws_instance" "web_server" {
  ami           = data.aws_ami.ubuntu.id
  instance_type = "t3.micro"
  subnet_id     = aws_subnet.subnet_1.id
  # Attaching the SG to ensure connectivity within the VPC
  vpc_security_group_ids = [aws_security_group.alb_sg.id]

  tags = {
    Name = "ubuntu-web-server"
  }
}

# 4. AWS Application Load Balancer
resource "aws_lb" "app_lb" {
  name               = "test-app-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = [
    aws_subnet.subnet_1.id,
    aws_subnet.subnet_2.id,
    aws_subnet.subnet_3.id
  ]

  tags = {
    Environment = "test"
  }
}

# 5. AWS LB Target Group
resource "aws_lb_target_group" "app_tg" {
  name     = "app-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id
}

# 6. AWS LB Listener
resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.app_lb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.app_tg.arn
  }
}

# 7. AWS LB Target Group Attachment
resource "aws_lb_target_group_attachment" "web_attach" {
  target_group_arn = aws_lb_target_group.app_tg.arn
  target_id        = aws_instance.web_server.id
  port             = 80
}

# 8. AWS Route53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = "test-video-stream.com"
}

# 9. Route53 Alias Record (IPv4)
resource "aws_route53_record" "lb_alias_a" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "lb.test-video-stream.com"
  type    = "A"

  alias {
    name                   = aws_lb.app_lb.dns_name
    zone_id                = aws_lb.app_lb.zone_id
    evaluate_target_health = true
  }
}

# 10. Route53 Alias Record (IPv6)
resource "aws_route53_record" "lb_alias_aaaa" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "lb.test-video-stream.com"
  type    = "AAAA"

  alias {
    name                   = aws_lb.app_lb.dns_name
    zone_id                = aws_lb.app_lb.zone_id
    evaluate_target_health = true
  }
}
