  vpc_security_group_ids = [aws_security_group.db_sg.id]
  publicly_accessible    = true # Set to false if you do not want public access
  skip_final_snapshot    = true  # Set to false for production to retain backups
  parameter_group_name   = "default.mysql8.0"

  tags = {
    Name = "MyMySQLDatabase"
  }
}

# Output the generated credentials
output "db_username" {
  description = "The generated username for the database"
