# 1. VPC Configuration
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "dolphinscheduler-vpc"
  }
}

# Internet Gateway for Public Subnets
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "dolphinscheduler-igw"
  }
}

# Public Subnets (2 Subnets required for RDS Subnet Group)
resource "aws_subnet" "public_1" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "dolphinscheduler-public-subnet-1"
  }
}

resource "aws_subnet" "public_2" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true

  tags = {
    Name = "dolphinscheduler-public-subnet-2"
  }
}

# Route Table for Public Subnets
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "dolphinscheduler-public-rt"
  }
}

resource "aws_route_table_association" "public_1" {
  subnet_id      = aws_subnet.public_1.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "public_2" {
  subnet_id      = aws_subnet.public_2.id
  route_table_id = aws_route_table.public.id
}

# 2. Security Group for Database Access
resource "aws_security_group" "db_access" {
  name        = "dolphinscheduler-db-access"
  description = "Allow inbound PostgreSQL traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict to specific IPs in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "dolphinscheduler-db-sg"
  }
}

# 3. DB Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "dolphinscheduler-subnet-group"
  subnet_ids = [aws_subnet.public_1.id, aws_subnet.public_2.id]

  tags = {
    Name = "dolphinscheduler-subnet-group"
  }
}

# 4. PostgreSQL Instance
resource "aws_db_instance" "dolphinscheduler" {
  identifier             = "dolphinscheduler"
  engine                 = "postgres"
  engine_version         = "17.1"
  instance_class         = "db.t3.micro"
  allocated_storage      = 5
  storage_type           = "gp2" # gp2 often supports lower storage minimums than gp3
  storage_encrypted      = false

  # Database Credentials
  username               = "adminuser"
  password               = "ChangeMe123!" # In production, use var.password or aws_secretsmanager_secret

  # Networking
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.db_access.id]
  publicly_accessible    = false # Best practice: false, even if subnets are public

  # Snapshot & Deletion
  skip_final_snapshot    = true
  delete_automated_backups = true

  # Monitoring
  monitoring_interval    = 0

  tags = {
    Name = "dolphinscheduler-db"
  }
}
