provider "aws" {
  region = var.aws_region
}

# -----------------------------------------------------------------------------
# 1. Random Password Generation
# -----------------------------------------------------------------------------
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "_!%@" # Avoid characters that might cause shell issues
}

# -----------------------------------------------------------------------------
# 2. Networking (VPC & Subnets)
# -----------------------------------------------------------------------------
resource "aws_vpc" "main" {
  cidr_block           = var.vpc_cidr
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "secure-postgres-vpc"
  }
}

# Fetch available AZs to create subnets dynamically
data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_subnet" "private" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(var.vpc_cidr, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "secure-postgres-subnet-${count.index + 1}"
  }
}

# -----------------------------------------------------------------------------
# 3. KMS Encryption Key
# -----------------------------------------------------------------------------
resource "aws_kms_key" "rds_encryption" {
  description             = "KMS key for RDS PostgreSQL encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = {
    Name = "rds-postgres-kms-key"
  }
}

# -----------------------------------------------------------------------------
# 4. Security Group
# -----------------------------------------------------------------------------
resource "aws_security_group" "rds_sg" {
  name        = "secure-postgres-sg"
  description = "Security group for PostgreSQL RDS instance"
  vpc_id      = aws_vpc.main.id

  # Ingress rule: Allow PostgreSQL access from within the VPC
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [var.vpc_cidr]
  }

  # Egress rule: Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "secure-postgres-sg"
  }
}

# -----------------------------------------------------------------------------
# 5. DB Subnet Group
# -----------------------------------------------------------------------------
resource "aws_db_subnet_group" "main" {
  name       = "secure-postgres-subnet-group"
  subnet_ids = aws_subnet.private[*].id

  tags = {
    Name = "Secure PostgreSQL Subnet Group"
  }
}

# -----------------------------------------------------------------------------
# 6. Custom DB Parameter Group (PostgreSQL 15)
# -----------------------------------------------------------------------------
resource "aws_db_parameter_group" "postgres15" {
  name        = "secure-postgres15-pg"
  family      = "postgres15"
  description = "Custom parameter group for PostgreSQL 15"

  # Example custom parameter
  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "log_min_duration_statement"
    value = "1000" # Log queries taking longer than 1s
  }
}

# -----------------------------------------------------------------------------
# 7. RDS Instance
# -----------------------------------------------------------------------------
resource "aws_db_instance" "postgres" {
  identifier             = "secure-postgres-instance"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = var.instance_class
  allocated_storage      = 50
  storage_type           = "gp2"
  storage_encrypted      = true
  kms_key_id             = aws_kms_key.rds_encryption.arn
  multi_az               = true

  # Authentication
  db_name  = var.db_name
  username = var.db_username
  password = random_password.db_password.result

  # Networking
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = false

  # Configuration
  parameter_group_name   = aws_db_parameter_group.postgres15.name
  skip_final_snapshot    = true # Set to false in production
  backup_retention_period = 7
  backup_window          = "03:00-04:00"
  maintenance_window     = "Mon:04:00-Mon:05:00"

  tags = {
    Name = "Secure-PostgreSQL-15"
  }
}

# -----------------------------------------------------------------------------
# Variables
# -----------------------------------------------------------------------------
variable "aws_region" {
  description = "AWS region where resources will be created"
  default     = "us-east-1"
}

variable "vpc_cidr" {
  description = "CIDR block for the VPC"
  default     = "10.0.0.0/16"
}

variable "db_name" {
  description = "The name of the database to create when the DB instance is created"
  default     = "securedb"
}

variable "db_username" {
  description = "Username for the master DB user"
  default     = "adminuser"
}

variable "instance_class" {
  description = "The instance type of the RDS instance"
  default     = "db.t3.medium"
}

# -----------------------------------------------------------------------------
# Outputs
# -----------------------------------------------------------------------------
output "rds_endpoint" {
  description = "The connection endpoint for the RDS instance"
  value       = aws_db_instance.postgres.endpoint
}

output "rds_password" {
  description = "The generated password for the database (sensitive)"
  value       = random_password.db_password.result
  sensitive   = true
}

