```hcl
# -----------------------------------------------------------------------------
# Provider Configuration
# -----------------------------------------------------------------------------
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change as needed
}

# -----------------------------------------------------------------------------
# Random Password Generator
# Generates a secure password for the database master user.
# -----------------------------------------------------------------------------
resource "random_password" "db_master_password" {
  length           = 16
  special          = true
  override_special = "_!@" # Avoid characters that might cause shell issues
}

# -----------------------------------------------------------------------------
# Network Infrastructure (VPC & Subnets)
# Creating a designated VPC and private subnets for the RDS instance.
# -----------------------------------------------------------------------------
resource "aws_vpc" "main_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "designated-rds-vpc"
  }
}

# Fetch available AZs
data "aws_availability_zones" "available" {
  state = "available"
}

# Create Private Subnets
resource "aws_subnet" "private_subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.main_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.main_vpc.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "private-subnet-${count.index + 1}"
  }
}

# -----------------------------------------------------------------------------
# Security Infrastructure
# Security Group and KMS Key for encryption.
# -----------------------------------------------------------------------------

# KMS Key for encryption at rest
resource "aws_kms_key" "rds_encryption_key" {
  description             = "KMS key for RDS PostgreSQL instance encryption"
  deletion_window_in_days = 10

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
          AWS = "*"
        }
        Action   = "kms:*"
        Resource = "*"
      },
      {
        Sid    = "Allow RDS Service"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:GenerateDataKey"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_kms_alias" "rds_key_alias" {
  name          = "alias/rds-postgres-key"
  target_key_id = aws_kms_key.rds_encryption_key.key_id
}

# Security Group for Database Access
resource "aws_security_group" "rds_sg" {
  name        = "rds-postgres-sg"
  description = "Security group for PostgreSQL RDS instance"
  vpc_id      = aws_vpc.main_vpc.id

  # Only allow access within the VPC (or specific CIDR blocks) for protection
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-postgres-sg"
  }
}

# -----------------------------------------------------------------------------
# RDS Components
# Subnet Group, Parameter Group, and the Database Instance.
# -----------------------------------------------------------------------------

# DB Subnet Group
resource "aws_db_subnet_group" "rds_subnet_group" {
  name       = "rds-postgres-subnet-group"
  subnet_ids = aws_subnet.private_subnets[*].id

  tags = {
    Name = "RDS PostgreSQL Subnet Group"
  }
}

# Custom DB Parameter Group
resource "aws_db_parameter_group" "rds_param_group" {
  name        = "rds-postgres-param-group"
  family      = "postgres15" # Ensure this matches the engine version
  description = "Custom parameter group for PostgreSQL"

  # Example parameter configuration
  parameter {
    name  = "max_connections"
    value = "100"
  }

  parameter {
    name  = "shared_buffers"
    value = "{DBInstanceClassMemory/16384}"
  }
}

# RDS Instance
resource "aws_db_instance" "postgres_db" {
  identifier             = "protected-postgres-db"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20 # GB
  storage_type           = "gp3"
  storage_encrypted      = true
  kms_key_id             = aws_kms_key.rds_encryption_key.arn
  db_name                = "myappdb"
  username               = "dbadmin"
  password               = random_password.db_master_password.result
  db_subnet_group_name   = aws_db_subnet_group.rds_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  parameter_group_name   = aws_db_parameter_group.rds_param_group.name
  multi_az               = true
  backup_retention_period = 7
  skip_final_snapshot    = true # Set to false for production
  final_snapshot_identifier = "protected-postgres-final-snapshot"

  # Performance Insights (Optional, often requires encryption)
  performance_insights_enabled = true
  performance_insights_kms_key_id = aws_kms_key.rds_encryption_key.arn

  tags = {
    Name = "Protected-PostgreSQL-RDS"
    Environment = "Production"
  }
}
