  description             = "KMS key for PostgreSQL RDS encryption"
  deletion_window_in_days = 10

  # Policy to allow RDS service to use the key
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
