  multi_az               = true

  # Snapshots
  skip_final_snapshot    = false
  final_snapshot_identifier = "pgsnapshot"

  # Maintenance
  allow_major_version_upgrade = false
  auto_minor_version_upgrade  = true
  maintenance_window          = "Mon:03:00-Mon:04:00"
