# ------------------------------------------------------------------------------
# Variables
# ------------------------------------------------------------------------------
variable "db_name" {
  description = "The name of the database to create"
  default     = "airbyte_test_db"
  type        = string
}

variable "db_username" {
  description = "The master username for the database"
  default     = "airbyte_admin"
  type        = string
}

variable "db_password" {
  description = "The master password for the database"
  type        = string
  sensitive   = true
}

variable "vpc_cidr" {
  description = "CIDR block for the VPC"
  default     = "10.0.0.0/16"
  type        = string
}

variable "allowed_cidr" {
  description = "CIDR block allowed to connect to the database (e.g., your IP or Airbyte server)"
  default     = "0.0.0.0/0" # WARNING: Open for testing. Restrict in production.
  type        = string
}

# ------------------------------------------------------------------------------
# Network Infrastructure (VPC & Public Subnets)
# ------------------------------------------------------------------------------
resource "aws_vpc" "main" {
  cidr_block           = var.vpc_cidr
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "airbyte-test-vpc"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "airbyte-test-igw"
  }
}

# Create two public subnets in different AZs (Required for RDS Subnet Group)
resource "aws_subnet" "public" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(var.vpc_cidr, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "airbyte-public-subnet-${count.index + 1}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "airbyte-public-rt"
  }
}

resource "aws_route_table_association" "public" {
  count          = 2
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

# ------------------------------------------------------------------------------
# Security Group
# ------------------------------------------------------------------------------
resource "aws_security_group" "rds" {
  name        = "airbyte-rds-sg"
  description = "Allow PostgreSQL inbound traffic for Airbyte testing"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [var.allowed_cidr]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "airbyte-rds-sg"
  }
}

# ------------------------------------------------------------------------------
# RDS Subnet Group
# ------------------------------------------------------------------------------
resource "aws_db_subnet_group" "default" {
  name       = "airbyte-test-subnet-group"
  subnet_ids = aws_subnet.public[*].id

  tags = {
    Name = "Airbyte Test Subnet Group"
  }
}

# ------------------------------------------------------------------------------
# RDS Instance (PostgreSQL 15)
# ------------------------------------------------------------------------------
resource "aws_db_instance" "airbyte_test" {
  identifier             = "airbyte-postgres-15"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp3"
  storage_encrypted      = false # Optional: Enable for higher security

  # Database credentials
  db_name                = var.db_name
  username               = var.db_username
  password               = var.db_password

  # Networking
  db_subnet_group_name   = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds.id]
  publicly_accessible    = true # Required as we are in public subnets for testing
  port                   = 5432

  # Maintenance & Management
  multi_az               = false # Not required for basic connector tests
  auto_minor_version_upgrade = true
  apply_immediately      = true
  skip_final_snapshot    = true # Crucial for test environments to allow destroy
  delete_automated_backups = true # Clean up backups on destroy
  backup_retention_period = 0   # Disable backups for cost saving in tests

  # Performance
  monitoring_interval    = 0 # Disable enhanced monitoring for cost saving

  tags = {
    Name = "airbyte-test-instance"
  }
}

# ------------------------------------------------------------------------------
# Outputs
# ------------------------------------------------------------------------------
output "db_endpoint" {
  description = "The endpoint of the RDS instance"
  value       = aws_db_instance.airbyte_test.endpoint
}

output "db_username" {
  description = "The master username"
  value       = aws_db_instance.airbyte_test.username
  sensitive   = true
}

output "db_name" {
  description = "The database name"
  value       = aws_db_instance.airbyte_test.db_name
}

