}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"

  name = "main-vpc"
  cidr = "10.0.0.0/16"

  azs                  = data.aws_availability_zones.available.names
  public_subnets       = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]
}

resource "aws_db_subnet_group" "db-subnet-group" {
  name       = "db-subnet-group"
  subnet_ids = module.vpc.public_subnets
}

resource "aws_security_group" "db-sg" {
  name = "db-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "db-sg-ingress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_vpc_security_group_egress_rule" "db-sg-egress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_db_parameter_group" "postgre-param-group" {
  name   = "pgparamgrp15"
  family = "postgres15"

  parameter {
    name  = "password_encryption"
    value = "scram-sha-256"
  }

  parameter {
    name  = "rds.force_ssl"
    value = "0"
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_kms_key" "rds-key" {
  description             = "kmsrds"
  deletion_window_in_days = 14
}

resource "aws_db_instance" "postgres" {
  identifier                      = "pg"
  skip_final_snapshot             = true
  allocated_storage               = 5
  backup_retention_period         = 7
  db_subnet_group_name            = aws_db_subnet_group.db-subnet-group.id
  parameter_group_name            = aws_db_parameter_group.postgre-param-group.name
  enabled_cloudwatch_logs_exports = ["postgresql", "upgrade"]
  engine                          = "postgres"
  engine_version                  = "15"
  instance_class                  = "db.t3.micro"
  db_name                         = "postgres" # Initial database name
  username                        = "myusername"
  password                        = "mypassword"
  vpc_security_group_ids          = [aws_security_group.db-sg.id]
  # Other security settings
  publicly_accessible             = true
  multi_az                        = true
  storage_encrypted               = true
  kms_key_id                      = aws_kms_key.rds-key.arn
  # Default daily backup window
  # https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_WorkingWithAutomatedBackups.html#USER_WorkingWithAutomatedBackups.BackupWindow
}

response:
Here is the step-by-step thought process to generate the Terraform configuration:

1.  **Provider Configuration**: Define the AWS provider to ensure Terraform interacts with the correct AWS region.
2.  **VPC and Networking**: Since the request specifies "designated public subnets," we need to create a VPC, an Internet Gateway (to make them public), and two subnets in different Availability Zones (required for RDS Subnet Groups).
3.  **Routing**: Configure a Route Table associating the public subnets with the Internet Gateway to ensure they have public connectivity.
4.  **Security Group**: Create a Security Group specifically for PostgreSQL (port 5432). As this is for Airbyte connector testing, we will allow ingress from a specific CIDR block (configurable via variable) to ensure the test runner can connect.
5.  **DB Subnet Group**: Create an RDS Subnet Group that explicitly references the public subnets created in step 2.
6.  **RDS Instance**: Provision the `aws_db_instance`.
    *   **Engine**: `postgres`
    *   **Engine Version**: `15.4` (PostgreSQL 15 as requested).
    *   **Instance Class**: `db.t3.micro` (Low cost, suitable for testing).
    *   **Storage**: 20GB `gp3` (Balanced cost/performance).
    *   **Public Accessibility**: Set to `true` because the subnets are public and the prompt implies ease of access for testing.
    *   **Maintenance**: Enable `auto_minor_version_upgrade` and set a reasonable backup window, but disable `deletion_protection` to allow easy teardown during tests.
7.  **Outputs**: Output the database endpoint and connection details so the user can easily configure Airbyte.

Here is the complete Terraform configuration:

