  vpc_id                  = aws_vpc.airbyte_test_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "airbyte-test-public-subnet-1"
  }
}

# Designated Public Subnet 2
resource "aws_subnet" "public_subnet_2" {
  vpc_id                  = aws_vpc.airbyte_test_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true

  tags = {
    Name = "airbyte-test-public-subnet-2"
  }
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.airbyte_test_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "airbyte-test-public-rt"
  }
}

resource "aws_route_table_association" "public_rta_1" {
  subnet_id      = aws_subnet.public_subnet_1.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "public_rta_2" {
  subnet_id      = aws_subnet.public_subnet_2.id
  route_table_id = aws_route_table.public_rt.id
}

# -----------------------------------------------------------------------------
# Security Group
# -----------------------------------------------------------------------------

resource "aws_security_group" "rds_sg" {
  name        = "airbyte-test-rds-sg"
  description = "Allow PostgreSQL inbound traffic for Airbyte tests"
  vpc_id      = aws_vpc.airbyte_test_vpc.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Opened for external connector testing
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "airbyte-test-rds-sg"
  }
}

# -----------------------------------------------------------------------------
# Database Subnet Group
# -----------------------------------------------------------------------------

resource "aws_db_subnet_group" "airbyte_test_subnet_group" {
  name       = "airbyte-test-subnet-group"
  subnet_ids = [aws_subnet.public_subnet_1.id, aws_subnet.public_subnet_2.id]

  tags = {
    Name = "Airbyte Test DB Subnet Group"
  }
}

# -----------------------------------------------------------------------------
# RDS Instance
# -----------------------------------------------------------------------------

resource "aws_db_instance" "airbyte_db" {
  identifier             = "airbyte-test-db"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t3.micro"

  # Note: AWS RDS PostgreSQL requires a minimum of 20GB for gp2/gp3 storage.
  # We set to 20GB to ensure the provisioned configuration is valid and functional.
  allocated_storage      = 20 
  storage_type           = "gp2"

  db_name                = "airbyte_db"
  username               = var.db_username
  password               = var.db_password

  db_subnet_group_name   = aws_db_subnet_group.airbyte_test_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]

  # Designated for public subnets, so we enable public accessibility
  publicly_accessible    = true

  # Low-maintenance / Test configuration
  skip_final_snapshot    = true
  backup_retention_period = 0
  multi_az               = false

  tags = {
    Name = "Airbyte Test Database"
  }
}

# -----------------------------------------------------------------------------
# Variables
# -----------------------------------------------------------------------------

variable "db_username" {
  description = "The master username for the database"
  default     = "admin_master"
  type        = string
}

variable "db_password" {
  description = "The master password for the database"
  default     = "ChangeMePassword123!"
  type        = string
  sensitive   = true
}

# -----------------------------------------------------------------------------
# Outputs
# -----------------------------------------------------------------------------

output "db_endpoint" {
  description = "The connection endpoint for the database"
  value       = aws_db_instance.airbyte_db.endpoint
}

output "db_username" {
  description = "The master username for the database"
  value       = aws_db_instance.airbyte_db.username
}
