```hcl
# Terraform configuration to provision an Amazon RDS PostgreSQL 15 database
# with 500GB storage in public subnets for Airbyte connector testing.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = ">= 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = ">= 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# Network Configuration (VPC & Public Subnets)
# -----------------------------------------------------------------------------

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "airbyte-test-vpc"
  }
}

# Internet Gateway for Public Subnets
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "airbyte-test-igw"
  }
}

# Route Table for Public Subnets
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "airbyte-test-public-rt"
  }
}

# Designated Public Subnets
resource "aws_subnet" "public_1" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "airbyte-test-public-subnet-1"
  }
}

resource "aws_subnet" "public_2" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true

  tags = {
    Name = "airbyte-test-public-subnet-2"
  }
}

# Associate Subnets with Route Table
resource "aws_route_table_association" "public_1" {
  subnet_id      = aws_subnet.public_1.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "public_2" {
  subnet_id      = aws_subnet.public_2.id
  route_table_id = aws_route_table.public.id
}

# -----------------------------------------------------------------------------
# Security Configuration
# -----------------------------------------------------------------------------

# Security Group allowing access to Postgres (5432)
resource "aws_security_group" "rds_sg" {
  name        = "airbyte-rds-sg"
  description = "Security group for Airbyte test RDS instance"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Open for testing workloads
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "airbyte-rds-sg"
  }
}

# -----------------------------------------------------------------------------
# Database Resources
# -----------------------------------------------------------------------------

# Generate a secure password for the database
resource "random_password" "password" {
  length  = 16
  special = true
}

# DB Subnet Group (Required for RDS, grouping the public subnets)
resource "aws_db_subnet_group" "default" {
  name       = "airbyte-test-subnet-group"
  subnet_ids = [aws_subnet.public_1.id, aws_subnet.public_2.id]

  tags = {
    Name = "Airbyte Test DB Subnet Group"
  }
}

# The RDS PostgreSQL Instance
resource "aws_db_instance" "default" {
  identifier             = "airbyte-test-db"
  engine                 = "postgres"
  engine_version         = "15.4"
  instance_class         = "db.t3.medium" # Balance of cost and performance for testing
  allocated_storage      = 500
  storage_type           = "gp3" # General Purpose SSD (recommended)
  storage_encrypted      = true # Enable encryption for security

  # Credentials
  db_name  = "airbyte_test"
  username = "airbyte_admin"
  password = random_password.password.result

  # Networking
  db_subnet_group_name   = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = true # Required as it is in public subnets

  # Management & Maintenance
  multi_az               = false # Keep single AZ for cost efficiency in test env
  backup_retention_period = 7     # Standard retention
  skip_final_snapshot    = true  # Useful for quick tear-down in test workflows
  apply_immediately      = true

  # Performance/Scaling
  max_allocated_storage = 1000   # Enable storage autoscaling up to 1TB
  monitoring_interval    = 0     # Disable enhanced monitoring to minimize overhead/cost

  tags = {
    Name = "Airbyte Test Postgres 15"
  }
}

# Output the connection details
output "rds_endpoint" {
  value = aws_db_instance.default.endpoint
}

output "db_username" {
  value = aws_db_instance.default.username
}
```

