extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# Step 1: Generate a secure random password for the database
# ------------------------------------------------------------------------------
resource "random_password" "db_password" {
  length  = 16
  special = true
}

# ------------------------------------------------------------------------------
# Step 2: Network Infrastructure (VPC, Subnets, IGW, Route Table)
# ------------------------------------------------------------------------------

# Primary VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "primary-vpc"
  }
}

# Internet Gateway (Required for Public Access)
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# Public Route Table
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public-rt"
  }
}

# Data source to retrieve available Availability Zones
data "aws_availability_zones" "available" {
  state = "available"
}

# Create a pair of subnets in separate Availability Zones
resource "aws_subnet" "public_subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-${count.index + 1}"
  }
}

# Associate subnets with the public route table
resource "aws_route_table_association" "public_assoc" {
  count          = 2
  subnet_id      = aws_subnet.public_subnets[count.index].id
  route_table_id = aws_route_table.public.id
}

# ------------------------------------------------------------------------------
# Step 3: Database Security Group
# ------------------------------------------------------------------------------
resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Permit database traffic for PostgreSQL"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL from anywhere"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-sg"
  }
}

# ------------------------------------------------------------------------------
# Step 4: RDS Subnet Group and Instance
# ------------------------------------------------------------------------------

# DB Subnet Group (Required for RDS within VPC)
resource "aws_db_subnet_group" "postgres_subnet_group" {
  name       = "postgres-subnet-group"
  subnet_ids = aws_subnet.public_subnets[*].id

  tags = {
    Name = "postgres-subnet-group"
  }
}

# PostgreSQL RDS Instance
resource "aws_db_instance" "postgres" {
  identifier             = "primary-postgres-instance"
  engine                 = "postgres"
  engine_version         = "15.3"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp2"
  storage_encrypted      = false

  # Authentication
  db_name                = "mydb"
  username               = "dbadmin"
  password               = random_password.db_password.result

  # Networking
  db_subnet_group_name   = aws_db_subnet_group.postgres_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = true

  # Maintenance/Snapshots
  skip_final_snapshot    = true
  multi_az               = false

  tags = {
    Name = "postgres-15-3-instance"
  }
}

# ------------------------------------------------------------------------------
# Step 5: Outputs
# ------------------------------------------------------------------------------
output "db_endpoint" {
