data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# 4. Create a DB Subnet Group using the default subnets
resource "aws_db_subnet_group" "default" {
  name       = "mysql-subnet-group"
  subnet_ids = data.aws_subnets.default.ids

  tags = {
    Name = "My MySQL Subnet Group"
  }
}

# 5. Create a Security Group that permits public access (Port 3306)
resource "aws_security_group" "mysql_sg" {
  name        = "mysql-public-sg"
  description = "Allow public MySQL inbound traffic"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    description = "MySQL from public"
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "mysql-public-sg"
  }
}

# 6. Provision the AWS RDS MySQL Instance
resource "aws_db_instance" "mysql" {
  identifier             = "my-mysql-instance"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp2"
  storage_encrypted      = false
  db_name                = "mydatabase"
  username               = "admin"
  password               = random_password.db_password.result
  db_subnet_group_name   = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.mysql_sg.id]
  publicly_accessible    = true
  skip_final_snapshot    = true

  tags = {
    Name = "MyMySQLInstance"
  }
}

# 7. Output the generated password and endpoint
output "db_endpoint" {
  description = "The RDS instance endpoint"
  value       = aws_db_instance.mysql.endpoint
}

output "db_password" {
  description = "The database password"
  value       = random_password.db_password.result
  sensitive   = true
}
