  length           = 16
  special          = true
  override_special = "_!@" # Override special characters to ensure compatibility
}

# -----------------------------------------------------------------------------
# 2. Network Configuration (Default VPC & Subnets)
# -----------------------------------------------------------------------------
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  vpc_id = data.aws_vpc.default.id
}

# RDS requires a DB Subnet Group to exist within the VPC
resource "aws_db_subnet_group" "default" {
  name       = "mysql-subnet-group"
  subnet_ids = data.aws_subnets.default.ids

  tags = {
    Name = "My MySQL Subnet Group"
  }
}

# -----------------------------------------------------------------------------
# 3. Security Group (Public Access)
# -----------------------------------------------------------------------------
resource "aws_security_group" "rds_sg" {
  name        = "rds-mysql-public-access"
  description = "Allow public inbound MySQL traffic"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
