```hcl
# ------------------------------------------------------------------------------
# Provider Configuration
# ------------------------------------------------------------------------------
provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# Random Password Generator (Best Practice for DB credentials)
# ------------------------------------------------------------------------------
resource "random_password" "postgres_password" {
  length  = 16
  special = true
}

# ------------------------------------------------------------------------------
# VPC and Networking Components
# ------------------------------------------------------------------------------

# 1. Create a Custom VPC
resource "aws_vpc" "main_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "tf-postgres-vpc"
  }
}

# 2. Create two Subnets in different Availability Zones (Required for RDS)
resource "aws_subnet" "subnet_1" {
  vpc_id                  = aws_vpc.main_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = false # Private subnet

  tags = {
    Name = "tf-postgres-subnet-1"
  }
}

resource "aws_subnet" "subnet_2" {
  vpc_id                  = aws_vpc.main_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = false # Private subnet

  tags = {
    Name = "tf-postgres-subnet-2"
  }
}

# 3. Create a DB Subnet Group (Associates subnets with the RDS instance)
resource "aws_db_subnet_group" "postgres_subnet_group" {
  name       = "tf-postgres-subnet-group"
  subnet_ids = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  tags = {
    Name = "My Postgres Subnet Group"
  }
}

# ------------------------------------------------------------------------------
# Security Components
# ------------------------------------------------------------------------------

# Security Group for PostgreSQL
resource "aws_security_group" "postgres_sg" {
  name        = "tf-postgres-sg"
  description = "Allow inbound PostgreSQL traffic"
  vpc_id      = aws_vpc.main_vpc.id

  # Ingress rule: Allow PostgreSQL (port 5432) from within the VPC
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main_vpc.cidr_block]
  }

  # Egress rule: Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "tf-postgres-sg"
  }
}

# ------------------------------------------------------------------------------
# Database Instance (RDS)
# ------------------------------------------------------------------------------
resource "aws_db_instance" "postgres_db" {
  identifier             = "tf-postgres-instance"
  engine                 = "postgres"
  engine_version         = "14.11" # Specific PostgreSQL Engine Version
  instance_class         = "db.t3.micro" # DB Instance Class
  allocated_storage      = 20         # Storage allocation in GB
  storage_type           = "gp2"
  storage_encrypted      = true
  db_name                = "mydatabase"
  username               = "dbadmin"
  password               = random_password.postgres_password.result

  # Networking
  db_subnet_group_name   = aws_db_subnet_group.postgres_subnet_group.name
  vpc_security_group_ids = [aws_security_group.postgres_sg.id]
  publicly_accessible    = false # Ensure it is not publicly accessible

  # Maintenance and Backups
  backup_retention_period = 7
  skip_final_snapshot     = true # Set to false in production
  final_snapshot_identifier = "tf-postgres-final-snapshot"

  tags = {
    Name = "tf-postgres-db"
  }
}

# ------------------------------------------------------------------------------
# Outputs
# ------------------------------------------------------------------------------
output "db_endpoint" {
  description = "The endpoint of the PostgreSQL database"
  value       = aws_db_instance.postgres_db.endpoint
}

output "db_username" {
  description = "The master username for the database"
  value       = aws_db_instance.postgres_db.username
  sensitive   = true
}

output "db_password" {
  description = "The master password for the database"
  value       = random_password.postgres_password.result
  sensitive   = true
}
