# Fetch available Availability Zones to make the configuration more portable
data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_subnet" "private_subnet_1" {
  vpc_id            = aws_vpc.custom_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "private-subnet-1"
  }
}

resource "aws_subnet" "private_subnet_2" {
  vpc_id            = aws_vpc.custom_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[1]

  tags = {
    Name = "private-subnet-2"
  }
}

# 2. Security Group
resource "aws_security_group" "postgres_sg" {
  name        = "postgres-security-group"
  description = "Allow inbound PostgreSQL traffic from within the VPC"
  vpc_id      = aws_vpc.custom_vpc.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.custom_vpc.cidr_block] # Only accessible from within the VPC
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "postgres-sg"
  }
}

# 3. DB Subnet Group
resource "aws_db_subnet_group" "postgres_subnet_group" {
  name       = "postgres-subnet-group"
  subnet_ids = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]

  tags = {
    Name = "postgres-subnet-group"
  }
}

# 4. Database Credentials
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "_!%^"
}

# 5. RDS PostgreSQL Instance
resource "aws_db_instance" "postgres_db" {
  identifier             = "custom-postgres-instance"
  engine                 = "postgres"
  engine_version         = "15.4" # Specific PostgreSQL release
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp2"
  storage_encrypted      = true

  # Authentication
  db_name  = "myappdb"
  username = "postgresadmin"
  password = random_password.db_password.result

  # Networking
  db_subnet_group_name   = aws_db_subnet_group.postgres_subnet_group.name
  vpc_security_group_ids = [aws_security_group.postgres_sg.id]
  publicly_accessible    = false # Ensures the DB remains private

  # Maintenance and Upgrades
  allow_major_version_upgrade = true
  auto_minor_version_upgrade  = true
  maintenance_window          = "Mon:03:00-Mon:04:00"
  backup_retention_period     = 7
  backup_window               = "03:00-04:00"

  # Final snapshot (true simplifies destruction for this example, set to false for prod)
  skip_final_snapshot = true 
  deletion_protection = false

  tags = {
    Name = "custom-postgres-db"
  }
}

# Output the DB Endpoint (for connection purposes)
output "db_endpoint" {
  description = "The endpoint of the PostgreSQL database"
  value       = aws_db_instance.postgres_db.endpoint
}

