  password = random_password.db_password.result

  # Networking
  db_subnet_group_name   = aws_db_subnet_group.postgres_subnet_group.name
  vpc_security_group_ids = [aws_security_group.postgres_sg.id]
  publicly_accessible    = false # Ensures the DB remains private

  # Maintenance and Upgrades
  allow_major_version_upgrade = true
  auto_minor_version_upgrade  = true
  maintenance_window          = "Mon:03:00-Mon:04:00"
  backup_retention_period     = 7
  backup_window               = "03:00-04:00"

  # Final snapshot (true simplifies destruction for this example, set to false for prod)
  skip_final_snapshot = true 
  deletion_protection = false

  tags = {
    Name = "custom-postgres-db"
  }
}

# Output the DB Endpoint (for connection purposes)
output "db_endpoint" {
  description = "The endpoint of the PostgreSQL database"
