}

resource "aws_security_group" "rds-proxy-sg" {
  name        = "rds-proxy-sg"
  vpc_id      = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "db-proxy-sg-ingress-rule" {
  from_port       = 3306
  to_port         = 3306
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.rds-proxy-sg.id
}

resource "aws_vpc_security_group_egress_rule" "db-proxy-sg-egress-rule" {
  from_port       = 3306
  to_port         = 3306
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.rds-proxy-sg.id
}

resource "aws_db_subnet_group" "main" {
  name       = "main"
  subnet_ids = module.vpc.private_subnets
}

resource "aws_rds_cluster" "example" {
  cluster_identifier      = "example-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.08.0"
  master_username         = "myusername"
  master_password         = "password123"
  database_name           = "exampledb"
  backup_retention_period = 5
  preferred_backup_window = "07:00-09:00"
  skip_final_snapshot     = true
  vpc_security_group_ids  = [aws_security_group.rds-proxy-sg.id]
  db_subnet_group_name    = aws_db_subnet_group.main.name
}

resource "aws_secretsmanager_secret" "db-credentials" {
  name_prefix = "db-credentials-"
}

resource "aws_secretsmanager_secret_version" "db-credentials-version" {
  secret_id     = aws_secretsmanager_secret.db-credentials.id
  secret_string = jsonencode({
    username = aws_rds_cluster.example.master_username
    password = aws_rds_cluster.example.master_password
  })
}

resource "aws_iam_role" "rds-proxy-role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_policy" "rds-proxy-policy" {
  name        = "rds-proxy-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue",
        ]
        Resource = [
          "${aws_secretsmanager_secret_version.db-credentials-version.arn}",
        ]
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "attach-proxy-policy" {
  role       = aws_iam_role.rds-proxy-role.name
  policy_arn = aws_iam_policy.rds-proxy-policy.arn
}

resource "aws_db_proxy" "example" {
  name                   = "example-proxy"
  debug_logging          = false
  engine_family          = "MYSQL"
  idle_client_timeout    = 1800
  require_tls            = true
  role_arn               = aws_iam_role.rds-proxy-role.arn
  vpc_security_group_ids = [aws_security_group.rds-proxy-sg.id]
  vpc_subnet_ids         = module.vpc.private_subnets

  auth {
    auth_scheme  = "SECRETS"
    secret_arn   = aws_secretsmanager_secret.db-credentials.arn
    iam_auth     = "DISABLED"
  }
}

resource "aws_db_proxy_default_target_group" "example" {
  db_proxy_name = aws_db_proxy.example.name

  connection_pool_config {
    connection_borrow_timeout    = 120
    init_query                   = "SET x=1, y=2"
    max_connections_percent      = 100
    max_idle_connections_percent = 50
    session_pinning_filters      = ["EXCLUDE_VARIABLE_SETS"]
  }
}

resource "aws_db_proxy_target" "example" {
  db_cluster_identifier = aws_rds_cluster.example.cluster_identifier
  db_proxy_name          = aws_db_proxy.example.name
  target_group_name      = aws_db_proxy_default_target_group.example.name
}

response:
Here is the step-by-step Terraform configuration to deploy the requested infrastructure.

This configuration performs the following steps:
1.  **Networking**: Creates a VPC, two private subnets (required for RDS), and a DB Subnet Group.
2.  **Security**: Creates Security Groups for the RDS Cluster (allowing traffic only from the Proxy) and the RDS Proxy (allowing traffic from the application).
3.  **Secrets**: Generates a random password and stores it in AWS Secrets Manager.
4.  **IAM**: Creates an IAM role for the RDS Proxy to access the Secrets Manager secret and CloudWatch Logs.
5.  **Database**: Deploys an Aurora MySQL Cluster with a single DB instance.
6.  **Proxy**: Deploys an RDS Proxy and links it to the database cluster and secrets.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# 1. Networking Configuration
# ------------------------------------------------------------------------------

# Create a VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "aurora-proxy-vpc"
  }
}

# Get available Availability Zones
data "aws_availability_zones" "available" {
  state = "available"
}

# Create two private subnets for RDS (must be in different AZs)
resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "aurora-subnet-${count.index + 1}"
  }
}

# Create a DB Subnet Group
resource "aws_db_subnet_group" "aurora" {
  name       = "aurora-subnet-group"
  subnet_ids = aws_subnet.private[*].id

  tags = {
    Name = "Aurora Subnet Group"
  }
}

# ------------------------------------------------------------------------------
# 2. Security Groups
# ------------------------------------------------------------------------------

# Security Group for the RDS Cluster
# Only allows ingress from the RDS Proxy Security Group
resource "aws_security_group" "rds" {
  name_prefix = "aurora-rds-sg-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.proxy.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Aurora RDS Security Group"
  }
}

# Security Group for the RDS Proxy
# Allows ingress from the application (e.g., EC2/Lambda) represented here by a CIDR block
resource "aws_security_group" "proxy" {
  name_prefix = "aurora-proxy-sg-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restrict to your App's IP/SG in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Aurora Proxy Security Group"
  }
}

# ------------------------------------------------------------------------------
# 3. Secrets Management
# ------------------------------------------------------------------------------

# Generate a random password
resource "random_password" "db_password" {
  length  = 16
  special = true
}

# Store the credentials in AWS Secrets Manager
resource "aws_secretsmanager_secret" "db_credentials" {
  name = "aurora-proxy-db-credentials"
}

resource "aws_secretsmanager_secret_version" "db_credentials" {
  secret_id = aws_secretsmanager_secret.db_credentials.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.db_password.result
  })
}

# ------------------------------------------------------------------------------
# 4. IAM Role for RDS Proxy
# ------------------------------------------------------------------------------

# IAM Role assumed by the RDS Proxy
resource "aws_iam_role" "proxy_role" {
  name = "aurora-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# Policy to allow the Proxy to access the Secret and publish logs
resource "aws_iam_role_policy" "proxy_policy" {
  name = "aurora-proxy-policy"
  role = aws_iam_role.proxy_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ]
        Effect = "Allow"
        Resource = aws_secretsmanager_secret.db_credentials.arn
      },
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Effect = "Allow"
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# ------------------------------------------------------------------------------
# 5. Aurora MySQL Database
# ------------------------------------------------------------------------------

# Parameter Group (optional but recommended)
resource "aws_rds_cluster_parameter_group" "aurora_mysql" {
  name        = "aurora-mysql-params"
  family      = "aurora-mysql8.0"
  description = "Aurora MySQL 8.0 parameter group"
}

# The Aurora Cluster
resource "aws_rds_cluster" "aurora" {
  engine                = "aurora-mysql"
  engine_version        = "8.0.mysql_aurora.3.02.0"
  database_name         = "mydb"
  master_username       = "admin"
  master_password       = random_password.db_password.result
  db_subnet_group_name  = aws_db_subnet_group.aurora.name
  vpc_security_group_ids = [aws_security_group.rds.id]
  skip_final_snapshot   = true
  apply_immediately     = true

  # Use Secrets Manager for credentials (Requires IAM integration, but setting explicit pass here for simplicity)
  # In advanced setups, you remove master_password and set kms_key_id.
}

# A single DB instance within the cluster
resource "aws_rds_cluster_instance" "aurora" {
  identifier         = "aurora-instance-1"
  cluster_identifier = aws_rds_cluster.aurora.id
  instance_class     = "db.t3.small"
  engine             = aws_rds_cluster.aurora.engine
  engine_version     = aws_rds_cluster.aurora.engine_version
  publicly_accessible = false
}

# ------------------------------------------------------------------------------
# 6. RDS Proxy
# ------------------------------------------------------------------------------

resource "aws_db_proxy" "aurora_proxy" {
  name                   = "aurora-mysql-proxy"
  engine_family          = "MYSQL"
  role_arn               = aws_iam_role.proxy_role.arn
  vpc_subnet_ids         = aws_subnet.private[*].id
  vpc_security_group_ids = [aws_security_group.proxy.id]
  requires_tls           = false

  auth {
    secret_arn = aws_secretsmanager_secret.db_credentials.arn
    iam_auth   = "DISABLED"
  }

  depends_on = [
    aws_iam_role_policy.proxy_policy
  ]
}

# Link the Proxy to the Cluster
resource "aws_db_proxy_default_target_group" "default" {
  db_proxy_name = aws_db_proxy.aurora_proxy.name

  connection_pool_config {
    connection_borrow_timeout    = 120
    init_query                   = "SET x=1"
    max_connections_percent      = 100
    max_idle_connections_percent = 50
    session_pinning_filters      = []
  }
}

# Register the Cluster as a target for the Proxy
resource "aws_db_proxy_target" "aurora" {
  db_proxy_name          = aws_db_proxy.aurora_proxy.name
  target_group_name      = aws_db_proxy_default_target_group.default.name
  db_cluster_identifier  = aws_rds_cluster.aurora.id

  depends_on = [
    aws_rds_cluster_instance.aurora
  ]
}
