terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# -----------------------------------------------------------------------------
# 1. Networking (VPC, Subnets, Route Tables)
# -----------------------------------------------------------------------------

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "aurora-vpc"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "aurora-igw"
  }
}

# Create two private subnets in different AZs for the RDS Cluster
resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "aurora-subnet-${count.index}"
  }
}

# Route table for private subnets (allows outbound internet access for updates/logs)
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "aurora-private-rt"
  }
}

resource "aws_route_table_association" "private" {
  count          = 2
  subnet_id      = aws_subnet.private[count.index].id
  route_table_id = aws_route_table.private.id
}

# DB Subnet Group required by RDS
resource "aws_db_subnet_group" "aurora" {
  name       = "aurora-subnet-group"
  subnet_ids = aws_subnet.private[*].id

  tags = {
    Name = "Aurora Subnet Group"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# -----------------------------------------------------------------------------
# 2. Security Groups
# -----------------------------------------------------------------------------

# Security Group for the Aurora Cluster
resource "aws_security_group" "rds" {
  name        = "aurora-rds-sg"
  description = "Security group for Aurora MySQL Cluster"
  vpc_id      = aws_vpc.main.id

  tags = {
    Name = "aurora-rds-sg"
  }
}

# Ingress: Allow traffic from the RDS Proxy only
resource "aws_security_group_rule" "rds_ingress" {
  description              = "Allow MySQL traffic from RDS Proxy"
  from_port                = 3306
  to_port                  = 3306
  protocol                 = "tcp"
  security_group_id        = aws_security_group.rds.id
  source_security_group_id = aws_security_group.proxy.id
}

# Security Group for the RDS Proxy
resource "aws_security_group" "proxy" {
  name        = "aurora-proxy-sg"
  description = "Security group for RDS Proxy"
  vpc_id      = aws_vpc.main.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-proxy-sg"
  }
}

# Ingress: Allow client traffic (e.g., App servers) to the Proxy
# Note: In production, restrict source_cidr_blocks to specific IP ranges
resource "aws_security_group_rule" "proxy_ingress" {
  description     = "Allow MySQL traffic from clients"
  from_port       = 3306
  to_port         = 3306
  protocol        = "tcp"
  security_group_id = aws_security_group.proxy.id
  cidr_blocks     = ["0.0.0.0/0"]
}

# -----------------------------------------------------------------------------
# 3. Secrets Manager
# -----------------------------------------------------------------------------

resource "aws_secretsmanager_secret" "db_credentials" {
  name = "aurora-db-credentials"
}

resource "aws_secretsmanager_secret_version" "db_credentials" {
  secret_id = aws_secretsmanager_secret.db_credentials.id
  secret_string = jsonencode({
    username = "admin"
    password = "ChangeMe123!"
  })
}

# -----------------------------------------------------------------------------
# 4. IAM Roles for RDS Proxy
# -----------------------------------------------------------------------------

resource "aws_iam_role" "rds_proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# Policy to allow the proxy to retrieve the secret from Secrets Manager
resource "aws_iam_role_policy_attachment" "rds_proxy_secrets_policy" {
  role       = aws_iam_role.rds_proxy_role.name
  policy_arn = "arn:aws:iam::aws:policy/SecretsManagerReadWrite"
}

# -----------------------------------------------------------------------------
# 5. Aurora MySQL Cluster
# -----------------------------------------------------------------------------

resource "aws_rds_cluster" "aurora" {
  engine                = "aurora-mysql"
  engine_version        = "8.0.mysql_aurora.3.02.0"
  database_name         = "mydb"
  master_username       = "admin"
  master_password       = "ChangeMe123!" # Not used if secret is fully integrated, but often kept for initial creation compatibility
  db_subnet_group_name  = aws_db_subnet_group.aurora.name
  vpc_security_group_ids = [aws_security_group.rds.id]
  skip_final_snapshot    = true
  storage_encrypted      = true

  tags = {
    Name = "aurora-mysql-cluster"
  }
}

resource "aws_rds_cluster_instance" "aurora" {
  count              = 1
  identifier         = "aurora-instance-${count.index}"
  cluster_identifier = aws_rds_cluster.aurora.id
  instance_class     = "db.t3.small"
  engine             = aws_rds_cluster.aurora.engine
  engine_version     = aws_rds_cluster.aurora.engine_version
  publicly_accessible = false
  db_subnet_group_name = aws_db_subnet_group.aurora.name
}

# -----------------------------------------------------------------------------
# 6. RDS Proxy
# -----------------------------------------------------------------------------

resource "aws_db_proxy" "main" {
  name                   = "aurora-rds-proxy"
  engine_family          = "MYSQL"
  role_arn               = aws_iam_role.rds_proxy_role.arn
  vpc_subnet_ids         = aws_subnet.private[*].id
  vpc_security_group_ids = [aws_security_group.proxy.id]
  require_tls            = false

  # Configuration requirements
  idle_client_timeout    = 1800
  debug_logging          = false

  auth {
    auth_scheme = "SECRETS"
    description = "Auth via Secret Manager"
    iam_auth    = "DISABLED"
    secret_arn  = aws_secretsmanager_secret.db_credentials.arn
  }

  depends_on = [
    aws_rds_cluster_instance.aurora
  ]
}

resource "aws_db_proxy_target_group" "main" {
  db_proxy_name = aws_db_proxy.main.name
  name          = "default"
}

# Register the Aurora Cluster as a target for the proxy
resource "aws_db_proxy_default_target_group" "main" {
  db_proxy_name = aws_db_proxy.main.name

  connection_pool_config {
    connection_borrow_timeout    = 120
    max_connections_percent     = 100
    max_idle_connections_percent = 50
    session_pinning_filters      = []
  }
}

resource "aws_db_proxy_target" "aurora" {
  db_proxy_name       = aws_db_proxy.main.name
  target_group_name   = aws_db_proxy_default_target_group.main.name
  db_cluster_identifiers = [aws_rds_cluster.aurora.id]
}
