provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# 1. Network Infrastructure (VPC, Subnets, Security Groups)
# ------------------------------------------------------------------------------

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
