        ]
        # We will use the ARN generated by RDS later, or a generic wildcard for the module
        # Ideally, we reference the secret ARN directly.
        Resource = aws_rds_cluster.aurora.master_user_secret[0].secret_arn
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "proxy_attach" {
  role       = aws_iam_role.proxy_role.name
  policy_arn = aws_iam_policy.proxy_secrets_policy.arn
}

# Attach policy for KMS decryption if using custom KMS keys (not used here with default AWS secrets)
# and CloudWatch Logs if needed.
resource "aws_iam_role_policy_attachment" "proxy_logging_attach" {
  role       = aws_iam_role.proxy_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonRDSEnhancedMonitoringRole"
}

# ------------------------------------------------------------------------------
# 3. RDS Aurora MySQL Cluster
# ------------------------------------------------------------------------------

resource "aws_rds_cluster" "aurora" {
  engine                = "aurora-mysql"
  engine_version        = "8.0.mysql_aurora.3.02.0"
  database_name         = "mydb"
  master_username       = "admin"

  # Enable Secrets Manager integration for master credentials
  manage_master_user_password = true

  db_subnet_group_name   = aws_db_subnet_group.aurora.name
  vpc_security_group_ids = [aws_security_group.rds.id]

  backup_retention_period = 5
  preferred_backup_window = "07:00-09:00"

  skip_final_snapshot = true
  deletion_protection = false

  tags = {
    Name = "aurora-mysql-cluster"
  }
}

resource "aws_rds_cluster_instance" "aurora_instances" {
  count              = 1
  identifier         = "aurora-instance-${count.index + 1}"
  cluster_identifier = aws_rds_cluster.aurora.id
  instance_class     = "db.t3.small"
  engine             = aws_rds_cluster.aurora.engine
  engine_version     = aws_rds_cluster.aurora.engine_version

  publicly_accessible = false
  db_subnet_group_name = aws_db_subnet_group.aurora.name

  tags = {
    Name = "aurora-mysql-instance"
  }
}

# ------------------------------------------------------------------------------
# 4. RDS Proxy
# ------------------------------------------------------------------------------

resource "aws_db_proxy" "proxy" {
  name                   = "aurora-mysql-proxy"
  engine_family          = "MYSQL"
  vpc_subnet_ids         = aws_subnet.subnets[*].id
  vpc_security_group_ids = [aws_security_group.proxy.id]
  role_arn               = aws_iam_role.proxy_role.arn
  require_tls            = false

  auth {
    auth_scheme = "SECRETS"
    description = "Auth via Secrets Manager"
    iam_auth    = "DISABLED"
    secret_arn  = aws_rds_cluster.aurora.master_user_secret[0].secret_arn
  }

  depends_on = [
    aws_iam_role_policy_attachment.proxy_attach
  ]

  tags = {
    Name = "aurora-rds-proxy"
  }
}

resource "aws_db_proxy_default_target_group" "default" {
  db_proxy_name = aws_db_proxy.proxy.name

  connection_pool_config {
    connection_borrow_timeout    = 120
    max_connections_percent     = 100
    max_idle_connections_percent = 50
    session_pinning_filters      = []
  }
}

resource "aws_db_proxy_target" "proxy_target" {
  db_cluster_identifier = aws_rds_cluster.aurora.id
  db_proxy_name         = aws_db_proxy.proxy.name
  target_group_name     = aws_db_proxy_default_target_group.default.name
}

# ------------------------------------------------------------------------------
# Outputs
# ------------------------------------------------------------------------------

output "rds_cluster_endpoint" {
  value = aws_rds_cluster.aurora.endpoint
}

output "rds_proxy_endpoint" {
  value = aws_db_proxy.proxy.endpoint
}

output "secret_arn" {
  value = aws_rds_cluster.aurora.master_user_secret[0].secret_arn
  description = "The ARN of the secret stored in Secrets Manager containing the DB credentials"
}
