terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# 1. Generate Random Password
# ------------------------------------------------------------------------------
resource "random_password" "db_password" {
  length  = 16
  special = true
}

# ------------------------------------------------------------------------------
# 2. Networking (VPC & Subnets)
# ------------------------------------------------------------------------------
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "aurora-vpc"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_subnet" "subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "aurora-subnet-${count.index}"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "aurora-igw"
  }
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public-rt"
  }
}

resource "aws_route_table_association" "public_assoc" {
  count          = 2
  subnet_id      = aws_subnet.subnets[count.index].id
  route_table_id = aws_route_table.public.id
}

# ------------------------------------------------------------------------------
# 3. Security Groups
# ------------------------------------------------------------------------------
# Security Group for the Aurora Cluster
resource "aws_security_group" "rds_sg" {
  name        = "aurora-rds-sg"
  description = "Allow traffic from RDS Proxy"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.proxy_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-rds-sg"
  }
}

# Security Group for the RDS Proxy
resource "aws_security_group" "proxy_sg" {
  name        = "aurora-proxy-sg"
  description = "Allow traffic to Aurora RDS"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  egress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-proxy-sg"
  }
}

# ------------------------------------------------------------------------------
# 4. IAM Role for RDS Proxy
# ------------------------------------------------------------------------------
resource "aws_iam_role" "proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "proxy_secrets_attachment" {
  role       = aws_iam_role.proxy_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonRDSDataFullAccess" # Simplified policy for demo
}

# ------------------------------------------------------------------------------
# 5. AWS Secrets Manager
# ------------------------------------------------------------------------------
resource "aws_secretsmanager_secret" "db_credentials" {
  name = "aurora-db-credentials"
}

resource "aws_secretsmanager_secret_version" "db_credentials" {
  secret_id = aws_secretsmanager_secret.db_credentials.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.db_password.result
  })
}

# ------------------------------------------------------------------------------
# 6. DB Subnet Group
# ------------------------------------------------------------------------------
resource "aws_db_subnet_group" "aurora_subnet_group" {
  name       = "aurora-subnet-group"
  subnet_ids = aws_subnet.subnets[*].id

  tags = {
    Name = "Aurora Subnet Group"
  }
}

# ------------------------------------------------------------------------------
# 7. Aurora MySQL RDS Cluster
# ------------------------------------------------------------------------------
resource "aws_rds_cluster" "aurora_cluster" {
  engine                = "aurora-mysql"
  engine_version        = "8.0.mysql_aurora.3.02.0"
  database_name         = "mydb"
  master_username       = "admin"
  master_secret_arn     = aws_secretsmanager_secret_version.db_credentials.arn
  db_subnet_group_name  = aws_db_subnet_group.aurora_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  skip_final_snapshot   = false
  final_snapshot_identifier = "snapshot" # Requirement: Named "snapshot"

  # Storage and scaling
  storage_encrypted = true
  apply_immediately = true

  tags = {
    Name = "aurora-mysql-cluster"
  }
}

resource "aws_rds_cluster_instance" "aurora_instances" {
  count              = 1
  identifier         = "aurora-instance-${count.index}"
  cluster_identifier = aws_rds_cluster.aurora_cluster.id
  engine             = aws_rds_cluster.aurora_cluster.engine
  engine_version     = aws_rds_cluster.aurora_cluster.engine_version
  instance_class     = "db.t3.small"
  db_subnet_group_name = aws_db_subnet_group.aurora_subnet_group.name
}

# ------------------------------------------------------------------------------
# 8. RDS Proxy
# ------------------------------------------------------------------------------
resource "aws_db_proxy" "aurora_proxy" {
  name                   = "aurora-proxy"
  engine_family          = "MYSQL"
  role_arn               = aws_iam_role.proxy_role.arn
  vpc_subnet_ids         = aws_subnet.subnets[*].id
  vpc_security_group_ids = [aws_security_group.proxy_sg.id]
  require_tls            = false

  auth {
    auth_scheme = "SECRETS"
    description = "Auth via Secret Manager"
    iam_auth    = "DISABLED"
    secret_arn  = aws_secretsmanager_secret.db_credentials.arn
  }

  depends_on = [aws_rds_cluster_instance.aurora_instances]
}

resource "aws_db_proxy_default_target_group" "default_target" {
  db_proxy_name = aws_db_proxy.aurora_proxy.name

  connection_pool_config {
    connection_borrow_timeout    = 120
    max_connections_percent      = 100
    max_idle_connections_percent = 50
    session_pinning_filters      = ["STICKY_ROUTING"]
  }
}

resource "aws_db_proxy_target" "proxy_target" {
  db_proxy_name          = aws_db_proxy.aurora_proxy.name
  target_group_name      = aws_db_proxy_default_target_group.default_target.name
  db_cluster_identifier  = aws_rds_cluster.aurora_cluster.id
}

resource "aws_db_proxy_endpoint" "read_write_endpoint" {
  db_proxy_name          = aws_db_proxy.aurora_proxy.name
  db_proxy_endpoint_name = "aurora-proxy-rw"
  vpc_subnet_ids         = aws_subnet.subnets[*].id
  target_role            = "READ_WRITE"
}

