}

response:
To create a simple Amazon Lightsail setup using Terraform, we need to follow these steps:

1.  **Configure the AWS Provider**: Establish the connection to AWS, setting a default region (e.g., `us-east-1`).
2.  **Select Data Sources**: Instead of hardcoding specific blueprint (OS) and bundle (sizing) IDs, we will use data sources to dynamically look up the latest "Amazon Linux 2" OS and a "Nano" instance size. This makes the code more portable.
3.  **Generate SSH Keys**: For a complete, runnable example, we will use the `tls` provider to generate a new SSH key pair locally, then upload the public key to Lightsail so we can log in.
4.  **Create the Instance**: Provision the actual Lightsail instance using the selected blueprint, bundle, and SSH key.
5.  **Create a Static IP**: Attach a static public IP address to the instance to ensure the IP doesn't change if the instance is restarted.
6.  **Save the Private Key**: Write the generated private key to a local file so the user can actually SSH into the server.
7.  **Output Connection Details**: Provide the user with the Public IP and a sample SSH command.

Here is the complete Terraform configuration in a single code block:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    tls = {
      source  = "hashicorp/tls"
      version = "~> 4.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ------------------------------------------------------------------------------
# Step 1: Data Sources - Find Blueprint (OS) and Bundle (Size)
# ------------------------------------------------------------------------------

# Find the latest Amazon Linux 2 blueprint
data "aws_lightsail_blueprint" "amazon_linux_2" {
  name = "amazon_linux_2"
}

# Find a small instance bundle (e.g., nano 2.0 or similar)
# We assume availability in us-east-1. 'nano_2_0' is the standard naming for the smallest instance.
data "aws_lightsail_bundle" "nano" {
  name = "nano_2_0"
}

# ------------------------------------------------------------------------------
# Step 2: Create SSH Key Pair
# ------------------------------------------------------------------------------

# Generate a private key locally
resource "tls_private_key" "generated" {
  algorithm = "RSA"
  rsa_bits  = 4096
}

# Create the Lightsail Key Pair using the generated public key
resource "aws_lightsail_key_pair" "default" {
  name       = "terraform_lightsail_key"
  public_key = tls_private_key.generated.public_key_openssh
}

# Save the private key to a file named "lightsail_key.pem" in the current directory
resource "local_file" "private_key" {
  content  = tls_private_key.generated.private_key_pem
  filename = "lightsail_key.pem"
  file_permission = "0400"
}

# ------------------------------------------------------------------------------
# Step 3: Create Lightsail Instance
# ------------------------------------------------------------------------------
resource "aws_lightsail_instance" "simple_server" {
  name              = "simple-lightsail-app"
  availability_zone = "us-east-1a"
  blueprint_id      = data.aws_lightsail_blueprint.amazon_linux_2.id
  bundle_id         = data.aws_lightsail_bundle.nano.id
  key_pair_name     = aws_lightsail_key_pair.default.name

  # Optional: Add user data to run a script on startup
  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              echo "Hello from Terraform" > /home/ec2-user/index.html
              EOF

  tags = {
    Name        = "Simple-Lightsail"
    Environment = "Demo"
    ManagedBy   = "Terraform"
  }
}

# ------------------------------------------------------------------------------
# Step 4: Create and Attach Static IP
# ------------------------------------------------------------------------------
resource "aws_lightsail_static_ip" "static_ip" {
  name = "simple-lightsail-static-ip"
}

resource "aws_lightsail_static_ip_attachment" "ip_attach" {
  static_ip_name = aws_lightsail_static_ip.static_ip.name
  instance_name  = aws_lightsail_instance.simple_server.name
}

# ------------------------------------------------------------------------------
# Step 5: Outputs
# ------------------------------------------------------------------------------
output "lightsail_public_ip" {
  description = "The public IP address of the Lightsail instance"
  value       = aws_lightsail_static_ip.static_ip.ip_address
}

output "ssh_connection_string" {
  description = "Command to SSH into the instance (Requires private key file)"
  value       = "ssh -i lightsail_key.pem ec2-user@${aws_lightsail_static_ip.static_ip.ip_address}"
}
```

