    Name = "DefaultLightsailInstance"
  }
}

output "public_ip" {
  value       = aws_lightsail_instance.default.public_ip_address
  description = "The public IP address of the Lightsail instance"
}

output "username" {
  value       = aws_lightsail_instance.default.username
  description = "The default username for connecting to the instance"
}
```

