              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Provisioned by Terraform</h1>" > /var/www/html/index.html
              EOF

  tags = {
    Name        = "LightsailAppInstance"
    Environment = "Production"
  }
}

# Create a Managed Database in Lightsail
resource "aws_lightsail_database" "app_database" {
  name                = "lightsail-managed-db"
  availability_zone   = "us-east-1a"

  # Relational Database Blueprint ID (e.g., mysql_8_0)
  relational_database_blueprint_id = "mysql_8_0"

  # Relational Database Bundle ID (e.g., micro_2_0 for 1GB RAM)
  relational_database_bundle_id    = "micro_2_0"

  # Database access credentials
  master_database_name = "appdb"
  master_username      = "admin"
  master_password      = random_password.db_master_password.result

  # Apply changes immediately
  apply_immediately    = true

  # Database backup settings
  backup_retention_enabled = true

  # Security: Disable public access if only connecting via VPC peering
  # Note: To connect the Instance to the DB, you typically need to 
  # configure networking or VPC peering, which is separate from provisioning.
  publicly_accessible  = false

  tags = {
    Name        = "LightsailDatabase"
    Environment = "Production"
  }
}

# Output the database endpoint and master password
output "database_endpoint" {
  description = "The endpoint of the Lightsail database"
  value       = aws_lightsail_database.app_database.master_endpoint_address
  sensitive   = false
}

output "database_master_password" {
  description = "The master password for the Lightsail database"
  value       = random_password.db_master_password.result
  sensitive   = true
}

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create the Lightsail Instance
resource "aws_lightsail_instance" "mysql_db" {
  name              = "mysql-database-instance"
  availability_zone = "us-east-1a"

  # Use Amazon Linux 2 as the OS blueprint
  blueprint_id      = "amazon_linux_2"

  # Use a nano instance (1 vCPU, 0.5 GB RAM, 20 GB SSD) for cost efficiency
  bundle_id         = "nano_2_0"

  # User data script to install and configure MySQL (MariaDB on Amazon Linux 2)
  user_data = <<-EOF
              #!/bin/bash
              # Update all packages
              yum update -y
              # Install MariaDB server (standard MySQL replacement on Amazon Linux 2)
              yum install -y mariadb-server
              # Start the service
              systemctl start mariadb
              # Enable the service to start on boot
              systemctl enable mariadb
              # Secure the installation (Optional: sets root password, removes anonymous users)
              # Note: In a real production scenario, use Ansible or a provisioning tool for config management.
              # The following command sets the root password to 'Terraform123!'
              mysql -e "SET PASSWORD FOR 'root'@'localhost' = PASSWORD('Terraform123!');"
              EOF

  tags = {
    Name        = "MySQL-Lightsail"
    Environment = "Development"
  }
}

# Configure the firewall (Networking) to allow MySQL traffic on port 3306
resource "aws_lightsail_instance_public_ports" "mysql_access" {
  instance_name = aws_lightsail_instance.mysql_db.name

  port_info {
    protocol = "tcp"
    from_port = 3306
    to_port   = 3306
  }
}

