terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

# -----------------------------------------------------------------------------
# Variables
# -----------------------------------------------------------------------------

variable "aws_region" {
  description = "The AWS region where resources will be created."
  type        = string
  default     = "us-east-1"
}

variable "availability_zone" {
  description = "The Availability Zone (e.g., us-east-1a)."
  type        = string
  default     = "us-east-1a"
}

variable "instance_name" {
  description = "The name of the Lightsail instance."
  type        = string
  default     = "terraform-lightsail-app"
}

variable "blueprint_id" {
  description = "The ID for the blueprint (OS image). e.g., amazon_linux_2, ubuntu_22"
  type        = string
  default     = "amazon_linux_2"
}

variable "bundle_id" {
  description = "The bundle ID for the instance (specifies CPU/RAM). e.g., nano_2_0, micro_2_0"
  type        = string
  default     = "micro_2_0"
}

variable "attached_disks" {
  description = "A map of additional disks to create and attach. Key is the disk name, value is size in GB."
  type = map(object({
    size_in_gb = number
  }))
  default = {
    "disk-data" = {
      size_in_gb = 20
    }
    "disk-logs" = {
      size_in_gb = 50
    }
  }
}

variable "user_data" {
  description = "A script to run on the instance during first boot."
  type        = string
  default     = "#!/bin/bash
echo 'Hello from Terraform Lightsail' > /tmp/terraform.txt"
}

# -----------------------------------------------------------------------------
# Resources
# -----------------------------------------------------------------------------

# 1. Create the Lightsail Instance
resource "aws_lightsail_instance" "server" {
  name              = var.instance_name
  availability_zone = var.availability_zone
  blueprint_id      = var.blueprint_id
  bundle_id         = var.bundle_id

  # Attach the user data script
  user_data = var.user_data

  tags = {
    Name = "TerraformLightsail"
  }
}

# 2. Create the Storage Disks
# We iterate over the 'attached_disks' variable to create multiple disk resources.
resource "aws_lightsail_disk" "storage" {
  for_each = var.attached_disks

  name              = "${var.instance_name}-${each.key}"
  size_in_gb        = each.value.size_in_gb
  availability_zone = var.availability_zone # Must match the instance AZ

  tags = {
    Name = "${var.instance_name}-storage-${each.key}"
  }
}

# 3. Attach Disks to Instance
# We iterate over the created disks to attach them.
# We calculate the 'disk_path' (e.g., /dev/xvdb) dynamically based on the index.
resource "aws_lightsail_instance_disk_attachment" "attachment" {
  # We need to ensure the disks are attached in a consistent order to assign device paths correctly.
  # We convert the map keys to a list, sort them, and iterate by index.
  for_each = {
    for idx, key in sort(keys(var.attached_disks)) : 
    key => {
      disk_name = aws_lightsail_disk.storage[key].name
      index     = idx
    }
  }

  instance_name = aws_lightsail_instance.server.name
  disk_name     = each.value.disk_name

  # Calculate device path: 'b' is the second letter (after root 'a').
  # index 0 -> /dev/xvdb
  # index 1 -> /dev/xvdc
  disk_path = "/dev/xvd${chr(98 + each.value.index)}"
}

# -----------------------------------------------------------------------------
# Outputs
# -----------------------------------------------------------------------------

output "public_ip" {
  description = "The public IP address of the Lightsail instance."
  value       = aws_lightsail_instance.server.public_ip_address
}

output "disk_names" {
  description = "List of names of the created disks."
  value       = [for disk in aws_lightsail_disk.storage : disk.name]
}

output "attachment_info" {
  description = "Details of disk attachments including the calculated device path."
  value = {
    for k, v in aws_lightsail_instance_disk_attachment.attachment : k => {
      disk_name = v.disk_name
      disk_path = v.disk_path
    }
  }
}

