# 1. Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# 2. Create the S3 Bucket
resource "aws_s3_bucket" "lightsail_bucket" {
  bucket = "my-lightsail-resource-bucket-12345" # Ensure this is globally unique
}

# Set ownership controls to ensure the ACL works as expected
resource "aws_s3_bucket_ownership_controls" "lightsail_bucket_ownership" {
  bucket = aws_s3_bucket.lightsail_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# Set the ACL to private
resource "aws_s3_bucket_acl" "lightsail_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.lightsail_bucket_ownership]
  bucket     = aws_s3_bucket.lightsail_bucket.id
  acl        = "private"
}

# 3. Create the IAM Policy for S3 Access
resource "aws_iam_policy" "s3_access_policy" {
  name        = "LightsailS3AccessPolicy"
  description = "Policy granting access to the specific Lightsail S3 bucket"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:DeleteObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.lightsail_bucket.arn,
          "${aws_s3_bucket.lightsail_bucket.arn}/*"
        ]
      }
    ]
  })
}

# 4. Create the IAM Role for Lightsail
# Note: The trust relationship must allow lightsail.amazonaws.com
resource "aws_iam_role" "lightsail_role" {
  name = "LightsailS3AccessRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lightsail.amazonaws.com"
        }
      }
    ]
  })
}

# 5. Attach the Policy to the Role
resource "aws_iam_role_policy_attachment" "policy_attach" {
  role       = aws_iam_role.lightsail_role.name
  policy_arn = aws_iam_policy.s3_access_policy.arn
}

# 6. Create the Lightsail Instance
resource "aws_lightsail_instance" "app_instance" {
  name              = "lightsail-s3-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_2_0"

  # User data to verify connectivity (requires AWS CLI installed or role attached manually)
  user_data = <<-EOF
              #!/bin/bash
              # Install AWS CLI
              yum install -y aws-cli
              # The IAM Role created above needs to be attached to this instance
              # via the AWS Console (Networking -> Account -> IAM role ARN)
              # Once attached, the instance can execute: aws s3 ls ${aws_s3_bucket.lightsail_bucket.id}
              EOF

  tags = {
    Environment = "Dev"
  }
}

# Output the Bucket Name and Role ARN for reference
output "s3_bucket_name" {
  value = aws_s3_bucket.lightsail_bucket.id
}

output "iam_role_arn" {
  value = aws_iam_role.lightsail_role.arn
  description = "Attach this ARN to the Lightsail Instance in the AWS Console under Networking -> Account"
}

