      revocation_reason,
      revoked_at,
      serial,
      signature_algorithm,
      subject,
      tags,
      subject_alternative_names # AWS may reorder these during issuance
    ]
  }
}

# Outputs to reference the created certificate
output "certificate_arn" {
  description = "The Amazon Resource Name (ARN) of the certificate"
  value       = aws_lightsail_certificate.this.arn
}

output "certificate_name" {
