  name        = "my-app-distribution"
  bundle_id   = "small_1_0" # Determines the CDN bandwidth and monthly cost
  is_enabled  = true

  # Define the Origin: The Lightsail Bucket created above
  origin {
    name        = aws_lightsail.content_bucket.name # Must match the bucket name
    region_name = "us-east-1"                       # Region of the bucket
    protocol_policy = "https-only"                  # Protocol between Distribution and Origin
  }

  # Default Cache Behavior
  default_cache_behavior {
    behavior = "cache" # Options: cache, dont-cache
  }

  # Certificate configuration (Optional)
