Tomanage an AWS Lightsail Distribution using a bucket as its origin via Terraform, it is important to note a specific constraint: **AWS Lightsail Distributions (via the Terraform `aws_lightsail_distribution` resource) are designed to work natively with `aws_lightsail_bucket` resources, not standard S3 buckets (`aws_s3_bucket`).**

While Lightsail Distributions are built on CloudFront, the simplified Terraform resource does not currently support standard S3 buckets as "Custom Origins" (which would require HTTP/HTTPS configuration). Instead, you must use the Lightsail-specific bucket service, which provides object storage compatible with Lightsail Distributions.

Below is the step-by-step Terraform configuration to:
1.  Create a **Lightsail Bucket** (Object Storage).
2.  Create a **Lightsail Distribution** (CDN) pointing to that bucket.
3.  Grant the Distribution permission to access the Bucket using a resource access rule.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create a Lightsail Bucket to store the static content
# Note: Lightsail Bucket names must be globally unique.
resource "aws_lightsail_bucket" "content_bucket" {
  name      = "my-unique-content-bucket-example-123"
  bundle_id = "small_1_0" # Determines the storage capacity and monthly cost

  # Enable access logging if needed (optional)
  # access_rules {
  #   access_public = false # Default is private
  # }

  tags = {
    Name = "LightsailContentBucket"
  }
}

# 2. Create the Lightsail Distribution
resource "aws_lightsail_distribution" "cdn_distribution" {
  name        = "my-app-distribution"
  bundle_id   = "small_1_0" # Determines the CDN bandwidth and monthly cost
  is_enabled  = true

  # Define the Origin: The Lightsail Bucket created above
  origin {
    name        = aws_lightsail.content_bucket.name # Must match the bucket name
    region_name = "us-east-1"                       # Region of the bucket
    protocol_policy = "https-only"                  # Protocol between Distribution and Origin
  }

  # Default Cache Behavior
  default_cache_behavior {
    behavior = "cache" # Options: cache, dont-cache
  }

  # Certificate configuration (Optional)
  # If you have a Lightsail SSL certificate attached to this distribution
  # certificate_name = aws_lightsail_certificate.my_cert.name

  tags = {
    Name = "LightsailCDN"
  }
}

# 3. Attach the Distribution to the Bucket
# This resource grants the Lightsail Distribution permission to access 
# the private contents of the Lightsail Bucket.
resource "aws_lightsail_bucket_resource_access" "distribution_access" {
  bucket_name   = aws_lightsail_bucket.content_bucket.name
  resource_name = aws_lightsail_distribution.cdn_distribution.name
}

# Output the Distribution Domain Name
output "distribution_domain_name" {
  value = aws_lightsail_distribution.cdn_distribution.domain_name
  description = "The domain name of the Lightsail Distribution (e.g., d1234.cloudfront.net)"
}
```

