# 1. Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 2. Create a Lightsail Instance to serve as the Origin
resource "aws_lightsail_instance" "web_server" {
  name              = "origin-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_2_0"

  # User data to install and start a simple web server
  user_data = <<-EOF
              #!/bin/bash
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Successfully Served from Lightsail Instance Origin!</h1>" > /var/www/html/index.html
              EOF

  tags = {
    Name = "Lightsail-Origin-Instance"
  }
}

# 3. Create a Lightsail Distribution using the Instance as Origin
resource "aws_lightsail_distribution" "cdn" {
  name        = "my-app-distribution"
  bundle_id   = "small_1_0" # Determines the monthly cost and transfer limit
  is_enabled  = true

  # Define the Origin
  # The 'name' must match the name of the Lightsail instance exactly.
  origin {
    name            = aws_lightsail_instance.web_server.name
    region_name     = "us-east-1"
    protocol_policy = "http-only"
  }

  # Define Default Cache Behavior
  default_cache_behavior {
    target_origin_id = aws_lightsail_instance.web_server.name
    behavior         = "cache" # Can be 'cache' or 'dont-cache'
    compress         = true

    # Configure cookies forwarding
    forwarded_cookies {
      allow_no_cookies = true
    }

    # Configure headers forwarding
    forwarded_headers {
      allow_no_headers = true
    }

    # Configure query strings forwarding
    forwarded_query_strings {
      option = false
    }

    # Time to Live settings
    min_ttl     = 60
    default_ttl = 86400
    max_ttl     = 31536000
  }

  # Set the location (Region) for the distribution
  location {
    region_name = "us-east-1"
  }

  tags = {
    Name = "Lightsail-Distribution"
  }
}

