# 1. Create the S3 Bucket
resource "aws_s3_bucket" "backup_bucket" {
  bucket = "long-term-backups-${random_pet.this.id}"
}

# 2. Enable Bucket Versioning (Critical for Backups)
resource "aws_s3_bucket_versioning" "backup_bucket" {
  bucket = aws_s3_bucket.backup_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# 3. Enable Server-Side Encryption
resource "aws_s3_bucket_server_side_encryption_configuration" "backup_bucket" {
  bucket = aws_s3_bucket.backup_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# 4. Configure Lifecycle Rules for Cost-Effective Long-Term Retention
resource "aws_s3_bucket_lifecycle_configuration" "backup_bucket" {
  bucket = aws_s3_bucket.backup_bucket.id

  rule {
    id     = "long_term_retention_rule"
    status = "Enabled"

    # Transition current versions to cheaper storage tiers over time
    transition {
      days          = 30
      storage_class = "STANDARD_IA" # Infrequent Access
    }

    transition {
      days          = 90
      storage_class = "GLACIER" # Flexible Retrieval
    }

    transition {
      days          = 365
      storage_class = "DEEP_ARCHIVE" # Lowest cost for long-term retention
    }

    # Expire old non-current versions (e.g. keep backups for 7 years)
    noncurrent_version_expiration {
      noncurrent_days = 2555 # 7 years * 365 days
    }
  }
}

# 5. Block Public Access for Security
resource "aws_s3_bucket_public_access_block" "backup_bucket" {
  bucket = aws_s3_bucket.backup_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Output the Bucket Name and ARN
output "backup_bucket_name" {
  description = "The name of the S3 bucket for backups"
  value       = aws_s3_bucket.backup_bucket.id
}

output "backup_bucket_arn" {
  description = "The ARN of the S3 bucket"
  value       = aws_s3_bucket.backup_bucket.arn
