# Data source to define the access policy for the Glacier vault
data "aws_iam_policy_document" "vault_access_policy" {
  statement {
    sid    = "EnforceVaultAccess"
    effect = "Allow"

    principals {
      type        = "AWS"
      # Replace with the specific AWS Account ID or ARN that should have access
      identifiers = ["arn:aws:iam::123456789012:root"]
    }

    actions = [
      "glacier:UploadArchive",
      "glacier:DeleteArchive",
      "glacier:InitiateMultipartUpload",
      "glacier:AbortMultipartUpload",
      "glacier:CompleteMultipartUpload"
    ]

    resources = [
      aws_glacier_vault.example.arn
    ]
  }

  # A typical WORM (Write Once Read Many) compliance statement might look like this
  # depending on specific governance requirements, but the above grants access.
  statement {
    sid    = "DenyDeleteWithoutRetention"
    effect = "Deny"

    principals {
      type        = "*"
      identifiers = ["*"]
    }

    actions = [
      "glacier:DeleteArchive"
    ]

    resources = [
      aws_glacier_vault.example.arn
    ]

    condition {
      test     = "StringNotLike"
      variable = "glacier:ArchiveRetentionPeriod"
      values   = ["365"] # Example: Require a minimum retention of 365 days
    }
  }
}

