# Provider configuration
provider "aws" {
  region = "us-east-1"
}

# Data source to define the access policy for the Glacier vault
data "aws_iam_policy_document" "vault_access_policy" {
  statement {
    sid    = "EnforceVaultAccess"
    effect = "Allow"

    principals {
      type        = "AWS"
      # Replace with the specific AWS Account ID or ARN that should have access
      identifiers = ["arn:aws:iam::123456789012:root"]
    }

    actions = [
      "glacier:UploadArchive",
      "glacier:DeleteArchive",
      "glacier:InitiateMultipartUpload",
      "glacier:AbortMultipartUpload",
      "glacier:CompleteMultipartUpload"
    ]

    resources = [
      aws_glacier_vault.example.arn
    ]
  }

  # A typical WORM (Write Once Read Many) compliance statement might look like this
  # depending on specific governance requirements, but the above grants access.
  statement {
    sid    = "DenyDeleteWithoutRetention"
    effect = "Deny"

    principals {
      type        = "*"
      identifiers = ["*"]
    }

    actions = [
      "glacier:DeleteArchive"
    ]

    resources = [
      aws_glacier_vault.example.arn
    ]

    condition {
      test     = "StringNotLike"
      variable = "glacier:ArchiveRetentionPeriod"
      values   = ["365"] # Example: Require a minimum retention of 365 days
    }
  }
}

# Resource: S3 Glacier Vault
resource "aws_glacier_vault" "example" {
  name = "my-glacier-vault"

  # Optional: Define tags
  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

# Resource: Glacier Vault Lock to enforce the access policy
# This implements a "Write Once Read Many" (WORM) model by locking the policy
resource "aws_glacier_vault_lock" "example" {
  complete_lock = true # Set to false to test the policy before permanent enforcement

  # The policy JSON comes from the data source defined above
  policy = data.aws_iam_policy_document.vault_access_policy.json

  vault_name = aws_glacier_vault.example.name

  # Ignore deletion errors is useful if the vault is locked and Terraform 
  # attempts to destroy it, as a locked policy cannot be deleted.
  ignore_deletion_error = true
}
```

