response:
To create an AWS Application Load Balancer (ALB), we need to configure several resources to make it functional:

1.  **AWS Provider**: To interact with AWS resources.
2.  **VPC and Subnet Variables**: Since an ALB requires at least two subnets in different Availability Zones, we will define variables for `vpc_id` and `subnet_ids` to make the configuration reusable.
3.  **Security Group**: To allow inbound traffic (typically HTTP on port 80) to the load balancer.
4.  **ALB Resource (`aws_lb`)**: The load balancer itself, configured as `application` type.
5.  **Target Group (`aws_lb_target_group`)**: Defines the destination for the traffic (e.g., instances or IPs).
6.  **Listener (`aws_lb_listener`)**: Listens for traffic on a specific port (e.g., 80) and forwards it to the target group.

Here is the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Variable for VPC ID (required for the Security Group and Target Group)
variable "vpc_id" {
  description = "The ID of the VPC where the ALB will be created"
  type        = string
  default     = "vpc-0a1b2c3d4e5f6g7h8" # Replace with your actual VPC ID
}

# Variable for Subnet IDs (ALBs require at least two subnets in different AZs)
variable "subnet_ids" {
  description = "A list of subnet IDs to attach to the ALB"
  type        = list(string)
  default     = [
    "subnet-0123456789abcdef0", # Replace with Subnet A ID
    "subnet-0abcdef0123456789"  # Replace with Subnet B ID
  ]
}

# 1. Security Group for the ALB
resource "aws_security_group" "alb_sg" {
  name        = "alb-security-group"
  description = "Security group for the Application Load Balancer"
  vpc_id      = var.vpc_id

  ingress {
    description = "HTTP from anywhere"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "alb-sg"
  }
}

# 2. Application Load Balancer
resource "aws_lb" "app_lb" {
  name               = "my-application-load-balancer"
  internal           = false # Set to true for an internal ALB
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = var.subnet_ids

  enable_deletion_protection = false
  enable_http2               = true

  tags = {
    Environment = "dev"
    Name        = "my-app-alb"
  }
}

# 3. Target Group (Where traffic is routed to)
resource "aws_lb_target_group" "app_tg" {
  name        = "app-target-group"
  port        = 80
  protocol    = "HTTP"
  vpc_id      = var.vpc_id
  target_type = "instance"

  health_check {
    enabled             = true
    path                = "/"
    protocol            = "HTTP"
    matcher             = "200"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 5
    unhealthy_threshold = 2
  }
}

# 4. Listener (Accepts traffic and forwards to Target Group)
resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.app_lb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.app_tg.arn
  }
}

# Outputs
output "alb_dns_name" {
  description = "The DNS name of the load balancer"
  value       = aws_lb.app_lb.dns_name
}

output "alb_arn" {
  description = "The ARN of the load balancer"
  value       = aws_lb.app_lb.arn
}
```

