provider "aws" {
  region = "us-east-1"
}

# 1. Create VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "nlb-vpc"
  }
}

# 2. Retrieve available Availability Zones
data "aws_availability_zones" "available" {
  state = "available"
}

# 3. Create Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "nlb-igw"
  }
}

# 4. Create Public Subnets
# An internet-facing NLB requires subnets in at least two Availability Zones.
resource "aws_subnet" "public" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "nlb-public-subnet-${count.index}"
  }
}

# 5. Create Route Table
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "nlb-public-rt"
  }
}

# 6. Associate Route Table with Subnets
resource "aws_route_table_association" "public" {
  count          = 2
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

# 7. Create Network Load Balancer
resource "aws_lb" "network" {
  name               = "my-network-lb"
  internal           = false # Set to true for internal load balancer
  load_balancer_type = "network"
  subnets            = aws_subnet.public[*].id

  enable_deletion_protection = false

  tags = {
    Environment = "production"
  }
}

# 8. Create Target Group
# NLBs target groups support instance, ip, or lambda IDs.
resource "aws_lb_target_group" "network" {
  name        = "my-tg-nlb-tcp"
  port        = 80
  protocol    = "TCP"
  vpc_id      = aws_vpc.main.id
  target_type = "instance"

  health_check {
    protocol = "TCP"
  }
}

# 9. Create Listener
