  load_balancer_arn = aws_lb.network.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.network.arn
  }
}

# Output the DNS name of the Load Balancer
output "lb_dns_name" {
  value = aws_lb.network.dns_name
}

