# Step 1: Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Step 2: Create a VPC and Subnets to host the Load Balancer
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "lb-vpc"
  }
}

resource "aws_subnet" "public_1" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-1"
  }
}

resource "aws_subnet" "public_2" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-2"
  }
}

# Step 3: Allocate the Specific Elastic IP Addresses
resource "aws_eip" "lb_eip_1" {
  domain = "vpc"

  tags = {
    Name = "lb-eip-1"
  }
}

resource "aws_eip" "lb_eip_2" {
  domain = "vpc"

  tags = {
    Name = "lb-eip-2"
  }
}

# Step 4: Create the Network Load Balancer
# Note: We use 'network' type because it allows static IP (Elastic IP) assignment.
# The 'subnet_mapping' block is where we explicitly assign the Allocation IDs of the EIPs.
resource "aws_lb" "network_lb" {
  name               = "ip-based-nlb"
  internal           = false
  load_balancer_type = "network"
  subnets            = [aws_subnet.public_1.id, aws_subnet.public_2.id]

  subnet_mapping {
    subnet_id     = aws_subnet.public_1.id
    allocation_id = aws_eip.lb_eip_1.id
  }

  subnet_mapping {
    subnet_id     = aws_subnet.public_2.id
    allocation_id = aws_eip.lb_eip_2.id
  }

  enable_deletion_protection = false

  tags = {
    Name = "network-load-balancer"
  }
}

# Step 5: Create a Target Group for the Load Balancer
resource "aws_lb_target_group" "main" {
  name        = "tg-tcp-80"
  port        = 80
  protocol    = "TCP"
  vpc_id      = aws_vpc.main.id
  target_type = "instance"

  health_check {
    port = 80
  }
}

# Step 6: Create a Listener to forward traffic to the Target Group
resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.network_lb.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.main.arn
  }
}

# Step 7: Outputs to verify the IPs and DNS Name
output "load_balancer_dns_name" {
  value = aws_lb.network_lb.dns_name
}

output "allocated_eip_1" {
  value = aws_eip.lb_eip_1.public_ip
}

output "allocated_eip_2" {
  value = aws_eip.lb_eip_2.public_ip
}

