response:
Here is the Terraform configuration to create an internal Network Load Balancer (NLB) on AWS with specific private IP addresses.

**Step-by-Step Logic:**
1.  **Provider:** Configure the AWS provider.
2.  **VPC:** Create a Virtual Private Cloud to host the resources.
3.  **Subnets:** Create two subnets in different Availability Zones. An internal load balancer typically requires at least two subnets for high availability.
4.  **Load Balancer:** Create an `aws_lb` resource.
    *   Set `internal` to `true` to ensure it is not accessible from the public internet.
    *   Set `load_balancer_type` to `network`. (Network Load Balancers are required to assign specific private IP addresses; Application Load Balancers manage IPs dynamically).
    *   Use `subnet_mapping` blocks instead of the simple `subnets` list. This allows us to explicitly define the `private_ipv4_address` for the load balancer in each subnet.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "internal-lb-vpc"
  }
}

# 2. Create two subnets in different Availability Zones
resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "internal-lb-subnet-a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "internal-lb-subnet-b"
  }
}

# 3. Create an Internal Network Load Balancer with Specific Private IPs
resource "aws_lb" "internal_lb" {
  name               = "internal-static-ip-lb"
  internal           = true
  load_balancer_type = "network"
  subnets            = [] # Subnets are defined in subnet_mapping for static IPs

  # Define specific private IP addresses for each subnet
  subnet_mapping {
    subnet_id            = aws_subnet.subnet_a.id
    private_ipv4_address = "10.0.1.50"
  }

  subnet_mapping {
    subnet_id            = aws_subnet.subnet_b.id
    private_ipv4_address = "10.0.2.50"
  }

  tags = {
    Environment = "Internal"
  }
}

# Output the Load Balancer DNS Name and specific IPs
output "lb_dns_name" {
  value = aws_lb.internal_lb.dns_name
}

output "lb_private_ips" {
  value = [
    "10.0.1.50",
    "10.0.2.50"
  ]
  description = "The specific private IP addresses assigned to the Load Balancer"
}
