  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = aws_subnet.public[*].id

  tags = {
    Environment = "dev"
  }
}

# 4. Create Listener with Redirect Action
# This listens on Port 80 (HTTP) and redirects to Port 443 (HTTPS)
