}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"

  name = "main-vpc"
  cidr = "10.0.0.0/16"

  azs                  = data.aws_availability_zones.available.names
  public_subnets       = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]
}

data "aws_ami" "ubuntu" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["*ubuntu-noble-24.04-amd64-server-*"]
  }
}

resource "aws_security_group" "instance-sg" {
  name = "instance-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "instance-sg-ingress-rule" {
  from_port       = 80
  to_port         = 80
  ip_protocol     = "tcp"
  referenced_security_group_id = aws_security_group.lb-sg.id
  security_group_id = aws_security_group.instance-sg.id
}

resource "aws_vpc_security_group_egress_rule" "instance-sg-egress-rule" {
  from_port       = 0
  to_port         = 0
  ip_protocol     = "-1"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.instance-sg.id
}

resource "aws_security_group" "lb-sg" {
  name = "lb-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "lb-sg-ingress-rule" {
  from_port   = 80
  to_port     = 80
  ip_protocol = "tcp"
  cidr_ipv4   = "0.0.0.0/0"
  security_group_id = aws_security_group.lb-sg.id
}

resource "aws_vpc_security_group_egress_rule" "lb-sg-egress-rule" {
  from_port   = 0
  to_port     = 0
  ip_protocol = "-1"
  cidr_ipv4   = "0.0.0.0/0"
  security_group_id = aws_security_group.lb-sg.id
}


resource "aws_instance" "my_instance" {
  ami           = data.aws_ami.ubuntu.id
  instance_type = "t2.micro"
  subnet_id     = module.vpc.public_subnets[0]
  security_groups = [ aws_security_group.instance-sg.id ]
}

resource "aws_lb" "test" {
  subnets            = module.vpc.public_subnets
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb-sg.id]
}

resource "aws_lb_listener" "my_listener" {
  load_balancer_arn = aws_lb.test.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type = "authenticate-oidc"

  authenticate_oidc {
      authorization_endpoint = "https://example.com/authorization_endpoint"
      client_id              = "client_id"
      client_secret          = "client_secret"
      issuer                 = "https://example.com"
      token_endpoint         = "https://example.com/token_endpoint"
      user_info_endpoint     = "https://example.com/user_info_endpoint"
    }
  }

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.target_group.arn
  }
}

resource "aws_lb_target_group" "target_group" {
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id
}

resource "aws_lb_target_group_attachment" "ec2_attach" {
  target_group_arn = aws_lb_target_group.target_group.arn
  target_id = aws_instance.my_instance.id
}

response:
Here is the step-by-step thought process to generate the Terraform configuration:

1.  **Identify the Cloud Provider and Resource Type:** The request asks for a "Load Balancer" with an "Authenticate-OIDC action." This specific terminology (Authenticate-OIDC Action) is a feature specific to **AWS Application Load Balancers (ALB)**. Therefore, we will use the `aws` provider.

2.  **Determine the Required Infrastructure Components:** To deploy a functional ALB with an OIDC action, we need the following resources:
    *   **VPC and Subnets:** An ALB requires a VPC and at least two subnets in different Availability Zones.
    *   **Security Group:** To control traffic to the Load Balancer (allowing HTTP/HTTPS).
    *   **Application Load Balancer (ALB):** The main load balancing resource.
    *   **Target Group:** Defines where the load balancer sends traffic (e.g., EC2 instances).
    *   **Listener:** Listens for traffic on a specific port (e.g., 80 or 443).
    *   **Listener Rule:** This is where the `authenticate-oidc` action is defined.

3.  **Configure the OIDC Action (The Core Requirement):**
    *   The OIDC action must be defined within the `action` block of an `aws_lb_listener_rule`.
    *   It requires specific parameters: `authorization_endpoint`, `client_id`, `client_secret`, `issuer`, `token_endpoint`, and `user_info_endpoint`.
    *   Since OIDC providers (like Auth0, Okta, or Cognito) vary, I will define these as variables to make the configuration reusable.

4.  **Construct the Terraform Code:**
    *   *Provider Block:* Standard AWS configuration.
    *   *Variables Block:* Define inputs for OIDC settings and VPC CIDR.
    *   *Network Resources:* Create `aws_vpc`, `aws_subnet`, and `aws_internet_gateway` (to make the LB internet-facing).
    *   *Security Group:* Create `aws_security_group` allowing port 80.
    *   *Load Balancer Resources:* Create `aws_lb`, `aws_lb_target_group`, and `aws_lb_listener`.
    *   *Listener Rule:* Create `aws_lb_listener_rule` with two actions:
        1.  `type = "authenticate-oidc"`: Handles the authentication.
        2.  `type = "forward"`: Forwards traffic to the target group upon successful auth.

5.  **Review and Refine:** Ensure all dependencies (ARNs, IDs) are correctly referenced. Ensure the code is contained within a single HCL block as requested.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ---------------------------------------------------------
# Variables for OIDC Configuration
# ---------------------------------------------------------
variable "oidc_config" {
  description = "Configuration for the OIDC Provider"
  type = object({
    authorization_endpoint = string
    token_endpoint         = string
    user_info_endpoint     = string
    client_id              = string
    client_secret          = string
    issuer                 = string
  })
  default = {
    # Placeholder values - replace with your actual OIDC provider (e.g., Auth0, Okta, Cognito)
    authorization_endpoint = "https://example-provider.com/oauth2/authorize"
    token_endpoint         = "https://example-provider.com/oauth2/token"
    user_info_endpoint     = "https://example-provider.com/oauth2/userinfo"
    client_id              = "your-client-id"
    client_secret          = "your-client-secret"
    issuer                 = "https://example-provider.com"
  }
}

# ---------------------------------------------------------
# Network Infrastructure (VPC & Subnets)
# ---------------------------------------------------------
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "alb-oidc-vpc"
  }
}

resource "aws_subnet" "public" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = true

  tags = {
    Name = "alb-subnet-${count.index}"
  }
}

data "aws_availability_zones" "available" {}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "alb-igw"
  }
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "public-rt"
  }
}

resource "aws_route_table_association" "public_assoc" {
  count          = 2
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

# ---------------------------------------------------------
# Security Group
# ---------------------------------------------------------
resource "aws_security_group" "alb_sg" {
  name        = "alb-sg"
  description = "Allow HTTP inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "HTTP from world"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "alb-sg"
  }
}

# ---------------------------------------------------------
# Load Balancer Resources
# ---------------------------------------------------------
resource "aws_lb" "front_end" {
  name               = "oidc-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = aws_subnet.public[*].id

  tags = {
    Environment = "production"
  }
}

resource "aws_lb_target_group" "app" {
  name     = "app-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id
}

resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.front_end.arn
  port              = "80"
  protocol          = "HTTP"

  # Default action if no rules match (e.g., 404 or redirect)
  default_action {
    type = "fixed-response"

    fixed_response {
      content_type = "text/plain"
      message_body = "404 - Not Found"
      status_code  = "404"
    }
  }
}

# ---------------------------------------------------------
# OIDC Authentication Listener Rule
# ---------------------------------------------------------
resource "aws_lb_listener_rule" "oidc_auth_rule" {
  listener_arn = aws_lb_listener.front_end.arn
  priority     = 100

  action {
    type = "authenticate-oidc"

    authenticate_oidc {
      authorization_endpoint = var.oidc_config.authorization_endpoint
      client_id              = var.oidc_config.client_id
      client_secret          = var.oidc_config.client_secret
      issuer                 = var.oidc_config.issuer
      token_endpoint         = var.oidc_config.token_endpoint
      user_info_endpoint     = var.oidc_config.user_info_endpoint

      # Optional: Cookie settings
      session_timeout = 86400
    }
  }

  action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.app.arn
  }

  condition {
    path_pattern {
      values = ["/secure/*"]
    }
  }
}

# ---------------------------------------------------------
# Outputs
# ---------------------------------------------------------
output "lb_dns_name" {
  value = aws_lb.front_end.dns_name
  description = "DNS name of the Load Balancer"
}
```

