response:
To create a Gateway Load Balancer (GWLB) on AWS, we need to follow these logical steps:

1.  **Provider Configuration**: Configure the AWS provider.
2.  **Networking (VPC & Subnets)**: GWLB requires a VPC and at least two subnets in different Availability Zones to ensure high availability.
3.  **Gateway Load Balancer**: Create the load balancer resource of type `gateway`.
4.  **Target Group**: Create a target group. Note that GWLB specifically requires the protocol to be `GENEVE` (usually on port 6081).
5.  **Listener**: Create a listener to accept traffic (Protocol `GENEVE`) and forward it to the target group.
6.  **Outputs**: Output the DNS name of the load balancer so it can be used.

Here is the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC to house the infrastructure
resource "aws_vpc" "gwlbe_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "gwlbe-vpc"
  }
}

# 2. Create two subnets in different Availability Zones (Required for GWLB)
resource "aws_subnet" "gwlbe_subnet_1" {
  vpc_id            = aws_vpc.gwlbe_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "gwlbe-subnet-1"
  }
}

resource "aws_subnet" "gwlbe_subnet_2" {
  vpc_id            = aws_vpc.gwlbe_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "gwlbe-subnet-2"
  }
}

# 3. Create the Gateway Load Balancer
resource "aws_lb" "gwlbe" {
  name               = "my-gateway-load-balancer"
  load_balancer_type = "gateway"
  subnets            = [aws_subnet.gwlbe_subnet_1.id, aws_subnet.gwlbe_subnet_2.id]

  tags = {
    Environment = "production"
  }
}

# 4. Create a Target Group (Protocol must be GENEVE)
resource "aws_lb_target_group" "gwlbe_tg" {
  name        = "my-gwlbe-target-group"
  port        = 6081
  protocol    = "GENEVE"
  vpc_id      = aws_vpc.gwlbe_vpc.id
  target_type = "ip" # "ip" is common for appliances, "instance" is also supported

  health_check {
    enabled             = true
    port                = 80
    protocol            = "TCP"
    interval            = 30
    healthy_threshold   = 3
    unhealthy_threshold = 3
  }
}

# 5. Create a Listener (Protocol must be GENEVE)
resource "aws_lb_listener" "gwlbe_listener" {
  load_balancer_arn = aws_lb.gwlbe.arn
  port              = 6081
  protocol          = "GENEVE"

  default_action {
