# Step 1: Configure the AWS Provider
provider "aws" {
  region = var.aws_region
}

# Step 2: Create a random password for the database
# This avoids hardcoding sensitive credentials in the code
resource "random_password" "db_password" {
  length  = 16
  special = true
}

# Step 3: Create Networking Components (VPC and Subnets)
# A simple VPC is required to host the RDS instance
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "terraform-sql-db-vpc"
  }
}

# Create two subnets in different Availability Zones (Required for RDS)
resource "aws_subnet" "subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = element(["us-east-1a", "us-east-1b"], count.index) # Adjust AZs based on your region
  map_public_ip_on_launch = false # Private subnets for the database

  tags = {
    Name = "db-subnet-${count.index}"
  }
}

# Step 4: Create a DB Subnet Group
# RDS requires a subnet group to span multiple AZs
resource "aws_db_subnet_group" "default" {
  name       = "main-db-subnet-group"
  subnet_ids = aws_subnet.subnets[*].id

  tags = {
    Name = "My DB subnet group"
  }
}

# Step 5: Create a Security Group
# Allows access to the database port (3306 for MySQL)
resource "aws_security_group" "db_access" {
  name        = "db-security-group"
  description = "Allow access to the database"
  vpc_id      = aws_vpc.main.id

  # Inbound rule for MySQL (adjust CIDR as needed for security)
  ingress {
    from_port   = 3306
    to_port     = 3306
