# Step 3: Security Group
# Allow access to the PostgreSQL port (5432).
# ---------------------------------------------------------

resource "aws_security_group" "postgres_sg" {
  name_prefix = "postgres-sg-"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # WARNING: Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "PostgreSQL Security Group"
  }
}

# ---------------------------------------------------------
# Step 4: RDS Instance
# Create the PostgreSQL instance using db.t4g.large.
# ---------------------------------------------------------

resource "aws_db_instance" "postgres" {
  identifier             = "tf-postgres-instance"
  engine                 = "postgres"
  engine_version         = "15.4" # Ensure version is compatible with ARM
  instance_class         = "db.t4g.large"
  allocated_storage      = 20
  storage_type           = "gp2"
  storage_encrypted      = true # Best practice

  # Database Credentials
  db_name                = "mydb"
  username               = "adminuser"
  password               = "ChangeMePlease123!" # Should use a variable/secret in production

  # Networking
  db_subnet_group_name   = aws_db_subnet_group.postgres_subnet_group.name
  vpc_security_group_ids = [aws_security_group.postgres_sg.id]

  # Availability and Backup
  publicly_accessible    = true # Set to false for production
  skip_final_snapshot    = true # Set to false for production to retain data on delete
  multi_az               = false # Set to true for High Availability

  tags = {
    Name = "PostgreSQL-T4G-Large"
  }
}

response:
Here is the step-by-step reasoning followed by the Terraform configuration.

1.  **Provider Configuration**: We need to configure the AWS provider to interact with AWS resources.
2.  **Networking (VPC & Subnets)**: An RDS instance cannot exist in isolation; it requires a VPC and subnets. To make this code portable without creating a complex VPC from scratch, we will use `data` sources to fetch the **Default VPC** and **Default Subnets** in the selected region.
3.  **DB Subnet Group**: We will create an `aws_db_subnet_group` resource. This is mandatory for RDS instances and tells AWS which subnets to place the database in. We will select two subnets from the default VPC to satisfy the availability zone redundancy requirement.
4.  **Security Group**: We will create an `aws_security_group` to control traffic. We will allow ingress on port 5432 (default PostgreSQL port) so we can connect to the database.
5.  **RDS Instance**: Finally, we will create the `aws_db_instance` resource with the specific requirements:
    *   `engine`: "postgres"
    *   `instance_class`: "db.t4g.large" (as requested).
    *   `allocated_storage`: 20 GB (standard minimum).
    *   `username`/`password`: Credentials for the database.
    *   `skip_final_snapshot`: Set to `true` for this example to allow the instance to be destroyed immediately without waiting for a backup snapshot (useful for testing).

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Change this to your preferred region
}

# ---------------------------------------------------------
# Step 1: Networking Setup
# Fetch the Default VPC and Subnets to keep this example standalone.
# ---------------------------------------------------------

data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# ---------------------------------------------------------
# Step 2: DB Subnet Group
# Define which subnets the database can reside in.
# ---------------------------------------------------------

resource "aws_db_subnet_group" "postgres_subnet_group" {
  name       = "tf-postgres-subnet-group"
  subnet_ids = slice(data.aws_subnets.default.ids, 0, 2)

  tags = {
    Name = "Terraform Postgres Subnet Group"
  }
}

# ---------------------------------------------------------
# Step 3: Security Group
# Allow access to the PostgreSQL port (5432).
# ---------------------------------------------------------

resource "aws_security_group" "postgres_sg" {
  name_prefix = "postgres-sg-"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # WARNING: Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "PostgreSQL Security Group"
  }
}

# ---------------------------------------------------------
# Step 4: RDS Instance
# Create the PostgreSQL instance using db.t4g.large.
# ---------------------------------------------------------

resource "aws_db_instance" "postgres" {
  identifier             = "tf-postgres-instance"
  engine                 = "postgres"
  engine_version         = "15.4" # Ensure version is compatible with ARM
  instance_class         = "db.t4g.large"
  allocated_storage      = 20
  storage_type           = "gp2"
  storage_encrypted      = true # Best practice

  # Database Credentials
  db_name                = "mydb"
  username               = "adminuser"
  password               = "ChangeMePlease123!" # Should use a variable/secret in production

  # Networking
  db_subnet_group_name   = aws_db_subnet_group.postgres_subnet_group.name
  vpc_security_group_ids = [aws_security_group.postgres_sg.id]

  # Availability and Backup
  publicly_accessible    = true # Set to false for production
  skip_final_snapshot    = true # Set to false for production to retain data on delete
  multi_az               = false # Set to true for High Availability

  tags = {
    Name = "PostgreSQL-T4G-Large"
  }
}
