  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "minimal-postgres-subnet-${count.index + 1}"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "minimal-postgres-igw"
  }
}

resource "aws_route_table" "rt" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "minimal-postgres-rt"
  }
}

resource "aws_route_table_association" "rta" {
  count          = 2
  subnet_id      = aws_subnet.subnets[count.index].id
  route_table_id = aws_route_table.rt.id
}

data "aws_availability_zones" "available" {
  state = "available"
}

# ------------------------------------------------------------------------------
# Security Group
# ------------------------------------------------------------------------------

resource "aws_security_group" "postgres_sg" {
  name        = "minimal-postgres-sg"
  description = "Allow PostgreSQL inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL from VPC"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "minimal-postgres-sg"
  }
}

# ------------------------------------------------------------------------------
# RDS Parameter Group (Optimized for Minimal Memory)
# ------------------------------------------------------------------------------

resource "aws_db_parameter_group" "minimal_memory_pg" {
  name        = "minimal-postgres-pg"
  family      = "postgres14"
  description = "Parameter group optimized for minimal memory usage (t3.micro)"

  # Settings optimized for a db.t3.micro (1GB RAM)
  parameter {
    name  = "shared_buffers"
    value = "128MB" # Lowered from default to save RAM
  }

  parameter {
    name  = "effective_cache_size"
    value = "256MB" # Assumes half of RAM is available for cache
  }

  parameter {
    name  = "work_mem"
    value = "2048kB" # Reduced per-operation memory
  }

  parameter {
    name  = "maintenance_work_mem"
    value = "32MB" # Reduced maintenance memory
  }

  parameter {
    name  = "max_connections"
    value = "50" # Lowered to prevent OOM on small instances
  }

  parameter {
    name  = "checkpoint_completion_target"
    value = "0.7"
  }

  parameter {
    name  = "wal_buffers"
    value = "1024kB"
  }

  parameter {
    name  = "random_page_cost"
    value = "1.1" # Optimized for SSD (gp3)
  }
}

# ------------------------------------------------------------------------------
# RDS Instance
# ------------------------------------------------------------------------------

resource "aws_db_subnet_group" "default" {
