  subnet_ids = aws_subnet.subnets[*].id

  tags = {
    Name = "Minimal Postgres Subnet Group"
  }
}

resource "aws_db_instance" "postgres" {
  identifier             = "minimal-postgres-instance"
  engine                 = "postgres"
  engine_version         = "14.11"
  instance_class         = "db.t3.micro" # Smallest instance class
  allocated_storage      = 20
  storage_type           = "gp3"
  storage_encrypted      = false
  db_name                = "minimaldb"
  username               = var.db_username
  password               = var.db_password

  db_subnet_group_name   = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.postgres_sg.id]
  parameter_group_name   = aws_db_parameter_group.minimal_memory_pg.name

  multi_az               = false # Disabled to minimize resource usage
  publicly_accessible    = true  # Set to false for production
  skip_final_snapshot    = true
  deletion_protection    = false

  tags = {
    Name = "MinimalPostgresInstance"
  }
}

# ------------------------------------------------------------------------------
# Variables
# ------------------------------------------------------------------------------

variable "db_username" {
  description = "The master username for the database"
  type        = string
  default     = "postgres_admin"
  sensitive   = true
}

variable "db_password" {
  description = "The master password for the database"
  type        = string
  sensitive   = true
}

# ------------------------------------------------------------------------------
# Outputs
# ------------------------------------------------------------------------------

output "db_endpoint" {
  description = "The connection endpoint"
  value       = aws_db_instance.postgres.endpoint
}

