  region = "us-east-1"
}

# ---------------------------------------------------------
# 1. Networking Setup
# ---------------------------------------------------------

# Create a VPC to host the database
resource "aws_vpc" "db_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "sql-db-vpc"
  }
}

# Create two subnets in different Availability Zones for the RDS Subnet Group
resource "aws_subnet" "db_subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.db_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.db_vpc.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false

  tags = {
    Name = "sql-db-subnet-${count.index + 1}"
  }
}

# Data source to get available AZs
data "aws_availability_zones" "available" {
  state = "available"
}

# Create a DB Subnet Group (Required for RDS)
resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "sql-db-subnet-group"
  subnet_ids = aws_subnet.db_subnets[*].id

  tags = {
    Name = "My DB Subnet Group"
  }
}

# Security Group to allow access to the database
resource "aws_security_group" "db_sg" {
  name        = "sql-db-security-group"
  description = "Allow MySQL inbound traffic"
  vpc_id      = aws_vpc.db_vpc.id

  # Inbound rule for MySQL (default port 3306)
  # NOTE: In production, restrict the cidr_blocks to specific IPs.
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "sql-db-sg"
  }
}

# ---------------------------------------------------------
# 2. Security (Password Generation)
# ---------------------------------------------------------

resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "_!%@" # Avoid characters that can cause shell issues
}

# ---------------------------------------------------------
# 3. Primary Database Instance
# ---------------------------------------------------------

resource "aws_db_instance" "primary" {
  identifier             = "sql-db-primary"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_encrypted      = true

  # Credentials
  username               = "adminuser"
  password               = random_password.db_password.result

  # Networking
  db_subnet_group_name   = aws_db_subnet_group.db_subnet_group.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  publicly_accessible    = false
  multi_az               = false # Set to false as we are creating a manual replica resource

  # Maintenance & Backup
  backup_retention_period = 7
  skip_final_snapshot    = true # Set to true for easy destroy (false in prod)
  final_snapshot_identifier = "sql-db-primary-final-snapshot"

  tags = {
    Name = "SQL-DB-Primary"
  }
}

# ---------------------------------------------------------
# 4. Replica Database Instance
# ---------------------------------------------------------

resource "aws_db_instance" "replica" {
  identifier             = "sql-db-replica"
  instance_class         = "db.t3.micro"

  # This links the instance to the primary for replication
  replicate_source_db    = aws_db_instance.primary.identifier

  # Networking (Must be in the same VPC/Subnet group as source)
  db_subnet_group_name   = aws_db_subnet_group.db_subnet_group.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  publicly_accessible    = false

  # Maintenance
  skip_final_snapshot    = true
  final_snapshot_identifier = "sql-db-replica-final-snapshot"

  # Ensure replica is created only after primary is available
  depends_on = [aws_db_instance.primary]

  tags = {
    Name = "SQL-DB-Replica"
  }
}

# ---------------------------------------------------------
# Outputs
# ---------------------------------------------------------

output "primary_endpoint" {
  description = "Endpoint of the Primary Database"
  value       = aws_db_instance.primary.endpoint
}

output "replica_endpoint" {
  description = "Endpoint of the Replica Database"
  value       = aws_db_instance.replica.endpoint
}

output "db_username" {
  description = "Database admin username"
  value       = aws_db_instance.primary.username
  sensitive   = true
}

output "db_password" {
  description = "Database admin password"
  value       = random_password.db_password.result
  sensitive   = true
}

