terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

# -----------------------------------------------------------------------------
# Variables
# -----------------------------------------------------------------------------

variable "aws_region" {
  description = "The AWS region where the RDS instance will be launched"
  default     = "us-east-1"
}

variable "db_identifier" {
  description = "The identifier for the new RDS instance"
  default     = "restored-db-instance"
}

variable "snapshot_identifier" {
  description = "The identifier of the existing snapshot to restore from"
  type        = string
}

variable "db_engine" {
  description = "The database engine (e.g., mysql, postgres). This must match the engine of the snapshot."
  type        = string
  default     = "mysql"
}

variable "instance_class" {
  description = "The instance type of the RDS instance"
  default     = "db.t3.micro"
}

variable "allocated_storage" {
  description = "The allocated storage size in GB. If not specified, defaults to the snapshot size."
  type        = number
  default     = null
}

variable "db_subnet_group_name" {
  description = "The name of the DB subnet group to use for the instance"
  type        = string
  default     = null
}

variable "vpc_security_group_ids" {
  description = "A list of VPC security group IDs to associate with the instance"
  type        = list(string)
  default     = null
}

# -----------------------------------------------------------------------------
# Resources
# -----------------------------------------------------------------------------

resource "aws_db_instance_from_snapshot" "this" {
  # Required Arguments
  identifier          = var.db_identifier
  snapshot_identifier = var.snapshot_identifier
  instance_class      = var.instance_class
  engine              = var.db_engine

  # Optional Storage Configuration
  # If left null, storage size and type are inherited from the snapshot
  allocated_storage = var.allocated_storage
  # storage_type      = "gp2" # Uncomment to override snapshot storage type

  # Networking
  # If null, defaults to the default VPC in the region (if one exists)
  db_subnet_group_name   = var.db_subnet_group_name
  vpc_security_group_ids = var.vpc_security_group_ids

  # Backup & Maintenance
  backup_retention_period = 0  # Set to 0 for dev/test, higher for prod
  skip_final_snapshot     = false
  final_snapshot_identifier = "${var.db_identifier}-final-snapshot"

  # Username and password are inherited from the snapshot, 
  # but can be explicitly set here if you want to reset them.
  # username = "admin"
  # password = "changeme"

  tags = {
    Name        = var.db_identifier
    RestoredFrom = var.snapshot_identifier
    ManagedBy   = "Terraform"
  }
}

# -----------------------------------------------------------------------------
# Outputs
# -----------------------------------------------------------------------------

output "db_instance_endpoint" {
  description = "The connection endpoint for the restored RDS instance"
  value       = aws_db_instance_from_snapshot.this.endpoint
}

output "db_instance_id" {
  description = "The ID of the restored RDS instance"
  value       = aws_db_instance_from_snapshot.this.id
}

