  description = "The version of the source database that created the backup (e.g., 5.7, 8.0)"
  default     = "5.7"
  type        = string
}

# ---------------------------------------------------------
# Data Sources: Networking
# ---------------------------------------------------------

# Fetch the default VPC
data "aws_vpc" "default" {
  default = true
}

# Fetch subnets in the default VPC to create the DB Subnet Group
data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# ---------------------------------------------------------
# IAM Resources for S3 Import
# ---------------------------------------------------------

# IAM Role that RDS will assume to access S3
resource "aws_iam_role" "rds_s3_import_role" {
  name = "rds-s3-import-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy allowing RDS to read the specific S3 bucket
resource "aws_iam_role_policy" "rds_s3_access_policy" {
  name = "rds-s3-read-access"
  role = aws_iam_role.rds_s3_import_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:ListBucket",
          "s3:GetObject"
        ]
        Resource = [
          "arn:aws:s3:::${var.s3_bucket_name}",
          "arn:aws:s3:::${var.s3_bucket_name}/*"
        ]
      }
    ]
  })
}

# Attach the AWS managed policy required for S3 import enhancements (optional but recommended)
resource "aws_iam_role_policy_attachment" "rds_s3_import_attachment" {
  role       = aws_iam_role.rds_s3_import_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# ---------------------------------------------------------
# Networking Resources
# ---------------------------------------------------------

# DB Subnet Group (Required for RDS in VPC)
resource "aws_db_subnet_group" "default" {
  name       = "default-db-subnet-group"
  subnet_ids = data.aws_subnets.default.ids

  tags = {
    Name = "My DB Subnet Group"
  }
}

# Security Group for the Database
resource "aws_security_group" "db_sg" {
  name        = "db-security-group"
  description = "Allow inbound traffic for database"
  vpc_id      = data.aws_vpc.default.id

  # MySQL/Aurora port
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production!
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# ---------------------------------------------------------
# Database Instance with S3 Restore
# ---------------------------------------------------------

resource "aws_db_instance" "restored_db" {
  identifier             = "restored-db-instance"
  engine                 = "mysql"
  engine_version         = var.source_engine_version
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp2"
  db_name                = var.db_name
  username               = var.db_username
  password               = var.db_password

  # Networking
  db_subnet_group_name   = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  publicly_accessible    = true
  skip_final_snapshot    = true # Set to false in production

  # Backup & Maintenance
  backup_retention_period = 0
  maintenance_window      = "Mon:00:00-Mon:03:00"

  # S3 Import Configuration
  # This block initializes the database from the S3 backup
  s3_import {
    source_engine         = "mysql"
    source_engine_version = var.source_engine_version
    bucket_name           = var.s3_bucket_name
    bucket_prefix         = var.s3_backup_prefix
    ingestion_role        = aws_iam_role.rds_s3_import_role.arn
  }

  tags = {
    Name = "Restored-Database"
  }
}

