resource "aws_kms_key" "db_credentials_key" {
  description             = "KMS key for encrypting RDS master user credentials"
  deletion_window_in_days = 10
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action   = "kms:*"
        Resource = "*"
      },
      {
        Sid    = "Allow RDS Service to use the key"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
        Action = [
          "kms:Decrypt",
          "kms:Encrypt",
          "kms:GenerateDataKey"
        ]
        Resource = "*"
      }
    ]
  })
}

# Create an alias to easily identify the key
resource "aws_kms_alias" "db_credentials_key_alias" {
  name          = "alias/rds-db-credentials-key"
  target_key_id = aws_kms_key.db_credentials_key.id
}

# ------------------------------------------------------------------------------
# Step 2: Networking Setup (VPC, Subnets, Security Group)
# ------------------------------------------------------------------------------

# Retrieve the current AWS account ID
data "aws_caller_identity" "current" {}

# Create a VPC
resource "aws_vpc" "main_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "rds-vpc"
  }
}

# Create Subnets
resource "aws_subnet" "db_subnets" {
  count                   = 2
  vpc_id                  = aws_vpc.main_vpc.id
  cidr_block              = cidrsubnet(aws_vpc.main_vpc.cidr_block, 8, count.index)
  availability_zone       = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = false

  tags = {
    Name = "rds-subnet-${count.index + 1}"
  }
}

# Create a DB Subnet Group
resource "aws_db_subnet_group" "default" {
  name       = "main-subnet-group"
  subnet_ids = aws_subnet.db_subnets[*].id

  tags = {
    Name = "My DB Subnet Group"
  }
}

# Security Group for the Database
resource "aws_security_group" "db_sg" {
  name        = "rds-security-group"
  description = "Allow inbound MySQL traffic"
  vpc_id      = aws_vpc.main_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production environments
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-sg"
  }
}

# Data source for availability zones
data "aws_availability_zones" "available" {}

# ------------------------------------------------------------------------------
# Step 3: Create the AWS Database (RDS)
# ------------------------------------------------------------------------------

resource "aws_db_instance" "default" {
  identifier             = "my-secured-database"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_encrypted      = true
  storage_type           = "gp2"
  db_subnet_group_name   = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]

  # Database name
  db_name  = "myapp"
  username = "admin"

  # IMPORTANT: 
  # 1. manage_master_user_password = true tells AWS to store the password in Secrets Manager.
  # 2. master_user_secret_kms_key_id links the designated KMS key for encryption.
  manage_master_user_password = true
  master_user_secret_kms_key_id = aws_kms_key.db_credentials_key.id

  # Skip final snapshot to avoid issues during 'terraform destroy' for this demo
  skip_final_snapshot = true

  # Public accessibility is generally false for secure DBs, kept false here
  publicly_accessible = false

  tags = {
    Name = "MySecureDB"
  }
}
```

