Tosatisfy the request for an Amazon EFS file system with tags, we need to:

1.  **Configure the Terraform AWS Provider:** This allows Terraform to interact with AWS resources.
2.  **Define the EFS File System Resource:** We will use the `aws_efs_file_system` resource. This is the core component that creates the file system.
3.  **Apply Tags:** We will use the `tags` argument within the resource block to apply metadata (e.g., Name, Environment) to the file system as requested.

Here is the complete Terraform configuration:

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

variable "aws_region" {
  description = "The AWS region where the EFS file system will be created"
  default     = "us-east-1"
}

variable "efs_name" {
  description = "The name tag for the EFS file system"
  default     = "MyMainFileSystem"
}

variable "environment" {
  description = "The environment tag (e.g., dev, prod)"
  default     = "dev"
}

resource "aws_efs_file_system" "this" {
  # Optional token to ensure idempotency
  creation_token = "terraform-efs-example"

  # Performance mode can be 'generalPurpose' or 'maxIO'
  performance_mode = "generalPurpose"

  # Throughput mode can be 'bursting', 'provisioned', or 'elastic'
  throughput_mode = "bursting"

  # Enable encryption at rest
  encrypted = true

  # Tags to apply to the EFS file system
  tags = {
    Name        = var.efs_name
    Environment = var.environment
    ManagedBy   = "Terraform"
  }
}
