provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

# Variable to define the IAM Principal allowed to access the EFS
variable "efs_principal_arn" {
  description = "The ARN of the IAM user or role allowed to access this file system."
  type        = string
  default     = "arn:aws:iam::123456789012:root" # Replace with your specific ARN
}

# 1. Create the Amazon EFS File System
resource "aws_efs_file_system" "this" {
  creation_token = "my-efs-token"

  tags = {
    Name = "TerraformEFS"
    Environment = "Dev"
  }
}

# 2. Attach a Resource-Based Policy
resource "aws_efs_file_system_policy" "this" {
  file_system_id = aws_efs_file_system.this.id

  # Bypass policy lockout safety check for this example. 
  # In production, ensure you do not lock yourself out of managing the file system.
  bypass_policy_lockout_safety_check = false

  policy = <<POLICY
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "EFSAllowAccess",
      "Effect": "Allow",
      "Principal": {
        "AWS": "${var.efs_principal_arn}"
      },
      "Action": [
        "elasticfilesystem:ClientMount",
        "elasticfilesystem:ClientWrite"
      ],
      "Resource": "${aws_efs_file_system.this.arn}"
    }
  ]
}
POLICY
}

