extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Network Setup (VPC and Subnets)
# EFS requires a VPC and subnets to host mount targets.

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "efs-example-vpc"
  }
}

# Subnet in Availability Zone A
resource "aws_subnet" "subnet_a" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "efs-subnet-a"
  }
}

# Subnet in Availability Zone B
resource "aws_subnet" "subnet_b" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true

  tags = {
    Name = "efs-subnet-b"
  }
}

# 2. Security Group
# Controls inbound and outbound traffic to the EFS file system (NFS port 2049).

resource "aws_security_group" "efs_sg" {
  name        = "efs-security-group"
  description = "Allow NFS inbound traffic for EFS"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 2049
    to_port     = 2049
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "efs-sg"
  }
}

# 3. EFS File System
# The actual file storage resource.

resource "aws_efs_file_system" "example" {
  creation_token   = "example-efs-token"
  performance_mode = "generalPurpose"

  tags = {
    Name = "example-efs"
  }
}

# 4. Mount Targets
# Interfaces that allow resources in specific subnets to access the EFS file system.
# We create one mount target per subnet to ensure high availability.

resource "aws_efs_mount_target" "mount_a" {
  file_system_id  = aws_efs_file_system.example.id
  subnet_id       = aws_subnet.subnet_a.id
  security_groups = [aws_security_group.efs_sg.id]
}

resource "aws_efs_mount_target" "mount_b" {
  file_system_id  = aws_efs_file_system.example.id
  subnet_id       = aws_subnet.subnet_b.id
  security_groups = [aws_security_group.efs_sg.id]
}

# Outputs
output "efs_file_system_id" {
  description = "ID of the EFS file system"
  value       = aws_efs_file_system.example.id
}

output "efs_dns_name" {
  description = "DNS name of the EFS file system"
  value       = aws_efs_file_system.example.dns_name
}

