extracted_code:
# Terraform configuration to provision an Egress-Only Internet Gateway (EIGW)
# This setup allows IPv6 instances to communicate to the internet but prevents
# unsolicited inbound connections from the internet.

provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC with an associated IPv6 CIDR block
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  # Request an Amazon-provided IPv6 CIDR block
  assign_generated_ipv6_cidr_block = true

  tags = {
    Name = "ipv6-vpc"
  }
}

# 2. Create a Subnet that supports IPv6
resource "aws_subnet" "private" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"

  # Automatically assign IPv6 addresses to instances launched in this subnet
  assign_ipv6_address_on_creation = true

  # Define a subnet from the VPC's IPv6 CIDR block
  # This creates a /64 subnet (standard for IPv6) from the VPC's CIDR
  ipv6_cidr_block = cidrsubhost(aws_vpc.main.ipv6_cidr_block, 8, 1)

  tags = {
    Name = "ipv6-subnet"
  }
}

# 3. Provision the Egress-Only Internet Gateway
resource "aws_egress_only_internet_gateway" "eigw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-egress-only-igw"
  }
}

# 4. Create a Route Table to route IPv6 traffic
resource "aws_route_table" "ipv6_rt" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "ipv6-route-table"
  }
}

# 5. Add a route for all IPv6 internet traffic (::/0) to the Egress-Only Gateway
resource "aws_route" "ipv6_egress_route" {
  route_table_id                         = aws_route_table.ipv6_rt.id
  destination_ipv6_cidr_block            = "::/0"
  egress_only_gateway_id                 = aws_egress_only_internet_gateway.eigw.id
}

# 6. Associate the Route Table with the Subnet
resource "aws_route_table_association" "a" {
  subnet_id      = aws_subnet.private.id
  route_table_id = aws_route_table.ipv6_rt.id
}

