extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# ---------------------------------------------------------------------------
# 1. Networking Setup (VPC & Subnets)
# ---------------------------------------------------------------------------
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "lb-vpc"
  }
}

resource "aws_subnet" "public" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.${count.index + 1}.0/24"
  availability_zone       = element(data.aws_availability_zones.available.names, count.index)
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-${count.index + 1}"
  }
}

data "aws_availability_zones" "available" {}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
}

resource "aws_route_table_association" "public" {
  count          = 2
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

# ---------------------------------------------------------------------------
# 2. Network Load Balancer (NLB) - The Destination
# ---------------------------------------------------------------------------
resource "aws_lb" "network_lb" {
  name               = "my-network-lb"
  internal           = false
  load_balancer_type = "network"
  subnets            = aws_subnet.public[*].id

  enable_cross_zone_load_balancing = true

  tags = {
    Environment = "production"
  }
}

# The NLB needs its own target group for the actual backend servers (EC2, etc.)
resource "aws_lb_target_group" "nlb_tg" {
  name        = "nlb-tg-ip"
  port        = 80
  protocol    = "TCP"
  vpc_id      = aws_vpc.main.id
  target_type = "ip"

  health_check {
    enabled = true
  }
}

resource "aws_lb_listener" "nlb_frontend" {
  load_balancer_arn = aws_lb.network_lb.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.nlb_tg.arn
  }
}

# ---------------------------------------------------------------------------
# 3. Application Load Balancer (ALB) - The Entry Point
# ---------------------------------------------------------------------------
resource "aws_lb" "app_lb" {
  name               = "my-app-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = aws_subnet.public[*].id

  tags = {
    Environment = "production"
  }
}

resource "aws_security_group" "alb_sg" {
  name        = "alb-sg"
  description = "Allow HTTP inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "HTTP from Internet"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# This Target Group acts as the bridge. It is of type 'ip'.
# The targets registered here will be the IPs of the NLB created above.
resource "aws_lb_target_group" "alb_to_nlb_tg" {
  name        = "alb-to-nlb-tg"
  port        = 80
  protocol    = "HTTP"
  vpc_id      = aws_vpc.main.id
  target_type = "ip"

  health_check {
    enabled = true
    path    = "/"
  }
}

resource "aws_lb_listener" "alb_frontend" {
  load_balancer_arn = aws_lb.app_lb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.alb_to_nlb_tg.arn
  }
}

# ---------------------------------------------------------------------------
# 4. Integration: Connecting ALB to NLB
# ---------------------------------------------------------------------------

# NOTE: Terraform does not automatically expose the dynamic Node IPs of an NLB.
# In a real-world scenario, you would fetch these IPs via a data source or 
# external script and pass them in. For this configuration, we use a variable.

variable "nlb_node_ips" {
  description = "The private IP addresses of the NLB nodes to be registered as targets in the ALB"
  type        = list(string)
  # Placeholder IPs. Replace these with the actual IPs of the NLB nodes 
  # found in the AWS Console or via CLI: aws elb describe-load-balancers
  default = ["10.0.1.100", "10.0.2.100"] 
}

resource "aws_lb_target_group_attachment" "alb_to_nlb_attach" {
  count            = length(var.nlb_node_ips)
  target_group_arn = aws_lb_target_group.alb_to_nlb_tg.arn
  target_id        = var.nlb_node_ips[count.index]
  port             = 80
}

# ---------------------------------------------------------------------------
# 5. Output
# ---------------------------------------------------------------------------
output "alb_dns_name" {
  value = aws_lb.app_lb.dns_name
  description = "DNS name of the Application Load Balancer"
}

output "nlb_dns_name" {
  value = aws_lb.network_lb.dns_name
  description = "DNS name of the Network Load Balancer"
}

