terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"

  name = "main-vpc"
  cidr = "10.0.0.0/16"

  azs                  = data.aws_availability_zones.available.names
  public_subnets       = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]
}

data "aws_ami" "ubuntu" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["*ubuntu-noble-24.04-amd64-server-*"]
  }
}

resource "aws_security_group" "instance-sg" {
  name = "instance-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "instance-sg-ingress-rule" {
  from_port       = 80
  to_port         = 80
  ip_protocol     = "tcp"
  referenced_security_group_id = aws_security_group.lb-sg.id
  security_group_id = aws_security_group.instance-sg.id
}

resource "aws_vpc_security_group_egress_rule" "instance-sg-egress-rule" {
  from_port       = 0
  to_port         = 0
  ip_protocol     = "-1"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.instance-sg.id
}

resource "aws_security_group" "lb-sg" {
  name = "lb-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "lb-sg-ingress-rule" {
  from_port   = 80
  to_port     = 80
  ip_protocol = "tcp"
  cidr_ipv4   = "0.0.0.0/0"
  security_group_id = aws_security_group.lb-sg.id
}

resource "aws_vpc_security_group_egress_rule" "lb-sg-egress-rule" {
  from_port   = 0
  to_port     = 0
  ip_protocol = "-1"
  cidr_ipv4   = "0.0.0.0/0"
  security_group_id = aws_security_group.lb-sg.id
}


resource "aws_instance" "my_instance" {
  ami           = data.aws_ami.ubuntu.id
  instance_type = "t2.micro"
  subnet_id     = module.vpc.public_subnets[0]
  security_groups = [ aws_security_group.instance-sg.id ]
}

resource "aws_lb" "test" {
  subnets            = module.vpc.public_subnets
  internal           = false
  load_balancer_type = "network"
  security_groups    = [aws_security_group.lb-sg.id]
}

resource "aws_lb_listener" "my_listener" {
  load_balancer_arn = aws_lb.test.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.target_group.arn
  }
}

resource "aws_lb_target_group" "target_group" {
  port     = 80
  protocol = "TCP"
  vpc_id   = module.vpc.vpc_id
}

resource "aws_lb_target_group_attachment" "ec2_attach" {
  target_group_arn = aws_lb_target_group.target_group.arn
  target_id = aws_instance.my_instance.id
}

response:
Here is the step-by-step thought process to generate the Terraform configuration:

1.  **Analyze the Request:** The user wants a "Load Balancer" that routes traffic to a "Network Load Balancer (NLB)".
    *   **Cloud Provider:** The term "Network Load Balancer (NLB)" is specific terminology primarily used by **AWS**.
    *   **Architecture Pattern:** This describes a scenario where an **Application Load Balancer (ALB)** sits in front of a **Network Load Balancer (NLB)**.
    *   **Routing Mechanism:** An ALB operates at Layer 7 (HTTP), while an NLB operates at Layer 4 (TCP). To route from an ALB to an NLB, the ALB must treat the NLB as a target. This is achieved by creating an ALB Target Group of type `ip` and registering the NLB's private IP addresses (Node IPs) as targets.

2.  **Determine Required Resources (AWS):**
    *   **Networking:** A VPC and at least two subnets are mandatory for both Load Balancers.
    *   **NLB Resources:**
        *   `aws_lb` (type `network`)
        *   `aws_lb_target_group` (backend targets for the NLB, e.g., instances)
        *   `aws_lb_listener` (TCP listener on port 80)
    *   **ALB Resources:**
        *   `aws_lb` (type `application`)
        *   `aws_lb_target_group` (type `ip`, targets the NLB)
        *   `aws_lb_listener` (HTTP listener on port 80, forwards to the IP target group)
    *   **The "Link":** We need `aws_lb_target_group_attachment` resources to attach the NLB's IPs to the ALB's target group.

3.  **Address Dependency Challenges (The "IP" Problem):**
    *   Terraform does not natively output the specific Network Interface IPs of an NLB in a way that can be directly referenced by another resource in the same run without complex data sources or external scripts.
    *   *Solution:* I will define a Terraform variable (`nlb_target_ips`) to represent the IPs of the NLB. This makes the configuration reusable. I will also include a `dummy_target` logic for the NLB's own target group so the resources validate successfully.

4.  **Drafting the Code Structure:**

    *   **Provider Block:** Standard AWS configuration.
    *   **VPC/Subnets:** Create a basic network foundation.
    *   **NLB Module:**
        *   Create NLB.
        *   Create Target Group (for the backend servers).
        *   Create Listener.
    *   **ALB Module:**
        *   Create ALB.
        *   Create Target Group (Type `ip`). This is key.
        *   Create Listener (Forward action to the IP TG).
    *   **Integration:** Use `for_each` on the `nlb_target_ips` variable to attach the NLB's IPs to the ALB's Target Group.

5.  **Refining the Configuration:**
    *   Ensure security groups allow traffic.
    *   Use `depends_on` where necessary to avoid race conditions (though implicit dependency graphs usually handle this).
    *   Add comments explaining that the user needs to supply the NLB IPs.

6.  **Final Code Generation:** Assemble the HCL blocks into the single requested code block.

